import { createClient } from "@supabase/supabase-js";

import {
  getSupabaseServerUrl,
  getSupabaseServiceRoleKey,
} from "../../src/features/api/config/apiKeyStoreConfig.js";

/** Match browser bundle JWT issuer — SUPABASE_URL override can point at wrong project. */
export function getIdentityApiSupabaseUrl() {
  const viteUrl = String(process.env.VITE_SUPABASE_URL || "").trim();
  return viteUrl || getSupabaseServerUrl();
}

function createServiceClient(url, serviceKey) {
  return createClient(url, serviceKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });
}

function mapAuthError(userError) {
  const message = String(userError?.message || "").toLowerCase();
  if (message.includes("expired")) {
    return "Phiên đăng nhập đã hết hạn. Đăng xuất và đăng nhập lại.";
  }
  if (message.includes("invalid") || message.includes("jwt")) {
    return "Token đăng nhập không khớp project Supabase trên server. Kiểm tra VITE_SUPABASE_URL Production trên Vercel.";
  }
  return "Phiên đăng nhập không hợp lệ. Đăng xuất và đăng nhập lại.";
}

async function resolveUserManagePermission(adminClient, userId) {
  const { data: profile, error: profileError } = await adminClient
    .from("profiles")
    .select("role, status")
    .eq("id", userId)
    .maybeSingle();

  if (profileError) {
    return {
      ok: false,
      code: "PERMISSION_CHECK_FAILED",
      error: profileError.message || "Không đọc được profile.",
    };
  }

  if (!profile || profile.status !== "active") {
    return {
      ok: false,
      code: "FORBIDDEN",
      error: "Tài khoản chưa active hoặc thiếu profile.",
    };
  }

  const role = String(profile.role || "").trim();
  if (role === "SUPER_ADMIN") {
    return { ok: true };
  }

  const { data: permRow, error: permError } = await adminClient
    .from("role_permissions")
    .select("role_id")
    .eq("role_id", role)
    .eq("permission_id", "user.manage")
    .maybeSingle();

  if (permError) {
    return {
      ok: false,
      code: "PERMISSION_CHECK_FAILED",
      error: permError.message || "Không kiểm tra được quyền.",
    };
  }

  if (!permRow) {
    return { ok: false, code: "FORBIDDEN", error: "Không có quyền user.manage." };
  }

  return { ok: true };
}

export async function authorizeUserManage(req) {
  const authHeader = String(req.headers?.authorization || req.headers?.Authorization || "");
  const token = authHeader.startsWith("Bearer ") ? authHeader.slice(7).trim() : "";
  if (!token) {
    return { ok: false, code: "NOT_AUTHENTICATED", error: "Thiếu access token." };
  }

  const url = getIdentityApiSupabaseUrl();
  const serviceKey = getSupabaseServiceRoleKey();
  if (!url || !serviceKey) {
    return {
      ok: false,
      code: "NO_SUPABASE",
      error: "Supabase server chưa cấu hình (URL hoặc SUPABASE_SERVICE_ROLE_KEY).",
    };
  }

  const adminClient = createServiceClient(url, serviceKey);
  const { data: userData, error: userError } = await adminClient.auth.getUser(token);
  if (userError || !userData?.user?.id) {
    return {
      ok: false,
      code: "NOT_AUTHENTICATED",
      error: mapAuthError(userError),
    };
  }

  const permission = await resolveUserManagePermission(adminClient, userData.user.id);
  if (!permission.ok) {
    return permission;
  }

  return { ok: true, actorId: userData.user.id, adminClient };
}

import {
  ROLES,
  isGlobalRole,
  isPlatformWideRole,
  isClubScopedRole,
  isVenueScopedRole,
  isRefereeRole,
  isPlatformScopedRole,
  isTournamentTeamScopedRole,
  rolesEqual,
  normalizeRole,
} from "./roles.js";
import { getPermissionScopes, PERMISSION_SCOPE, PERMISSIONS } from "./permissions.js";
import { roleHasPermission } from "./rolePermissions.js";
import { getEffectivePermissionsForTenantRole } from "../features/identity/services/tenantRolePermissionService.js";
import { resolveGovernanceElevatedRole } from "../features/club/services/governanceRoleElevation.js";
import { isUserActive } from "../models/user.js";
import { loadClubs } from "../data/club.js";
import { getExplicitTenantIdForClub } from "../features/tenant/guards/tenantGuard.js";
import {
  canUserAccessCluster,
  isOrgWideClusterRole,
  resolveAssignedClusterIdsForUser,
} from "../features/court-cluster/services/courtClusterService.js";
import { isCourtClustersEnabled } from "../features/court-cluster/config/clusterFlags.js";

/**
 * RBAC có được áp dụng không.
 * Khi false hoặc chưa đăng nhập → mọi kiểm tra trả về true (không phá app hiện tại).
 */
export function isRbacEnforced({ rbacEnabled = false, user = null } = {}) {
  return Boolean(rbacEnabled && user);
}

export function hasRole(user, role) {
  if (!user?.role) return false;
  return rolesEqual(user.role, role);
}

export function hasAnyRole(user, roles = []) {
  if (!user?.role) return false;
  return roles.some((role) => rolesEqual(user.role, role));
}

/**
 * Kiểm tra role permission, có áp dụng tenant overrides khi user có tenantId/venueId.
 */
export function roleHasEffectivePermission(user, permission) {
  const role = resolveGovernanceElevatedRole(user) || normalizeRole(user?.role);
  if (!role) {
    return false;
  }

  const tenantId = user?.tenantId || user?.venueId || null;
  if (tenantId) {
    return getEffectivePermissionsForTenantRole(tenantId, role).has(permission);
  }

  return roleHasPermission(role, permission);
}

/**
 * Kiểm tra user có permission trong scope không.
 *
 * @param {object|null} user
 * @param {string} permission
 * @param {object} scope - { venueId?, clubId?, playerId? }
 * @param {object} options - { rbacEnabled? }
 */
export function can(user, permission, scope = {}, options = {}) {
  const { rbacEnabled = false } = options;

  if (!isRbacEnforced({ rbacEnabled, user })) {
    return true;
  }

  if (!isUserActive(user)) {
    return false;
  }

  if (!roleHasEffectivePermission(user, permission)) {
    return false;
  }

  return matchesScope(user, permission, scope);
}

export function canAll(user, permissions = [], scope = {}, options = {}) {
  return permissions.every((permission) => can(user, permission, scope, options));
}

export function canAny(user, permissions = [], scope = {}, options = {}) {
  return permissions.some((permission) => can(user, permission, scope, options));
}

export function assertCan(user, permission, scope = {}, options = {}) {
  if (!can(user, permission, scope, options)) {
    const role = normalizeRole(user?.role) || user?.role || "anonymous";
    return {
      ok: false,
      error: `Không có quyền: ${permission} (role: ${role})`,
      code: "FORBIDDEN",
      permission,
    };
  }

  return { ok: true };
}

export function canAccessVenue(user, venueId, options = {}) {
  const { rbacEnabled = false } = options;

  if (!isRbacEnforced({ rbacEnabled, user })) {
    return true;
  }

  if (!isUserActive(user)) {
    return false;
  }

  if (hasRole(user, ROLES.PLATFORM_ADMIN) || hasRole(user, ROLES.SUPER_ADMIN)) {
    return true;
  }

  if (!venueId) {
    return false;
  }

  if (isVenueScopedRole(user.role)) {
    return user.venueId === venueId;
  }

  if (isClubScopedRole(user.role)) {
    return !user.venueId || user.venueId === venueId;
  }

  return false;
}

export function canAccessClub(user, clubId, clubMeta = {}, options = {}) {
  const { rbacEnabled = false } = options;
  const { venueId: clubVenueId = null } = clubMeta;

  if (!isRbacEnforced({ rbacEnabled, user })) {
    return true;
  }

  if (!isUserActive(user)) {
    return false;
  }

  if (isPlatformWideRole(user.role)) {
    return true;
  }

  if (!clubId) {
    return false;
  }

  if (isVenueScopedRole(user.role)) {
    if (!user.venueId) {
      return false;
    }

    const club = loadClubs().find((item) => item.id === clubId);
    const registryVenueId = club?.venueId || clubVenueId || null;

    if (registryVenueId === user.venueId) {
      return true;
    }

    const explicitTenant = getExplicitTenantIdForClub(clubId);
    if (explicitTenant === user.venueId) {
      return true;
    }

    if (!registryVenueId && !explicitTenant) {
      return true;
    }

    return false;
  }

  if (isClubScopedRole(user.role)) {
    if (user.clubId !== clubId) {
      return false;
    }
    if (clubVenueId && user.venueId && user.venueId !== clubVenueId) {
      return false;
    }
    return true;
  }

  if (isRefereeRole(user.role)) {
    if (clubVenueId && user.venueId && user.venueId !== clubVenueId) {
      return false;
    }
    return Boolean(user.venueId);
  }

  return false;
}

export function canAccessCluster(user, clusterId, clusterMeta = {}, options = {}) {
  const { rbacEnabled = false } = options;
  const { venueId: clusterVenueId = null } = clusterMeta;

  if (!isRbacEnforced({ rbacEnabled, user })) {
    return true;
  }

  if (!isUserActive(user)) {
    return false;
  }

  if (hasRole(user, ROLES.PLATFORM_ADMIN) || hasRole(user, ROLES.SUPER_ADMIN)) {
    return true;
  }

  if (!clusterId) {
    return false;
  }

  if (!isCourtClustersEnabled()) {
    if (clusterVenueId && user?.venueId) {
      return user.venueId === clusterVenueId;
    }
    if (user?.venueId && cluster.venueId) {
      return user.venueId === cluster.venueId;
    }
    return isVenueScopedRole(user?.role);
  }

  return canUserAccessCluster(user, clusterId, { venueId: clusterVenueId || user?.venueId });
}

function matchesScope(user, permission, scope) {
  if (hasRole(user, ROLES.PLATFORM_ADMIN) || hasRole(user, ROLES.SUPER_ADMIN)) {
    return true;
  }

  const scopes = getPermissionScopes(permission);

  if (hasRole(user, ROLES.PLAYER) && scopes.includes(PERMISSION_SCOPE.SELF)) {
    return matchesSelfScope(user, scope, permission);
  }

  if (isTournamentTeamScopedRole(user.role) && scopes.includes(PERMISSION_SCOPE.TEAM)) {
    return matchesTeamScope(user, scope);
  }

  return scopes.some((permissionScope) =>
    matchesScopeType(user, permissionScope, scope, permission)
  );
}

function matchesScopeType(user, permissionScope, scope, permission) {
  switch (permissionScope) {
    case PERMISSION_SCOPE.GLOBAL:
      return isGlobalRole(user.role);

    case PERMISSION_SCOPE.PLATFORM:
      return matchesPlatformScope(user, scope);

    case PERMISSION_SCOPE.VENUE:
      return matchesVenueScope(user, scope.venueId, permission);

    case PERMISSION_SCOPE.CLUSTER:
      return matchesClusterScope(user, scope);

    case PERMISSION_SCOPE.CLUB:
      return matchesClubScope(user, scope);

    case PERMISSION_SCOPE.TOURNAMENT:
      return matchesTournamentScope(user, scope);

    case PERMISSION_SCOPE.TEAM:
      return matchesTeamScope(user, scope);

    case PERMISSION_SCOPE.SELF:
      return matchesSelfScope(user, scope, permission);

    default:
      return false;
  }
}

function matchesPlatformScope(user, scope) {
  if (!isPlatformScopedRole(user.role)) {
    return false;
  }

  if (scope.tenantId && user.tenantId && user.tenantId !== scope.tenantId) {
    return false;
  }

  return true;
}

function matchesTournamentScope(user, scope) {
  const tournamentId = scope.tournamentId || scope.tournament_id;
  if (!tournamentId) {
    return isVenueScopedRole(user.role) || isClubScopedRole(user.role);
  }

  if (isVenueScopedRole(user.role)) {
    if (scope.venueId && user.venueId && user.venueId !== scope.venueId) {
      return false;
    }
    return true;
  }

  if (isClubScopedRole(user.role)) {
    if (scope.clubId && user.clubId && user.clubId !== scope.clubId) {
      return false;
    }
    return true;
  }

  if (isTournamentTeamScopedRole(user.role)) {
    const userTournamentId = user.tournamentId || user.tournament_id;
    return Boolean(userTournamentId && userTournamentId === tournamentId);
  }

  return false;
}

function matchesTeamScope(user, scope) {
  const tournamentId = scope.tournamentId || scope.tournament_id;
  const teamId = scope.teamId || scope.team_id;

  if (!isTournamentTeamScopedRole(user.role)) {
    return false;
  }

  const userTournamentId = user.tournamentId || user.tournament_id;
  const userTeamId = user.teamId || user.team_id;

  if (!userTournamentId || !userTeamId) {
    return false;
  }

  if (!tournamentId || !teamId) {
    return false;
  }

  return userTournamentId === tournamentId && userTeamId === teamId;
}

function matchesClusterScope(user, scope) {
  const clusterId = scope.clusterId || scope.cluster_id;
  const venueId = scope.venueId || scope.tenantId || user.venueId;

  if (!isCourtClustersEnabled()) {
    return matchesVenueScope(user, venueId);
  }

  if (!clusterId) {
    if (isOrgWideClusterRole(user) || isGlobalRole(user.role)) {
      return matchesVenueScope(user, venueId);
    }

    return resolveAssignedClusterIdsForUser(user).length > 0;
  }

  if (venueId && user.venueId && user.venueId !== venueId) {
    return false;
  }

  if (isGlobalRole(user.role) || isOrgWideClusterRole(user)) {
    return !venueId || !user.venueId || user.venueId === venueId;
  }

  return canUserAccessCluster(user, clusterId, { venueId });
}

function matchesVenueScope(user, venueId, permission) {
  if (permission === PERMISSIONS.SYSTEM_SETTING && !venueId) {
    return false;
  }

  if (!venueId) {
    return (
      (isVenueScopedRole(user.role) && Boolean(user.venueId)) ||
      isPlatformScopedRole(user.role)
    );
  }

  if (isPlatformScopedRole(user.role)) {
    return true;
  }

  if (isVenueScopedRole(user.role)) {
    return user.venueId === venueId;
  }

  if (isClubScopedRole(user.role)) {
    return !user.venueId || user.venueId === venueId;
  }

  return false;
}

function matchesClubScope(user, scope) {
  const { clubId, venueId } = scope;

  if (isVenueScopedRole(user.role)) {
    if (venueId && user.venueId !== venueId) {
      return false;
    }
    return !venueId || user.venueId === venueId;
  }

  if (isRefereeRole(user.role)) {
    if (venueId && user.venueId !== venueId) {
      return false;
    }
    return Boolean(user.venueId);
  }

  if (isClubScopedRole(user.role)) {
    if (!user.clubId) {
      return false;
    }
    if (clubId && user.clubId !== clubId) {
      return false;
    }
    if (venueId && user.venueId && user.venueId !== venueId) {
      return false;
    }
    return true;
  }

  return false;
}

function matchesSelfScope(user, scope, permission) {
  if (!hasRole(user, ROLES.PLAYER)) {
    return false;
  }

  if (scope.clubId && user.clubId && user.clubId !== scope.clubId) {
    return false;
  }

  if (permission === PERMISSIONS.PLAYER_VIEW || permission === PERMISSIONS.PLAYER_UPDATE) {
    if (!scope.playerId) {
      return false;
    }
    return user.playerId === scope.playerId;
  }

  if (
    permission === PERMISSIONS.SKILL_LEVEL_VIEW_PRIVATE ||
    permission === PERMISSIONS.SKILL_LEVEL_REQUEST_CHANGE
  ) {
    if (!scope.playerId) {
      return false;
    }
    return user.playerId === scope.playerId;
  }

  if (permission === PERMISSIONS.TOURNAMENT_VIEW || permission === PERMISSIONS.STATISTICS_VIEW) {
    return true;
  }

  return Boolean(user.playerId || user.clubId);
}

/**
 * Kiểm tra viewer có được xem điểm trình độ riêng tư của VĐV không.
 */
export function canViewPlayerSkillLevel(user, scope = {}, options = {}) {
  const { clubId, playerId, tournamentContext = false } = scope;

  if (!isRbacEnforced({ rbacEnabled: options.rbacEnabled, user })) {
    return true;
  }

  if (!isUserActive(user)) {
    return false;
  }

  if (playerId && user.playerId && user.playerId === playerId) {
    return can(
      user,
      PERMISSIONS.SKILL_LEVEL_VIEW_PRIVATE,
      { clubId, playerId },
      options
    );
  }

  if (
    can(user, PERMISSIONS.SKILL_LEVEL_VIEW_PRIVATE, { clubId, playerId }, options)
  ) {
    return true;
  }

  if (
    tournamentContext &&
    can(
      user,
      PERMISSIONS.SKILL_LEVEL_VIEW_PRIVATE,
      { clubId, tournamentId: scope.tournamentId },
      options
    )
  ) {
    return true;
  }

  return false;
}

import { useCallback, useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  AppBar,
  Badge,
  Box,
  Button,
  Divider,
  IconButton,
  Menu,
  MenuItem,
  Stack,
  Toolbar,
  Typography,
} from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import NotificationsIcon from "@mui/icons-material/Notifications";
import HelpOutlineOutlinedIcon from "@mui/icons-material/HelpOutlineOutlined";

import GlobalSearch from "./GlobalSearch.jsx";
import AccountMenu from "./shell/AccountMenu.jsx";
import TenantSwitcher from "./TenantSwitcher.jsx";
import { usePlatformRuntime } from "../core/platform/app/usePlatformRuntime.js";
import { useIsMobile } from "../features/mobile/hooks/useIsMobile.js";
import { useTenant } from "../context/TenantContext.jsx";
import { SHELL_COLORS, SHELL_LAYOUT } from "./shell/shellTokens.js";

export default function Header({ onMenuClick }) {
  const isMobile = useIsMobile();
  const { isSuperAdmin } = useTenant();
  const runtime = usePlatformRuntime();
  const navigate = useNavigate();
  const [unreadNotificationCount, setUnreadNotificationCount] = useState(0);
  const [notificationAnchorEl, setNotificationAnchorEl] = useState(null);

  const syncNotificationCount = useCallback(() => {
    const notifications = runtime?.notificationService?.list?.() || [];
    const unread = notifications.filter(
      (notification) => !(notification?.read || notification?.status === "read")
    ).length;
    setUnreadNotificationCount(unread);
  }, [runtime?.notificationService]);

  useEffect(() => {
    syncNotificationCount();
    const intervalId = window.setInterval(syncNotificationCount, 2000);
    return () => window.clearInterval(intervalId);
  }, [syncNotificationCount]);

  const notificationItems = useMemo(() => {
    const notifications = runtime?.notificationService?.list?.() || [];
    return notifications.slice().reverse().slice(0, 6);
  }, [runtime?.notificationService, unreadNotificationCount]);

  const handleNotificationOpen = (event) => {
    setNotificationAnchorEl(event.currentTarget);
  };

  const handleNotificationClose = () => {
    setNotificationAnchorEl(null);
  };

  const handleNotificationClick = (notification) => {
    if (!(notification?.read || notification?.status === "read")) {
      runtime?.notificationService?.markAsRead?.(notification.id);
      syncNotificationCount();
    }
    handleNotificationClose();
    navigate("/tournament");
  };

  const handleMarkAllNotificationsAsRead = () => {
    runtime?.notificationService?.markAllAsRead?.();
    syncNotificationCount();
    handleNotificationClose();
  };

  return (
    <AppBar
      position="sticky"
      elevation={0}
      sx={{
        zIndex: (theme) => theme.zIndex.drawer + 1,
        bgcolor: SHELL_COLORS.cardBg,
        color: SHELL_COLORS.textPrimary,
        borderBottom: `1px solid ${SHELL_COLORS.border}`,
        boxShadow: "0 1px 3px rgba(15, 23, 42, 0.06)",
      }}
    >
      <Toolbar
        disableGutters
        sx={{
          px: { xs: 1.5, md: 2.5, lg: 3 },
          gap: 1.5,
          minHeight: `${SHELL_LAYOUT.topbarHeight}px !important`,
          height: SHELL_LAYOUT.topbarHeight,
          flexWrap: "nowrap",
          overflow: "hidden",
        }}
      >
        {isMobile && onMenuClick && (
          <IconButton edge="start" onClick={onMenuClick} aria-label="Mở menu" sx={{ color: "inherit" }}>
            <MenuIcon />
          </IconButton>
        )}

        {!isMobile && (
          <Stack direction="row" alignItems="center" spacing={1.5} sx={{ flex: 1, minWidth: 0, justifyContent: "center" }}>
            {isSuperAdmin && (
              <Box sx={{ flexShrink: 0 }}>
                <TenantSwitcher variant="light" minWidth={200} />
              </Box>
            )}
            <Box sx={{ flex: 1, display: "flex", justifyContent: "center", minWidth: 0, maxWidth: 520 }}>
              <GlobalSearch variant="light" maxWidth={520} />
            </Box>
          </Stack>
        )}

        {isMobile && (
          <Typography variant="subtitle2" fontWeight={700} noWrap sx={{ flex: 1, minWidth: 0 }}>
            Pickleball Pro
          </Typography>
        )}

        <Stack
          direction="row"
          spacing={0.5}
          alignItems="center"
          sx={{ flexShrink: 0, ml: isMobile ? "auto" : 0 }}
        >
          {isMobile && <GlobalSearch variant="light" maxWidth={160} size="small" />}

          <IconButton
            aria-label="Thông báo"
            onClick={handleNotificationOpen}
            sx={{
              border: `1px solid ${SHELL_COLORS.border}`,
              borderRadius: 2,
              color: SHELL_COLORS.textSecondary,
            }}
          >
            <Badge
              badgeContent={unreadNotificationCount}
              color="error"
              max={99}
              invisible={unreadNotificationCount === 0}
            >
              <NotificationsIcon fontSize="small" />
            </Badge>
          </IconButton>

          {!isMobile && (
            <IconButton
              aria-label="Hỗ trợ"
              onClick={() => navigate("/settings")}
              sx={{
                border: `1px solid ${SHELL_COLORS.border}`,
                borderRadius: 2,
                color: SHELL_COLORS.textSecondary,
              }}
            >
              <HelpOutlineOutlinedIcon fontSize="small" />
            </IconButton>
          )}

          <AccountMenu />
        </Stack>
      </Toolbar>

      <Menu
        anchorEl={notificationAnchorEl}
        open={Boolean(notificationAnchorEl)}
        onClose={handleNotificationClose}
        transformOrigin={{ horizontal: "right", vertical: "top" }}
        anchorOrigin={{ horizontal: "right", vertical: "bottom" }}
        slotProps={{
          paper: {
            sx: { mt: 1, minWidth: 320, maxWidth: 360, borderRadius: 2 },
          },
        }}
      >
        <Box sx={{ px: 2, py: 1.25 }}>
          <Box sx={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 1, mb: 0.5 }}>
            <Typography variant="subtitle2" fontWeight={700}>
              Thông báo
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {unreadNotificationCount} chưa đọc
            </Typography>
          </Box>
          {unreadNotificationCount > 0 && (
            <Button size="small" variant="text" onClick={handleMarkAllNotificationsAsRead} sx={{ px: 0, mt: 0.25 }}>
              Đánh dấu tất cả đã đọc
            </Button>
          )}
        </Box>
        <Divider />
        {notificationItems.length > 0 ? (
          notificationItems.map((notification) => {
            const isUnread = !(notification?.read || notification?.status === "read");
            return (
              <MenuItem
                key={notification.id || `${notification.title}-${notification.created_at}`}
                onClick={() => handleNotificationClick(notification)}
                sx={{
                  alignItems: "flex-start",
                  py: 1.2,
                  bgcolor: isUnread ? SHELL_COLORS.mintBg : "transparent",
                }}
              >
                <Box sx={{ minWidth: 0 }}>
                  <Typography variant="body2" fontWeight={600} sx={{ mb: 0.25 }}>
                    {notification.title || "Thông báo hệ thống"}
                  </Typography>
                  <Typography variant="caption" color="text.secondary" sx={{ display: "block", mb: 0.25 }}>
                    {notification.body || notification.detail || "Không có chi tiết"}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {new Date(
                      notification.created_at || notification.createdAt || new Date().toISOString()
                    ).toLocaleString("vi-VN")}
                  </Typography>
                </Box>
              </MenuItem>
            );
          })
        ) : (
          <Box sx={{ px: 2, py: 2 }}>
            <Typography variant="body2" color="text.secondary">
              Chưa có thông báo nào.
            </Typography>
          </Box>
        )}
      </Menu>
    </AppBar>
  );
}

import { FormControl, InputLabel, MenuItem, Select, Typography } from "@mui/material";
import { useMemo } from "react";

import { useTenant } from "../context/TenantContext.jsx";
import { listTenants } from "../features/tenant/index.js";
import { SHELL_COLORS } from "./shell/shellTokens.js";

const VARIANT_STYLES = {
  dark: {
    bgcolor: "rgba(255,255,255,0.12)",
    color: "common.white",
    outline: "rgba(255,255,255,0.3)",
    icon: "common.white",
  },
  context: {
    bgcolor: "#FFFFFF",
    color: SHELL_COLORS.textPrimary,
    outline: SHELL_COLORS.border,
    icon: SHELL_COLORS.textSecondary,
  },
};

export default function TenantSwitcher({ size = "small", minWidth = 180, variant = "dark" }) {
  const { currentTenantId, isSuperAdmin, switchTenant, revision } = useTenant();
  const styles = VARIANT_STYLES[variant] || VARIANT_STYLES.dark;

  if (!isSuperAdmin) {
    return null;
  }

  const tenants = useMemo(() => listTenants(), [revision]);
  const hasSelection = tenants.some((tenant) => tenant.id === currentTenantId);
  const value = hasSelection ? currentTenantId : "";

  return (
    <FormControl size={size} sx={{ minWidth }}>
      <InputLabel id="header-tenant-label" sx={variant !== "dark" ? { color: SHELL_COLORS.textSecondary } : undefined}>
        Đang quản trị
      </InputLabel>
      <Select
        labelId="header-tenant-label"
        value={value}
        label="Đang quản trị"
        displayEmpty
        renderValue={(selected) => {
          if (!selected) {
            return "Chọn tenant…";
          }
          const tenant = tenants.find((item) => item.id === selected);
          return tenant?.name || selected;
        }}
        onChange={(event) => {
          const next = event.target.value;
          if (next) {
            switchTenant(next);
          }
        }}
        sx={{
          bgcolor: styles.bgcolor,
          color: styles.color,
          borderRadius: 1.5,
          ".MuiOutlinedInput-notchedOutline": { borderColor: styles.outline },
          ".MuiSvgIcon-root": { color: styles.icon },
        }}
      >
        <MenuItem value="" disabled>
          <em>Chọn tenant…</em>
        </MenuItem>
        {tenants.map((tenant) => (
          <MenuItem key={tenant.id} value={tenant.id}>
            {tenant.name}
          </MenuItem>
        ))}
      </Select>
    </FormControl>
  );
}

export function TenantBadge() {
  const { currentTenant, isSuperAdmin } = useTenant();

  if (!currentTenant) {
    return null;
  }

  return (
    <Typography
      variant="caption"
      sx={{
        color: "rgba(255,255,255,0.85)",
        fontWeight: 700,
        display: { xs: "none", md: "block" },
      }}
    >
      {isSuperAdmin ? "Đang quản trị: " : "Sân: "}
      {currentTenant.name}
    </Typography>
  );
}

import { useMemo } from "react";
import { FormControl, InputLabel, MenuItem, Select } from "@mui/material";

import { useAuth } from "../context/AuthContext.jsx";
import { useTenant } from "../context/TenantContext.jsx";
import { listVenues } from "../domain/venueService.js";
import { canAccessVenue } from "../auth/rbac.js";
import { loadActiveVenueId, saveActiveVenueId } from "../data/venueSession.js";
import { SHELL_COLORS } from "./shell/shellTokens.js";

const VARIANT_STYLES = {
  dark: {
    bgcolor: "rgba(255,255,255,0.12)",
    color: "common.white",
    outline: "rgba(255,255,255,0.3)",
    icon: "common.white",
  },
  light: {
    bgcolor: SHELL_COLORS.pageBg,
    color: SHELL_COLORS.textPrimary,
    outline: SHELL_COLORS.border,
    icon: SHELL_COLORS.textSecondary,
  },
  context: {
    bgcolor: "#FFFFFF",
    color: SHELL_COLORS.textPrimary,
    outline: SHELL_COLORS.border,
    icon: SHELL_COLORS.textSecondary,
  },
};

export default function VenueSwitcher({ size = "small", minWidth = 180, variant = "dark", hideLabel = false }) {
  const { user, rbacEnabled, isAuthenticated } = useAuth();
  const { currentTenantId } = useTenant();
  const styles = VARIANT_STYLES[variant] || VARIANT_STYLES.dark;

  const venues = useMemo(() => {
    const all = listVenues();
    if (!rbacEnabled || !isAuthenticated || !user) {
      return all;
    }
    return all.filter((venue) => canAccessVenue(user, venue.id, { rbacEnabled }));
  }, [rbacEnabled, isAuthenticated, user, currentTenantId]);

  if (venues.length <= 1 && !user?.venueId) {
    return null;
  }

  const storedId = loadActiveVenueId();
  const defaultId = user?.venueId || venues[0]?.id || "";
  const value = venues.some((v) => v.id === storedId) ? storedId : defaultId;

  const handleChange = (event) => {
    saveActiveVenueId(event.target.value);
    window.dispatchEvent(new CustomEvent("venue-switched", { detail: event.target.value }));
  };

  const fieldLabel = hideLabel ? "" : "Tổ chức";

  return (
    <FormControl size={size} sx={{ minWidth, width: hideLabel ? "100%" : undefined }}>
      {!hideLabel && (
        <InputLabel id="header-venue-label" sx={variant !== "dark" ? { color: SHELL_COLORS.textSecondary } : undefined}>
          Tổ chức
        </InputLabel>
      )}
      <Select
        labelId="header-venue-label"
        value={value}
        label={fieldLabel}
        onChange={handleChange}
        displayEmpty={hideLabel}
        sx={{
          bgcolor: styles.bgcolor,
          color: styles.color,
          borderRadius: variant === "light" ? 2 : 1,
          fontWeight: variant === "light" ? 700 : 500,
          fontSize: hideLabel ? 11.5 : undefined,
          ...(hideLabel && {
            height: 30,
            "& .MuiSelect-select": { py: 0.5 },
          }),
          ".MuiOutlinedInput-notchedOutline": { borderColor: styles.outline },
          ".MuiSvgIcon-root": { color: styles.icon },
        }}
      >
        {venues.map((venue) => (
          <MenuItem key={venue.id} value={venue.id}>
            {venue.name}
          </MenuItem>
        ))}
      </Select>
    </FormControl>
  );
}

