            <Stack spacing={0.5}>
              {upcoming.map((booking) => (
                <Typography key={booking.id} variant="body2" color="text.secondary">
                  {booking.startTime} · {booking.customerName} · {booking.courtName}
                  {" · "}
                  {formatTimeRange(booking.startTime, booking.endTime)}
                </Typography>
              ))}
            </Stack>
          </Box>
        )}
      </CardContent>
    </Card>
  );
}

