import { useMemo, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import {
  Alert,
  Box,
  Card,
  CardActionArea,
  CardContent,
  Chip,
  Tab,
  Tabs,
  Typography,
} from "@mui/material";
import ChevronRightIcon from "@mui/icons-material/ChevronRight";

import { FEATURE_STATUS } from "../../config/v5Menu/menuBuilders.js";
import { useAuth } from "../../context/AuthContext.jsx";
import { useClub } from "../../context/ClubContext.jsx";
import { filterInPageNavHub, resolveRouteAccessScope } from "../../auth/menuAccess.js";
import TournamentPageHeader from "../tournament/TournamentPageHeader.jsx";
import {
  TOURNAMENT_HUB,
  tournamentCardContentSx,
  tournamentCardHoverSx,
  tournamentCardSx,
  tournamentHubTabSx,
} from "../tournament/tournamentLayout.js";
import "./inPageNavHubSlate.css";

function ItemBadge({ item }) {
  if (item.featureStatus === FEATURE_STATUS.PLANNED) {
    return (
      <Chip size="small" label="Sắp ra mắt" variant="outlined" sx={{ ml: 1, height: 20, fontSize: 10 }} />
    );
  }
  if (item.featureStatus === FEATURE_STATUS.PARTIAL) {
    return (
      <Chip size="small" label="Một phần" variant="outlined" color="warning" sx={{ ml: 1, height: 20, fontSize: 10 }} />
    );
  }
  return null;
}

/**
 * Hub trong màn hình — tab + thẻ lựa chọn (sidebar tối đa 2 cấp).
 */
export default function InPageNavHub({ hub }) {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const auth = useAuth();
  const { activeClubId, activeClub } = useClub();

  const scope = resolveRouteAccessScope({
    user: auth.user,
    activeClubId,
    activeClub,
  });

  const filteredHub = useMemo(
    () =>
      filterInPageNavHub(hub, {
        can: auth.can,
        rbacEnabled: auth.rbacEnabled,
        isAuthenticated: auth.isAuthenticated,
        user: auth.user,
      }, scope),
    [hub, auth.can, auth.rbacEnabled, auth.isAuthenticated, auth.user, scope]
  );

  const sections = filteredHub?.sections || [];
  const defaultTab = sections[0]?.id || "";
  const tabParam = searchParams.get("tab") || defaultTab;
  const [tab, setTab] = useState(tabParam);

  const activeSection = useMemo(
    () => sections.find((section) => section.id === tab) || sections[0],
    [sections, tab]
  );

  const handleTabChange = (_event, nextTab) => {
    setTab(nextTab);
    setSearchParams({ tab: nextTab }, { replace: true });
  };

  const handleItemClick = (item) => {
    if (item.featureStatus === FEATURE_STATUS.PLANNED) {
      navigate(`/coming-soon/${encodeURIComponent(item.key)}`);
      return;
    }
    if (!item.path) return;
    navigate(item.path);
  };

  if (!hub) {
    return <Alert severity="warning">Không tìm thấy cấu hình điều hướng.</Alert>;
  }

  if (!filteredHub?.sections?.length) {
    return (
      <Alert severity="warning">
        Bạn không có quyền truy cập các mục trong phần này.
      </Alert>
    );
  }

  return (
    <Box
      className="in-page-nav-hub in-page-nav-hub--slate"
      sx={{
        "--hub-accent-lime": TOURNAMENT_HUB.accent,
        "--hub-card-min-height": `${TOURNAMENT_HUB.cardMinHeight}px`,
      }}
    >
      <TournamentPageHeader
        title={filteredHub.title}
        description={filteredHub.description}
      />

      {sections.length > 1 ? (
        <Tabs value={tab} onChange={handleTabChange} sx={tournamentHubTabSx}>
          {sections.map((section) => (
            <Tab key={section.id} value={section.id} label={section.label} />
          ))}
        </Tabs>
      ) : null}

      <Box
        className="in-page-nav-hub__grid"
        sx={{
          display: "grid",
          gridTemplateColumns: { xs: "1fr", sm: "1fr 1fr", md: "1fr 1fr 1fr" },
          gap: TOURNAMENT_HUB.gridGap,
        }}
      >
        {(activeSection?.items || []).map((item) => {
          const plannedNoPath =
            !item.path && item.featureStatus === FEATURE_STATUS.PLANNED;
          return (
            <Card
              key={item.key}
              variant="outlined"
              elevation={0}
              sx={{
                ...tournamentCardSx,
                ...tournamentCardHoverSx,
              }}
            >
              <CardActionArea
                onClick={() => handleItemClick(item)}
                disabled={!item.path && !plannedNoPath}
                sx={{
                  height: "100%",
                  borderRadius: "inherit",
                  "&.Mui-disabled": { opacity: 0.55 },
                }}
              >
                <CardContent
                  sx={{
                    ...tournamentCardContentSx,
                    position: "relative",
                    minHeight: 72,
                    pr: 5,
                  }}
                >
                  <Box sx={{ display: "flex", alignItems: "center", flexWrap: "wrap" }}>
                    <Typography fontWeight={700} color="text.primary">
                      {item.text}
                    </Typography>
                    <ItemBadge item={item} />
                  </Box>
                  {item.featureNote ? (
                    <Typography variant="caption" color="text.secondary" display="block" sx={{ mt: 0.5 }}>
                      {item.featureNote}
                    </Typography>
                  ) : null}
                  {item.path ? (
                    <ChevronRightIcon
                      fontSize="small"
                      sx={{
                        position: "absolute",
                        right: 16,
                        top: "50%",
                        transform: "translateY(-50%)",
                        color: "text.secondary",
                      }}
                    />
                  ) : null}
                </CardContent>
              </CardActionArea>
            </Card>
          );
        })}
      </Box>
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  MenuItem,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import BusinessIcon from "@mui/icons-material/Business";

import { useClub } from "../../context/ClubContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import PermissionGate from "../auth/PermissionGate.jsx";
import {
  assignClubToVenue,
  createVenue,
  ensureDemoVenue,
  getVenueSummaryForClub,
  getSubscriptionPlans,
  listVenues,
  DEMO_VENUE_ID,
} from "../../domain/venueService.js";
import { requestPlanUpgrade, getPaymentMode } from "../../domain/paymentService.js";
import { formatCurrency } from "../../domain/courtBookingEngine.js";

export default function VenueOnboardingPanel() {
  const { activeClub, activeClubId, refreshClubs } = useClub();
  const { rbacEnabled } = useAuth();
  const [venueName, setVenueName] = useState("");
  const [selectedVenueId, setSelectedVenueId] = useState("");
  const [message, setMessage] = useState(null);
  const [revision, setRevision] = useState(0);

  useEffect(() => {
    ensureDemoVenue();
    setRevision((value) => value + 1);
  }, []);

  const summary = useMemo(
    () => getVenueSummaryForClub(activeClubId),
    [activeClubId, revision, activeClub?.venueId]
  );

  const venues = useMemo(() => listVenues(), [revision]);
  const plans = useMemo(() => getSubscriptionPlans(), [revision]);

  const handleUpgradePlan = (planId) => {
    if (!summary.venue?.id) {
      setMessage({ type: "error", text: "CLB chưa gắn venue." });
      return;
    }

    const result = requestPlanUpgrade(summary.venue.id, planId);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    if (result.requiresRedirect && result.redirectUrl) {
      window.location.href = result.redirectUrl;
      return;
    }

    setRevision((value) => value + 1);
    setMessage({
      type: "success",
      text: `Đã nâng cấp lên gói ${result.plan.name}.`,
    });
  };

  const handleCreateVenue = () => {
    const result = createVenue(venueName);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setVenueName("");
    setRevision((value) => value + 1);
    setMessage({ type: "success", text: `Đã tạo venue ${result.venue.name}.` });
  };

  const handleAssignDemo = () => {
    ensureDemoVenue();
    const result = assignClubToVenue(activeClubId, DEMO_VENUE_ID);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    refreshClubs();
    setRevision((value) => value + 1);
    setMessage({
      type: "success",
      text: `CLB ${activeClub?.name} đã gắn venue demo.`,
    });
  };

  const handleAssignVenue = () => {
    if (!selectedVenueId) {
      setMessage({ type: "error", text: "Chọn venue trước." });
      return;
    }

    const result = assignClubToVenue(activeClubId, selectedVenueId);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    refreshClubs();
    setRevision((value) => value + 1);
    setMessage({ type: "success", text: "Đã gán CLB vào venue." });
  };

  return (
    <Card id="tenant-subscription">
      <CardContent>
        <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 2 }}>
          <BusinessIcon color="primary" />
          <Typography variant="h6" fontWeight="bold">
            Tenant / Venue
          </Typography>
        </Stack>

        {message && (
          <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
            {message.text}
          </Alert>
        )}

        <Box sx={{ mb: 2, p: 1.5, bgcolor: "action.hover", borderRadius: 1 }}>
          <Typography variant="subtitle2" fontWeight={700}>
            CLB: {activeClub?.name}
          </Typography>
          <Stack direction="row" spacing={0.5} sx={{ mt: 0.5, flexWrap: "wrap" }}>
            {summary.venue ? (
              <>
                <Chip size="small" label={summary.venue.name} color="primary" />
                <Chip size="small" variant="outlined" label={`ID: ${summary.venue.id}`} />
                <Chip
                  size="small"
                  variant="outlined"
                  color={summary.subscriptionActive ? "success" : "warning"}
                  label={
                    summary.subscription
                      ? `Gói ${summary.subscription.planName} · ${summary.subscription.status}`
                      : "Chưa có subscription"
                  }
                />
              </>
            ) : (
              <Chip size="small" color="warning" label="CLB chưa gắn venue" />
            )}
          </Stack>
          {!rbacEnabled && (
            <Typography variant="caption" color="text.secondary" sx={{ display: "block", mt: 1 }}>
              RBAC tắt — venue chỉ để chuẩn bị multi-tenant. Bật RBAC để kiểm tra phân quyền theo
              venue.
            </Typography>
          )}
        </Box>

        <Stack spacing={2}>
          <PermissionGate
            permissions={[PERMISSIONS.VENUE_UPDATE, PERMISSIONS.VENUE_UPDATE]}
          >
            <Button variant="outlined" onClick={handleAssignDemo}>
              Gán CLB vào venue demo ({DEMO_VENUE_ID})
            </Button>
          </PermissionGate>

          <PermissionGate permission={PERMISSIONS.VENUE_UPDATE}>
            <Stack direction={{ xs: "column", sm: "row" }} spacing={1}>
              <TextField
                size="small"
                label="Tên venue mới"
                value={venueName}
                onChange={(e) => setVenueName(e.target.value)}
                fullWidth
              />
              <Button variant="contained" onClick={handleCreateVenue} disabled={!venueName.trim()}>
                Tạo venue
              </Button>
            </Stack>
          </PermissionGate>

          <PermissionGate
            permissions={[PERMISSIONS.VENUE_UPDATE, PERMISSIONS.VENUE_UPDATE, PERMISSIONS.CLUB_UPDATE]}
          >
            <Stack direction={{ xs: "column", sm: "row" }} spacing={1}>
              <TextField
                select
                size="small"
                label="Gán CLB vào venue"
                value={selectedVenueId}
                onChange={(e) => setSelectedVenueId(e.target.value)}
                fullWidth
              >
                <MenuItem value="">Chọn venue…</MenuItem>
                {venues.map((venue) => (
                  <MenuItem key={venue.id} value={venue.id}>
                    {venue.name} ({venue.id})
                  </MenuItem>
                ))}
              </TextField>
              <Button variant="contained" onClick={handleAssignVenue} disabled={!selectedVenueId}>
                Gán
              </Button>
            </Stack>
          </PermissionGate>

          {summary.venue && (
            <PermissionGate
              permissions={[
                PERMISSIONS.SUBSCRIPTION_VIEW,
                PERMISSIONS.VENUE_UPDATE,
                PERMISSIONS.SUBSCRIPTION_UPDATE,
              ]}
            >
              <Box>
                <Typography variant="subtitle2" fontWeight={700} sx={{ mb: 1 }}>
                  Gói thuê phần mềm ({getPaymentMode() === "stripe" ? "Stripe" : "dev"})
                </Typography>
                <Stack direction={{ xs: "column", md: "row" }} spacing={1}>
                  {plans.map((plan) => (
                    <Card key={plan.id} variant="outlined" sx={{ flex: 1, minWidth: 160 }}>
                      <CardContent sx={{ py: 1.5, "&:last-child": { pb: 1.5 } }}>
                        <Typography fontWeight={700}>{plan.name}</Typography>
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                          {plan.priceMonthly === 0
                            ? "Miễn phí"
                            : `${formatCurrency(plan.priceMonthly)}/tháng`}
                        </Typography>
                        <Typography variant="caption" display="block" color="text.secondary">
                          {plan.maxCourts} sân · {plan.maxClubs} CLB · {plan.maxUsers} user
                        </Typography>
                        <Button
                          size="small"
                          variant={
                            summary.subscription?.planId === plan.id ? "outlined" : "contained"
                          }
                          disabled={summary.subscription?.planId === plan.id}
                          onClick={() => handleUpgradePlan(plan.id)}
                          sx={{ mt: 1 }}
                        >
                          {summary.subscription?.planId === plan.id ? "Đang dùng" : "Chọn gói"}
                        </Button>
                      </CardContent>
                    </Card>
                  ))}
                </Stack>
              </Box>
            </PermissionGate>
          )}
        </Stack>
      </CardContent>
    </Card>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  IconButton,
  MenuItem,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  TextField,
  Typography,
} from "@mui/material";
import GroupIcon from "@mui/icons-material/Group";
import DeleteOutlinedIcon from "@mui/icons-material/DeleteOutlined";
import CheckCircleOutlinedIcon from "@mui/icons-material/CheckCircleOutlined";

import { useClub } from "../../context/ClubContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import { ROLE_LABELS } from "../../auth/roles.js";
import PermissionGate from "../auth/PermissionGate.jsx";
import {
  activateVenueStaff,
  getInvitableRoles,
  inviteVenueStaff,
  listVenueStaff,
  removeVenueStaff,
  syncStaffInviteToSupabase,
} from "../../domain/staffService.js";
import { getVenueSummaryForClub } from "../../domain/venueService.js";
import { USER_STATUS } from "../../models/user.js";

const STATUS_LABELS = {
  [USER_STATUS.ACTIVE]: "Đang hoạt động",
  [USER_STATUS.INVITED]: "Đã mời",
  [USER_STATUS.SUSPENDED]: "Tạm khóa",
};

export default function VenueStaffPanel() {
  const { activeClubId } = useClub();
  const { supabaseAvailable } = useAuth();
  const [email, setEmail] = useState("");
  const [displayName, setDisplayName] = useState("");
  const [role, setRole] = useState(getInvitableRoles()[0]);
  const [message, setMessage] = useState(null);
  const [revision, setRevision] = useState(0);

  const summary = useMemo(
    () => getVenueSummaryForClub(activeClubId),
    [activeClubId, revision]
  );

  const staff = useMemo(() => {
    if (!summary.venue?.id) {
      return [];
    }
    return listVenueStaff(summary.venue.id);
  }, [summary.venue?.id, revision]);

  const handleInvite = async () => {
    if (!summary.venue?.id) {
      setMessage({ type: "error", text: "CLB chưa gắn venue." });
      return;
    }

    const result = inviteVenueStaff(summary.venue.id, {
      email,
      displayName,
      role,
      clubId: role === "CLUB_OWNER" ? activeClubId : null,
    });

    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    if (supabaseAvailable) {
      const synced = await syncStaffInviteToSupabase(result.member);
      if (!synced.ok && synced.code !== "NO_SUPABASE") {
        setMessage({
          type: "warning",
          text: `Đã lưu local. Supabase: ${synced.error || "chưa sync profile"}`,
        });
      }
    }

    setEmail("");
    setDisplayName("");
    setRevision((value) => value + 1);
    setMessage({ type: "success", text: `Đã mời ${result.member.email}.` });
  };

  const handleActivate = (memberId) => {
    const result = activateVenueStaff(summary.venue.id, memberId);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setRevision((value) => value + 1);
    setMessage({ type: "success", text: "Đã kích hoạt nhân sự." });
  };

  const handleRemove = (memberId) => {
    const result = removeVenueStaff(summary.venue.id, memberId);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setRevision((value) => value + 1);
    setMessage({ type: "info", text: "Đã xóa khỏi danh sách." });
  };

  if (!summary.venue) {
    return null;
  }

  return (
    <Card>
      <CardContent>
        <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 2 }}>
          <GroupIcon color="primary" />
          <Typography variant="h6" fontWeight="bold">
            Nhân sự venue
          </Typography>
          <Chip size="small" variant="outlined" label={`${staff.length} user`} />
        </Stack>

        {message && (
          <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
            {message.text}
          </Alert>
        )}

        <PermissionGate permission={PERMISSIONS.USER_MANAGE} scope={{ venueId: summary.venue.id }}>
          <Stack spacing={1.5} sx={{ mb: 2 }}>
            <Stack direction={{ xs: "column", sm: "row" }} spacing={1}>
              <TextField
                size="small"
                label="Email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                fullWidth
              />
              <TextField
                size="small"
                label="Tên hiển thị"
                value={displayName}
                onChange={(e) => setDisplayName(e.target.value)}
                fullWidth
              />
              <TextField
                select
                size="small"
                label="Vai trò"
                value={role}
                onChange={(e) => setRole(e.target.value)}
                sx={{ minWidth: 160 }}
              >
                {getInvitableRoles().map((item) => (
                  <MenuItem key={item} value={item}>
                    {ROLE_LABELS[item]}
                  </MenuItem>
                ))}
              </TextField>
              <Button variant="contained" onClick={handleInvite} disabled={!email.trim()}>
                Mời
              </Button>
            </Stack>
          </Stack>
        </PermissionGate>

        {staff.length === 0 ? (
          <Typography variant="body2" color="text.secondary">
            Chưa có nhân sự. Mời quản lý, thu ngân hoặc kế toán cho venue này.
          </Typography>
        ) : (
          <Box sx={{ overflowX: "auto" }}>
            <Table size="small">
              <TableHead>
                <TableRow>
                  <TableCell>Tên</TableCell>
                  <TableCell>Email</TableCell>
                  <TableCell>Vai trò</TableCell>
                  <TableCell>Trạng thái</TableCell>
                  <TableCell align="right">Thao tác</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {staff.map((member) => (
                  <TableRow key={member.id}>
                    <TableCell>{member.displayName}</TableCell>
                    <TableCell>{member.email}</TableCell>
                    <TableCell>{ROLE_LABELS[member.role] || member.role}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={STATUS_LABELS[member.status] || member.status}
                        color={member.status === USER_STATUS.ACTIVE ? "success" : "default"}
                      />
                    </TableCell>
                    <TableCell align="right">
                      <PermissionGate permission={PERMISSIONS.USER_MANAGE} scope={{ venueId: summary.venue.id }}>
                        {member.status === USER_STATUS.INVITED && (
                          <IconButton size="small" onClick={() => handleActivate(member.id)} title="Kích hoạt">
                            <CheckCircleOutlinedIcon fontSize="small" />
                          </IconButton>
                        )}
                        <IconButton size="small" onClick={() => handleRemove(member.id)} title="Xóa">
                          <DeleteOutlinedIcon fontSize="small" />
                        </IconButton>
                      </PermissionGate>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Box>
        )}
      </CardContent>
    </Card>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Link as RouterLink, useNavigate } from "react-router-dom";

import {
  Box,
  Button,
  Chip,
  FormControl,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import { useClub } from "../../context/ClubContext.jsx";
import { useSeasonLeague } from "../../context/SeasonContext.jsx";
import { loadClubData } from "../../domain/clubStorage.js";
import {
  createLeagueRound,
  getTournamentsForRound,
  linkTournamentToRound,
  listLeagueRounds,
  listLeagueTournaments,
  setActiveLeagueRound,
  unlinkTournamentFromRound,
  updateLeagueRound,
} from "../../domain/leagueRoundService.js";
import { TOURNAMENT_MODE } from "../../models/tournament/index.js";
import { touchButtonSx } from "./mobileUi.js";

const MODE_LABELS = {
  [TOURNAMENT_MODE.DAILY_PLAY]: "Daily",
  [TOURNAMENT_MODE.INTERNAL_TOURNAMENT]: "Nội bộ",
  [TOURNAMENT_MODE.OFFICIAL_TOURNAMENT]: "Chính thức",
};

function resolveTournamentPath(tournament) {
  if (tournament.mode === TOURNAMENT_MODE.DAILY_PLAY) {
    return `/tournament/daily/${tournament.id}`;
  }
  if (tournament.mode === TOURNAMENT_MODE.INTERNAL_TOURNAMENT) {
    return `/tournament/internal/${tournament.id}`;
  }
  if (tournament.mode === TOURNAMENT_MODE.OFFICIAL_TOURNAMENT) {
    return `/tournament/official/${tournament.id}`;
  }
  return "/tournament";
}

function RoundCard({
  round,
  isActive,
  tournaments,
  unassignedTournaments,
  onRename,
  onSetActive,
  onAssign,
  onUnlink,
}) {
  const navigate = useNavigate();
  const [draftName, setDraftName] = useState(round.name);
  const [assignTournamentId, setAssignTournamentId] = useState("");

  return (
    <Paper variant="outlined" sx={{ p: 1.5 }}>
      <Stack spacing={1.25}>
        <Stack direction={{ xs: "column", sm: "row" }} spacing={1} alignItems={{ sm: "center" }}>
          <TextField
            size="small"
            label="Tên vòng"
            value={draftName}
            sx={{ flex: 1 }}
            onChange={(event) => setDraftName(event.target.value)}
          />
          <Button
            size="small"
            variant="outlined"
            onClick={() => onRename(round.id, draftName)}
            disabled={!draftName.trim() || draftName.trim() === round.name}
          >
            Lưu tên
          </Button>
          {!isActive ? (
            <Button size="small" variant="contained" onClick={() => onSetActive(round.id)}>
              Đặt vòng active
            </Button>
          ) : (
            <Chip size="small" color="success" label="Vòng đang active" />
          )}
        </Stack>

        <Typography variant="body2" color="text.secondary">
          {(round.tournamentIds || []).length} giải trong vòng này
        </Typography>

        {tournaments.length === 0 ? (
          <Typography variant="body2" color="text.secondary">
            Chưa có giải nào gắn vòng này.
          </Typography>
        ) : (
          <Stack spacing={0.75}>
            {tournaments.map((tournament) => (
              <Stack
                key={tournament.id}
                direction={{ xs: "column", sm: "row" }}
                spacing={1}
                alignItems={{ xs: "stretch", sm: "center" }}
                sx={{
                  p: 1,
                  borderRadius: 1,
                  border: "1px solid",
                  borderColor: "divider",
                }}
              >
                <Box sx={{ flex: 1, minWidth: 0 }}>
                  <Typography fontWeight="medium" sx={{ wordBreak: "break-word" }}>
                    {tournament.name}
                  </Typography>
                  <Stack direction="row" spacing={0.75} flexWrap="wrap" useFlexGap sx={{ mt: 0.5 }}>
                    <Chip
                      size="small"
                      label={MODE_LABELS[tournament.mode] || tournament.mode}
                    />
                    <Chip size="small" variant="outlined" label={tournament.status} />
                  </Stack>
                </Box>
                <Stack direction="row" spacing={1}>
                  <Button size="small" onClick={() => navigate(resolveTournamentPath(tournament))}>
                    Mở
                  </Button>
                  <Button
                    size="small"
                    color="warning"
                    onClick={() => onUnlink(tournament.id)}
                  >
                    Gỡ
                  </Button>
                </Stack>
              </Stack>
            ))}
          </Stack>
        )}

        {unassignedTournaments.length > 0 ? (
          <Stack direction={{ xs: "column", sm: "row" }} spacing={1}>
            <FormControl fullWidth size="small">
              <InputLabel>Gán giải vào vòng</InputLabel>
              <Select
                label="Gán giải vào vòng"
                value={assignTournamentId}
                onChange={(event) => setAssignTournamentId(event.target.value)}
              >
                <MenuItem value="">
                  <em>Chọn giải</em>
                </MenuItem>
                {unassignedTournaments.map((tournament) => (
                  <MenuItem key={tournament.id} value={tournament.id}>
                    {tournament.name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
            <Button
              variant="contained"
              disabled={!assignTournamentId}
              sx={{ ...touchButtonSx, whiteSpace: "nowrap" }}
              onClick={() => {
                onAssign(round.id, assignTournamentId);
                setAssignTournamentId("");
              }}
            >
              Gán giải
            </Button>
          </Stack>
        ) : null}
      </Stack>
    </Paper>
  );
}

export default function LeagueRoundManager({ onMessage }) {
  const { activeClubId, revision, refreshClubs } = useClub();
  const { seasons, leagues, activeSeason, activeLeague } = useSeasonLeague();
  const [seasonId, setSeasonId] = useState(activeSeason?.id || "");
  const [leagueId, setLeagueId] = useState(activeLeague?.id || "");
  const [newRoundName, setNewRoundName] = useState("");

  useEffect(() => {
    if (activeSeason?.id) {
      setSeasonId(activeSeason.id);
    }
  }, [activeSeason?.id]);

  useEffect(() => {
    if (activeLeague?.id) {
      setLeagueId(activeLeague.id);
    }
  }, [activeLeague?.id]);

  const clubData = useMemo(
    () => loadClubData(activeClubId),
    [activeClubId, revision]
  );

  const leaguesForSeason = useMemo(
    () => leagues.filter((league) => String(league.seasonId) === String(seasonId)),
    [leagues, seasonId]
  );

  const rounds = useMemo(
    () => listLeagueRounds(activeClubId, { seasonId, leagueId }),
    [activeClubId, seasonId, leagueId, revision]
  );

  const leagueTournaments = useMemo(
    () => listLeagueTournaments(activeClubId, { seasonId, leagueId }),
    [activeClubId, seasonId, leagueId, revision]
  );

  const unassignedTournaments = useMemo(
    () => leagueTournaments.filter((tournament) => !tournament.roundId),
    [leagueTournaments]
  );

  const activeRoundId = clubData.active?.roundSlot || "";

  const notify = (type, text) => {
    if (onMessage) {
      onMessage({ type, text });
    }
  };

  const handleSeasonChange = (nextSeasonId) => {
    setSeasonId(nextSeasonId);
    const nextLeagues = leagues.filter(
      (league) => String(league.seasonId) === String(nextSeasonId)
    );
    setLeagueId(nextLeagues[0]?.id || "");
  };

  const handleCreateRound = () => {
    const name = newRoundName.trim() || `Vòng ${rounds.length + 1}`;
    const result = createLeagueRound(activeClubId, {
      seasonId,
      leagueId,
      name,
    });

    if (!result.ok) {
      notify("error", result.error || "Không tạo được vòng.");
      return;
    }

    setNewRoundName("");
    refreshClubs();
    notify("success", `Đã tạo ${result.round.name}.`);
  };

  const handleRename = (roundId, name) => {
    const result = updateLeagueRound(activeClubId, roundId, { name: name.trim() });
    if (!result.ok) {
      notify("error", result.error || "Không đổi được tên vòng.");
      return;
    }
    refreshClubs();
    notify("success", "Đã cập nhật tên vòng.");
  };

  const handleSetActive = (roundId) => {
    const result = setActiveLeagueRound(activeClubId, roundId);
    if (!result.ok) {
      notify("error", result.error || "Không đặt được vòng active.");
      return;
    }
    refreshClubs();
    notify("success", "Đã đặt vòng active. Giải mới sẽ gắn vào vòng này.");
  };

  const handleAssign = (roundId, tournamentId) => {
    const result = linkTournamentToRound(activeClubId, tournamentId, roundId);
    if (!result.ok) {
      notify("error", result.error || "Không gán được giải.");
      return;
    }
    refreshClubs();
    notify("success", "Đã gán giải vào vòng.");
  };

  const handleUnlink = (tournamentId) => {
    const result = unlinkTournamentFromRound(activeClubId, tournamentId);
    if (!result.ok) {
      notify("error", result.error || "Không gỡ được giải.");
      return;
    }
    refreshClubs();
    notify("success", "Đã gỡ giải khỏi vòng.");
  };

  return (
    <Stack spacing={2}>
      <Typography variant="body2" color="text.secondary">
        Mỗi vòng mùa gom các giải V3.3. Giải mới tự gắn vào vòng đang active.
      </Typography>

      <Stack direction={{ xs: "column", md: "row" }} spacing={1.5}>
        <FormControl size="small" sx={{ minWidth: 200 }}>
          <InputLabel>Mùa giải</InputLabel>
          <Select
            label="Mùa giải"
            value={seasonId}
            onChange={(event) => handleSeasonChange(event.target.value)}
          >
            {seasons.map((season) => (
              <MenuItem key={season.id} value={season.id}>
                {season.name}
              </MenuItem>
            ))}
          </Select>
        </FormControl>

        <FormControl size="small" sx={{ minWidth: 200 }}>
          <InputLabel>Giải / League</InputLabel>
          <Select
            label="Giải / League"
            value={leagueId}
            onChange={(event) => setLeagueId(event.target.value)}
          >
            {leaguesForSeason.map((league) => (
              <MenuItem key={league.id} value={league.id}>
                {league.name}
              </MenuItem>
            ))}
          </Select>
        </FormControl>
      </Stack>

      <Stack direction={{ xs: "column", sm: "row" }} spacing={1}>
        <TextField
          size="small"
          label="Tên vòng mới"
          placeholder={`Vòng ${rounds.length + 1}`}
          value={newRoundName}
          sx={{ flex: 1 }}
          onChange={(event) => setNewRoundName(event.target.value)}
        />
        <Button variant="contained" sx={touchButtonSx} onClick={handleCreateRound}>
          Tạo vòng
        </Button>
        <Button variant="outlined" sx={touchButtonSx} component={RouterLink} to="/tournament">
          Tới Giải đấu
        </Button>
        <Button variant="outlined" sx={touchButtonSx} component={RouterLink} to="/club">
          CLB & Giải
        </Button>
      </Stack>

      {unassignedTournaments.length > 0 ? (
        <AlertLike text={`${unassignedTournaments.length} giải chưa gắn vòng trong mùa/giải này.`} />
      ) : null}

      {rounds.length === 0 ? (
        <Typography variant="body2" color="text.secondary">
          Chưa có vòng nào. Bấm &quot;Tạo vòng&quot; hoặc tạo giải mới để hệ thống tự tạo vòng.
        </Typography>
      ) : (
        <Stack spacing={1.5}>
          {rounds.map((round) => (
            <RoundCard
              key={round.id}
              round={round}
              isActive={String(round.id) === String(activeRoundId)}
              tournaments={getTournamentsForRound(activeClubId, round.id)}
              unassignedTournaments={unassignedTournaments}
              onRename={handleRename}
              onSetActive={handleSetActive}
              onAssign={handleAssign}
              onUnlink={handleUnlink}
            />
          ))}
        </Stack>
      )}
    </Stack>
  );
}

function AlertLike({ text }) {
  return (
    <Paper variant="outlined" sx={{ p: 1.25, bgcolor: "warning.50" }}>
      <Typography variant="body2">{text}</Typography>
    </Paper>
  );
}

import { useMemo, useState } from "react";

import { FormControl, InputLabel, MenuItem, Select, Stack } from "@mui/material";

import { listTournaments } from "../../domain/tournamentService.js";
import { TOURNAMENT_STATUS } from "../../models/tournament/index.js";
import TournamentCourtSchedulePanel from "./TournamentCourtSchedulePanel.jsx";

export default function TournamentCourtScheduleManager({ clubId, courts = [], revision = 0, onSaved }) {
  const tournaments = useMemo(() => {
    return listTournaments(clubId).filter(
      (item) =>
        item.status !== TOURNAMENT_STATUS.CANCELLED &&
        item.status !== TOURNAMENT_STATUS.COMPLETED
    );
  }, [clubId, revision]);

  const [selectedId, setSelectedId] = useState("");

  const selectedTournament = useMemo(
    () => tournaments.find((item) => item.id === selectedId) || null,
    [tournaments, selectedId]
  );

  return (
    <Stack spacing={2}>
      <FormControl fullWidth>
        <InputLabel>Chọn giải đấu</InputLabel>
        <Select
          label="Chọn giải đấu"
          value={selectedId}
          onChange={(event) => setSelectedId(event.target.value)}
        >
          {tournaments.map((tournament) => (
            <MenuItem key={tournament.id} value={tournament.id}>
              {tournament.name}
            </MenuItem>
          ))}
        </Select>
      </FormControl>

      {selectedTournament ? (
        <TournamentCourtSchedulePanel
          clubId={clubId}
          tournament={selectedTournament}
          courts={courts}
          onSaved={onSaved}
        />
      ) : null}
    </Stack>
  );
}

import { useEffect, useState } from "react";

