  onSaved,
}) {
  const schedule = tournament?.courtSchedule;
  const [date, setDate] = useState(schedule?.date || todayIsoDate());
  const [startTime, setStartTime] = useState(schedule?.startTime || "07:00");
  const [endTime, setEndTime] = useState(schedule?.endTime || "12:00");
  const [courtIds, setCourtIds] = useState(schedule?.courtIds || []);
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!tournament) {
      return;
    }

    setDate(schedule?.date || todayIsoDate());
    setStartTime(schedule?.startTime || "07:00");
    setEndTime(schedule?.endTime || "12:00");
    setCourtIds(schedule?.courtIds || []);
    setMessage(null);
    setError(null);
  }, [tournament?.id, schedule?.syncedAt]);

  if (!tournament) {
    return null;
  }

  const toggleCourt = (id) => {
    setCourtIds((current) =>
      current.includes(id) ? current.filter((item) => item !== id) : [...current, id]
    );
  };

  const handleSync = () => {
    const result = setTournamentCourtSchedule(clubId, tournament.id, {
      date,
      startTime,
      endTime,
      courtIds,
    });

    if (!result.ok) {
      setError(result.error || result.message);
      setMessage(null);
      return;
    }

    setError(null);
    setMessage(
      `${result.message || "Đã khóa sân cho giải."}${
        result.failed?.length ? ` · ${result.failed.length} sân trùng lịch.` : ""
      }`
    );
    onSaved?.(result);
  };

  return (
    <Card variant="outlined">
      <CardContent>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6">Khóa sân cho giải đấu</Typography>
            <Typography variant="body2" color="text.secondary">
              {tournament.name} · Tạo booking loại <strong>tournament</strong> trên lịch Quản lý sân
            </Typography>
            {schedule?.syncedAt && (
              <Typography variant="caption" color="text.secondary">
                Lần đồng bộ gần nhất: {new Date(schedule.syncedAt).toLocaleString("vi-VN")}
              </Typography>
            )}
          </Box>

          {error && <Alert severity="error">{error}</Alert>}
          {message && <Alert severity="success">{message}</Alert>}

          <TextField
            label="Ngày giải"
            type="date"
            value={date}
            onChange={(event) => setDate(event.target.value)}
            fullWidth
            InputLabelProps={{ shrink: true }}
          />

          <Grid container spacing={2}>
            <Grid size={{ xs: 6 }}>
              <FormControl fullWidth>
                <InputLabel>Giờ bắt đầu</InputLabel>
                <Select label="Giờ bắt đầu" value={startTime} onChange={(event) => setStartTime(event.target.value)}>
                  {START_TIME_OPTIONS.map((time) => (
                    <MenuItem key={time} value={time}>
                      {time}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid size={{ xs: 6 }}>
              <FormControl fullWidth>
                <InputLabel>Giờ kết thúc</InputLabel>
                <Select label="Giờ kết thúc" value={endTime} onChange={(event) => setEndTime(event.target.value)}>
                  {END_TIME_OPTIONS.map((time) => (
                    <MenuItem key={time} value={time}>
                      {time}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
          </Grid>

          <Box>
            <Typography variant="subtitle2" gutterBottom>
              Sân sử dụng
            </Typography>
            <FormGroup>
              {courts.map((court, index) => (
                <FormControlLabel
                  key={court.id}
                  control={
                    <Checkbox
                      checked={courtIds.includes(court.id)}
                      onChange={() => toggleCourt(court.id)}
                    />
                  }
                  label={getCourtDisplayName(court, index)}
                />
              ))}
            </FormGroup>
          </Box>

          <Button variant="contained" onClick={handleSync}>
            Khóa sân trên lịch booking
          </Button>
        </Stack>
      </CardContent>
    </Card>
  );
}

import { Box, Checkbox, Chip, LinearProgress, Stack, Typography } from "@mui/material";
import SmartToyIcon from "@mui/icons-material/SmartToy";
import {
  getChecklistProgress,
  getChecklistState,
  setChecklistState,
} from "../../../features/ai-assistant/services/aiSuggestionStorage.js";
import { useEffect, useMemo, useState } from "react";

export default function AiSummaryCard({ summary, tenantId = "", tournamentId = "" }) {
  const checklistScope = useMemo(
    () => (tenantId && tournamentId ? { tenantId, tournamentId } : null),
    [tenantId, tournamentId]
  );
  const checklistItems = useMemo(() => summary?.workflowChecklist || [], [summary?.workflowChecklist]);
  const [checkedItems, setCheckedItems] = useState(() => {
    const initial = {};
    if (summary?.workflowChecklist?.length) {
      summary.workflowChecklist.forEach((item) => {
        initial[item.title] = getChecklistState(item.title, checklistScope);
      });
    }
    return initial;
  });

  const checklistProgress = useMemo(
    () => getChecklistProgress(checklistItems, checklistScope),
    [checklistItems, checkedItems, checklistScope]
  );

  useEffect(() => {
    const initial = {};
    checklistItems.forEach((item) => {
      const nextValue = Boolean(item.completed || getChecklistState(item.title, checklistScope));
      initial[item.title] = nextValue;
      if (nextValue && !getChecklistState(item.title, checklistScope)) {
        setChecklistState(item.title, true, checklistScope);
      }
    });
    setCheckedItems(initial);
  }, [checklistItems, checklistScope]);

  if (!summary) {
    return null;
  }

  const { overallScore, balanceScore, fairnessScore, timeRisk, scheduleRisk, issueCounts, bullets, explanation, nextActions } =
    summary;

  const handleChecklistToggle = (title) => {
    const nextValue = !checkedItems[title];
    setCheckedItems((prev) => ({ ...prev, [title]: nextValue }));
    setChecklistState(title, nextValue, checklistScope);
  };

  return (
    <Box
      sx={{
        p: 2,
        borderRadius: 2,
        border: "1px solid",
        borderColor: "divider",
        bgcolor: "background.paper",
      }}
    >
      <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1.5 }}>
        <SmartToyIcon color="primary" />
        <Typography variant="h6" fontWeight={700}>
          AI đánh giá giải đấu hiện tại: {overallScore}/100
        </Typography>
      </Stack>

      <LinearProgress
        variant="determinate"
        value={overallScore}
        sx={{ mb: 2, height: 8, borderRadius: 1 }}
      />

      <Stack direction="row" spacing={1} flexWrap="wrap" useFlexGap sx={{ mb: 1.5 }}>
        <Chip size="small" label={`Cân bằng: ${balanceScore}`} />
        <Chip size="small" label={`Công bằng: ${fairnessScore}`} />
        <Chip size="small" color={timeRisk > 0 ? "warning" : "default"} label={`Rủi ro thời gian: ${timeRisk}`} />
        <Chip size="small" color={scheduleRisk > 0 ? "warning" : "default"} label={`Rủi ro lịch: ${scheduleRisk}`} />
        {summary?.phaseLabel && (
          <Chip size="small" color={summary.phase === "live" ? "warning" : summary.phase === "review" ? "info" : "success"} label={summary.phaseLabel} />
        )}
        {issueCounts?.critical > 0 && (
          <Chip size="small" color="error" label={`${issueCounts.critical} critical`} />
        )}
        {issueCounts?.warning > 0 && (
          <Chip size="small" color="warning" label={`${issueCounts.warning} warning`} />
        )}
      </Stack>

      {summary?.phaseHint && (
        <Box sx={{ mb: 1.5, p: 1, borderRadius: 1.5, bgcolor: "grey.50", border: "1px solid", borderColor: "divider" }}>
          <Typography variant="body2" color="text.secondary">
            {summary.phaseHint}
          </Typography>
        </Box>
      )}

      {summary?.matchProgress && summary.matchProgress.totalMatches > 0 && (
        <Box sx={{ mb: 1.5, p: 1.25, borderRadius: 1.5, bgcolor: "info.50", border: "1px solid", borderColor: "info.100" }}>
          <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.5 }}>
            <Typography variant="subtitle2" fontWeight={700} color="info.dark">
              Tiến độ trận đang diễn ra
            </Typography>
            <Typography variant="body2" color="info.dark" fontWeight={700}>
              {summary.matchProgress.label}
            </Typography>
          </Stack>
          <LinearProgress
            variant="determinate"
            value={summary.matchProgress.percent}
            color="info"
            sx={{ height: 8, borderRadius: 1 }}
          />
          <Typography variant="body2" color="text.secondary" sx={{ mt: 0.75 }}>
            Hoàn thành {summary.matchProgress.completedMatches} / {summary.matchProgress.totalMatches} trận, đang có {summary.matchProgress.activeMatches} trận đang chạy.
          </Typography>
        </Box>
      )}

      {explanation && (
        <Box sx={{ mb: 1.5, p: 1.25, borderRadius: 1.5, bgcolor: "primary.50", border: "1px solid", borderColor: "primary.100" }}>
          <Typography variant="subtitle2" fontWeight={700} color="primary" sx={{ mb: 0.5 }}>
            Vì sao AI đưa ra đánh giá này
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {explanation}
          </Typography>
        </Box>
      )}

      {nextActions?.length > 0 && (
        <Box sx={{ mb: 1.5 }}>
          <Typography variant="subtitle2" fontWeight={700} sx={{ mb: 0.75 }}>
            Hành động tiếp theo
          </Typography>
          <Stack direction="row" spacing={1} flexWrap="wrap" useFlexGap>
            {nextActions.map((action) => (
              <Chip key={action} size="small" color="primary" variant="outlined" label={action} />
            ))}
          </Stack>
        </Box>
      )}

      {checklistItems.length > 0 && (
        <Box sx={{ mb: 1.5 }}>
          <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.75 }}>
            <Typography variant="subtitle2" fontWeight={700}>
              Checklist vận hành giải
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {checklistProgress.completed}/{checklistProgress.total} hoàn thành
            </Typography>
          </Stack>
          <LinearProgress
            variant="determinate"
            value={checklistProgress.percent}
            sx={{ mb: 1, height: 8, borderRadius: 1 }}
          />
          <Stack spacing={1}>
            {checklistItems.map((item) => {
              const checked = Boolean(item.completed || checkedItems[item.title]);
              return (
                <Box key={item.title} sx={{ p: 1, borderRadius: 1, bgcolor: checked ? "success.50" : "grey.50", border: "1px solid", borderColor: checked ? "success.100" : "divider" }}>
                  <Stack direction="row" spacing={1} alignItems="flex-start">
                    <Checkbox checked={checked} onChange={() => handleChecklistToggle(item.title)} size="small" />
                    <Box sx={{ flexGrow: 1 }}>
                      <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 0.25, flexWrap: "wrap" }}>
                        <Typography variant="body2" fontWeight={700} sx={{ textDecoration: checked ? "line-through" : "none" }}>
                          {item.title}
                        </Typography>
                        {item.status === "completed" ? (
                          <Chip size="small" color="success" label="Hoàn thành" />
                        ) : item.status === "active" ? (
                          <Chip size="small" color="warning" label="Đang chạy" />
                        ) : (
                          <Chip size="small" color="default" label="Chờ thực hiện" />
                        )}
                        {item.priority === "high" ? (
                          <Chip size="small" color="error" label="Ưu tiên cao" />
                        ) : item.priority === "medium" ? (
                          <Chip size="small" color="warning" label="Ưu tiên vừa" />
                        ) : (
                          <Chip size="small" color="default" label="Ưu tiên thấp" />
                        )}
                        {item.recommended && !checked && (
                          <Chip size="small" color="primary" label="Đề xuất tiếp theo" />
                        )}
                      </Stack>
                      <Typography variant="body2" color="text.secondary" sx={{ textDecoration: checked ? "line-through" : "none" }}>
                        {item.description}
                      </Typography>
                    </Box>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Box>
      )}

      <Stack component="ul" spacing={0.5} sx={{ m: 0, pl: 2 }}>
        {(bullets || []).map((line) => (
          <Typography key={line} component="li" variant="body2" color="text.secondary">
            {line}
          </Typography>
        ))}
      </Stack>
    </Box>
  );
}

import { useCallback, useEffect, useState } from "react";
import {
  Alert,
  Box,
  FormControl,
  InputLabel,
  MenuItem,
  Select,
  Stack,
  Typography,
} from "@mui/material";
import SmartToyIcon from "@mui/icons-material/SmartToy";

import {
  GROUP_SUGGESTION_MODE,
  PAIRING_STRATEGY,
  applyAiSuggestion,
  dismissAiSuggestion,
  generateGroupSuggestion,
  generatePairingSuggestion,
  generateRuleSuggestions,
  generateSeedSuggestion,
  getAiTournamentSummary,
  predictTournamentTime,
  validateTournamentSchedule,
} from "../../../features/ai-assistant/index.js";
import { hydrateSuggestionsFromCloud, hydrateChecklistFromCloud } from "../../../features/ai-assistant/services/aiSuggestionStorage.js";
import AiSummaryCard from "./AiSummaryCard.jsx";
import AiSuggestionCard from "./AiSuggestionCard.jsx";

const GROUP_MODE_OPTIONS = [
  { value: GROUP_SUGGESTION_MODE.MANUAL_REVIEW, label: "Manual — chỉ cảnh báo" },
  { value: GROUP_SUGGESTION_MODE.LIGHT_RANDOM, label: "Random có điều kiện nhẹ" },
  { value: GROUP_SUGGESTION_MODE.COMPETITIVE_BALANCED, label: "Competitive Balanced" },
];

const PAIRING_OPTIONS = [
  { value: PAIRING_STRATEGY.BALANCED, label: "Cân bằng sức mạnh" },
  { value: PAIRING_STRATEGY.SAME_LEVEL, label: "Cùng trình độ" },
  { value: PAIRING_STRATEGY.MIXED_GENDER, label: "Nam + nữ" },
  { value: PAIRING_STRATEGY.AVOID_REPEAT, label: "Tránh lặp partner" },
  { value: PAIRING_STRATEGY.LIGHT_RANDOM, label: "Random có điều kiện" },
];

export default function TournamentAiAssistantPanel({
  tournamentId,
  clubId,
  tenantId,
  players = [],
  courts = [],
  userId = "",
  onApplied,
}) {
  const [summary, setSummary] = useState(null);
  const [canApply, setCanApply] = useState(true);
  const [viewOnly, setViewOnly] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const [seedResult, setSeedResult] = useState(null);
  const [pairingResult, setPairingResult] = useState(null);
  const [groupResult, setGroupResult] = useState(null);
  const [timeResult, setTimeResult] = useState(null);
  const [scheduleResult, setScheduleResult] = useState(null);
  const [ruleResult, setRuleResult] = useState(null);

  const [groupMode, setGroupMode] = useState(GROUP_SUGGESTION_MODE.COMPETITIVE_BALANCED);
  const [pairingStrategy, setPairingStrategy] = useState(PAIRING_STRATEGY.BALANCED);

  const baseOptions = { clubId, players, courts };

  const refreshSummary = useCallback(async () => {
    await hydrateSuggestionsFromCloud(tournamentId, tenantId);
    await hydrateChecklistFromCloud(tournamentId, tenantId);
    const result = await getAiTournamentSummary(tournamentId, tenantId, baseOptions);
    if (!result.ok) {
      setError(result.error || "Không thể tải tổng quan AI.");
      return;
    }
    setSummary(result.summary);
    setCanApply(result.canApply);
    setViewOnly(result.viewOnly);
    setError("");
  }, [tournamentId, tenantId, clubId, players, courts]);

  useEffect(() => {
    void refreshSummary();
  }, [refreshSummary]);

  useEffect(() => {
    const onCloudError = (event) => {
      setError(event?.detail?.error || "Lưu gợi ý cloud thất bại.");
    };
    window.addEventListener("ai-suggestion:cloud-error", onCloudError);
    return () => window.removeEventListener("ai-suggestion:cloud-error", onCloudError);
  }, []);

  const runAction = async (fn, setter) => {
    setLoading(true);
    setError("");
    const result = await fn();
    setLoading(false);
    if (!result.ok) {
      setError(result.error || "Lỗi AI.");
      return;
    }
    setter(result);
  };

  const handleApply = async (suggestionId) => {
    setLoading(true);
    const result = await applyAiSuggestion(suggestionId, tenantId, userId, {
      ...baseOptions,
      tournamentId,
    });
    setLoading(false);
    if (!result.ok) {
      setError(result.error || "Không thể áp dụng đề xuất.");
      return;
    }
    onApplied?.(result.tournament);
    refreshSummary();
  };

  const handleDismiss = async (suggestionId) => {
    setLoading(true);
    const result = await dismissAiSuggestion(suggestionId, tenantId, userId, {
      ...baseOptions,
      tournamentId,
    });
    setLoading(false);
    if (!result.ok) {
      setError(result.error || "Không thể bỏ qua đề xuất.");
    }
  };

  if (viewOnly) {
    return (
      <Alert severity="info" sx={{ mb: 2 }}>
        Chế độ trọng tài — chỉ xem cảnh báo, không được Apply đề xuất.
      </Alert>
    );
  }

  return (
    <Stack spacing={2}>
      <Stack direction="row" spacing={1} alignItems="center">
        <SmartToyIcon color="primary" />
        <Typography variant="h6" fontWeight={700}>
          AI Assistant
        </Typography>
      </Stack>

      {error && <Alert severity="error">{error}</Alert>}

      <AiSummaryCard summary={summary} tenantId={tenantId} tournamentId={tournamentId} />

      <Section title="Đề xuất hạt giống">
        <AiSuggestionCard
          title="Xếp hạt giống"
          impact={seedResult?.confidence}
          reasons={
            seedResult?.data?.seeds?.slice(0, 3).map(
              (s) => `#${s.seedRank} — điểm ${s.aiScore} (${s.confidence}): ${s.reasons?.[0] || ""}`
            ) || ["Phân tích ELO, trình độ và lịch sử để đề xuất hạt giống."]
          }
          warnings={seedResult?.warnings}
          explanation={seedResult?.data?.explanation}
          actionPlan={seedResult?.data?.seeds?.[0]?.actionPlan}
          canApply={canApply}
          loading={loading}
          previewContent={
            seedResult?.data?.seeds?.length ? (
              <Stack spacing={0.5}>
                {seedResult.data.seeds.map((s) => (
                  <Typography key={s.playerId} variant="body2">
                    #{s.seedRank} — {s.playerId} — {s.aiScore} pts ({s.confidence})
                  </Typography>
                ))}
              </Stack>
            ) : null
          }
          onPreview={() =>
            runAction(
              () => generateSeedSuggestion(tournamentId, tenantId, baseOptions),
              setSeedResult
            )
          }
          onApply={() => seedResult?.suggestionId && handleApply(seedResult.suggestionId)}
          onDismiss={() => seedResult?.suggestionId && handleDismiss(seedResult.suggestionId)}
        />
      </Section>

      <Section title="Đề xuất ghép cặp">
        <FormControl size="small" sx={{ mb: 1, minWidth: 220 }}>
          <InputLabel>Chiến lược</InputLabel>
          <Select
            value={pairingStrategy}
            label="Chiến lược"
            onChange={(e) => setPairingStrategy(e.target.value)}
          >
            {PAIRING_OPTIONS.map((opt) => (
              <MenuItem key={opt.value} value={opt.value}>
                {opt.label}
              </MenuItem>
            ))}
          </Select>
        </FormControl>
        <AiSuggestionCard
          title="Ghép cặp / đội"
          impact={pairingResult?.data?.fairnessScore ? `Fairness ${pairingResult.data.fairnessScore}` : null}
          reasons={[pairingResult?.data?.explanation || "Đề xuất ghép cặp theo chiến lược đã chọn."]}
          warnings={pairingResult?.warnings}
          explanation={pairingResult?.data?.explanation}
          actionPlan={pairingResult?.data?.teams?.[0]?.actionPlan}
          canApply={canApply}
          loading={loading}
          previewContent={
            pairingResult?.data?.teams?.length ? (
              <Stack spacing={0.5}>
                {pairingResult.data.teams.map((team) => (
                  <Typography key={team.playerIds.join("-")} variant="body2">
                    {team.playerIds.join(" + ")} — {Math.round(team.combinedScore)}
                  </Typography>
                ))}
              </Stack>
            ) : null
          }
          onPreview={() =>
            runAction(
              () =>
                generatePairingSuggestion(
                  tournamentId,
                  tenantId,
                  pairingStrategy,
                  baseOptions
                ),
              setPairingResult
            )
          }
          onApply={() => pairingResult?.suggestionId && handleApply(pairingResult.suggestionId)}
          onDismiss={() => pairingResult?.suggestionId && handleDismiss(pairingResult.suggestionId)}
        />
      </Section>

      <Section title="Đề xuất chia bảng">
        <FormControl size="small" sx={{ mb: 1, minWidth: 220 }}>
          <InputLabel>Chế độ</InputLabel>
          <Select value={groupMode} label="Chế độ" onChange={(e) => setGroupMode(e.target.value)}>
            {GROUP_MODE_OPTIONS.map((opt) => (
              <MenuItem key={opt.value} value={opt.value}>
                {opt.label}
              </MenuItem>
            ))}
          </Select>
        </FormControl>
        <AiSuggestionCard
          title="Chia bảng"
          impact={groupResult?.data?.overallBalanceScore ? `Balance ${groupResult.data.overallBalanceScore}` : null}
          reasons={[groupResult?.data?.explanation || "Phân tích cân bằng sức mạnh giữa các bảng."]}
          warnings={groupResult?.warnings}
          explanation={groupResult?.data?.explanation}
          actionPlan={groupResult?.data?.groups?.[0]?.actionPlan}
          canApply={canApply && groupMode !== GROUP_SUGGESTION_MODE.MANUAL_REVIEW}
          loading={loading}
          previewContent={
            groupResult?.data?.groups?.length ? (
              <Stack spacing={0.5}>
                {groupResult.data.groups.map((g) => (
                  <Typography key={g.groupName} variant="body2">
                    {g.groupName}: {g.teamIds.length} đội — TB {g.averageElo}
                  </Typography>
                ))}
              </Stack>
            ) : null
          }
          onPreview={() =>
            runAction(
              () => generateGroupSuggestion(tournamentId, tenantId, groupMode, baseOptions),
              setGroupResult
            )
          }
          onApply={() => groupResult?.suggestionId && handleApply(groupResult.suggestionId)}
          onDismiss={() => groupResult?.suggestionId && handleDismiss(groupResult.suggestionId)}
        />
      </Section>

      <Section title="Dự đoán thời gian">
        <AiSuggestionCard
          title="Thời gian giải"
          impact={timeResult?.data?.reasonableTotalMinutes ? `${timeResult.data.reasonableTotalMinutes} phút` : null}
          reasons={[timeResult?.data?.explanation || "Ước tính dựa trên số trận, sân và luật điểm."]}
          warnings={timeResult?.warnings}
          explanation={timeResult?.data?.explanation}
          actionPlan={timeResult?.data?.actionPlan}
          canApply={false}
          loading={loading}
          previewContent={
            timeResult?.data ? (
              <Stack spacing={0.5}>
                <Typography variant="body2">Trận: {timeResult.data.totalMatches}</Typography>
                <Typography variant="body2">TB/trận: {timeResult.data.averageMatchMinutes} phút</Typography>
                <Typography variant="body2">Tối thiểu: {timeResult.data.minTotalMinutes} phút</Typography>
                <Typography variant="body2">Hợp lý: {timeResult.data.reasonableTotalMinutes} phút</Typography>
                <Typography variant="body2">Rủi ro trễ: {timeResult.data.riskTotalMinutes} phút</Typography>
                <Typography variant="body2">Kết thúc dự kiến: {timeResult.data.estimatedFinishTime}</Typography>
              </Stack>
            ) : null
          }
