            summarySubtitle={payload.subtitle}
            onComplete={onPreludeComplete}
            onSkip={onPreludeComplete}
            onExit={onFlowExit || onDismiss}
          />
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <Dialog
      open={Boolean(open && Component)}
      onClose={guidedBracketReview ? undefined : onDismiss}
