            animationMode={animationMode}
            flowMode={flowMode}
            bracketReviewMode={bracketReviewMode}
            onAnimationComplete={onAnimationComplete}
            onSkip={onSkip}
            onStepComplete={onStepComplete}
            onFlowExit={onFlowExit || onDismiss}
            onViewSchedule={onDismiss}
            {...payload}
            {...boardProps}
          />
        ) : null}
      </DialogContent>
    </Dialog>
