import { DEFAULT_SKILL_LEVEL_RULES } from "../ai/config.js";
import {
  getPlayerCurrentRating,
  normalizePlayers,
  syncCurrentRatingMirrors,
  syncSkillLevelMirrors,
} from "../models/player.js";
import { snapPickVnRating, PICK_VN_MIN, PICK_VN_MAX } from "../features/pick-vn-rating/constants/pickVnRatingScale.js";
import { RATING_STATUS } from "../features/pick-vn-rating/constants/ratingStatus.js";
import { migratePlayerRatingFields } from "../features/pick-vn-rating/models/pickVnRating.js";
import { verifyAdminPlayerRating } from "../features/pick-vn-rating/services/ratingVerificationService.js";
import { listClubs } from "./clubService.js";
import { loadClubData, saveClubData } from "./clubStorage.js";
import { getSkillLevelRules } from "./skillLevelService.js";

export const CHANGE_REQUEST_STATUS = Object.freeze({
  PENDING: "pending",
  APPROVED: "approved",
  REJECTED: "rejected",
});

function toLevel(value, fallback = 3.5) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function clampLevel(value, rules = DEFAULT_SKILL_LEVEL_RULES) {
  const min = Number(rules.minLevel) || PICK_VN_MIN;
  const max = Number(rules.maxLevel) || PICK_VN_MAX;
  return snapPickVnRating(Math.min(max, Math.max(min, toLevel(value))));
}

export function normalizeSkillLevelChangeRequest(request) {
  if (!request || request.id == null) {
    return null;
  }

  return {
    id: String(request.id),
    clubId: String(request.clubId || ""),
    playerId: request.playerId,
    playerName: request.playerName ? String(request.playerName) : "",
    currentLevel: toLevel(request.currentLevel),
    requestedLevel: toLevel(request.requestedLevel),
    reason: request.reason ? String(request.reason).trim() : "",
    status: Object.values(CHANGE_REQUEST_STATUS).includes(request.status)
      ? request.status
      : CHANGE_REQUEST_STATUS.PENDING,
    requestedBy: request.requestedBy ? String(request.requestedBy) : null,
    requestedAt: request.requestedAt ? String(request.requestedAt) : null,
    reviewedBy: request.reviewedBy ? String(request.reviewedBy) : null,
    reviewedAt: request.reviewedAt ? String(request.reviewedAt) : null,
    reviewNote: request.reviewNote ? String(request.reviewNote) : "",
  };
}

function getClubChangeRequests(clubData) {
  return (clubData?.skillLevelChangeRequests || [])
    .map((item) => normalizeSkillLevelChangeRequest(item))
    .filter(Boolean);
}

export function setInitialSkillLevel(player, level, lockedAt = new Date().toISOString()) {
  if (!player) {
    return null;
  }

  if (player.skillLevelLockedAt) {
    return player;
  }

  const skillLevel = clampLevel(level);
  const base = {
    ...player,
    ...syncSkillLevelMirrors(player, skillLevel),
    skillLevelLockedAt: lockedAt,
  };
  return {
    ...base,
    ...migratePlayerRatingFields({
      ...base,
      self_declared_rating: skillLevel,
      current_rating: skillLevel,
      rating_status: RATING_STATUS.SELF_DECLARED,
      rating_confidence: 0.2,
      last_rating_updated_at: lockedAt,
    }),
  };
}

export function applySkillLevelValue(player, level, options = {}) {
  const skillLevel = clampLevel(level, options.rules);
  const now = options.lockedAt || new Date().toISOString();
  const base = {
    ...player,
    ...syncCurrentRatingMirrors(skillLevel),
    ratingInternal: player?.ratingInternal ?? skillLevel,
  };

  if (options.lock && !player.skillLevelLockedAt) {
    base.skillLevelLockedAt = now;
  }

  const status = options.ratingStatus || RATING_STATUS.ADMIN_VERIFIED;
  return {
    ...base,
    ...migratePlayerRatingFields({
      ...base,
      verified_rating: skillLevel,
      current_rating: skillLevel,
      rating_status: status,
      rating_verified_by: options.verifiedBy || null,
      rating_verification_note: options.note || "",
      last_rating_updated_at: now,
    }),
  };
}

export function listSkillLevelChangeRequests(clubId, options = {}) {
  const data = loadClubData(clubId);
  const requests = getClubChangeRequests(data);
  const status = options.status ? String(options.status) : null;

  if (!status) {
    return requests;
  }

  return requests.filter((item) => item.status === status);
}

export function listPendingSkillLevelChangeRequests(options = {}) {
  const clubFilter = options.clubId ? [options.clubId] : listClubs().map((club) => club.id);
  const rows = [];

  clubFilter.forEach((clubId) => {
    listSkillLevelChangeRequests(clubId, { status: CHANGE_REQUEST_STATUS.PENDING }).forEach(
      (request) => {
        rows.push({
          ...request,
          clubId,
          clubName: listClubs().find((club) => club.id === clubId)?.name || clubId,
        });
      }
    );
  });

  return rows.sort((a, b) => String(b.requestedAt).localeCompare(String(a.requestedAt)));
}

export function getPlayerPendingSkillLevelRequest(clubId, playerId) {
  return listSkillLevelChangeRequests(clubId, { status: CHANGE_REQUEST_STATUS.PENDING }).find(
    (item) => String(item.playerId) === String(playerId)
  ) || null;
}

export function submitSkillLevelChangeRequest(
  clubId,
  playerId,
  requestedLevel,
  { reason = "", requestedBy = null } = {}
) {
  const trimmedReason = String(reason || "").trim();
  if (!trimmedReason) {
    return { ok: false, error: "Vui lòng nhập lý do thay đổi trình độ." };
  }

  const data = loadClubData(clubId);
  const rules = getSkillLevelRules(clubId);
  const playerIndex = (data.players || []).findIndex(
    (item) => String(item.id) === String(playerId)
  );

  if (playerIndex < 0) {
    return { ok: false, error: "Không tìm thấy vận động viên." };
  }

  const player = data.players[playerIndex];
  if (!player.skillLevelLockedAt) {
    return { ok: false, error: "Điểm trình độ chưa được khóa." };
  }

  const currentLevel = getPlayerCurrentRating(player);
  const nextLevel = clampLevel(requestedLevel, rules);

  if (nextLevel === currentLevel) {
    return { ok: false, error: "Điểm trình độ mới phải khác điểm hiện tại." };
  }

  const existingPending = getPlayerPendingSkillLevelRequest(clubId, playerId);
  if (existingPending) {
    return { ok: false, error: "Đã có yêu cầu đang chờ duyệt." };
  }

  const now = new Date().toISOString();
  const request = normalizeSkillLevelChangeRequest({
    id: `slcr-${Date.now()}-${playerId}`,
    clubId,
    playerId,
    playerName: player.name,
    currentLevel,
    requestedLevel: nextLevel,
    reason: trimmedReason,
    status: CHANGE_REQUEST_STATUS.PENDING,
    requestedBy,
    requestedAt: now,
  });

  data.skillLevelChangeRequests = [...getClubChangeRequests(data), request];
  data.updatedAt = now;
  saveClubData(clubId, data);

  return { ok: true, request };
}

function findRequestInClub(clubId, requestId) {
  const data = loadClubData(clubId);
  const requests = getClubChangeRequests(data);
  const index = requests.findIndex((item) => String(item.id) === String(requestId));

  return { data, requests, index, request: index >= 0 ? requests[index] : null };
}

export function approveSkillLevelChangeRequest(
  clubId,
  requestId,
  { reviewedBy = null, reviewNote = "" } = {}
) {
  const { data, requests, index, request } = findRequestInClub(clubId, requestId);

  if (!request) {
    return { ok: false, error: "Không tìm thấy yêu cầu." };
  }

  if (request.status !== CHANGE_REQUEST_STATUS.PENDING) {
    return { ok: false, error: "Yêu cầu đã được xử lý." };
  }

  const playerIndex = (data.players || []).findIndex(
    (item) => String(item.id) === String(request.playerId)
  );

  if (playerIndex < 0) {
    return { ok: false, error: "Không tìm thấy vận động viên." };
  }

  const reviewedAt = new Date().toISOString();
  const verifyResult = verifyAdminPlayerRating(clubId, request.playerId, request.requestedLevel, {
    verifiedBy: reviewedBy,
    note: reviewNote ? String(reviewNote).trim() : "",
    authUserId: data.players[playerIndex]?.authUserId || null,
  });

  if (!verifyResult.ok) {
    return verifyResult;
  }

  const refreshed = loadClubData(clubId);
  const refreshedRequests = getClubChangeRequests(refreshed);
  const refreshedIndex = refreshedRequests.findIndex(
    (item) => String(item.id) === String(requestId)
  );

  if (refreshedIndex < 0) {
    return { ok: false, error: "Không tìm thấy yêu cầu sau khi cập nhật." };
  }

  refreshedRequests[refreshedIndex] = {
    ...request,
    status: CHANGE_REQUEST_STATUS.APPROVED,
    reviewedBy,
    reviewedAt,
    reviewNote: reviewNote ? String(reviewNote).trim() : "",
  };

  refreshed.skillLevelChangeRequests = refreshedRequests;
  refreshed.updatedAt = reviewedAt;
  saveClubData(clubId, refreshed);

  return {
    ok: true,
    request: refreshedRequests[refreshedIndex],
    player: verifyResult.player,
  };
}

export function rejectSkillLevelChangeRequest(
  clubId,
  requestId,
  { reviewedBy = null, reviewNote = "" } = {}
) {
  const { data, requests, index, request } = findRequestInClub(clubId, requestId);

  if (!request) {
    return { ok: false, error: "Không tìm thấy yêu cầu." };
  }

  if (request.status !== CHANGE_REQUEST_STATUS.PENDING) {
    return { ok: false, error: "Yêu cầu đã được xử lý." };
  }

  const reviewedAt = new Date().toISOString();
  requests[index] = {
    ...request,
    status: CHANGE_REQUEST_STATUS.REJECTED,
    reviewedBy,
    reviewedAt,
    reviewNote: reviewNote ? String(reviewNote).trim() : "",
  };

  data.skillLevelChangeRequests = requests;
  data.updatedAt = reviewedAt;
  saveClubData(clubId, data);

  return { ok: true, request: requests[index] };
}

import { useCallback, useEffect, useMemo, useState } from "react";

import { useAuth } from "../../../context/AuthContext.jsx";
import { useTenant } from "../../../context/TenantContext.jsx";
import { getPlanCatalog } from "../constants/billingConstants.js";
import {
  BILLING_PERSIST_SETS,
  ensureBillingStoreHydrated,
  flushBillingStoreDirty,
  isSupabaseBillingStore,
  persistBillingCollections,
  resetBillingStoreHydration,
} from "../repositories/billingStoreRuntime.js";
import { getBillingStore } from "../repositories/billingRepository.js";
import {
  formatBillingTenantError,
  resolveBillingTenantId,
  sanitizeBillingTenantId,
} from "../services/billingTenantResolver.js";
import { validateBillingTenantOnSupabase } from "../services/billingVenueService.js";
import { ensureTrialSubscriptionRpc } from "../services/billingTrialRpc.js";
import { BillingEngine } from "../services/billingEngine.js";
import { InvoiceService } from "../services/invoiceService.js";
import { PaymentService } from "../services/paymentService.js";
import { PlanLimitService } from "../services/planLimitService.js";
import { SubscriptionService } from "../services/subscriptionService.js";
import { TenantAccessService } from "../services/tenantAccessService.js";

function buildServices(store) {
  const subscriptionService = new SubscriptionService({ store });
  const invoiceService = new InvoiceService({ store });
  const paymentService = new PaymentService({ store, subscriptionService, invoiceService });
  const planLimitService = new PlanLimitService({ store });
  const tenantAccessService = new TenantAccessService({ store });
  const engine = new BillingEngine({
    store,
    subscriptionService,
    invoiceService,
    paymentService,
  });

  return {
    subscriptionService,
    invoiceService,
    paymentService,
    planLimitService,
    tenantAccessService,
    engine,
  };
}

export function useBilling({ tenantId: tenantIdOverride } = {}) {
  const { user } = useAuth();
  const { currentTenantId } = useTenant();
  const tenantId = resolveBillingTenantId({
    user,
    tenantIdOverride,
    currentTenantId,
  });
  const [refreshKey, setRefreshKey] = useState(0);
  const [hydrateState, setHydrateState] = useState({
    loading: false,
    ready: false,
    error: null,
  });
  const [persistError, setPersistError] = useState(null);

  const store = useMemo(() => getBillingStore(), []);
  const services = useMemo(() => buildServices(store), [store, refreshKey]);
  const {
    subscriptionService,
    invoiceService,
    paymentService,
    planLimitService,
    tenantAccessService,
    engine,
  } = services;

  const refresh = useCallback(() => setRefreshKey((value) => value + 1), []);

  const persistChanges = useCallback(
    async (collections = []) => {
      if (!isSupabaseBillingStore(store)) {
        return { ok: true, errors: [] };
      }

      const result = collections.length
        ? await persistBillingCollections(store, collections)
        : await flushBillingStoreDirty(store);

      if (!result.ok) {
        setPersistError(result.errors?.[0]?.message || "Không thể lưu billing lên Supabase.");
      } else {
        setPersistError(null);
      }

      return result;
    },
    [store]
  );

  const runMutation = useCallback(
    async (mutationFn, collections = []) => {
      const result = mutationFn();
      await persistChanges(collections);
      refresh();
      return result;
    },
    [persistChanges, refresh]
  );

  useEffect(() => {
    let cancelled = false;

    async function bootstrap() {
      const runtime = buildServices(store);

      if (isSupabaseBillingStore(store)) {
        setHydrateState({ loading: true, ready: false, error: null });
        // Auth/session may finish after first layout mount — refetch billing once user+tenant exist.
        if (user?.id && tenantId) {
          resetBillingStoreHydration(store);
        }
        const hydrated = await ensureBillingStoreHydrated(store);
        if (cancelled) {
          return;
        }
        if (!hydrated.ok) {
          setHydrateState({
            loading: false,
            ready: false,
            error: hydrated.error || "Không thể tải dữ liệu billing từ Supabase.",
          });
          return;
        }
      } else {
        runtime.engine.seedDefaults();
      }

      if (cancelled) {
        return;
      }

      if (!tenantId) {
        if (!cancelled) {
          setHydrateState({
            loading: false,
            ready: true,
            error: formatBillingTenantError({ code: "TENANT_MISSING" }),
          });
        }
        return;
      }

      if (isSupabaseBillingStore(store)) {
        const tenantValidation = await validateBillingTenantOnSupabase(store.client, tenantId);
        if (cancelled) {
          return;
        }
        if (!tenantValidation.ok) {
          setHydrateState({
            loading: false,
            ready: true,
            error: tenantValidation.error,
          });
          setPersistError(tenantValidation.error);
          return;
        }
      }

      const existing = runtime.subscriptionService.getByTenant(tenantId);
      if (!existing) {
        if (isSupabaseBillingStore(store)) {
          const trial = await ensureTrialSubscriptionRpc(store, { tenantId });
          if (trial.ok) {
            try {
              await store.hydrate("subscriptions");
            } catch {
              // subscription row already merged from RPC response
            }
          } else if (!cancelled) {
            setPersistError(formatBillingTenantError({ code: trial.code, message: trial.error }));
          }
        } else {
          runtime.engine.createTrialSubscription({ tenantId, ownerUserId: user?.id || null });
        }
      }

      if (cancelled) {
        return;
      }

      setHydrateState((current) =>
        current.ready && !current.loading && !current.error
          ? current
          : { loading: false, ready: true, error: null }
      );
    }

    bootstrap();

    return () => {
      cancelled = true;
    };
  }, [store, tenantId, user?.id]);

  const subscription = hydrateState.ready ? subscriptionService.getByTenant(tenantId) : null;
  const planCode = subscription?.plan_code || "TRIAL";
  const hydratedPlans = hydrateState.ready ? store.read("plans") : [];
  const planFromStore = hydratedPlans.find((item) => item.code === planCode);
  const plan = planFromStore || getPlanCatalog().find((item) => item.code === planCode) || getPlanCatalog()[0];
  const access = hydrateState.ready
    ? tenantAccessService.evaluateAccess({ tenantId })
    : { allowed: true, lockLevel: "none", reason: "loading" };
  const invoices = hydrateState.ready ? invoiceService.listByTenant(tenantId) : [];
  const payments = hydrateState.ready ? paymentService.listByTenant(tenantId) : [];
  const usageSummary = hydrateState.ready
    ? planLimitService.getUsageSummary({
        planCode,
        usage: { courts: 4, clubs: 1, players: 10, bookings: 5, tournaments: 0 },
      })
    : [];

  return {
    tenantId,
    store,
    storeMode: store.mode || "local",
    engine,
    subscriptionService,
    invoiceService,
    paymentService,
    planLimitService,
    tenantAccessService,
    subscription,
    plan,
    planCatalog: hydrateState.ready && hydratedPlans.length ? hydratedPlans : getPlanCatalog(),
    access,
    invoices,
    payments,
    usageSummary,
    billingLoading: hydrateState.loading || !hydrateState.ready,
    billingError: hydrateState.error,
    persistError,
    refresh,
    persistChanges,
    changePlan: (nextPlanCode) =>
      runMutation(() => {
        if (!subscription) return null;
        return engine.changePlan(subscription.id, nextPlanCode, { actorUserId: user?.id });
      }, BILLING_PERSIST_SETS.PLAN_CHANGE),
    createInvoice: (amount) =>
      runMutation(() => {
        return invoiceService.createInvoice({
          tenantId,
          subscriptionId: subscription?.id,
          amount,
          currency: plan.currency,
          actorUserId: user?.id,
        });
      }, BILLING_PERSIST_SETS.INVOICE),
    recordManualPayment: async (amount) => {
      const invoice = invoiceService.createInvoice({
        tenantId,
        subscriptionId: subscription?.id,
        amount,
        currency: plan.currency,
        actorUserId: user?.id,
      });
      await paymentService.createPaymentIntent({
        tenantId,
        invoiceId: invoice.id,
        provider: "manual",
        amount,
        currency: plan.currency,
      });
      paymentService.handleProviderSuccess({
        paymentId: paymentService.listByTenant(tenantId).at(-1)?.id,
        actorUserId: user?.id,
      });
      await persistChanges(BILLING_PERSIST_SETS.PAYMENT);
      refresh();
      return invoice;
    },
    requestCancel: () =>
      runMutation(() => {
        if (!subscription) return null;
        return engine.cancelSubscription(subscription.id, { actorUserId: user?.id });
      }, BILLING_PERSIST_SETS.SUBSCRIPTION),
    suspendSubscription: (subscriptionId) =>
      runMutation(
        () => engine.suspendSubscription(subscriptionId, { actorUserId: user?.id }),
        BILLING_PERSIST_SETS.SUBSCRIPTION
      ),
    unlockTenant: (targetTenantId) =>
      runMutation(
        () => engine.unlockTenant(targetTenantId, { actorUserId: user?.id }),
        BILLING_PERSIST_SETS.SUBSCRIPTION
      ),
    markInvoicePaid: (invoiceId, targetTenantId = tenantId) =>
      runMutation(() => {
        const tenantInvoice = invoiceService.getById(invoiceId);
        if (!tenantInvoice) return null;
        invoiceService.markPaid(invoiceId, { actorUserId: user?.id });
        paymentService.recordPayment({
          tenantId: targetTenantId,
          invoiceId,
          provider: "manual",
          amount: tenantInvoice.total_amount,
          currency: tenantInvoice.currency,
          status: "succeeded",
          actorUserId: user?.id,
        });
        return tenantInvoice;
      }, BILLING_PERSIST_SETS.PAYMENT),
    adminChangePlan: (subscriptionId, planCode) =>
      runMutation(
        () => engine.changePlan(subscriptionId, planCode, { actorUserId: user?.id }),
        BILLING_PERSIST_SETS.PLAN_CHANGE
      ),
    createTrialSubscription: async (targetTenantId) => {
      const resolvedTenantId = sanitizeBillingTenantId(targetTenantId || tenantId);
      if (!resolvedTenantId) {
        return {
          ok: false,
          code: "TENANT_MISSING",
          error: formatBillingTenantError({ code: "TENANT_MISSING" }),
        };
      }

      if (isSupabaseBillingStore(store)) {
        const tenantValidation = await validateBillingTenantOnSupabase(store.client, resolvedTenantId);
        if (!tenantValidation.ok) {
          setPersistError(tenantValidation.error);
          return {
            ok: false,
            code: tenantValidation.code,
            error: tenantValidation.error,
          };
        }
      }

      if (isSupabaseBillingStore(store)) {
        const trial = await ensureTrialSubscriptionRpc(store, { tenantId: resolvedTenantId });
        if (trial.ok) {
          try {
            await store.hydrate("subscriptions");
          } catch {
            // non-fatal
          }
          refresh();
          setPersistError(null);
        } else {
          setPersistError(formatBillingTenantError({ code: trial.code, message: trial.error }));
        }
        return trial;
      }

      const created = engine.createTrialSubscription({
        tenantId: resolvedTenantId,
        ownerUserId: user?.id || null,
      });
      refresh();
      return { ok: true, subscription: created };
    },
  };
}

import { hasSupabaseConfig, getSupabaseAuthClient } from "../../../auth/supabaseClient.js";
import { createLocalStorageBillingStore } from "../services/billingStorage.js";
import { ensureCollection, writeCollection } from "../services/billingStoreUtils.js";
import { createMemoryBillingStore } from "./memoryBillingStore.js";
import { createSupabaseBillingStore } from "./supabaseBillingStore.js";
import { isSupabaseBillingStore } from "./billingStoreRuntime.js";

export const BILLING_STORE_MODES = Object.freeze({
  MEMORY: "memory",
  LOCAL: "local",
  SUPABASE: "supabase",
});

function readEnvFlag(name) {
  if (typeof import.meta !== "undefined" && import.meta.env) {
    return import.meta.env[name];
  }
  return undefined;
}

/** Resolve billing persistence mode: memory (test), supabase (production), local (dev fallback). */
export function resolveBillingStoreMode() {
  const forced = readEnvFlag("VITE_BILLING_STORE_MODE");
  if (forced && Object.values(BILLING_STORE_MODES).includes(forced)) {
    return forced;
  }

  if (readEnvFlag("NODE_ENV") === "test" || readEnvFlag("VITEST") === "true") {
    return BILLING_STORE_MODES.MEMORY;
  }

  if (hasSupabaseConfig() && readEnvFlag("VITE_BILLING_SUPABASE") !== "false") {
    return BILLING_STORE_MODES.SUPABASE;
  }

  return BILLING_STORE_MODES.LOCAL;
}

let sharedStore = null;

export function createBillingStore({ mode, storage, client, seed } = {}) {
  const resolvedMode = mode || resolveBillingStoreMode();

  switch (resolvedMode) {
    case BILLING_STORE_MODES.MEMORY:
      return createMemoryBillingStore(seed);
    case BILLING_STORE_MODES.SUPABASE: {
      const supabaseClient = client || getSupabaseAuthClient();
      if (!supabaseClient) {
        return createLocalStorageBillingStore(storage);
      }
      return createSupabaseBillingStore(supabaseClient, { cache: seed });
    }
    case BILLING_STORE_MODES.LOCAL:
    default:
      return createLocalStorageBillingStore(storage);
  }
}

/** Singleton store for app runtime (dev local / staging supabase). */
export function getBillingStore(options = {}) {
  if (!sharedStore || options.forceNew) {
    sharedStore = createBillingStore(options);
  }
  return sharedStore;
}

export function resetBillingStore() {
  sharedStore = null;
}

class CollectionRepository {
  constructor(store, collection, fallback = []) {
    this.store = store;
    this.collection = collection;
    this.fallback = fallback;
  }

  list() {
    return ensureCollection(this.store, this.collection, this.fallback);
  }

  find(predicate) {
    return this.list().find(predicate) || null;
  }

  saveAll(items) {
    return writeCollection(this.store, this.collection, items);
  }

  upsert(item) {
    const current = this.list();
    const index = current.findIndex((row) => row.id === item.id);
    const next =
      index === -1
        ? [...current, item]
        : current.map((row) => (row.id === item.id ? item : row));
    return writeCollection(this.store, this.collection, next);
  }
}

export class PlanRepository extends CollectionRepository {
  constructor(store) {
    super(store, "plans", []);
  }

  getByCode(code) {
    return this.find((plan) => plan.code === code);
  }
}

export class PlanLimitRepository extends CollectionRepository {
  constructor(store) {
    super(store, "planLimits", []);
  }

  getByPlanId(planId) {
    return this.find((limit) => limit.plan_id === planId || limit.plan_code === planId);
  }
}

export class SubscriptionRepository extends CollectionRepository {
  constructor(store) {
    super(store, "subscriptions", []);
  }

  getByTenant(tenantId) {
    return this.find((item) => item.tenant_id === tenantId);
  }
}

export class InvoiceRepository extends CollectionRepository {
  constructor(store) {
    super(store, "invoices", []);
  }

  listByTenant(tenantId) {
    return this.list().filter((item) => item.tenant_id === tenantId);
  }
}

export class PaymentRepository extends CollectionRepository {
  constructor(store) {
    super(store, "payments", []);
  }

  listByTenant(tenantId) {
    return this.list().filter((item) => item.tenant_id === tenantId);
  }
}

export class BillingAuditRepository extends CollectionRepository {
  constructor(store) {
    super(store, "billingAuditLogs", []);
  }

  listByTenant(tenantId) {
    return this.list().filter((item) => item.tenant_id === tenantId);
  }
}

export function createBillingRepositories(store = getBillingStore()) {
  return {
    store,
    plans: new PlanRepository(store),
    planLimits: new PlanLimitRepository(store),
    subscriptions: new SubscriptionRepository(store),
    invoices: new InvoiceRepository(store),
    payments: new PaymentRepository(store),
    billingAudit: new BillingAuditRepository(store),
  };
}

import { createContext, useContext, useEffect, useMemo, useRef, useState } from "react";

import { useAuth } from "../../../context/AuthContext.jsx";
import { subscribeToSupabaseAuth } from "../../../auth/authService.js";
import { clearMembershipCacheForUser, invalidateMyActiveClubMembershipCache } from "../services/clubActiveMembershipService.js";
import { invalidateAllClubRegistryCache } from "../registry/clubRegistryCache.js";
import { useMyClubMembership } from "./useMyClubMembership.js";

const MyClubMembershipContext = createContext(null);

/**
 * Phase 42J.2.1 — single app-wide membership SSOT.
 * Provider shell always mounted (no remount on route change).
 */
export function MyClubMembershipRootProvider({ children }) {
  const { isAuthenticated, user } = useAuth();
  const userId = isAuthenticated && user?.id ? user.id : null;
  const [revision, setRevision] = useState(0);
  const prevUserIdRef = useRef(null);
  const membership = useMyClubMembership(revision, userId);

  useEffect(() => {
    if (!userId) {
      if (prevUserIdRef.current) {
        clearMembershipCacheForUser(prevUserIdRef.current);
        prevUserIdRef.current = null;
      }
      return;
    }
    if (prevUserIdRef.current && prevUserIdRef.current !== userId) {
      clearMembershipCacheForUser(prevUserIdRef.current);
      setRevision((current) => current + 1);
    }
    prevUserIdRef.current = userId;
  }, [userId]);

  useEffect(() => {
    if (!userId) {
      return undefined;
    }
    return subscribeToSupabaseAuth(({ event, user: nextUser }) => {
      if (event === "SIGNED_OUT") {
        if (prevUserIdRef.current) {
          clearMembershipCacheForUser(prevUserIdRef.current);
          prevUserIdRef.current = null;
        }
        return;
      }
      if (event === "TOKEN_REFRESHED" || event === "SIGNED_IN") {
        return;
      }
      if (nextUser?.id && prevUserIdRef.current && nextUser.id !== prevUserIdRef.current) {
        clearMembershipCacheForUser(prevUserIdRef.current);
        prevUserIdRef.current = nextUser.id;
        setRevision((current) => current + 1);
      }
    });
  }, [userId]);

  const value = useMemo(() => {
    if (!userId) {
      return null;
    }
    return {
      ...membership,
      revision,
      bumpRevision: () => {
        invalidateMyActiveClubMembershipCache(userId);
        invalidateAllClubRegistryCache();
        setRevision((current) => current + 1);
      },
    };
  }, [membership, revision, userId]);

  return (
    <MyClubMembershipContext.Provider value={value}>{children}</MyClubMembershipContext.Provider>
  );
}

/** @returns {import("./useMyClubMembership.js").MyClubMembershipState & { revision: number, bumpRevision: () => void } | null} */
export function useMyClubMembershipFromContext() {
  return useContext(MyClubMembershipContext);
}

/** Required on club routes — throws if root provider missing. */
export function useRequiredMyClubMembership() {
  const value = useContext(MyClubMembershipContext);
  if (!value) {
    throw new Error("MyClubMembershipRootProvider is required for club routes.");
  }
  return value;
}

