    name: club.name,
    status: club.status,
    tenantId,
    presidentLabel,
    ownerLabel: gov.ownerLabel || null,
    activeMemberCount: activeMembers.length,
    clusterLabel: formatRegisteredClusterDisplay(clusterLabel),
  };
}

