import { useEffect, useMemo, useState } from "react";
import { Link as RouterLink } from "react-router-dom";
import {
  Box,
  Button,
  Card,
  CardContent,
  Grid,
  Stack,
  Typography,
} from "@mui/material";
import EventIcon from "@mui/icons-material/Event";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import HistoryIcon from "@mui/icons-material/History";

import {
  CLUB_ACTIVITY_DAY_LABELS,
  canApproveClubMembershipRequests,
  getTodayClubActivitySessions,
  listClubActivitySessions,
  listPendingMembershipRequests,
} from "../index.js";
import { CLUB_ROUTE_PATHS } from "../routing/clubMembershipRouteLogic.js";

/** Home dashboard insight tiles — read-only, no new RPC contracts. */
export default function MyClubHomeInsights({
  clubId,
  tenantId,
  clubRecord,
  user,
  revision = 0,
  showRequestsLink = false,
  onViewSchedule,
  onViewRequests,
}) {
  const [pendingCount, setPendingCount] = useState(0);
  const [loadingPending, setLoadingPending] = useState(false);

  const canReview =
    Boolean(clubRecord && user && canApproveClubMembershipRequests(user, clubRecord));

  useEffect(() => {
    let cancelled = false;
    if (!clubId || !user?.id || !canReview) {
      setPendingCount(0);
      return undefined;
    }
    setLoadingPending(true);
    void listPendingMembershipRequests(clubId, tenantId, user).then((rows) => {
      if (!cancelled) {
        setPendingCount(rows?.length ?? 0);
        setLoadingPending(false);
      }
    });
    return () => {
      cancelled = true;
    };
  }, [clubId, tenantId, user, clubRecord, revision, canReview]);

  const todaySessions = useMemo(() => {
    void revision;
    if (!clubId) {
      return [];
    }
    return getTodayClubActivitySessions(clubId, tenantId);
  }, [clubId, tenantId, revision]);

  const nextSession = useMemo(() => {
    void revision;
    if (!clubId) {
      return null;
    }
    const sessions = listClubActivitySessions(clubId, tenantId);
    if (!sessions.length) {
      return null;
    }
    const today = new Date().getDay();
    const sorted = [...sessions].sort((a, b) => {
      const dayA = a.dayOfWeek >= today ? a.dayOfWeek : a.dayOfWeek + 7;
      const dayB = b.dayOfWeek >= today ? b.dayOfWeek : b.dayOfWeek + 7;
      if (dayA !== dayB) {
        return dayA - dayB;
      }
      return String(a.startTime).localeCompare(String(b.startTime));
    });
    return sorted[0];
  }, [clubId, tenantId, revision]);

  const scheduleLabel = todaySessions.length
    ? `Hôm nay: ${todaySessions.length} buổi`
    : nextSession
      ? `${CLUB_ACTIVITY_DAY_LABELS[nextSession.dayOfWeek] || "Tuần"} · ${nextSession.startTime}–${nextSession.endTime}`
      : "Chưa có lịch sinh hoạt";

  return (
    <Grid container spacing={2} sx={{ mt: 0.5 }}>
      <Grid item xs={12} sm={4}>
        <Card variant="outlined" sx={{ height: "100%", borderRadius: 2 }}>
          <CardContent>
            <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1 }}>
              <EventIcon color="primary" fontSize="small" aria-hidden />
              <Typography variant="subtitle2" fontWeight={700}>
                Lịch sinh hoạt
              </Typography>
            </Stack>
            <Typography variant="body2" color="text.secondary">
              {scheduleLabel}
            </Typography>
            <Button size="small" sx={{ mt: 1, px: 0 }} onClick={onViewSchedule}>
              Xem lịch
            </Button>
          </CardContent>
        </Card>
      </Grid>

      {canReview && (
        <Grid item xs={12} sm={4}>
          <Card variant="outlined" sx={{ height: "100%", borderRadius: 2 }}>
            <CardContent>
              <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1 }}>
                <PendingActionsIcon color="warning" fontSize="small" aria-hidden />
                <Typography variant="subtitle2" fontWeight={700}>
                  Yêu cầu chờ duyệt
                </Typography>
              </Stack>
              <Typography variant="h4" fontWeight={700} color="warning.main">
                {loadingPending ? "…" : pendingCount}
              </Typography>
              {showRequestsLink && pendingCount > 0 && (
                <Button
                  size="small"
                  component={RouterLink}
                  to={CLUB_ROUTE_PATHS.REQUESTS}
                  sx={{ mt: 1, px: 0 }}
                  onClick={onViewRequests}
                >
                  Duyệt ngay
                </Button>
              )}
            </CardContent>
          </Card>
        </Grid>
      )}

      <Grid item xs={12} sm={canReview ? 4 : 8}>
        <Card variant="outlined" sx={{ height: "100%", borderRadius: 2 }}>
          <CardContent>
            <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1 }}>
              <HistoryIcon color="action" fontSize="small" aria-hidden />
              <Typography variant="subtitle2" fontWeight={700}>
                Hoạt động gần đây
              </Typography>
            </Stack>
            <Typography variant="body2" color="text.secondary">
              {todaySessions.length
                ? `${todaySessions.length} buổi sinh hoạt hôm nay.`
                : "Theo dõi giải đấu và lịch CLB tại tab Lịch sinh hoạt."}
            </Typography>
          </CardContent>
        </Card>
      </Grid>
    </Grid>
  );
}

export function isCourtClustersEnabled() {
  const fromVite = String(import.meta.env?.VITE_COURT_CLUSTERS_ENABLED || "").toLowerCase();
  const fromNode =
    typeof process !== "undefined" && process?.env
      ? String(process.env.VITE_COURT_CLUSTERS_ENABLED || "").toLowerCase()
      : "";
  return fromVite === "true" || fromNode === "true";
}

import { isValidGoogleMapsUrl } from "../utils/clusterMapsUtils.js";
import {
  buildDefaultClusterId,
  createCourtClusterRecord,
  normalizeClusterAssignment,
  normalizeCourtCluster,
  slugifyClusterName,
} from "../../../models/courtCluster.js";
import { ROLES, normalizeRole } from "../../../auth/roles.js";
import { isGlobalRole, isPlatformScopedRole, isVenueScopedRole } from "../../../auth/roles.js";
import { isCourtClustersEnabled } from "../config/clusterFlags.js";
import { sanitizeBillingTenantId } from "../../billing/services/billingTenantResolver.js";
import { isValidProfileUserId } from "../utils/profileUserId.js";
import {
  getActiveClusterId,
  getActiveClusterIdForVenue,
  loadClusterAssignments,
  loadCourtClusters,
  saveClusterAssignments,
  saveCourtClusters,
  setActiveClusterId,
} from "../../../data/courtCluster.js";

function upsertClusterList(cluster) {
  const normalized = normalizeCourtCluster(cluster);
  const clusters = loadCourtClusters().filter((item) => item.id !== normalized.id);
  clusters.push(normalized);
  saveCourtClusters(clusters);
  return normalized;
}

const MANAGED_CLUSTER_PATCH_KEYS = new Set([
  "name",
  "slug",
  "status",
  "address",
  "googleMapsUrl",
  "ownerUserId",
]);

export function canManageCourtClusters(user) {
  if (!user) {
    return false;
  }

  const role = normalizeRole(user.role);
  return (
    role === ROLES.PLATFORM_ADMIN ||
    role === ROLES.SUPER_ADMIN ||
    role === ROLES.SYSTEM_TECHNICIAN ||
    isGlobalRole(user.role) ||
    isPlatformScopedRole(user.role)
  );
}

function assertClusterManageAccess(user) {
  if (!canManageCourtClusters(user)) {
    return { ok: false, error: "Không có quyền quản lý cụm sân" };
  }

  return { ok: true };
}

function assertGoogleMapsUrl(googleMapsUrl) {
  if (!isValidGoogleMapsUrl(googleMapsUrl)) {
    return { ok: false, error: "Link Google Maps không hợp lệ" };
  }

  return { ok: true };
}

export function listClustersForVenue(venueId) {
  if (!venueId) {
    return loadCourtClusters();
  }

  return loadCourtClusters().filter((cluster) => cluster.venueId === venueId);
}

export function getClusterById(clusterId) {
  if (!clusterId) {
    return null;
  }

  return loadCourtClusters().find((cluster) => cluster.id === clusterId) || null;
}

export function getDefaultClusterIdForVenue(venueId) {
  return buildDefaultClusterId(venueId);
}

export function ensureDefaultClusterForVenue(venueId, { name = "Cụm chính", ownerUserId = null } = {}) {
  if (!venueId) {
    return { ok: false, error: "Thiếu venueId" };
  }

  const clusterId = buildDefaultClusterId(venueId);
  const existing = getClusterById(clusterId);
  if (existing) {
    return { ok: true, cluster: existing, created: false };
  }

  const cluster = upsertClusterList(
    createCourtClusterRecord({
      id: clusterId,
      venueId,
      name,
      slug: "main",
      ownerUserId,
    })
  );

  return { ok: true, cluster, created: true };
}

export function createCourtCluster({
  venueId,
  name,
  slug,
  ownerUserId = null,
  address = "",
  googleMapsUrl = "",
  user = null,
}) {
  const access = assertClusterManageAccess(user);
  if (!access.ok) {
    return access;
  }

  if (!venueId || !String(name || "").trim()) {
    return { ok: false, error: "Thiếu venueId hoặc tên cụm sân" };
  }

  const mapsCheck = assertGoogleMapsUrl(googleMapsUrl);
  if (!mapsCheck.ok) {
    return mapsCheck;
  }

  const normalizedSlug = slug || slugifyClusterName(name);
  const existingSlug = listClustersForVenue(venueId).find((item) => item.slug === normalizedSlug);
  if (existingSlug) {
    return { ok: false, error: "Slug cụm sân đã tồn tại trong tổ chức này" };
  }

  const cluster = upsertClusterList(
    createCourtClusterRecord({
      venueId,
      name: String(name).trim(),
      slug: normalizedSlug,
      ownerUserId,
      address: String(address || "").trim(),
      googleMapsUrl: String(googleMapsUrl || "").trim(),
    })
  );

  if (ownerUserId) {
    assignUserToCluster(ownerUserId, cluster.id, { role: "CLUSTER_OWNER", user });
  }

  return { ok: true, cluster };
}

export function updateCourtCluster(clusterId, patch = {}, { user = null } = {}) {
  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return { ok: false, error: "Không tìm thấy cụm sân" };
  }

  const managedKeys = Object.keys(patch).filter((key) => MANAGED_CLUSTER_PATCH_KEYS.has(key));
  if (managedKeys.length > 0) {
    const access = assertClusterManageAccess(user);
    if (!access.ok) {
      return access;
    }
  }

  if (Object.prototype.hasOwnProperty.call(patch, "googleMapsUrl")) {
    const mapsCheck = assertGoogleMapsUrl(patch.googleMapsUrl);
    if (!mapsCheck.ok) {
      return mapsCheck;
    }
  }

  const next = upsertClusterList({
    ...cluster,
    ...patch,
    id: cluster.id,
    venueId: cluster.venueId,
    updatedAt: new Date().toISOString(),
  });

  return { ok: true, cluster: next };
}

export function deleteCourtCluster(clusterId, { user = null } = {}) {
  const access = assertClusterManageAccess(user);
  if (!access.ok) {
    return access;
  }

  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return { ok: false, error: "Không tìm thấy cụm sân" };
  }

  const clusters = loadCourtClusters().filter((item) => item.id !== clusterId);
  saveCourtClusters(clusters);

  const assignments = loadClusterAssignments().filter((item) => item.clusterId !== clusterId);
  saveClusterAssignments(assignments);

  if (getActiveClusterId() === clusterId) {
    setActiveClusterId(null);
  }

  return { ok: true };
}

export function listAssignmentsForUser(userId) {
  if (!userId) {
    return [];
  }

  return loadClusterAssignments().filter((item) => item.userId === userId);
}

export function listAssignmentsForCluster(clusterId) {
  if (!clusterId) {
    return [];
  }

  return loadClusterAssignments().filter((item) => item.clusterId === clusterId);
}

export function assignUserToCluster(userId, clusterId, { role = "CLUSTER_OWNER", user: actor = null } = {}) {
  const access = assertClusterManageAccess(actor);
  if (!access.ok) {
    return access;
  }

  if (!userId || !clusterId) {
    return { ok: false, error: "Thiếu userId hoặc clusterId" };
  }

  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return { ok: false, error: "Không tìm thấy cụm sân" };
  }

  const assignment = normalizeClusterAssignment({ userId, clusterId, role });
  const assignments = loadClusterAssignments().filter(
    (item) => !(item.userId === userId && item.clusterId === clusterId)
  );
  assignments.push(assignment);
  saveClusterAssignments(assignments);

  return { ok: true, assignment };
}

export function unassignUserFromCluster(userId, clusterId, { user: actor = null } = {}) {
  const access = assertClusterManageAccess(actor);
  if (!access.ok) {
    return access;
  }

  const assignments = loadClusterAssignments().filter(
    (item) => !(item.userId === userId && item.clusterId === clusterId)
  );
  saveClusterAssignments(assignments);
  return { ok: true };
}

export function setUserClusterAssignments(userId, clusterIds = [], { role = "CLUSTER_OWNER", user: actor = null } = {}) {
  const access = assertClusterManageAccess(actor);
  if (!access.ok) {
    return access;
  }

  if (!userId) {
    return { ok: false, error: "Thiếu userId" };
  }

  const ids = new Set((clusterIds || []).map((id) => String(id).trim()).filter(Boolean));
  const kept = loadClusterAssignments().filter((item) => item.userId !== userId);
  const next = [
    ...kept,
    ...[...ids].map((clusterId) => normalizeClusterAssignment({ userId, clusterId, role })),
  ];
  saveClusterAssignments(next);
  return { ok: true, assignments: next.filter((item) => item.userId === userId) };
}

export function resolveAssignedClusterIdsForUser(user) {
  if (!user?.id) {
    return [];
  }

  if (Array.isArray(user.assignedClusterIds) && user.assignedClusterIds.length > 0) {
    return user.assignedClusterIds;
  }

  return listAssignmentsForUser(user.id).map((item) => item.clusterId);
}

export function isOrgWideClusterRole(user) {
  const role = normalizeRole(user?.role);
  return role === ROLES.TENANT_OWNER || role === ROLES.VENUE_MANAGER;
}

export function isVenueWideClusterManagerRole(user) {
  return normalizeRole(user?.role) === ROLES.VENUE_MANAGER;
}

export function isClusterUnassigned(clusterId) {
  if (!clusterId) {
    return false;
  }
  const cluster = getClusterById(clusterId);
  if (!cluster || cluster.status !== "active") {
    return false;
  }
  if (cluster.ownerUserId && isValidProfileUserId(cluster.ownerUserId)) {
    return false;
  }
  return !listAssignmentsForCluster(clusterId).some(
    (item) => item.role === "CLUSTER_OWNER" && isValidProfileUserId(item.userId)
  );
}

export function isClusterAssigned(clusterId) {
  if (!clusterId) {
    return false;
  }
  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return false;
  }
  return !isClusterUnassigned(clusterId);
}

/**
 * Admin management list — includes assigned + unassigned clusters.
 * Platform admins see all clusters when selected tenant is legacy/local-only.
 */
export const ADMIN_ALL_TENANTS_ID = "__all_tenants__";

export function listClustersForAdminManagement(user, selectedVenueId) {
  const all = [...loadCourtClusters()].sort((a, b) =>
    String(a.name || "").localeCompare(String(b.name || ""), "vi")
  );

  const selected = String(selectedVenueId || "").trim();

  if (!user) {
    if (!selected || selected === ADMIN_ALL_TENANTS_ID) {
      return all;
    }
    return listClustersForVenue(selected);
  }

  if (canManageCourtClusters(user)) {
    if (!selected || selected === ADMIN_ALL_TENANTS_ID) {
      return all;
    }

    const cloudVenueId = sanitizeBillingTenantId(selected);
    if (!cloudVenueId) {
      return all;
    }
    return all.filter(
      (cluster) => cluster.venueId === cloudVenueId || cluster.venueId === selected
    );
  }

  const userVenue = String(user.venueId || user.tenantId || "").trim();
  const scopeVenue = sanitizeBillingTenantId(userVenue) || sanitizeBillingTenantId(selectedVenueId);
  if (!scopeVenue) {
    return all;
  }

  return all.filter(
    (cluster) =>
      cluster.venueId === scopeVenue ||
      cluster.venueId === userVenue ||
      cluster.venueId === selectedVenueId
  );
}

export function listUnassignedClusters({ search = "" } = {}) {
  const term = String(search || "").trim().toLowerCase();
  return loadCourtClusters().filter((cluster) => {
    if (!isClusterUnassigned(cluster.id)) {
      return false;
    }
    if (!term) {
      return true;
    }
    return (
      cluster.name.toLowerCase().includes(term) ||
      cluster.address.toLowerCase().includes(term) ||
      cluster.venueId.toLowerCase().includes(term)
    );
  });
}

export function listClustersForAssignedUser(user) {
  const assignedIds = new Set(resolveAssignedClusterIdsForUser(user));
  if (assignedIds.size === 0) {
    return [];
  }
  return loadCourtClusters().filter((cluster) => assignedIds.has(cluster.id));
}

export function listAccessibleClustersForUser(user, venueId) {
  if (!isCourtClustersEnabled()) {
    if (!venueId) {
      const assigned = listClustersForAssignedUser(user);
      if (assigned.length > 0) {
        return assigned;
      }
      return [];
    }

    const ensured = ensureDefaultClusterForVenue(venueId);
    return ensured.cluster ? [ensured.cluster] : [];
  }

  const assignedClusters = listClustersForAssignedUser(user);
  if (assignedClusters.length > 0) {
    if (!venueId) {
      return assignedClusters;
    }
    return assignedClusters.filter((cluster) => cluster.venueId === venueId);
  }

  if (!venueId) {
    return [];
  }

  const venueClusters = listClustersForVenue(venueId);
  if (!user) {
    return venueClusters;
  }

  if (isGlobalRole(user.role)) {
    return venueClusters;
  }

  if (isVenueWideClusterManagerRole(user) && user.venueId === venueId) {
    return venueClusters;
  }

  return [];
}

export function canUserAccessCluster(user, clusterId, options = {}) {
  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return false;
  }

  if (!isCourtClustersEnabled()) {
    if (!user?.venueId) {
      return false;
    }
    return user.venueId === cluster.venueId;
  }

  if (!user) {
    return true;
  }

  if (isGlobalRole(user.role)) {
    return true;
  }

  const assignedIds = resolveAssignedClusterIdsForUser(user);
  if (assignedIds.length > 0) {
    return assignedIds.includes(clusterId);
  }

  if (user.venueId && user.venueId !== cluster.venueId) {
    return false;
  }

  if (isVenueWideClusterManagerRole(user) && user.venueId === cluster.venueId) {
    return true;
  }

  return false;
}

export function switchActiveCluster(clusterId, { user = null, venueId = null } = {}) {
  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return { ok: false, error: "Không tìm thấy cụm sân" };
  }

  if (user && !canUserAccessCluster(user, clusterId, { venueId: venueId || user.venueId })) {
    return { ok: false, error: "Không có quyền truy cập cụm sân này", code: "FORBIDDEN" };
  }

  if (venueId && cluster.venueId !== venueId) {
    return { ok: false, error: "Cụm sân không thuộc tổ chức hiện tại", code: "TENANT_FORBIDDEN" };
  }

  setActiveClusterId(clusterId);
  return { ok: true, cluster };
}

export function resolveActiveClusterForUser(user, venueId) {
  const accessible = listAccessibleClustersForUser(user, venueId);
  if (accessible.length === 0) {
    return null;
  }

  const storedId = venueId
    ? getActiveClusterIdForVenue(venueId)
    : getActiveClusterId();
  if (storedId && accessible.some((cluster) => cluster.id === storedId)) {
    return getClusterById(storedId);
  }

  return accessible[0];
}

export function syncClusterCourtCount(clusterId, courtCount) {
  const cluster = getClusterById(clusterId);
  if (!cluster) {
    return { ok: false };
  }

  return updateCourtCluster(clusterId, {
    courtCount: Number.isFinite(Number(courtCount)) ? Number(courtCount) : 0,
  });
}

export function stampCourtWithCluster(court, clusterId) {
  if (!court || !clusterId) {
    return court;
  }

  return {
    ...court,
    clusterId,
  };
}

export function filterCourtsByCluster(courts = [], clusterId) {
  if (!isCourtClustersEnabled() || !clusterId) {
    return courts;
  }

  return courts.filter((court) => court.clusterId === clusterId);
}

export function ensureCourtsHaveClusterId(courts = [], venueId) {
  if (!isCourtClustersEnabled() || !venueId) {
    return courts;
  }

  const defaultClusterId = buildDefaultClusterId(venueId);
  ensureDefaultClusterForVenue(venueId);

  return courts.map((court) =>
    court?.clusterId ? court : stampCourtWithCluster(court, defaultClusterId)
  );
}

import { useEffect, useMemo, useState } from "react";

import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Tab,
  Tabs,
  TextField,
  Typography,
} from "@mui/material";

import { PERMISSIONS } from "../../../auth/permissions.js";
import { resolveRouteAccessScope } from "../../../auth/menuAccess.js";
import { useAuth } from "../../../context/AuthContext.jsx";
import { useClub } from "../../../context/ClubContext.jsx";
import {
  loadCourts,
  saveCourts,
  upsertCourt,
  validateCourtLimit,
  validateCourtLimitBulk,
  createCourtsBulk,
  buildBulkCourtRecords,
  getCourtCapacityForClub,
  validateCourtName,
} from "../../../pages/courts.logic.js";

export default function CourtQuickManageDialog({
  open,
  onClose,
  editingCourt = null,
  clubId = null,
  onSaved,
}) {
  const { activeClubId, activeClub } = useClub();
  const targetClubId = clubId || editingCourt?.clubId || activeClubId;
  const { can, rbacEnabled, isAuthenticated, user } = useAuth();
  const scope = useMemo(
    () => resolveRouteAccessScope({ user, activeClubId: targetClubId, activeClub }),
    [user, targetClubId, activeClub]
  );
  const canCreate =
    !rbacEnabled || !isAuthenticated || can(PERMISSIONS.COURT_CREATE, scope);
  const canUpdate =
    !rbacEnabled || !isAuthenticated || can(PERMISSIONS.COURT_UPDATE, scope);
  const courtCapacity = useMemo(
    () => getCourtCapacityForClub(targetClubId),
    [targetClubId, open]
  );

  const [tab, setTab] = useState("single");
  const [courtName, setCourtName] = useState("");
  const [courtNumber, setCourtNumber] = useState("");
  const [bulkCourtCount, setBulkCourtCount] = useState("3");
  const [formError, setFormError] = useState(null);

  useEffect(() => {
    if (!open) {
      return;
    }

    setTab(editingCourt ? "single" : "single");
    setCourtName(editingCourt?.name || "");
    setCourtNumber(editingCourt?.number ?? "");
    setBulkCourtCount(String(courtCapacity?.remaining ?? 3));
    setFormError(null);
  }, [open, editingCourt, courtCapacity?.remaining]);

  const bulkPreview = useMemo(() => {
    const courts = loadCourts([], targetClubId);
    const count = Number(bulkCourtCount);
    if (!Number.isFinite(count) || count < 1) {
      return [];
    }
    return buildBulkCourtRecords(courts, count).map((court) => court.name);
  }, [bulkCourtCount, targetClubId, open]);

  const handleSaveSingle = () => {
    const nameError = validateCourtName(courtName);
    if (nameError) {
      setFormError(nameError);
      return;
    }

    if (!editingCourt) {
      const limitError = validateCourtLimit(targetClubId, { isNew: true });
      if (limitError) {
        setFormError(limitError);
        return;
      }
      if (!canCreate) {
        setFormError("Không có quyền thêm sân.");
        return;
      }
    } else if (!canUpdate) {
      setFormError("Không có quyền sửa sân.");
      return;
    }

    const courts = loadCourts([], targetClubId);
    const updatedCourts = upsertCourt(courts, {
      courtName,
      courtNumber,
      editingCourt,
      extra: {
        active: editingCourt?.active !== false,
        status: editingCourt?.status || "active",
      },
    });

    const permission = editingCourt ? PERMISSIONS.COURT_UPDATE : PERMISSIONS.COURT_CREATE;
    const result = saveCourts(updatedCourts, targetClubId, { permission });
    if (!result.ok) {
      setFormError(result.error || "Không thể lưu sân.");
      return;
    }

    onSaved?.();
    onClose?.();
  };

  const handleSaveBulk = () => {
    const count = Number(bulkCourtCount);
    if (!Number.isFinite(count) || count < 1) {
      setFormError("Vui lòng nhập số sân hợp lệ (từ 1 trở lên).");
      return;
    }

    const limitError = validateCourtLimitBulk(targetClubId, count);
    if (limitError) {
      setFormError(limitError);
      return;
    }

    if (!canCreate) {
      setFormError("Không có quyền thêm sân.");
      return;
    }

    const courts = loadCourts([], targetClubId);
    const updatedCourts = createCourtsBulk(courts, count);
    const result = saveCourts(updatedCourts, targetClubId, {
      permission: PERMISSIONS.COURT_CREATE,
    });
    if (!result.ok) {
      setFormError(result.error || "Không thể lưu sân.");
      return;
    }

    onSaved?.();
    onClose?.();
  };

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>{editingCourt ? "Sửa sân" : "Quản lý sân nhanh"}</DialogTitle>
      <DialogContent>
        {formError && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {formError}
          </Alert>
        )}

        {!editingCourt && (
          <Tabs value={tab} onChange={(_event, value) => setTab(value)} sx={{ mb: 2 }}>
            <Tab value="single" label="Thêm từng sân" />
            <Tab value="bulk" label="Tạo nhanh" />
          </Tabs>
        )}

        {(editingCourt || tab === "single") && (
          <Box>
            <TextField
              label="Tên sân"
              fullWidth
              margin="normal"
              value={courtName}
              onChange={(event) => setCourtName(event.target.value)}
            />
            <TextField
              label="Số sân (tuỳ chọn)"
              fullWidth
              margin="normal"
              type="number"
              value={courtNumber}
              onChange={(event) => setCourtNumber(event.target.value)}
            />
          </Box>
        )}

        {!editingCourt && tab === "bulk" && (
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Nhập số sân tại cơ sở (2, 3, 4, 6...). Hệ thống tạo Sân 1, Sân 2, ...
            </Typography>
            <TextField
              label="Số sân tại cơ sở"
              fullWidth
              type="number"
              inputProps={{
                min: 1,
                max: courtCapacity?.remaining ?? undefined,
              }}
              value={bulkCourtCount}
              onChange={(event) => setBulkCourtCount(event.target.value)}
            />
