  FORBIDDEN_PAYLOAD_FIELD: "Payload chứa trường không được phép.",
  VERSION_MISMATCH: "Phiên bản assessment không khớp.",
  SINGLES_NOT_IMPLEMENTED: "Đánh giá singles chưa được triển khai.",
