  }, [rounds, selectedCompareRoundB]);

  const compareWinner = useMemo(
    () =>
      buildCompareWinner(
        compareRoundAMetrics,
        compareRoundBMetrics,
        compareRoundAName,
        compareRoundBName
      ),
    [compareRoundAMetrics, compareRoundBMetrics, compareRoundAName, compareRoundBName]
  );

  const compareRoundAGrade = useMemo(
    () => getRoundGrade(compareRoundAMetrics),
    [compareRoundAMetrics]
  );
  const compareRoundBGrade = useMemo(
    () => getRoundGrade(compareRoundBMetrics),
    [compareRoundBMetrics]
  );

  const fairnessLevel = useMemo(() => {
    if (fairnessMetrics.fairnessScore >= 70) return "Tốt";
    if (fairnessMetrics.fairnessScore >= 40) return "Trung bình";
    return "Cần cải thiện";
  }, [fairnessMetrics.fairnessScore]);

  const assertExportAllowed = () => {
    if (!can(PERMISSIONS.STATISTICS_EXPORT, { clubId: activeClubId })) {
      setStatusMessage({ type: "error", text: "Không có quyền xuất thống kê." });
      return false;
    }

    const planCheck = guardSubscriptionForClub(activeClubId, "statistics");
    if (!planCheck.ok) {
      setStatusMessage({ type: "error", text: planCheck.error });
      return false;
    }

    return true;
  };

  const handleExportFilteredCsv = () => {
    if (!assertExportAllowed()) {
      return;
    }

    if (filteredSessions.length === 0) {
      setStatusMessage({ type: "error", text: "Không có dữ liệu sau lọc để xuất CSV." });
      return;
    }

    const csv = buildFilteredSessionsCsv(filteredSessions);
    downloadCsv(csv, `pickleball-statistics-${new Date().toISOString().slice(0, 10)}.csv`);
    setStatusMessage({ type: "success", text: "Đã xuất CSV theo bộ lọc hiện tại." });
  };

  const handleExportCompareCsv = () => {
    if (!assertExportAllowed()) {
      return;
    }

    if (compareRoundAMetrics.sessionCount === 0 && compareRoundBMetrics.sessionCount === 0) {
      setStatusMessage({ type: "error", text: "Không có dữ liệu so sánh để xuất CSV." });
      return;
    }

    const csv = buildRoundCompareCsv({
      compareRoundAName,
      compareRoundBName,
      compareRoundAMetrics,
      compareRoundBMetrics,
      compareRoundAGrade,
      compareRoundBGrade,
      waitingAlertThreshold,
    });
    downloadCsv(csv, `pickleball-round-compare-${new Date().toISOString().slice(0, 10)}.csv`);
    setStatusMessage({ type: "success", text: "Đã xuất CSV phần so sánh Round A/B." });
  };

  const handleStandingsSeasonChange = (seasonId) => {
    setStandingsSeasonId(seasonId);
    const nextLeagues = leagues.filter((league) => String(league.seasonId) === String(seasonId));
    setStandingsLeagueId(nextLeagues[0]?.id || "");
  };

  const handleExportSeasonStandingsCsv = () => {
    if (!assertExportAllowed()) {
      return;
    }

    if (!seasonStandingsRows.length) {
      setStatusMessage({ type: "warning", text: "Chưa có dữ liệu BXH mùa giải để xuất." });
      return;
    }

    const csv = buildSeasonStandingsCsv(seasonStandingsRows, {
      seasonName: selectedStandingsSeason?.name || "",
      leagueName: selectedStandingsLeague?.name || "",
    });
    downloadCsv(csv, `bxh-mua-giai-${new Date().toISOString().slice(0, 10)}.csv`);
    setStatusMessage({ type: "success", text: "Đã xuất CSV BXH mùa giải." });
  };

  return {
    activeSeason,
    activeLeague,
    statusMessage,
    seasons,
    leagues,
    rounds,
    shiftOptions,
    selectedRound,
    setSelectedRound,
    selectedShift,
    setSelectedShift,
    selectedCompareRoundA,
    setSelectedCompareRoundA,
    selectedCompareRoundB,
    setSelectedCompareRoundB,
    waitingAlertThreshold,
    setWaitingAlertThreshold,
    standingsSeasonId,
    standingsLeagueId,
    setStandingsLeagueId,
    leaguesForStandingsSeason,
    selectedStandingsSeason,
    selectedStandingsLeague,
    seasonStandingsRows,
    filteredSessions,
    matchOutcomeStats,
    completedResultSessions,
    operationalMetrics,
    trendPoints,
    waitingTrendPoints,
    waitingTrendMaxY,
    trendPath,
    waitingTrendPath,
    trendSummary,
    compareRoundAMetrics,
    compareRoundBMetrics,
    compareRoundAName,
    compareRoundBName,
    compareWinner,
    compareRoundAGrade,
    compareRoundBGrade,
    fairnessMetrics,
    fairnessLevel,
    playerStats,
    playerNameById,
    recentSessions,
    topPartners,
    topOpponents,
    handleStandingsSeasonChange,
    handleExportSeasonStandingsCsv,
    handleExportFilteredCsv,
    handleExportCompareCsv,
    setStatusMessage,
  };
}

import { createId } from "../../../utils/id.js";
import {
  ACTIVATION_RULE,
  DREAMBREAKER_ORDER_SOURCE,
  DREAMBREAKER_STATUS,
  DISCIPLINE_KIND,
  MATCHUP_STATUS,
  SUB_MATCH_STATUS,
} from "../constants.js";
import {
  findMatchup,
  findTeam,
  normalizeTeamData,
} from "../models/index.js";
import {
  getDreambreakerDiscipline,
  isMlpFormat,
} from "./mlpPresetEngine.js";
import { computeMatchupTieProgress } from "./matchupTieEngine.js";
import { getRallyWinner, validateRallyScore } from "./rallyScoringEngine.js";

function shufflePlayerIds(playerIds = []) {
  const copy = [...playerIds];
  for (let index = copy.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1));
    [copy[index], copy[swapIndex]] = [copy[swapIndex], copy[index]];
  }
  return copy;
}

export function randomDreambreakerOrder(team) {
  const roster = team?.playerIds || [];
  if (roster.length < 4) {
    return [];
  }
  return shufflePlayerIds(roster).slice(0, 4);
}

function resolveDreambreakerOrderLockAt(matchup, teamData, now = new Date().toISOString()) {
  if (matchup?.scheduledAt) {
    return matchup.scheduledAt;
  }

  const leadMinutes = teamData.settings?.lineupLockLeadMinutes || 15;
  return new Date(new Date(now).getTime() + leadMinutes * 60000).toISOString();
}

function emptyDreambreaker() {
  return {
    status: DREAMBREAKER_STATUS.PENDING,
    teamAOrder: [],
    teamBOrder: [],
    teamAScore: 0,
    teamBScore: 0,
    winnerTeamId: "",
    orderLockAt: null,
    ordersLockedAt: null,
    orderSourceA: "",
    orderSourceB: "",
    rotation: {
      segmentIndex: 0,
      pointsInSegment: 0,
      pointHistory: [],
      injurySkips: [],
    },
    subMatchId: "",
  };
}

export function getActiveDreambreakerPlayers(matchup, teamData, teamSide) {
  const dreambreaker = matchup.dreambreaker;
  if (!dreambreaker) {
    return [];
  }

  const order =
    teamSide === "A" ? dreambreaker.teamAOrder : dreambreaker.teamBOrder;
  const segmentIndex = dreambreaker.rotation?.segmentIndex || 0;
  const playerId = order[segmentIndex % Math.max(order.length, 1)];

  if (!playerId) {
    return [];
  }

  const teamId = teamSide === "A" ? matchup.teamAId : matchup.teamBId;
  const team = findTeam(teamData, teamId);
  const player = team?.playerIds?.includes(playerId) ? playerId : null;

  return player ? [player] : [];
}

export function isDreambreakerReady(dreambreaker) {
  return (
    dreambreaker?.teamAOrder?.length === 4 && dreambreaker?.teamBOrder?.length === 4
  );
}

function resolveEffectiveOrder(order = [], injurySkips = [], teamId, segmentIndex) {
  const skipsForSegment = injurySkips.filter(
    (skip) => skip.teamId === teamId && skip.atSegment <= segmentIndex
  );
  const skippedIds = new Set(skipsForSegment.map((skip) => skip.skippedPlayerId));

  let attempts = 0;
  let index = segmentIndex % order.length;

  while (attempts < order.length) {
    const playerId = order[index];
    if (!skippedIds.has(playerId)) {
      return playerId;
    }
    index = (index + 1) % order.length;
    attempts += 1;
  }

  return order[segmentIndex % order.length] || "";
}

export function getDreambreakerCourtPlayers(matchup, teamData) {
  const dreambreaker = matchup.dreambreaker;
  if (!dreambreaker) {
    return { teamAPlayerId: "", teamBPlayerId: "" };
  }

  const segmentIndex = dreambreaker.rotation?.segmentIndex || 0;
  const injurySkips = dreambreaker.rotation?.injurySkips || [];

  return {
    teamAPlayerId: resolveEffectiveOrder(
      dreambreaker.teamAOrder,
      injurySkips,
      matchup.teamAId,
      segmentIndex
    ),
    teamBPlayerId: resolveEffectiveOrder(
      dreambreaker.teamBOrder,
      injurySkips,
      matchup.teamBId,
      segmentIndex
    ),
    segmentIndex,
    pointsInSegment: dreambreaker.rotation?.pointsInSegment || 0,
  };
}

export function maybeActivateDreambreaker(teamData, matchupId, now = new Date().toISOString()) {
  const matchup = findMatchup(teamData, matchupId);
  if (!matchup || !isMlpFormat(teamData) || teamData.settings?.dreambreakerEnabled === false) {
    return { ok: true, teamData, activated: false };
  }

  const mainDisciplines = teamData.disciplines.filter(
    (discipline) => discipline.activationRule === ACTIVATION_RULE.ALWAYS
  );
  const mainSubMatches = matchup.subMatches.filter((subMatch) =>
    mainDisciplines.some((discipline) => discipline.id === subMatch.disciplineId)
  );

  const allMainDone = mainSubMatches.every(
    (subMatch) =>
      subMatch.status === SUB_MATCH_STATUS.COMPLETED ||
      subMatch.status === SUB_MATCH_STATUS.FORFEIT
  );

  if (!allMainDone) {
    return { ok: true, teamData, activated: false };
  }

  let teamAWins = 0;
  let teamBWins = 0;
  mainSubMatches.forEach((subMatch) => {
    if (subMatch.winnerTeamId === matchup.teamAId) {
      teamAWins += 1;
    } else if (subMatch.winnerTeamId === matchup.teamBId) {
      teamBWins += 1;
    }
  });

  if (teamAWins === teamBWins && teamAWins === 2) {
    const dreambreakerDiscipline = getDreambreakerDiscipline(teamData.disciplines);
    const existing = matchup.dreambreaker || emptyDreambreaker();

    const nextMatchups = teamData.matchups.map((item) => {
      if (item.id !== matchupId) {
        return item;
      }

      return {
        ...item,
        dreambreaker: {
          ...existing,
          status:
            existing.status === DREAMBREAKER_STATUS.PENDING
              ? DREAMBREAKER_STATUS.LINEUP_OPEN
              : existing.status,
          orderLockAt: existing.orderLockAt || resolveDreambreakerOrderLockAt(item, teamData, now),
        },
        status:
          item.status === MATCHUP_STATUS.COMPLETED
            ? MATCHUP_STATUS.IN_PROGRESS
            : item.status,
      };
    });

    return {
      ok: true,
      teamData: normalizeTeamData({ ...teamData, matchups: nextMatchups }),
      activated: true,
      dreambreakerDiscipline,
    };
  }

  return { ok: true, teamData, activated: false };
}

export function submitDreambreakerOrder(teamData, { matchupId, teamId, order = [] }) {
  let nextData = teamData;
  let matchup = findMatchup(nextData, matchupId);

  if (!matchup?.dreambreaker) {
    const activation = maybeActivateDreambreaker(nextData, matchupId);
    nextData = activation.teamData;
    matchup = findMatchup(nextData, matchupId);
  }

  if (!matchup) {
    return { ok: false, error: "Không tìm thấy lượt đối đầu." };
  }

  const dreambreaker = matchup.dreambreaker;
  if (
    !dreambreaker ||
    dreambreaker.status !== DREAMBREAKER_STATUS.LINEUP_OPEN
  ) {
    return { ok: false, error: "Dreambreaker chưa được kích hoạt." };
  }

  if (dreambreaker.ordersLockedAt) {
    return { ok: false, error: "Thứ tự Dreambreaker đã khóa." };
  }

  const team = findTeam(nextData, teamId);
  if (!team) {
    return { ok: false, error: "Không tìm thấy đội." };
  }

  const normalizedOrder = order.map((id) => String(id).trim()).filter(Boolean);
  if (normalizedOrder.length !== 4) {
    return { ok: false, error: "Dreambreaker cần đúng 4 VĐV theo thứ tự 1→4." };
  }

  const unique = new Set(normalizedOrder);
  if (unique.size !== 4) {
    return { ok: false, error: "Thứ tự Dreambreaker không được trùng VĐV." };
  }

  const invalid = normalizedOrder.filter((playerId) => !team.playerIds.includes(playerId));
  if (invalid.length > 0) {
    return { ok: false, error: "Tất cả VĐV phải thuộc đội." };
  }

  const isTeamA = team.id === matchup.teamAId;
  const nextDreambreaker = {
    ...dreambreaker,
    teamAOrder: isTeamA ? normalizedOrder : dreambreaker.teamAOrder,
    teamBOrder: isTeamA ? dreambreaker.teamBOrder : normalizedOrder,
    orderSourceA: isTeamA ? DREAMBREAKER_ORDER_SOURCE.CAPTAIN : dreambreaker.orderSourceA,
    orderSourceB: isTeamA ? dreambreaker.orderSourceB : DREAMBREAKER_ORDER_SOURCE.CAPTAIN,
  };

  if (isDreambreakerReady(nextDreambreaker)) {
    nextDreambreaker.status = DREAMBREAKER_STATUS.READY;
  }

  const nextMatchups = nextData.matchups.map((item) =>
    item.id === matchupId ? { ...item, dreambreaker: nextDreambreaker } : item
  );

  return {
    ok: true,
    teamData: normalizeTeamData({ ...nextData, matchups: nextMatchups }),
    dreambreaker: nextDreambreaker,
  };
}

export function lockDreambreakerOrders(teamData, matchupId, { now = new Date().toISOString(), force = false } = {}) {
  const matchup = findMatchup(teamData, matchupId);
  if (!matchup?.dreambreaker) {
    return { ok: false, error: "Dreambreaker chưa được kích hoạt." };
  }

  const dreambreaker = matchup.dreambreaker;
  if (
    ![DREAMBREAKER_STATUS.LINEUP_OPEN, DREAMBREAKER_STATUS.READY].includes(
      dreambreaker.status
    )
  ) {
    return { ok: true, teamData, logs: [] };
  }

  const pastDeadline =
    force ||
    (dreambreaker.orderLockAt &&
      new Date(now).getTime() >= new Date(dreambreaker.orderLockAt).getTime());

  if (!pastDeadline) {
    return { ok: true, teamData, logs: [] };
  }

  const teamA = findTeam(teamData, matchup.teamAId);
  const teamB = findTeam(teamData, matchup.teamBId);
  const logs = [];
  let nextDreambreaker = { ...dreambreaker };

  if (force) {
    nextDreambreaker.ordersLockedAt = nextDreambreaker.ordersLockedAt || now;
  }

  if (nextDreambreaker.teamAOrder.length !== 4 && teamA) {
    const order = randomDreambreakerOrder(teamA);
    if (order.length === 4) {
      nextDreambreaker = {
        ...nextDreambreaker,
        teamAOrder: order,
        orderSourceA: DREAMBREAKER_ORDER_SOURCE.RANDOM,
      };
      logs.push(`Tự động sắp xếp thứ tự Dreambreaker cho ${teamA.name}.`);
    }
  }

  if (nextDreambreaker.teamBOrder.length !== 4 && teamB) {
    const order = randomDreambreakerOrder(teamB);
    if (order.length === 4) {
      nextDreambreaker = {
        ...nextDreambreaker,
        teamBOrder: order,
        orderSourceB: DREAMBREAKER_ORDER_SOURCE.RANDOM,
      };
      logs.push(`Tự động sắp xếp thứ tự Dreambreaker cho ${teamB.name}.`);
    }
  }

  if (force || logs.length > 0) {
    nextDreambreaker.ordersLockedAt = nextDreambreaker.ordersLockedAt || now;
  }

  if (isDreambreakerReady(nextDreambreaker)) {
    nextDreambreaker.status = DREAMBREAKER_STATUS.READY;
  }

  const nextMatchups = teamData.matchups.map((item) =>
    item.id === matchupId ? { ...item, dreambreaker: nextDreambreaker } : item
  );

  const nextTeamData = normalizeTeamData({ ...teamData, matchups: nextMatchups });

  if (force && !isDreambreakerReady(nextDreambreaker)) {
    return {
      ok: false,
      error: "Không thể khóa thứ tự Dreambreaker — đội thiếu VĐV trên roster.",
      teamData: nextTeamData,
      dreambreaker: nextDreambreaker,
      logs,
    };
  }

  return {
    ok: true,
    teamData: nextTeamData,
    dreambreaker: nextDreambreaker,
    logs,
  };
}

export function syncDreambreakerForAllMatchups(teamData, { now = new Date().toISOString() } = {}) {
  let nextData = teamData;
  let changed = false;

  for (const matchup of teamData.matchups || []) {
    const progress = computeMatchupTieProgress(nextData, matchup);
    if (progress.needsDreambreaker) {
      const activation = maybeActivateDreambreaker(nextData, matchup.id, now);
      if (activation.activated) {
        changed = true;
        nextData = activation.teamData;
      }
    }
  }

  for (const matchup of nextData.matchups || []) {
    if (!matchup.dreambreaker) {
      continue;
    }

    const lockResult = lockDreambreakerOrders(nextData, matchup.id, { now });
    if (lockResult.logs?.length > 0) {
      changed = true;
      nextData = lockResult.teamData;
    }
  }

  return {
    ok: true,
    teamData: normalizeTeamData(nextData),
    changed,
  };
}

export function listDreambreakerMatchups(teamData, { teamId } = {}) {
  return (teamData.matchups || []).filter((matchup) => {
    if (teamId && matchup.teamAId !== teamId && matchup.teamBId !== teamId) {
      return false;
    }

    const progress = computeMatchupTieProgress(teamData, matchup);
    if (!progress.dreambreakerEnabled) {
      return false;
    }

    if (progress.needsDreambreaker) {
      return true;
    }

    const status = matchup.dreambreaker?.status;
    return [
      DREAMBREAKER_STATUS.LINEUP_OPEN,
      DREAMBREAKER_STATUS.READY,
      DREAMBREAKER_STATUS.IN_PROGRESS,
      DREAMBREAKER_STATUS.COMPLETED,
    ].includes(status);
  });
}

export function startDreambreaker(teamData, matchupId, options = {}) {
  const locked = lockDreambreakerOrders(teamData, matchupId, {
    now: options.now,
    force: options.forceLock,
  });
  if (!locked.ok) {
    return locked;
  }

  const matchup = findMatchup(locked.teamData, matchupId);
  if (!matchup?.dreambreaker) {
    return { ok: false, error: "Dreambreaker chưa sẵn sàng." };
  }

  if (!isDreambreakerReady(matchup.dreambreaker)) {
    return { ok: false, error: "Hai đội phải nộp thứ tự 4 VĐV trước." };
  }

  const dreambreakerDiscipline = getDreambreakerDiscipline(locked.teamData.disciplines);
  if (!dreambreakerDiscipline) {
    return { ok: false, error: "Thiếu nội dung Dreambreaker." };
  }

  let subMatchId = matchup.dreambreaker.subMatchId;
  let subMatches = [...matchup.subMatches];

  if (!subMatchId) {
    subMatchId = createId("sub");
    subMatches = [
      ...subMatches,
      {
        id: subMatchId,
        disciplineId: dreambreakerDiscipline.id,
        sortOrder: dreambreakerDiscipline.sortOrder,
        status: SUB_MATCH_STATUS.PLAYING,
        score: { teamA: 0, teamB: 0, games: [] },
        winnerTeamId: "",
      },
    ];
  }

  const nextMatchups = teamData.matchups.map((item) => {
    if (item.id !== matchupId) {
      return item;
    }

    return {
      ...item,
      subMatches,
      status: MATCHUP_STATUS.IN_PROGRESS,
      dreambreaker: {
        ...item.dreambreaker,
        status: DREAMBREAKER_STATUS.IN_PROGRESS,
        subMatchId,
        teamAScore: 0,
        teamBScore: 0,
        rotation: {
          segmentIndex: 0,
          pointsInSegment: 0,
          pointHistory: [],
          injurySkips: item.dreambreaker.rotation?.injurySkips || [],
        },
      },
    };
  });

  return {
    ok: true,
    teamData: normalizeTeamData({ ...locked.teamData, matchups: nextMatchups }),
  };
}

export function recordDreambreakerPoint(teamData, { matchupId, scoringTeamId }) {
  const matchup = findMatchup(teamData, matchupId);
  if (!matchup?.dreambreaker || matchup.dreambreaker.status !== DREAMBREAKER_STATUS.IN_PROGRESS) {
    return { ok: false, error: "Dreambreaker chưa bắt đầu." };
  }

  const dreambreakerDiscipline = getDreambreakerDiscipline(teamData.disciplines);
  const rotationPoints = dreambreakerDiscipline?.scoringFormat?.rotationPoints || 4;

  if (scoringTeamId !== matchup.teamAId && scoringTeamId !== matchup.teamBId) {
    return { ok: false, error: "Đội ghi điểm không hợp lệ." };
  }

  const isTeamA = scoringTeamId === matchup.teamAId;
  const teamAScore = matchup.dreambreaker.teamAScore + (isTeamA ? 1 : 0);
  const teamBScore = matchup.dreambreaker.teamBScore + (isTeamA ? 0 : 1);
  let pointsInSegment = (matchup.dreambreaker.rotation?.pointsInSegment || 0) + 1;
  let segmentIndex = matchup.dreambreaker.rotation?.segmentIndex || 0;

  const pointHistory = [
    ...(matchup.dreambreaker.rotation?.pointHistory || []),
    {
      teamId: scoringTeamId,
      segmentIndex,
      teamAScore,
      teamBScore,
    },
  ];

  if (pointsInSegment >= rotationPoints) {
    segmentIndex += 1;
    pointsInSegment = 0;
  }

  const rules = dreambreakerDiscipline?.scoringFormat || {};
  const winnerSide = getRallyWinner(teamAScore, teamBScore, rules);
  const winnerTeamId =
    winnerSide === "teamA"
      ? matchup.teamAId
      : winnerSide === "teamB"
        ? matchup.teamBId
        : "";

  const nextDreambreaker = {
    ...matchup.dreambreaker,
    teamAScore,
    teamBScore,
    winnerTeamId,
    status: winnerTeamId ? DREAMBREAKER_STATUS.COMPLETED : DREAMBREAKER_STATUS.IN_PROGRESS,
    rotation: {
      ...matchup.dreambreaker.rotation,
      segmentIndex,
      pointsInSegment,
      pointHistory,
    },
  };

  const nextSubMatches = matchup.subMatches.map((subMatch) => {
    if (subMatch.id !== matchup.dreambreaker.subMatchId) {
      return subMatch;
    }

    return {
      ...subMatch,
      status: winnerTeamId ? SUB_MATCH_STATUS.COMPLETED : SUB_MATCH_STATUS.PLAYING,
      score: { teamA: teamAScore, teamB: teamBScore, games: [] },
      winnerTeamId,
      resultConfirmedAt: winnerTeamId ? new Date().toISOString() : null,
    };
  });

  const nextMatchups = teamData.matchups.map((item) =>
    item.id === matchupId
      ? {
          ...item,
          subMatches: nextSubMatches,
          dreambreaker: nextDreambreaker,
          status: winnerTeamId ? MATCHUP_STATUS.COMPLETED : item.status,
          result: winnerTeamId
            ? {
                teamAWins: 2 + (winnerTeamId === matchup.teamAId ? 1 : 0),
                teamBWins: 2 + (winnerTeamId === matchup.teamBId ? 1 : 0),
                teamAPoints: teamAScore,
                teamBPoints: teamBScore,
                winnerTeamId,
              }
            : item.result,
        }
      : item
  );

  return {
    ok: true,
    teamData: normalizeTeamData({ ...teamData, matchups: nextMatchups }),
    completed: Boolean(winnerTeamId),
    winnerTeamId,
  };
}

export function undoDreambreakerPoint(teamData, matchupId) {
  const matchup = findMatchup(teamData, matchupId);
  const history = matchup?.dreambreaker?.rotation?.pointHistory || [];
  if (!matchup?.dreambreaker || history.length === 0) {
    return { ok: false, error: "Không có điểm để hoàn tác." };
  }

  const remaining = history.slice(0, -1);
  const last = remaining[remaining.length - 1];
  const teamAScore = last?.teamAScore || 0;
  const teamBScore = last?.teamBScore || 0;

  let segmentIndex = 0;
  let pointsInSegment = 0;
  if (remaining.length > 0) {
    const tail = remaining[remaining.length - 1];
    segmentIndex = tail.segmentIndex;
    pointsInSegment = remaining.filter((entry) => entry.segmentIndex === segmentIndex).length;
    const rotationPoints =
      getDreambreakerDiscipline(teamData.disciplines)?.scoringFormat?.rotationPoints || 4;
    if (pointsInSegment >= rotationPoints) {
      segmentIndex += 1;
      pointsInSegment = 0;
    }
  }

  const nextDreambreaker = {
    ...matchup.dreambreaker,
    teamAScore,
    teamBScore,
    winnerTeamId: "",
    status: DREAMBREAKER_STATUS.IN_PROGRESS,
    rotation: {
      ...matchup.dreambreaker.rotation,
      segmentIndex,
      pointsInSegment,
      pointHistory: remaining,
    },
  };

  const nextMatchups = teamData.matchups.map((item) =>
    item.id === matchupId
      ? {
          ...item,
          dreambreaker: nextDreambreaker,
          status: MATCHUP_STATUS.IN_PROGRESS,
          result: item.result
            ? { ...item.result, winnerTeamId: "" }
            : item.result,
        }
      : item
  );

  return {
    ok: true,
    teamData: normalizeTeamData({ ...teamData, matchups: nextMatchups }),
  };
}

export function validateDreambreakerFinalScore(teamData, matchupId) {
  const matchup = findMatchup(teamData, matchupId);
  const dreambreaker = matchup?.dreambreaker;
  if (!dreambreaker) {
    return { ok: false, error: "Không có Dreambreaker." };
  }

  const discipline = getDreambreakerDiscipline(teamData.disciplines);
  return validateRallyScore({
    scoreA: dreambreaker.teamAScore,
    scoreB: dreambreaker.teamBScore,
    rules: discipline?.scoringFormat,
  });
}

import { LINEUP_SOURCE, LINEUP_STATUS, GENDER_REQUIREMENT } from "../constants.js";
import { getPlayerGenderKey } from "../../../models/player.js";
import {
  findTeam,
  lineupKey,
  normalizeLineup,
  normalizeTeamData,
} from "../models/index.js";
import { computeTeamRosterStats } from "./teamRosterEngine.js";
import { validateDisciplineSelection } from "./lineupValidationEngine.js";

function shuffle(array = []) {
  const copy = [...array];
  for (let index = copy.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1));
    [copy[index], copy[swapIndex]] = [copy[swapIndex], copy[index]];
  }
  return copy;
}

function sortByAppearanceCount(playerIds, appearanceCounts) {
  return [...playerIds].sort((left, right) => {
    const leftCount = appearanceCounts.get(String(left)) || 0;
    const rightCount = appearanceCounts.get(String(right)) || 0;
    if (leftCount !== rightCount) {
      return leftCount - rightCount;
    }
    return String(left).localeCompare(String(right));
  });
}

function matchesGenderRequirement(player, requirement) {
  const gender = getPlayerGenderKey(player.gender);

  if (requirement === GENDER_REQUIREMENT.MALE) {
    return gender === "male";
  }

  if (requirement === GENDER_REQUIREMENT.FEMALE) {
    return gender === "female";
  }

  return true;
}

function eligiblePlayersForDiscipline(team, discipline, players, usedPlayerIds, allowReuse) {
  const playersById = new Map(players.map((player) => [String(player.id), player]));

  return team.playerIds.filter((playerId) => {
    if (!allowReuse && usedPlayerIds.has(String(playerId))) {
      return false;
    }

    if (team.absentPlayerIds?.includes(String(playerId)) ||
      team.lockedPlayerIds?.includes(String(playerId))) {
      return false;
    }

    const player = playersById.get(String(playerId));
    if (!player) {
      return false;
    }

    if (!matchesGenderRequirement(player, discipline.genderRequirement)) {
      return false;
    }

    if (discipline.genderRequirement === GENDER_REQUIREMENT.MIXED_PAIR) {
      const genderKey = getPlayerGenderKey(player.gender);
      if (genderKey !== "male" && genderKey !== "female") {
        return false;
      }
    }

    if (discipline.playerCount === 1) {
      return validateDisciplineSelection({
        team,
        discipline,
        playerIds: [playerId],
        players,
        usedPlayerIds,
        allowReuse: true,
      }).ok;
    }

    return true;
  });
}

function combinations(values, size) {
  if (size <= 0) {
    return [[]];
  }

  if (values.length < size) {
    return [];
  }

  if (size === 1) {
    return values.map((value) => [value]);
  }

  const results = [];
  values.forEach((head, index) => {
    const tailCombos = combinations(values.slice(index + 1), size - 1);
    tailCombos.forEach((combo) => {
      results.push([head, ...combo]);
    });
  });
  return results;
}

function pickMixedPair({
  team,
  discipline,
  players,
  usedPlayerIds,
  appearanceCounts,
  allowReuse,
}) {
  const playersById = new Map(players.map((player) => [String(player.id), player]));
  const maleIds = [];
  const femaleIds = [];

  const eligible = new Set(
    eligiblePlayersForDiscipline(team, discipline, players, usedPlayerIds, allowReuse).map(String)
  );

  team.playerIds.forEach((playerId) => {
    if (!eligible.has(String(playerId))) {
      return;
    }
    const player = playersById.get(String(playerId));
    if (!player) {
      return;
    }
    const genderKey = getPlayerGenderKey(player.gender);
    if (genderKey === "male") {
      maleIds.push(String(playerId));
    } else if (genderKey === "female") {
      femaleIds.push(String(playerId));
    }
  });

  const rankedMales = sortByAppearanceCount(shuffle(maleIds), appearanceCounts);
  const rankedFemales = sortByAppearanceCount(shuffle(femaleIds), appearanceCounts);

  for (const maleId of rankedMales) {
    for (const femaleId of rankedFemales) {
      const validation = validateDisciplineSelection({
        team,
        discipline,
        playerIds: [maleId, femaleId],
        players,
        usedPlayerIds,
        allowReuse,
      });

      if (validation.ok) {
        return { ok: true, playerIds: validation.playerIds };
      }
    }
  }

  return {
    ok: false,
    error: `${discipline.name}: không đủ cặp nam/nữ để random.`,
  };
}

function pickPlayersForDiscipline({
  team,
  discipline,
  players,
  usedPlayerIds,
  appearanceCounts,
  allowReuse,
}) {
  if (
    discipline.genderRequirement === GENDER_REQUIREMENT.MIXED_PAIR &&
    discipline.playerCount === 2
  ) {
    return pickMixedPair({
      team,
      discipline,
      players,
      usedPlayerIds,
      appearanceCounts,
      allowReuse,
    });
  }

  const candidates = eligiblePlayersForDiscipline(
    team,
    discipline,
    players,
    usedPlayerIds,
    allowReuse
  );

  const ranked = sortByAppearanceCount(shuffle(candidates), appearanceCounts);
  const combos = combinations(ranked, discipline.playerCount);

  for (const combo of combos) {
    const validation = validateDisciplineSelection({
      team,
      discipline,
      playerIds: combo,
      players,
      usedPlayerIds,
      allowReuse,
    });

    if (validation.ok) {
      return { ok: true, playerIds: validation.playerIds };
    }
  }

  return {
    ok: false,
    error: `${discipline.name}: không đủ VĐV hợp lệ để random.`,
  };
}

function buildRandomSelections(team, teamData, players, allowReuse) {
  const usedPlayerIds = new Set();
  const appearanceCounts = new Map();
  const selections = {};
  const errors = [];

  team.playerIds.forEach((playerId) => {
    appearanceCounts.set(String(playerId), 0);
  });

  for (const discipline of teamData.disciplines) {
    const result = pickPlayersForDiscipline({
      team,
      discipline,
      players,
      usedPlayerIds,
      appearanceCounts,
      allowReuse,
    });

    if (!result.ok) {
      errors.push(result.error);
      continue;
    }

    result.playerIds.forEach((playerId) => {
      if (!allowReuse) {
        usedPlayerIds.add(String(playerId));
      }
      appearanceCounts.set(
        String(playerId),
        (appearanceCounts.get(String(playerId)) || 0) + 1
      );
    });
    selections[discipline.id] = result.playerIds;
  }

  return {
    ok: errors.length === 0,
    selections,
    errors,
    usedReuse: allowReuse,
  };
}

function formatRandomLineupFailure(team, players, errors) {
  const stats = computeTeamRosterStats(team, players);
  const playersById = new Map(players.map((player) => [String(player.id), player]));
  const missingCount = team.playerIds.filter((playerId) => !playersById.has(String(playerId))).length;

  const parts = [
    `${team.name}: ${errors.join(" ")}`,
    `Đội có ${stats.males} nam, ${stats.females} nữ (${stats.total} VĐV).`,
  ];

  if (missingCount > 0) {
    parts.push(`${missingCount} VĐV trên đội không khớp dữ liệu hệ thống — kiểm tra CLB/giới tính.`);
  }

  parts.push(
    "Gợi ý: thêm đủ VĐV nam/nữ theo nội dung giải, hoặc bật «Cho phép VĐV đá nhiều nội dung»."
  );

  return parts.join(" ");
}

export function randomizeMissingLineups(teamData, { matchupId, teamId, players = [], now = new Date() }) {
  const team = findTeam(teamData, teamId);
  if (!team) {
    return { ok: false, error: "Không tìm thấy đội." };
  }

  const configuredReuse = teamData.settings?.allowPlayerReusePerMatchup === true;
  const attempts = configuredReuse ? [true] : [false, true];

  let lastErrors = [];
  let usedReuseFallback = false;

  for (const allowReuse of attempts) {
    const built = buildRandomSelections(team, teamData, players, allowReuse);
    if (built.ok) {
      usedReuseFallback = allowReuse && !configuredReuse;
      const lockTime = new Date(now).toISOString();
      const timeLabel = new Date(now).toLocaleTimeString("vi-VN", {
        hour: "2-digit",
        minute: "2-digit",
      });
      const reuseNote = usedReuseFallback
        ? " Một số VĐV được xếp cho nhiều nội dung vì đội thiếu người."
        : "";
      const auditNote = `Đội ${team.name} không nộp đội hình trước hạn. Hệ thống đã tự động chọn đội hình lúc ${timeLabel}.${reuseNote}`;

      const lineup = normalizeLineup({
        matchupId,
        teamId,
        status: LINEUP_STATUS.LOCKED,
        selections: built.selections,
        lockedAt: lockTime,
        source: LINEUP_SOURCE.RANDOM,
        auditNote,
      });

      const key = lineupKey(matchupId, teamId);

      return {
        ok: true,
        teamData: normalizeTeamData({
          ...teamData,
          lineups: {
            ...teamData.lineups,
            [key]: lineup,
          },
        }),
        lineup,
        auditNote,
      };
    }

    lastErrors = built.errors;
  }

  return {
    ok: false,
    error: formatRandomLineupFailure(team, players, lastErrors),
  };
}

export function countPlayerAppearances(teamData, teamId) {
  const counts = new Map();

  Object.values(teamData.lineups || {}).forEach((lineup) => {
    if (lineup.teamId !== String(teamId)) {
      return;
    }

    Object.values(lineup.selections || {}).forEach((playerIds) => {
      playerIds.forEach((playerId) => {
        const key = String(playerId);
        counts.set(key, (counts.get(key) || 0) + 1);
      });
    });
  });

  return counts;
}

import { MATCHUP_STATUS } from "../constants.js";
import { normalizeTeamData } from "../models/index.js";

export const SCHEDULE_PUBLISH_STATUS = {
  DRAFT: "draft",
  PUBLISHED: "published",
  LOCKED: "locked",
};

const EDITABLE_STATUSES = new Set([
  SCHEDULE_PUBLISH_STATUS.DRAFT,
  SCHEDULE_PUBLISH_STATUS.PUBLISHED,
]);

function patchSettings(teamData, patch) {
  return normalizeTeamData({
    ...teamData,
    settings: {
      ...teamData.settings,
      ...patch,
    },
  });
}

export function normalizeSchedulePublish(state = {}) {
  const status = Object.values(SCHEDULE_PUBLISH_STATUS).includes(state.status)
    ? state.status
    : SCHEDULE_PUBLISH_STATUS.DRAFT;

  return {
    status,
    publishedAt: state.publishedAt || null,
    lockedAt: state.lockedAt || null,
    publishedBy: state.publishedBy ? String(state.publishedBy).trim() : "",
    lockedBy: state.lockedBy ? String(state.lockedBy).trim() : "",
  };
}

export function getSchedulePublishStatus(teamData) {
  return normalizeSchedulePublish(teamData?.settings?.schedulePublish || {});
}

export function canEditSchedule(teamData) {
  const publish = getSchedulePublishStatus(teamData);
  return EDITABLE_STATUSES.has(publish.status);
}

export function canPublishSchedule(teamData) {
  const publish = getSchedulePublishStatus(teamData);
  if (publish.status === SCHEDULE_PUBLISH_STATUS.LOCKED) {
    return { ok: false, error: "Lịch đã khóa, không thể công bố lại." };
  }

  const matchups = teamData?.matchups || [];
  if (matchups.length === 0) {
    return { ok: false, error: "Chưa có lượt đối đầu để công bố lịch." };
  }

  const unscheduled = matchups.filter((matchup) => !matchup.scheduledAt);
  if (unscheduled.length > 0) {
    return {
      ok: false,
      error: `Còn ${unscheduled.length} lượt chưa có thời gian thi đấu.`,
    };
  }

  return { ok: true };
}

export function publishSchedule(teamData, options = {}) {
  const validation = canPublishSchedule(teamData);
  if (!validation.ok) {
    return validation;
  }

  const now = options.now || new Date().toISOString();
  const publish = normalizeSchedulePublish({
    status: SCHEDULE_PUBLISH_STATUS.PUBLISHED,
    publishedAt: now,
    publishedBy: options.userId || options.publishedBy || "",
    lockedAt: null,
    lockedBy: "",
  });

  const nextMatchups = (teamData.matchups || []).map((matchup) => {
    if (matchup.status === MATCHUP_STATUS.SCHEDULED) {
      return { ...matchup, status: MATCHUP_STATUS.LINEUP_OPEN };
    }
    return matchup;
  });

  const nextData = patchSettings(
    normalizeTeamData({ ...teamData, matchups: nextMatchups }),
    { schedulePublish: publish }
  );

  return {
    ok: true,
    teamData: nextData,
    schedulePublish: publish,
  };
}

export function lockPublishedSchedule(teamData, options = {}) {
  const publish = getSchedulePublishStatus(teamData);
  if (publish.status !== SCHEDULE_PUBLISH_STATUS.PUBLISHED) {
    return { ok: false, error: "Chỉ khóa lịch đã công bố." };
  }

  const now = options.now || new Date().toISOString();
  const locked = normalizeSchedulePublish({
    ...publish,
    status: SCHEDULE_PUBLISH_STATUS.LOCKED,
    lockedAt: now,
    lockedBy: options.userId || options.lockedBy || "",
  });

  return {
    ok: true,
    teamData: patchSettings(teamData, { schedulePublish: locked }),
    schedulePublish: locked,
  };
}

export function unlockSchedule(teamData, options = {}) {
  const publish = getSchedulePublishStatus(teamData);
  if (publish.status !== SCHEDULE_PUBLISH_STATUS.LOCKED) {
    return { ok: false, error: "Lịch chưa ở trạng thái khóa." };
  }

  const next = normalizeSchedulePublish({
    status: SCHEDULE_PUBLISH_STATUS.PUBLISHED,
    publishedAt: publish.publishedAt,
    publishedBy: publish.publishedBy,
    lockedAt: null,
    lockedBy: "",
  });

  return {
    ok: true,
    teamData: patchSettings(teamData, { schedulePublish: next }),
    schedulePublish: next,
  };
}

export function isScheduleLocked(teamData) {
  return getSchedulePublishStatus(teamData).status === SCHEDULE_PUBLISH_STATUS.LOCKED;
}

import { SCORING_SYSTEM } from "../constants.js";

const DEFAULT_RULES = {
  targetScore: 21,
  winBy: 2,
  freezeAt: 20,
  sideSwitchAt: 11,
};

export function normalizeRallyRules(scoringFormat = {}) {
  return {
    targetScore: Number(scoringFormat.targetScore) || DEFAULT_RULES.targetScore,
    winBy: Number(scoringFormat.winBy) || DEFAULT_RULES.winBy,
    freezeAt: Number(scoringFormat.freezeAt) || DEFAULT_RULES.freezeAt,
    sideSwitchAt: Number(scoringFormat.sideSwitchAt) || DEFAULT_RULES.sideSwitchAt,
  };
}

export function isRallyScoring(discipline) {
  return discipline?.scoringFormat?.scoringSystem === SCORING_SYSTEM.RALLY;
}

export function getRallyWinner(scoreA, scoreB, rules = DEFAULT_RULES) {
  const normalized = normalizeRallyRules(rules);
  const a = Number(scoreA) || 0;
  const b = Number(scoreB) || 0;

  if (a === b) {
    return "";
  }

  const leader = Math.max(a, b);
  const trailer = Math.min(a, b);

  if (leader < normalized.targetScore) {
    return "";
  }

  if (leader - trailer < normalized.winBy) {
    return "";
  }

  return a > b ? "teamA" : "teamB";
}

export function validateRallyScore({ scoreA, scoreB, rules = DEFAULT_RULES }) {
  const normalized = normalizeRallyRules(rules);
  const a = Number(scoreA) || 0;
  const b = Number(scoreB) || 0;

  if (a < 0 || b < 0) {
    return { ok: false, error: "Điểm số không được âm." };
  }

  if (a === b) {
    return { ok: false, error: "Hai bên không được bằng điểm khi xác nhận kết quả." };
  }

  const winner = getRallyWinner(a, b, normalized);
  if (!winner) {
    return {
      ok: false,
      error: `Tỷ số không hợp lệ. Cần đạt ${normalized.targetScore} điểm và thắng cách ${normalized.winBy} điểm (VD: 21-19, 22-20).`,
    };
  }

  const freezeError = validateFreezeScenario(a, b, normalized);
  if (freezeError) {
    return { ok: false, error: freezeError };
  }

  return { ok: true, winnerSide: winner };
}

function validateFreezeScenario(scoreA, scoreB, rules) {
  const { freezeAt, targetScore, winBy } = rules;
  const winner = scoreA > scoreB ? "A" : "B";
  const winScore = Math.max(scoreA, scoreB);
  const loseScore = Math.min(scoreA, scoreB);

  if (winScore !== targetScore) {
    return null;
  }

  if (loseScore === freezeAt) {
    return `Không hợp lệ với Freeze @${freezeAt}: đội dẫn ${freezeAt} không thể thắng ${targetScore}-${freezeAt} khi không cầm giao bóng. Thử ${targetScore + 1}-${freezeAt} hoặc ${freezeAt}-${freezeAt} rồi tiếp.`;
  }

  if (loseScore === freezeAt - 1 && winScore === targetScore) {
    return null;
  }

  if (loseScore >= freezeAt && winScore - loseScore < winBy) {
    return `Cần thắng cách ${winBy} điểm.`;
  }

  return null;
}

export function getRallyScoringHints(discipline) {
  if (!isRallyScoring(discipline)) {
    return "";
  }

  const rules = normalizeRallyRules(discipline.scoringFormat);
  const parts = [
    `Rally đến ${rules.targetScore}, thắng cách ${rules.winBy}`,
    `Đổi sân @${rules.sideSwitchAt}`,
    `Freeze @${rules.freezeAt}`,
  ];

  if (discipline.scoringFormat?.rotationPoints) {
    parts.push(`Xoay vòng ${discipline.scoringFormat.rotationPoints} điểm`);
  }

  return parts.join(" · ");
}

