import { useEffect, useMemo, useRef, useState } from "react";
import { useSearchParams } from "react-router-dom";

import { getDirectorState } from "../../../../ai/director.js";
import { PERMISSIONS } from "../../../../auth/permissions.js";
import { useClub } from "../../../../context/ClubContext.jsx";
import { useAuth } from "../../../../context/AuthContext.jsx";
import { loadCourtsForClub, loadPlayersForClub } from "../../../../domain/clubStorage.js";
import { getTournament, assertTournamentAccess } from "../../../../domain/tournamentService.js";
import { useTenant } from "../../../../context/TenantContext.jsx";
import { TOURNAMENT_MODE } from "../../../../models/tournament/index.js";
import { buildTournamentDirectorSnapshot } from "../../../../tournament/engines/index.js";
import { hasSupabaseConfig } from "../../../../domain/matchLiveSync.js";
import { getRefereeSettings } from "../../../../tournament/engines/refereeEngine.js";
import { useMatchLiveScores } from "../../../../tournament/useMatchLiveScores.js";
import { buildDirectorBackPath } from "../services/directorService.js";

export function useDirectorState(tournamentId) {
  const [searchParams] = useSearchParams();
  const { activeClubId, activeClub, refreshClubs } = useClub();
  const { can, rbacEnabled, isAuthenticated } = useAuth();
  const { currentTenantId } = useTenant();

  const tournamentAccess = useMemo(() => {
    if (!rbacEnabled || !isAuthenticated) {
      return { ok: true };
    }

    return assertTournamentAccess(activeClubId, tournamentId, {
      tenantId: currentTenantId,
    });
  }, [activeClubId, currentTenantId, isAuthenticated, rbacEnabled, tournamentId]);

  const canUseDirector =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.DIRECTOR_USE, {
      clubId: activeClubId,
      venueId: activeClub?.venueId || null,
    }) ||
    can(PERMISSIONS.TOURNAMENT_UPDATE, {
      clubId: activeClubId,
      venueId: activeClub?.venueId || null,
    });

  const [localRevision, setLocalRevision] = useState(0);
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [scoreDialog, setScoreDialog] = useState(null);
  const [scoreA, setScoreA] = useState("");
  const [scoreB, setScoreB] = useState("");
  const [scoreNote, setScoreNote] = useState("");
  const [activeEventId, setActiveEventId] = useState(searchParams.get("eventId") || "");
  const [refereeDialogMatch, setRefereeDialogMatch] = useState(null);
  const [auditHistoryMatch, setAuditHistoryMatch] = useState(null);

  const { liveByMatchId, error: liveError } = useMatchLiveScores(
    activeClubId,
    tournamentId,
    hasSupabaseConfig()
  );

  const tournament = useMemo(
    () => getTournament(activeClubId, tournamentId),
    [activeClubId, tournamentId, localRevision]
  );

  const players = useMemo(
    () => loadPlayersForClub(activeClubId),
    [activeClubId, localRevision]
  );

  const courts = useMemo(
    () => loadCourtsForClub(activeClubId).filter((court) => court.active !== false),
    [activeClubId, localRevision]
  );

  const isDaily = tournament?.mode === TOURNAMENT_MODE.DAILY_PLAY;
  const savedEvents = tournament?.events || [];
  const activeEvent =
    savedEvents.find((event) => String(event.id) === String(activeEventId)) ||
    savedEvents.find((event) => (event.matches || []).length > 0) ||
    savedEvents[0] ||
    null;

  const lockedCourtIds = useMemo(
    () => getDirectorState(activeClubId).lockedCourts || [],
    [activeClubId, localRevision]
  );

  const snapshot = useMemo(
    () =>
      buildTournamentDirectorSnapshot({
        tournament,
        event: activeEvent,
        courts,
        players,
        lockedCourtIds,
      }),
    [tournament, activeEvent, courts, players, lockedCourtIds]
  );

  const refereeSettings = useMemo(() => getRefereeSettings(tournament), [tournament]);

  useEffect(() => {
    if (!activeEventId && activeEvent?.id) {
      setActiveEventId(activeEvent.id);
    }
  }, [activeEventId, activeEvent?.id]);

  const tournamentRef = useRef(tournament);
  const activeEventRef = useRef(activeEvent);

  useEffect(() => {
    tournamentRef.current = tournament;
    activeEventRef.current = activeEvent;
  }, [tournament, activeEvent]);

  const backPath = buildDirectorBackPath(tournament, tournamentId);
  const waitingMatches = snapshot.matches?.waiting || [];
  const onCourtMatches = snapshot.matches?.onCourt || [];
  const completedMatches = snapshot.matches?.completed || [];

  return {
    activeClubId,
    refreshClubs,
    canUseDirector,
    tournamentAccess,
    tournament,
    players,
    courts,
    isDaily,
    savedEvents,
    activeEvent,
    lockedCourtIds,
    snapshot,
    refereeSettings,
    liveByMatchId,
    liveError,
    localRevision,
    setLocalRevision,
    message,
    setMessage,
    error,
    setError,
    scoreDialog,
    setScoreDialog,
    scoreA,
    setScoreA,
    scoreB,
    setScoreB,
    scoreNote,
    setScoreNote,
    activeEventId,
    setActiveEventId,
    refereeDialogMatch,
    setRefereeDialogMatch,
    auditHistoryMatch,
    setAuditHistoryMatch,
    tournamentRef,
    activeEventRef,
    backPath,
    waitingMatches,
    onCourtMatches,
    completedMatches,
    tournamentId,
  };
}

import { VPR_ELIGIBLE_LEVELS } from "../../../models/tournament/constants.js";
import { getVprPointConfig } from "../storage/vprLocalStore.js";

/** V1: participant multiplier hook — always 1.0 until Pick_VN defines tiers. */
export function resolveParticipantMultiplier(_participantCount) {
  return 1.0;
}

export function lookupBasePoints(tournamentLevel, placement, configTable = null) {
  const table = configTable || getVprPointConfig();
  const byLevel = table?.[placement];
  if (!byLevel) {
    return 0;
  }
  const points = byLevel[tournamentLevel];
  return Number.isFinite(Number(points)) ? Number(points) : 0;
}

export function calculateVprPoints({
  tournamentLevel,
  placement,
  participantCount = 0,
  configTable = null,
}) {
  if (!VPR_ELIGIBLE_LEVELS.includes(tournamentLevel)) {
    return 0;
  }
  const base = lookupBasePoints(tournamentLevel, placement, configTable);
  const multiplier = resolveParticipantMultiplier(participantCount);
  return Math.round(base * multiplier);
}

import { VPR_PLACEMENT_RANK } from "../constants/vprPlacements.js";
import {
  listLeaderboardRows,
  listLedgerEntries,
  saveLeaderboardRows,
} from "../storage/vprLocalStore.js";

function betterPlacement(current, candidate) {
  if (!current) {
    return candidate;
  }
  const currentRank = VPR_PLACEMENT_RANK[current] || 99;
  const candidateRank = VPR_PLACEMENT_RANK[candidate] || 99;
  return candidateRank < currentRank ? candidate : current;
}

export function rebuildLeaderboardFromLedger(ledger = listLedgerEntries()) {
  const map = new Map();

  ledger.forEach((entry) => {
    const key = `${entry.category}::${entry.vprAthleteId}`;
    const current = map.get(key) || {
      category: entry.category,
      vprAthleteId: entry.vprAthleteId,
      displayName: entry.displayName || "",
      clubName: entry.clubName || "",
      region: entry.region || "",
      gender: entry.gender || "unknown",
      totalPoints: 0,
      tournamentsCount: 0,
      bestPlacement: null,
      tournamentIds: new Set(),
    };

    current.totalPoints += Number(entry.points) || 0;
    current.tournamentIds.add(`${entry.clubId}::${entry.tournamentId}`);
    current.tournamentsCount = current.tournamentIds.size;
    current.bestPlacement = betterPlacement(current.bestPlacement, entry.placement);
    current.displayName = entry.displayName || current.displayName;
    current.clubName = entry.clubName || current.clubName;
    current.region = entry.region || current.region;
    map.set(key, current);
  });

  const byCategory = new Map();
  for (const row of map.values()) {
    const { tournamentIds, ...rest } = row;
    const list = byCategory.get(rest.category) || [];
    list.push(rest);
    byCategory.set(rest.category, list);
  }

  const leaderboard = [];
  for (const [category, rows] of byCategory.entries()) {
    const sorted = rows.sort((a, b) => b.totalPoints - a.totalPoints);
    sorted.forEach((row, index) => {
      leaderboard.push({ ...row, category, rank: index + 1 });
    });
  }

  saveLeaderboardRows(leaderboard);
  return leaderboard;
}

export function queryPublicLeaderboard({
  category = null,
  region = null,
  gender = null,
  year = null,
  search = "",
} = {}) {
  let rows = listLeaderboardRows();
  if (!rows.length) {
    rows = rebuildLeaderboardFromLedger();
  }

  if (category) {
    rows = rows.filter((row) => row.category === category);
  }
  if (region && region !== "Tất cả") {
    rows = rows.filter((row) => row.region === region);
  }
  if (gender) {
    rows = rows.filter((row) => row.gender === gender);
  }
  if (year) {
    const ledger = listLedgerEntries().filter((entry) => {
      const awardedYear = entry.awardedAt ? new Date(entry.awardedAt).getFullYear() : null;
      return awardedYear === Number(year);
    });
    const athletePoints = new Map();
    ledger.forEach((entry) => {
      const key = `${entry.category}::${entry.vprAthleteId}`;
      athletePoints.set(key, (athletePoints.get(key) || 0) + (entry.points || 0));
    });
    rows = rows
      .map((row) => ({
        ...row,
        totalPoints: athletePoints.get(`${row.category}::${row.vprAthleteId}`) ?? 0,
      }))
      .filter((row) => row.totalPoints > 0)
      .sort((a, b) => b.totalPoints - a.totalPoints)
      .map((row, index) => ({ ...row, rank: index + 1 }));
  }
  if (search) {
    const q = search.trim().toLowerCase();
    rows = rows.filter((row) => row.displayName?.toLowerCase().includes(q));
  }

  return rows;
}

export function getAthleteLedgerHistory(vprAthleteId, category = null) {
  let rows = listLedgerEntries().filter((entry) => entry.vprAthleteId === vprAthleteId);
  if (category) {
    rows = rows.filter((entry) => entry.category === category);
  }
  return rows.sort((a, b) => String(b.awardedAt).localeCompare(String(a.awardedAt)));
}

export function getAthleteProfileSummary(vprAthleteId, category) {
  const history = getAthleteLedgerHistory(vprAthleteId, category);
  const leaderboard = listLeaderboardRows().find(
    (row) => row.vprAthleteId === vprAthleteId && row.category === category
  );
  const cumulative = [];
  let running = 0;
  [...history].reverse().forEach((entry) => {
    running += entry.points || 0;
    cumulative.push({ at: entry.awardedAt, points: running, tournamentName: entry.tournamentName });
  });

  return {
    totalPoints: history.reduce((sum, entry) => sum + (entry.points || 0), 0),
    rank: leaderboard?.rank || null,
    tournamentsCount: new Set(history.map((entry) => `${entry.clubId}::${entry.tournamentId}`)).size,
    bestPlacement: leaderboard?.bestPlacement || null,
    history,
    cumulativeChart: cumulative,
    displayName: leaderboard?.displayName || history[0]?.displayName || "",
    clubName: leaderboard?.clubName || history[0]?.clubName || "",
    region: leaderboard?.region || history[0]?.region || "",
  };
}

import { DEFAULT_VPR_POINT_TABLE } from "../constants/defaultPointConfig.js";

const KEYS = {
  pointConfig: "pickleball-vpr-point-config-v1",
  certifications: "pickleball-vpr-certifications-v1",
  athletes: "pickleball-vpr-athletes-v1",
  links: "pickleball-vpr-athlete-links-v1",
  ledger: "pickleball-vpr-ledger-v1",
  leaderboard: "pickleball-vpr-leaderboard-v1",
  audit: "pickleball-vpr-audit-v1",
};

function readJson(key, fallback) {
  if (typeof localStorage === "undefined") {
    return fallback;
  }
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch {
    return fallback;
  }
}

function writeJson(key, value) {
  if (typeof localStorage === "undefined") {
    return;
  }
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // ignore quota errors in tests
  }
}

let memoryStore = null;

function ensureMemoryStore() {
  if (!memoryStore) {
    memoryStore = {
      pointConfig: structuredClone(DEFAULT_VPR_POINT_TABLE),
      certifications: [],
      athletes: [],
      links: [],
      ledger: [],
      leaderboard: [],
      audit: [],
    };
  }
  return memoryStore;
}

function useMemory() {
  return typeof localStorage === "undefined";
}

export function resetVprLocalStoreForTests() {
  memoryStore = null;
  if (typeof localStorage !== "undefined") {
    Object.values(KEYS).forEach((key) => localStorage.removeItem(key));
  }
}

export function getVprPointConfig() {
  if (useMemory()) {
    return ensureMemoryStore().pointConfig;
  }
  const stored = readJson(KEYS.pointConfig, null);
  if (!stored) {
    writeJson(KEYS.pointConfig, DEFAULT_VPR_POINT_TABLE);
    return structuredClone(DEFAULT_VPR_POINT_TABLE);
  }
  return stored;
}

export function setVprPointConfig(table) {
  if (useMemory()) {
    ensureMemoryStore().pointConfig = table;
    return;
  }
  writeJson(KEYS.pointConfig, table);
}

export function listCertifications() {
  if (useMemory()) {
    return [...ensureMemoryStore().certifications];
  }
  return readJson(KEYS.certifications, []);
}

export function saveCertifications(rows) {
  if (useMemory()) {
    ensureMemoryStore().certifications = rows;
    return;
  }
  writeJson(KEYS.certifications, rows);
}

export function upsertCertification(row) {
  const rows = listCertifications();
  const idx = rows.findIndex(
    (item) =>
      item.clubId === row.clubId && String(item.tournamentId) === String(row.tournamentId)
  );
  if (idx >= 0) {
    rows[idx] = { ...rows[idx], ...row, updatedAt: new Date().toISOString() };
  } else {
    rows.push({
      id: row.id || `vpr-cert-${Date.now()}`,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      ...row,
    });
  }
  saveCertifications(rows);
  return rows.find(
    (item) =>
      item.clubId === row.clubId && String(item.tournamentId) === String(row.tournamentId)
  );
}

export function listAthletes() {
  if (useMemory()) {
