  }, [sessions, selectedShift]);

  const history = useMemo(
    () => buildHistoryFromSessions(filteredSessions),
    [filteredSessions]
  );

  const playerStats = useMemo(() => {
    return Object.entries(history)
      .map(([id, data]) => ({
        id,
        name: playerNameById[id] || data.name || `Player ${id}`,
        games: data.games || 0,
