  const [removeOwnerConfirmOpen, setRemoveOwnerConfirmOpen] = useState(false);
  const [clusterRevision, setClusterRevision] = useState(0);
  const [venueFilter, setVenueFilter] = useState(ADMIN_ALL_TENANTS_ID);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [deleteSaving, setDeleteSaving] = useState(false);

  const canPickTenant = isSuperAdmin || isPlatformScopedRole(user?.role);
  const tenants = useMemo(() => listTenants(), [message]);
  const effectiveVenueId = canPickTenant
    ? venueFilter === ADMIN_ALL_TENANTS_ID
      ? ADMIN_ALL_TENANTS_ID
      : venueFilter || currentTenantId || user?.venueId || null
    : currentTenantId || user?.venueId || null;
  const venueId =
    effectiveVenueId === ADMIN_ALL_TENANTS_ID ? ADMIN_ALL_TENANTS_ID : effectiveVenueId;
  const createVenueId =
    effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId;
  const clusters = useMemo(
    () => listClustersForAdminManagement(user, venueId),
    [user, venueId, message, clusterRevision]
  );
  const showVenueColumn =
    canPickTenant &&
    (venueFilter === ADMIN_ALL_TENANTS_ID ||
      clusters.some((cluster) => cluster.venueId !== effectiveVenueId));
  const organizationLabel =
    venueFilter === ADMIN_ALL_TENANTS_ID
      ? "Tất cả"
      : getTenantById(effectiveVenueId)?.name || effectiveVenueId || "—";
  const canManage =
    !rbacEnabled ||
    can(PERMISSIONS.CLUSTER_MANAGE, {
      tenantId: effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId,
      venueId: effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId,
    });

  useEffect(() => {
    if (!canPickTenant && currentTenantId) {
      setVenueFilter(currentTenantId);
    }
  }, [canPickTenant, currentTenantId]);

  useEffect(() => {
    if (!isCourtClustersEnabled()) {
      setError("Bật VITE_COURT_CLUSTERS_ENABLED=true để quản lý cụm sân.");
    }
  }, []);

  useEffect(() => {
    if (!canManage || !user?.id) {
      return;
    }
    void pullClusterContextForUser(user).then((result) => {
      if (result.ok) {
        refreshClusters();
        setClusterRevision((value) => value + 1);
      }
    });
  }, [canManage, refreshClusters, user]);

  const loadPendingClaims = async () => {
    const result = await listPendingCourtClaimRequests();
    if (result.ok) {
      setPendingClaims(result.requests || []);
    }
  };

  useEffect(() => {
    if (canManage) {
      void loadPendingClaims();
    }
  }, [canManage, message]);

  const handleReviewClaim = async (requestId, action) => {
    setReviewingId(requestId);
    setError(null);
    const result = await reviewCourtClaimRequest({
      requestId,
      action,
      reviewNote,
    });
    setReviewingId(null);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(action === "approve" ? "Đã duyệt yêu cầu gắn cụm." : "Đã từ chối yêu cầu.");
    setReviewNote("");
    refreshClusters();
    await loadPendingClaims();
  };

  const resetForm = () => {
    setForm(EMPTY_FORM);
    setEditingCluster(null);
  };

  const handleCreate = async () => {
    setError(null);
    setCreateSaving(true);
    const result = createCourtCluster({
      venueId: createVenueId,
      name: form.name,
      slug: form.slug || undefined,
      address: form.address,
      googleMapsUrl: form.googleMapsUrl,
      ownerUserId: user?.id || null,
      user,
    });

    if (!result.ok) {
      setCreateSaving(false);
      setError(result.error);
      return;
    }

    const cloudResult = await persistCourtClusterToCloud(result.cluster, { venueId, actor: user });
    setCreateSaving(false);

    if (!cloudResult.ok) {
      setError(cloudResult.error || "Không đồng bộ được cụm lên Supabase.");
      return;
    }

    setMessage(`Đã tạo cụm sân: ${result.cluster.name}`);
    setCreateOpen(false);
    resetForm();
    refreshClusters();
  };

  const openEditDialog = (cluster) => {
    setEditingCluster(cluster);
    setForm({
      name: cluster.name || "",
      slug: cluster.slug || "",
      address: cluster.address || "",
      googleMapsUrl: cluster.googleMapsUrl || "",
    });
    setEditOpen(true);
  };

  const handleEdit = async () => {
    if (!editingCluster) {
      return;
    }

    setError(null);
    setEditSaving(true);
    const result = updateCourtCluster(
      editingCluster.id,
      {
        name: form.name,
        slug: form.slug || undefined,
        address: form.address,
        googleMapsUrl: form.googleMapsUrl,
      },
      { user }
    );

    if (!result.ok) {
      setEditSaving(false);
      setError(result.error);
      return;
    }

    const cloudResult = await persistCourtClusterToCloud(result.cluster, { venueId, actor: user });
    setEditSaving(false);

    if (!cloudResult.ok) {
      setError(cloudResult.error || "Không đồng bộ được cụm lên Supabase.");
      return;
    }

    setMessage(`Đã cập nhật cụm sân: ${result.cluster.name}`);
    setEditOpen(false);
    resetForm();
    refreshClusters();
  };

  const handleToggleStatus = async (cluster) => {
    const nextStatus = cluster.status === "active" ? "inactive" : "active";
    const result = updateCourtCluster(cluster.id, { status: nextStatus }, { user });
    if (!result.ok) {
      setError(result.error);
      return;
    }

    const cloudResult = await persistCourtClusterToCloud(result.cluster, { venueId, actor: user });
    if (!cloudResult.ok) {
      setError(cloudResult.error || "Không đồng bộ trạng thái lên Supabase.");
      return;
    }

    setMessage(`Cập nhật trạng thái: ${result.cluster.name}`);
    refreshClusters();
  };

  const handleSyncToCloud = async () => {
    setError(null);
    setSyncSaving(true);
    const result = await syncClustersForVenueToCloud({
      clusters,
      venueId,
      actor: user,
    });
    setSyncSaving(false);

    if (!result.ok) {
      setError(result.error || "Đồng bộ cụm lên cloud thất bại.");
      return;
    }

    setMessage(`Đã đồng bộ ${result.synced ?? clusters.length} cụm lên Supabase.`);
    refreshClusters();
    setClusterRevision((value) => value + 1);
  };

  const handleDelete = async () => {
    if (!deleteTarget?.id) {
      return;
    }

    const deletedName = deleteTarget.name;
    setDeleteSaving(true);
    setError(null);
    const result = await removeCourtCluster({
      clusterId: deleteTarget.id,
      venueId: effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId,
      actor: user,
    });
    setDeleteSaving(false);
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(`Đã xóa cụm sân: ${deletedName}`);
    refreshClusters();
    setClusterRevision((value) => value + 1);
  };

  const openDeleteConfirm = (cluster) => {
    setDeleteTarget(cluster);
    setDeleteConfirmOpen(true);
  };

  const openClusterInfoDialog = async (cluster) => {
    setInfoOpen(true);
    setInfoCluster(cluster);
    setOwnerUserId(null);
    setOwnerLoading(false);
    setOwnerError(null);
    setOwnerProfile(null);

    const assignments = listAssignmentsForCluster(cluster.id) || [];
    const ownerAssignment = assignments.find((a) => a.role === "CLUSTER_OWNER");
    const nextOwnerUserId = cluster?.ownerUserId || ownerAssignment?.userId || null;
    setOwnerUserId(nextOwnerUserId);

    if (!nextOwnerUserId) {
      return;
    }

    if (!isValidProfileUserId(nextOwnerUserId)) {
      setOwnerError(
        "Gán chủ sân chưa đồng bộ cloud (ID không hợp lệ). Dùng Gán chủ và chọn user từ danh sách."
      );
      return;
    }

    setOwnerLoading(true);
    const result = await fetchProfileByUserId(nextOwnerUserId);
    setOwnerLoading(false);

    if (!result.ok) {
      setOwnerError(result.error || "Không tải được thông tin chủ sở hữu.");
      return;
    }

    setOwnerProfile(result.user);
  };

  const hasClusterOwner = Boolean(
    ownerUserId || listAssignmentsForCluster(infoCluster?.id || "").some((a) => a.role === "CLUSTER_OWNER")
  );
  const ownerIdIsValid = isValidProfileUserId(ownerUserId);

  const handleRemoveOwner = async () => {
    if (!infoCluster?.id) {
      return;
    }

    setError(null);
    setRemoveOwnerSaving(true);
    const result = await removeClusterOwner({ clusterId: infoCluster.id, venueId, actor: user });
    setRemoveOwnerSaving(false);
    setRemoveOwnerConfirmOpen(false);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage("Đã xóa gán chủ sân cho cụm.");
    setOwnerUserId(null);
    setOwnerProfile(null);
    setOwnerError(null);
    refreshClusters();
    const refreshed = getClusterById(infoCluster.id);
    if (refreshed) {
      setInfoCluster(refreshed);
    }
  };

  const loadAssignUsers = async () => {
    setAssignUsersLoading(true);
    const result = await listUsers({ search: "" });
    setAssignUsersLoading(false);
    if (result.ok) {
      setAssignUsers(result.users || []);
    }
  };

  const openAssignDialog = (clusterId = null) => {
    const initialClusterIds = clusterId ? [clusterId] : [];
    setAssignForm({ user: null, clusterIds: initialClusterIds });
    setAssignOpen(true);
    void loadAssignUsers();
  };

  const handleAssign = async () => {
    setError(null);
    setAssignSaving(true);
    const result = await assignClusterOwnerToUser({
      userId: assignForm.user?.id,
      clusterIds: assignForm.clusterIds,
      venueId,
      actor: user,
    });
    setAssignSaving(false);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage("Đã cập nhật gán chủ sân cho cụm (Supabase)");
    setAssignOpen(false);
    refreshClusters();
    setClusterRevision((value) => value + 1);
  };

  if (!canManage) {
    return <Alert severity="warning">Bạn không có quyền quản lý cụm sân.</Alert>;
  }

  const formFields = (
    <Stack spacing={2} sx={{ pt: 1 }}>
      <TextField
        label="Tên cụm sân"
        value={form.name}
        onChange={(event) => setForm((prev) => ({ ...prev, name: event.target.value }))}
        placeholder="Cụm sân Nam Long"
        fullWidth
        required
      />
      <TextField
        label="Slug (tuỳ chọn)"
        value={form.slug}
        onChange={(event) => setForm((prev) => ({ ...prev, slug: event.target.value }))}
        placeholder="nam-long"
        fullWidth
      />
      <TextField
        label="Địa chỉ"
        value={form.address}
        onChange={(event) => setForm((prev) => ({ ...prev, address: event.target.value }))}
        placeholder="123 Đường Nam Long, Quận 7, TP.HCM"
        fullWidth
        multiline
        minRows={2}
      />
      <TextField
        label="Link Google Maps"
        value={form.googleMapsUrl}
        onChange={(event) => setForm((prev) => ({ ...prev, googleMapsUrl: event.target.value }))}
        placeholder="https://www.google.com/maps/dir/?api=1&destination=..."
        fullWidth
        helperText="Bấm Chỉ đường sẽ mở link này trên Google Maps"
      />
    </Stack>
  );

  return (
    <Box>
      <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 2 }}>
        <Box>
          <Typography variant="h5" fontWeight={700}>
            Quản lý cụm sân
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Tổ chức: {organizationLabel}
          </Typography>
        </Box>
        <Stack direction="row" spacing={1} alignItems="center">
          {canPickTenant && tenants.length > 0 && (
            <FormControl size="small" sx={{ minWidth: 220 }}>
              <InputLabel id="cluster-tenant-picker">Chọn tổ chức</InputLabel>
              <Select
                labelId="cluster-tenant-picker"
                value={venueFilter || ADMIN_ALL_TENANTS_ID}
                label="Chọn tổ chức"
                onChange={(event) => {
                  const nextValue = event.target.value;
                  setVenueFilter(nextValue);
                  if (nextValue !== ADMIN_ALL_TENANTS_ID) {
                    switchTenant(nextValue);
                  }
                  setClusterRevision((value) => value + 1);
                }}
              >
                <MenuItem value={ADMIN_ALL_TENANTS_ID}>Tất cả</MenuItem>
                {tenants.map((tenant) => (
                  <MenuItem key={tenant.id} value={tenant.id}>
                    {tenant.name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          )}
          <Button variant="outlined" onClick={() => openAssignDialog()}>
            Gán chủ sân
          </Button>
          {canPickTenant && (
            <Button variant="outlined" onClick={handleSyncToCloud} disabled={syncSaving || clusters.length === 0}>
              {syncSaving ? "Đang đồng bộ…" : "Đồng bộ lên cloud"}
            </Button>
          )}
          <Button
            variant="contained"
            startIcon={<AddIcon />}
            onClick={() => {
              resetForm();
              setCreateOpen(true);
            }}
            disabled={!createVenueId}
          >
            Thêm cụm sân
          </Button>
        </Stack>
      </Stack>

      {message && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message}
        </Alert>
      )}
      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {pendingClaims.length > 0 && (
        <Card sx={{ mb: 2 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={700} sx={{ mb: 1.5 }}>
              Yêu cầu gắn cụm sân ({pendingClaims.length})
            </Typography>
            <TableContainer component={Paper} variant="outlined">
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>Người yêu cầu</TableCell>
                    <TableCell>Cụm sân</TableCell>
                    <TableCell>Ghi chú</TableCell>
                    <TableCell>Thời gian</TableCell>
                    <TableCell align="right">Thao tác</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {pendingClaims.map((request) => (
                    <TableRow key={request.id} hover>
                      <TableCell>
                        <Typography variant="body2" fontWeight={600}>
                          {request.userDisplayName || request.userId}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {request.userEmail || "—"}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        {(request.clusterIds || []).map((clusterId) => {
                          const cluster = getClusterById(clusterId);
                          return (
                            <Chip
                              key={clusterId}
                              size="small"
                              label={cluster?.name || clusterId}
                              sx={{ mr: 0.5, mb: 0.5 }}
                            />
                          );
                        })}
                      </TableCell>
                      <TableCell sx={{ maxWidth: 200 }}>
                        <Typography variant="body2" noWrap title={request.message}>
                          {request.message || "—"}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        {request.requestedAt
                          ? new Date(request.requestedAt).toLocaleString("vi-VN")
                          : "—"}
                      </TableCell>
                      <TableCell align="right">
                        <Stack direction="row" spacing={1} justifyContent="flex-end">
                          <Button
                            size="small"
                            variant="contained"
                            color="success"
                            disabled={reviewingId === request.id}
                            onClick={() => handleReviewClaim(request.id, "approve")}
                          >
                            Duyệt
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            disabled={reviewingId === request.id}
                            onClick={() => handleReviewClaim(request.id, "reject")}
                          >
                            Từ chối
                          </Button>
                        </Stack>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
            <TextField
              size="small"
              label="Ghi chú duyệt (áp dụng lần duyệt tiếp theo)"
              value={reviewNote}
              onChange={(event) => setReviewNote(event.target.value)}
              fullWidth
              sx={{ mt: 2 }}
            />
          </CardContent>
        </Card>
      )}

      <Card>
        <CardContent>
          <TableContainer component={Paper} variant="outlined">
            <Table size="small">
              <TableHead>
                <TableRow>
                  <TableCell>ID</TableCell>
                  <TableCell>Tên cụm</TableCell>
                  {showVenueColumn && <TableCell>Tổ chức</TableCell>}
                  <TableCell>Địa chỉ</TableCell>
                  <TableCell>Số sân</TableCell>
                  <TableCell>Chủ sân</TableCell>
                  <TableCell>Trạng thái</TableCell>
                  <TableCell align="right">Thao tác</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {clusters.map((cluster) => (
                  <TableRow key={cluster.id} hover>
                    <TableCell>{cluster.id}</TableCell>
                    <TableCell>{cluster.name}</TableCell>
                    {showVenueColumn && (
                      <TableCell>
                        <Typography variant="caption" color="text.secondary">
                          {tenants.find((tenant) => tenant.id === cluster.venueId)?.name ||
                            cluster.venueId}
                        </Typography>
                      </TableCell>
                    )}
                    <TableCell sx={{ maxWidth: 240 }}>
                      <Typography variant="body2" noWrap title={cluster.address || "—"}>
                        {cluster.address || "—"}
                      </Typography>
                    </TableCell>
                    <TableCell>{cluster.courtCount || 0}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={isClusterAssigned(cluster.id) ? "Đã gán" : "Chưa gán"}
                        color={isClusterAssigned(cluster.id) ? "primary" : "warning"}
                        variant={isClusterAssigned(cluster.id) ? "filled" : "outlined"}
                      />
                    </TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={cluster.status === "active" ? "Hoạt động" : "Tạm dừng"}
                        color={cluster.status === "active" ? "success" : "default"}
                      />
                    </TableCell>
                    <TableCell align="right">
                      <Stack direction="row" spacing={0.5} justifyContent="flex-end" alignItems="center">
                        <Tooltip title="Chỉ đường Google Maps">
                          <span>
                            <IconButton
                              size="small"
                              color="primary"
                              disabled={!cluster.googleMapsUrl}
                              onClick={() => openClusterInGoogleMaps(cluster)}
                            >
                              <DirectionsIcon fontSize="small" />
                            </IconButton>
                          </span>
                        </Tooltip>
                        <Tooltip title="Thông tin cụm sân">
                          <span>
                            <IconButton size="small" color="primary" onClick={() => void openClusterInfoDialog(cluster)}>
                              <InfoOutlinedIcon fontSize="small" />
                            </IconButton>
                          </span>
                        </Tooltip>
                        <Button size="small" startIcon={<EditIcon />} onClick={() => openEditDialog(cluster)}>
                          Sửa
                        </Button>
                        <Button size="small" onClick={() => openAssignDialog(cluster.id)}>
                          Gán chủ
                        </Button>
                        <Button size="small" onClick={() => handleToggleStatus(cluster)}>
                          {cluster.status === "active" ? "Tạm dừng" : "Kích hoạt"}
                        </Button>
                        <Button
                          size="small"
                          color="error"
                          onClick={() => openDeleteConfirm(cluster)}
                        >
                          Xóa
                        </Button>
                      </Stack>
                    </TableCell>
                  </TableRow>
                ))}
                {clusters.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={showVenueColumn ? 8 : 7}>
                      <Typography variant="body2" color="text.secondary">
                        Chưa có cụm sân. Tạo cụm đầu tiên (vd. Nam Long, Nam Lý).
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </TableContainer>
        </CardContent>
      </Card>

      <Dialog open={createOpen} onClose={() => setCreateOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>Thêm cụm sân</DialogTitle>
        <DialogContent>{formFields}</DialogContent>
        <DialogActions>
          <Button onClick={() => setCreateOpen(false)}>Huỷ</Button>
          <Button variant="contained" onClick={handleCreate} disabled={createSaving || !form.name.trim()}>
            {createSaving ? "Đang tạo…" : "Tạo"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={editOpen} onClose={() => setEditOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>Sửa cụm sân</DialogTitle>
        <DialogContent>{formFields}</DialogContent>
        <DialogActions>
          <Button onClick={() => setEditOpen(false)}>Huỷ</Button>
          <Button variant="contained" onClick={handleEdit} disabled={editSaving || !form.name.trim()}>
            {editSaving ? "Đang lưu…" : "Lưu"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={assignOpen} onClose={() => setAssignOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>Gán chủ sân cho cụm</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ pt: 1 }}>
            <Autocomplete
              options={assignUsers}
              loading={assignUsersLoading}
              value={assignForm.user}
              onChange={(_event, nextUser) =>
                setAssignForm((prev) => ({ ...prev, user: nextUser }))
              }
              getOptionLabel={(option) =>
                `${option.displayName || option.email || option.id} (${option.email || option.id})`
              }
              isOptionEqualToValue={(option, value) => option.id === value?.id}
              renderInput={(params) => (
                <TextField
                  {...params}
                  label="Chủ sân"
                  placeholder="Tìm theo tên hoặc email"
                  helperText="Chọn tài khoản từ danh sách người dùng"
                  fullWidth
                />
              )}
            />
            <Typography variant="subtitle2">Cụm được gán</Typography>
            {clusters.map((cluster) => (
              <FormControlLabel
                key={cluster.id}
                control={
                  <Checkbox
                    checked={assignForm.clusterIds.includes(cluster.id)}
                    onChange={(event) => {
                      const checked = event.target.checked;
                      setAssignForm((prev) => ({
                        ...prev,
                        clusterIds: checked
                          ? [...prev.clusterIds, cluster.id]
                          : prev.clusterIds.filter((id) => id !== cluster.id),
                      }));
                    }}
                  />
                }
                label={`${cluster.name} (${cluster.id})`}
              />
            ))}
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setAssignOpen(false)}>Huỷ</Button>
          <Button
            variant="contained"
            onClick={handleAssign}
            disabled={assignSaving || !assignForm.user?.id || assignForm.clusterIds.length === 0}
          >
            {assignSaving ? "Đang lưu…" : "Lưu gán"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog
        open={infoOpen}
        onClose={() => {
          setInfoOpen(false);
          setInfoCluster(null);
          setOwnerUserId(null);
          setOwnerLoading(false);
          setOwnerError(null);
          setOwnerProfile(null);
        }}
        fullWidth
        maxWidth="sm"
      >
        <DialogTitle>Thông tin cụm sân</DialogTitle>
        <DialogContent>
          {!infoCluster ? (
            <Typography variant="body2" color="text.secondary">
              — 
            </Typography>
          ) : (
            <Stack spacing={1.5} sx={{ pt: 1 }}>
              <Box>
                <Typography variant="subtitle1" fontWeight={700}>
                  {infoCluster.name}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  ID: {infoCluster.id}
                </Typography>
              </Box>

              <Box>
                <Typography variant="body2" fontWeight={600}>
                  Địa chỉ
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {infoCluster.address || "—"}
                </Typography>
              </Box>

              <Stack direction="row" spacing={1.25} alignItems="center" flexWrap="wrap">
                <Typography variant="body2" color="text.secondary">
                  Số sân: <b>{infoCluster.courtCount || 0}</b>
                </Typography>
                <Chip
                  size="small"
                  label={infoCluster.status === "active" ? "Hoạt động" : "Tạm dừng"}
                  color={infoCluster.status === "active" ? "success" : "default"}
                />
              </Stack>

              <Box>
                <Typography variant="body2" fontWeight={600}>
                  Google Maps
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ wordBreak: "break-word" }}>
                  {infoCluster.googleMapsUrl || "—"}
                </Typography>
                <Box sx={{ mt: 1 }}>
                  <Button
                    size="small"
                    variant="outlined"
                    startIcon={<DirectionsIcon fontSize="small" />}
                    disabled={!infoCluster.googleMapsUrl}
                    onClick={() => openClusterInGoogleMaps(infoCluster)}
                    sx={{ textTransform: "none" }}
                  >
                    Chỉ đường
                  </Button>
                </Box>
              </Box>

              <Box>
                <Typography variant="body2" fontWeight={600}>
                  Chủ sở hữu (CLUSTER_OWNER)
                </Typography>
                {ownerLoading ? (
                  <Typography variant="body2" color="text.secondary">
                    Đang tải...
                  </Typography>
                ) : (
                  <Stack spacing={0.5} sx={{ mt: 0.5 }}>
                    <Stack direction="row" spacing={1} alignItems="center" flexWrap="wrap">
                      <Typography variant="body2" color="text.secondary">
                        ID chủ sân:
                      </Typography>
                      <Typography
                        variant="body2"
                        component="code"
                        sx={{ fontFamily: "monospace", wordBreak: "break-all" }}
                      >
                        {ownerUserId || "—"}
                      </Typography>
                      {ownerUserId && !ownerIdIsValid && (
                        <Chip size="small" color="warning" label="Legacy (email)" />
                      )}
                    </Stack>
                    <Typography variant="body2" color="text.secondary">
                      Tên hiển thị: <b>{ownerProfile?.displayName || "—"}</b>
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      SĐT: <b>{ownerProfile?.phone || "—"}</b>
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      Email: <b>{ownerProfile?.email || "—"}</b>
                    </Typography>
                    {hasClusterOwner && (
                      <Box sx={{ mt: 1 }}>
                        <Button
                          size="small"
                          color="error"
                          variant="outlined"
                          disabled={removeOwnerSaving}
                          onClick={() => setRemoveOwnerConfirmOpen(true)}
                        >
                          Xóa gán chủ sân
                        </Button>
                      </Box>
                    )}
                  </Stack>
                )}
                {ownerError && (
                  <Typography variant="caption" color="error" sx={{ display: "block", mt: 0.75 }}>
                    {ownerError}
                  </Typography>
                )}
              </Box>
            </Stack>
          )}
        </DialogContent>
        <DialogActions>
          <Button
            onClick={() => {
              setInfoOpen(false);
              setInfoCluster(null);
              setOwnerUserId(null);
              setOwnerLoading(false);
              setOwnerError(null);
              setOwnerProfile(null);
            }}
          >
            Đóng
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={removeOwnerConfirmOpen} onClose={() => setRemoveOwnerConfirmOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>Xóa gán chủ sân?</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary">
            Thao tác này gỡ chủ sân khỏi cụm <b>{infoCluster?.name}</b> trên cloud và trình duyệt.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRemoveOwnerConfirmOpen(false)}>Huỷ</Button>
          <Button color="error" variant="contained" onClick={handleRemoveOwner} disabled={removeOwnerSaving}>
            {removeOwnerSaving ? "Đang xóa…" : "Xóa gán"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={deleteConfirmOpen} onClose={() => setDeleteConfirmOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>Xóa cụm sân?</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary">
            Bạn sắp xóa cụm <b>{deleteTarget?.name}</b> khỏi hệ thống
            {deleteTarget?.venueId ? ` (tổ chức: ${deleteTarget.venueId})` : ""}. Thao tác không
            hoàn tác trên cloud.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteConfirmOpen(false)}>Huỷ</Button>
          <Button color="error" variant="contained" onClick={handleDelete} disabled={deleteSaving}>
            {deleteSaving ? "Đang xóa…" : "Xóa cụm"}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  FormControl,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  Tab,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Tabs,
  TextField,
  Typography,
} from "@mui/material";

import { useAuth } from "../../context/AuthContext.jsx";
import { useClub } from "../../context/ClubContext.jsx";
import { listTournaments } from "../../domain/tournamentService.js";
import { PERMISSIONS } from "../../auth/permissions.js";
import { VPR_CATEGORY_OPTIONS } from "../../features/vpr-ranking/constants/vprCategories.js";
import { VPR_PLACEMENT_LABELS } from "../../features/vpr-ranking/constants/vprPlacements.js";
import {
  listVprLedger,
  manualAdjustVprPoints,
  recalculateTournamentVpr,
} from "../../features/vpr-ranking/services/vprAwardService.js";
import { queryPublicLeaderboard } from "../../features/vpr-ranking/services/vprLeaderboardService.js";
import { listVprAuditLogs } from "../../features/vpr-ranking/storage/vprLocalStore.js";

export default function RankingManagementPage() {
  const { can, user } = useAuth();
  const { activeClubId, refreshClubs } = useClub();
  const [tab, setTab] = useState(0);
  const [category, setCategory] = useState("men_single");
  const [tournamentId, setTournamentId] = useState("");
  const [manualAthleteId, setManualAthleteId] = useState("");
  const [manualDelta, setManualDelta] = useState("");
  const [manualReason, setManualReason] = useState("");
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);

  const canView = can(PERMISSIONS.RANKING_VIEW);
  const canManage = can(PERMISSIONS.RANKING_MANAGE);

  const leaderboard = useMemo(
    () => queryPublicLeaderboard({ category }),
    [category]
  );
  const ledger = useMemo(() => listVprLedger({ category }), [category]);
  const auditLogs = useMemo(() => listVprAuditLogs().slice(0, 100), [tab, message]);

  const tournaments = useMemo(() => listTournaments(activeClubId), [activeClubId, message]);

  if (!canView) {
    return <Alert severity="warning">Bạn không có quyền xem quản trị VPR.</Alert>;
  }

  const handleRecalculate = async () => {
    if (!tournamentId || !canManage) {
      return;
    }
    setError(null);
    const result = await recalculateTournamentVpr(activeClubId, tournamentId, {
      actorUserId: user?.id,
    });
    refreshClubs();
    if (!result.ok) {
      setError(result.error || result.reason);
      return;
    }
    setMessage("Đã tính lại điểm VPR cho giải.");
  };

  const handleManualAdjust = () => {
    if (!canManage) {
      return;
    }
    const result = manualAdjustVprPoints({
      vprAthleteId: manualAthleteId,
      category,
      delta: Number(manualDelta),
      reason: manualReason,
      actorUserId: user?.id,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage("Đã điều chỉnh điểm thủ công.");
    setManualDelta("");
    setManualReason("");
  };

  return (
    <Box>
      <Typography variant="h5" fontWeight={700} sx={{ mb: 2 }}>
        Quản trị VPR Ranking
      </Typography>
      {message && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message}
        </Alert>
      )}
      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      <Tabs value={tab} onChange={(_, value) => setTab(value)} sx={{ mb: 2 }}>
        <Tab label="BXH" />
        <Tab label="Lịch sử điểm" />
        <Tab label="Tính lại" />
        {canManage && <Tab label="Điều chỉnh" />}
        <Tab label="Audit" />
      </Tabs>

      <FormControl size="small" sx={{ minWidth: 200, mb: 2 }}>
        <InputLabel>Nội dung</InputLabel>
        <Select label="Nội dung" value={category} onChange={(e) => setCategory(e.target.value)}>
          {VPR_CATEGORY_OPTIONS.map((item) => (
            <MenuItem key={item.id} value={item.id}>
              {item.label}
            </MenuItem>
          ))}
        </Select>
      </FormControl>

      {tab === 0 && (
        <TableContainer component={Paper} variant="outlined">
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Hạng</TableCell>
                <TableCell>VĐV</TableCell>
                <TableCell>CLB</TableCell>
                <TableCell>Khu vực</TableCell>
                <TableCell align="right">Điểm</TableCell>
                <TableCell align="right">Giải</TableCell>
                <TableCell>TT tốt nhất</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {leaderboard.map((row) => (
                <TableRow key={`${row.category}-${row.vprAthleteId}`}>
                  <TableCell>{row.rank}</TableCell>
                  <TableCell>{row.displayName}</TableCell>
                  <TableCell>{row.clubName}</TableCell>
                  <TableCell>{row.region}</TableCell>
                  <TableCell align="right">{row.totalPoints}</TableCell>
                  <TableCell align="right">{row.tournamentsCount}</TableCell>
                  <TableCell>
                    {VPR_PLACEMENT_LABELS[row.bestPlacement] || row.bestPlacement || "—"}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {tab === 1 && (
        <TableContainer component={Paper} variant="outlined">
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Thời gian</TableCell>
                <TableCell>Giải</TableCell>
                <TableCell>VĐV</TableCell>
                <TableCell>Thành tích</TableCell>
                <TableCell align="right">Điểm</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {ledger.map((row) => (
                <TableRow key={row.id}>
                  <TableCell>{new Date(row.awardedAt).toLocaleString("vi-VN")}</TableCell>
                  <TableCell>{row.tournamentName}</TableCell>
                  <TableCell>{row.displayName}</TableCell>
                  <TableCell>{VPR_PLACEMENT_LABELS[row.placement] || row.placement}</TableCell>
                  <TableCell align="right">{row.points}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {tab === 2 && canManage && (
        <Stack spacing={2} maxWidth={480}>
          <FormControl fullWidth size="small">
            <InputLabel>Giải</InputLabel>
            <Select
              label="Giải"
              value={tournamentId}
              onChange={(e) => setTournamentId(e.target.value)}
            >
              {tournaments.map((t) => (
                <MenuItem key={t.id} value={t.id}>
                  {t.name}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
          <Button variant="contained" disabled={!tournamentId} onClick={handleRecalculate}>
            Tính lại điểm VPR
          </Button>
        </Stack>
      )}

      {tab === 3 && canManage && (
        <Stack spacing={2} maxWidth={480}>
          <TextField
            label="VPR Athlete ID"
            size="small"
            value={manualAthleteId}
            onChange={(e) => setManualAthleteId(e.target.value)}
          />
          <TextField
            label="Điểm (+/-)"
            size="small"
            type="number"
            value={manualDelta}
            onChange={(e) => setManualDelta(e.target.value)}
          />
          <TextField
            label="Lý do"
            size="small"
            value={manualReason}
            onChange={(e) => setManualReason(e.target.value)}
          />
          <Button variant="contained" onClick={handleManualAdjust}>
            Áp dụng điều chỉnh
          </Button>
        </Stack>
      )}

      {tab === (canManage ? 4 : 3) && (
        <TableContainer component={Paper} variant="outlined">
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Thời gian</TableCell>
                <TableCell>Hành động</TableCell>
                <TableCell>Giải</TableCell>
                <TableCell>VĐV</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {auditLogs.map((row) => (
                <TableRow key={row.id}>
                  <TableCell>{new Date(row.createdAt).toLocaleString("vi-VN")}</TableCell>
                  <TableCell>{row.action}</TableCell>
                  <TableCell>{row.tournamentId || "—"}</TableCell>
                  <TableCell>{row.vprAthleteId || "—"}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";

import { useTenant } from "../../context/TenantContext.jsx";
import { useClub } from "../../context/ClubContext.jsx";
import { usePlatformRuntime } from "../../core/platform/app/usePlatformRuntime.js";
import { buildRuntimeAccessState } from "../../core/platform/app/runtimeAccess.js";
import {
  createTenant,
  listTenantsWithStats,
  renameTenant,
  setTenantStatus,
  TENANT_STATUS,
} from "../../features/tenant/index.js";

const STATUS_LABELS = {
  active: "Active",
  inactive: "Inactive",
  trial: "Trial",
  suspended: "Suspended",
};

function statusColor(status) {
  if (status === TENANT_STATUS.ACTIVE) return "success";
  if (status === TENANT_STATUS.TRIAL) return "info";
  if (status === TENANT_STATUS.SUSPENDED) return "warning";
  return "default";
}

export default function TenantManagement() {
  const { switchTenant, refreshTenant, isSuperAdmin } = useTenant();
  const { refreshClubs } = useClub();
  const runtime = usePlatformRuntime();
  const [createOpen, setCreateOpen] = useState(false);
  const [renameTarget, setRenameTarget] = useState(null);
  const [newName, setNewName] = useState("");
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [platformPreview, setPlatformPreview] = useState(null);
  const [accessAllowed, setAccessAllowed] = useState(true);

  const tenants = useMemo(() => listTenantsWithStats(), [message]);

  useEffect(() => {
    try {
      const primaryTenant = tenants?.[0];
      if (!primaryTenant) {
        setPlatformPreview({ status: "idle" });
        return;
      }

      const seed = runtime.ensureSeed({
        tenantInput: {
          name: primaryTenant.name,
          tenant_id: primaryTenant.id,
          plan: primaryTenant.plan || "trial",
        },
        subscriptionInput: {
          tenant_id: primaryTenant.id,
          plan: primaryTenant.plan || "trial",
          feature_flags: { mobile: true, ai: true },
        },
      });

      const accessState = buildRuntimeAccessState(
        runtime,
        {
          user_id: "demo-admin",
          tenant_id: primaryTenant.id,
          role: "SUPER_ADMIN",
        },
        "tenant.manage",
        primaryTenant.id,
        { source: "tenant.management" }
      );

      setAccessAllowed(accessState.allowed);
      setPlatformPreview({
        status: seed.subscription ? "ready" : "initialized",
        tenantName: seed.tenant?.name || primaryTenant.name,
        tenantId: seed.tenant?.tenant_id || primaryTenant.id,
        plan: seed.tenant?.plan || primaryTenant.plan || "trial",
        mobileEnabled: runtime.subscriptionService.hasFeature(seed.tenant.tenant_id, "mobile"),
        aiEnabled: runtime.subscriptionService.hasFeature(seed.tenant.tenant_id, "ai"),
        access: accessState.allowed ? "allowed" : "denied",
      });
    } catch (platformError) {
      setPlatformPreview({ status: "error", message: platformError.message });
    }
  }, [runtime, tenants]);

  if (!isSuperAdmin) {
    return (
      <Alert severity="error">Chỉ SUPER_ADMIN mới truy cập được trang này.</Alert>
    );
  }

  const handleCreate = () => {
    setError(null);
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác quản lý tenant.");
      return;
    }

    const result = createTenant(newName, { status: TENANT_STATUS.TRIAL, plan: "trial" });

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(`Đã tạo tenant "${result.tenant.name}".`);
    setNewName("");
    setCreateOpen(false);
    refreshTenant();
  };

  const handleRename = () => {
    if (!renameTarget) return;

    setError(null);
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác quản lý tenant.");
      return;
    }

    const result = renameTenant(renameTarget.id, newName);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(`Đã đổi tên tenant thành "${result.tenant.name}".`);
    setRenameTarget(null);
    setNewName("");
    refreshTenant();
  };

  const handleToggleStatus = (tenant) => {
    setError(null);
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác quản lý tenant.");
      return;
    }

    const nextStatus =
      tenant.status === TENANT_STATUS.ACTIVE || tenant.status === TENANT_STATUS.TRIAL
        ? TENANT_STATUS.SUSPENDED
        : TENANT_STATUS.ACTIVE;

    const result = setTenantStatus(tenant.id, nextStatus);
    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(`Đã cập nhật trạng thái tenant "${tenant.name}".`);
    refreshTenant();
  };

  const handleManage = (tenant) => {
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác quản lý tenant.");
      return;
    }

    const result = switchTenant(tenant.id);
    if (!result.ok) {
      setError(result.error);
      return;
    }

    refreshClubs();
    setMessage(`Đang quản trị tenant "${tenant.name}".`);
  };

  return (
    <Box>
      <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 2 }}>
        <Box>
          <Typography variant="h5" fontWeight={800}>
            Tenant Management
          </Typography>
          <Typography color="text.secondary">
            Quản lý cụm sân / cơ sở pickleball (multi-tenant).
          </Typography>
        </Box>
        <Button startIcon={<AddIcon />} variant="contained" onClick={() => setCreateOpen(true)} disabled={!accessAllowed}>
          Tạo tenant
        </Button>
      </Stack>

      {platformPreview && (
        <Card variant="outlined" sx={{ mb: 2 }}>
          <CardContent>
            <Stack
              direction={{ xs: "column", sm: "row" }}
              spacing={1.5}
              justifyContent="space-between"
              alignItems={{ xs: "flex-start", sm: "center" }}
            >
              <Box>
                <Typography variant="subtitle1" fontWeight={700}>
                  Platform v5 preview
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {platformPreview.status === "ready"
                    ? `Tenant ${platformPreview.tenantName} đã sẵn sàng cho runtime core.`
                    : `Tenant ${platformPreview.tenantName} đang được bootstrap vào platform core.`}
                </Typography>
              </Box>
              <Stack direction="row" spacing={1} flexWrap="wrap">
                <Chip
                  size="small"
                  color={platformPreview.status === "ready" ? "success" : "default"}
                  label={platformPreview.status === "ready" ? "Ready" : "Initialized"}
                />
                <Chip size="small" label={`Plan ${platformPreview.plan || "trial"}`} />
                <Chip size="small" label={`Mobile ${platformPreview.mobileEnabled ? "on" : "off"}`} />
                <Chip size="small" label={`AI ${platformPreview.aiEnabled ? "on" : "off"}`} />
              </Stack>
            </Stack>
          </CardContent>
        </Card>
      )}

      {message && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message}
        </Alert>
      )}

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      <TableContainer component={Paper}>
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell>Tenant Name</TableCell>
              <TableCell>Status</TableCell>
              <TableCell align="right">Players</TableCell>
              <TableCell align="right">Courts</TableCell>
              <TableCell align="right">Tournaments</TableCell>
              <TableCell align="right">Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {tenants.map((tenant) => (
              <TableRow key={tenant.id} hover>
                <TableCell>{tenant.name}</TableCell>
                <TableCell>
                  <Chip
                    size="small"
                    label={STATUS_LABELS[tenant.status] || tenant.status}
                    color={statusColor(tenant.status)}
                  />
                </TableCell>
                <TableCell align="right">{tenant.stats.players}</TableCell>
                <TableCell align="right">{tenant.stats.courts}</TableCell>
                <TableCell align="right">{tenant.stats.tournaments}</TableCell>
                <TableCell align="right">
                  <Stack direction="row" spacing={1} justifyContent="flex-end">
                    <Button size="small" onClick={() => handleManage(tenant)} disabled={!accessAllowed}>
                      Manage
                    </Button>
                    <Button
                      size="small"
                      onClick={() => {
                        setRenameTarget(tenant);
                        setNewName(tenant.name);
                      }}
                      disabled={!accessAllowed}
                    >
                      Sửa
                    </Button>
                    <Button size="small" color="warning" onClick={() => handleToggleStatus(tenant)} disabled={!accessAllowed}>
                      {tenant.status === TENANT_STATUS.SUSPENDED ||
                      tenant.status === TENANT_STATUS.INACTIVE
                        ? "Mở"
                        : "Khóa"}
                    </Button>
                  </Stack>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>

      <Dialog open={createOpen} onClose={() => setCreateOpen(false)} fullWidth maxWidth="xs">
        <DialogTitle>Tạo tenant mới</DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            fullWidth
            margin="dense"
            label="Tên tenant"
            value={newName}
            onChange={(event) => setNewName(event.target.value)}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setCreateOpen(false)}>Hủy</Button>
          <Button variant="contained" onClick={handleCreate}>
            Tạo
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={Boolean(renameTarget)} onClose={() => setRenameTarget(null)} fullWidth maxWidth="xs">
        <DialogTitle>Đổi tên tenant</DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            fullWidth
            margin="dense"
            label="Tên mới"
            value={newName}
            onChange={(event) => setNewName(event.target.value)}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRenameTarget(null)}>Hủy</Button>
          <Button variant="contained" onClick={handleRename}>
            Lưu
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useMemo, useState, useEffect } from "react";
import { Link as RouterLink, useNavigate, useParams, useSearchParams } from "react-router-dom";
import {
  Alert,
  Box,
  Breadcrumbs,
  Button,
  Chip,
  Link,
  Stack,
  Tab,
  Tabs,
  Typography,
} from "@mui/material";

import { useTenant } from "../../context/TenantContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import {
  CLUB_STATUS_LABELS,
  CLUB_STATUSES,
  getClubById,
  canViewFullClubMembers,
  canApproveClubRegistration,
  approveClubRegistration,
  rejectClubRegistration,
} from "../../features/club/index.js";
import ClubOverviewTab from "./tabs/ClubOverviewTab.jsx";
import ClubMembersTab from "./tabs/ClubMembersTab.jsx";
import ClubRatingsTab from "./tabs/ClubRatingsTab.jsx";
import ClubMatchHistoryTab from "./tabs/ClubMatchHistoryTab.jsx";
import ClubTournamentsTab from "./tabs/ClubTournamentsTab.jsx";

const ALL_TABS = [
  { key: "overview", label: "Tổng quan", requiresFullMembers: false },
  { key: "members", label: "Thành viên", requiresFullMembers: true },
  { key: "ratings", label: "ELO / Xếp hạng", requiresFullMembers: true },
  { key: "history", label: "Lịch sử thi đấu", requiresFullMembers: true },
  { key: "tournaments", label: "Giải nội bộ", requiresFullMembers: false },
];

export default function ClubDetailPage() {
  const { clubId } = useParams();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const { currentTenantId, revision } = useTenant();
  const { user } = useAuth();
  const [localRevision, setLocalRevision] = useState(0);

  const club = useMemo(
    () => getClubById(clubId, currentTenantId),
    [clubId, currentTenantId, revision, localRevision]
  );

  const fullMemberAccess = useMemo(
    () => (club ? canViewFullClubMembers(user, club) : false),
    [user, club]
  );

  const TABS = useMemo(
    () => ALL_TABS.filter((tab) => !tab.requiresFullMembers || fullMemberAccess),
    [fullMemberAccess]
  );

  const activeTab = searchParams.get("tab") || "overview";
  const tabIndex = Math.max(0, TABS.findIndex((t) => t.key === activeTab));
  const safeTab = TABS[tabIndex]?.key || "overview";

  const handleRefresh = () => setLocalRevision((v) => v + 1);

  const showApprovalActions = club && canApproveClubRegistration(user, club);

  const handleApprove = () => {
    const result = approveClubRegistration(club.id, currentTenantId);
    if (!result.ok) {
      return;
    }
    handleRefresh();
  };

  const handleReject = () => {
    const result = rejectClubRegistration(club.id, currentTenantId);
    if (!result.ok) {
      return;
    }
    handleRefresh();
  };

  const handleTabChange = (_, index) => {
    setSearchParams({ tab: TABS[index].key });
  };

  useEffect(() => {
    if (activeTab !== safeTab) {
      setSearchParams({ tab: safeTab }, { replace: true });
    }
  }, [activeTab, safeTab, setSearchParams]);

  if (!currentTenantId) {
    return <Alert severity="warning">Chưa xác định được tenant.</Alert>;
  }

  if (!club) {
    return (
      <Box>
        <Alert severity="error">Không tìm thấy CLB hoặc bạn không có quyền truy cập.</Alert>
        <Link component={RouterLink} to="/manage/clubs" sx={{ mt: 2, display: "inline-block" }}>
          ← Quay lại danh sách CLB
        </Link>
      </Box>
    );
  }

  return (
    <Box>
      <Breadcrumbs sx={{ mb: 2 }}>
        <Link component={RouterLink} to="/manage/clubs" underline="hover" color="inherit">
          CLB
        </Link>
        <Typography color="text.primary">{club.name}</Typography>
      </Breadcrumbs>

      <Box sx={{ mb: 2 }}>
        <StackTitle club={club} />
      </Box>

      {club.status === CLUB_STATUSES.PENDING_APPROVAL && (
        <Alert severity="warning" sx={{ mb: 2 }}>
          CLB đang chờ chủ sân duyệt trước khi hoạt động chính thức.
          {showApprovalActions && (
            <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
              <Button size="small" variant="contained" onClick={handleApprove}>
                Duyệt CLB
              </Button>
              <Button size="small" color="inherit" onClick={handleReject}>
                Từ chối
              </Button>
            </Stack>
          )}
        </Alert>
      )}

      <Tabs value={tabIndex} onChange={handleTabChange} variant="scrollable" scrollButtons="auto" sx={{ mb: 2 }}>
        {TABS.map((tab) => (
          <Tab key={tab.key} label={tab.label} />
        ))}
      </Tabs>

      {safeTab === "overview" && (
        <ClubOverviewTab club={club} tenantId={currentTenantId} onRefresh={handleRefresh} />
      )}
      {safeTab === "members" && (
        <ClubMembersTab club={club} tenantId={currentTenantId} onRefresh={handleRefresh} />
      )}
      {safeTab === "ratings" && (
        <ClubRatingsTab club={club} tenantId={currentTenantId} onRefresh={handleRefresh} />
      )}
      {safeTab === "history" && (
        <ClubMatchHistoryTab club={club} tenantId={currentTenantId} onRefresh={handleRefresh} />
      )}
      {safeTab === "tournaments" && (
        <ClubTournamentsTab
          club={club}
          tenantId={currentTenantId}
          onNavigateTournament={(tid) => navigate(`/tournament/internal/${tid}`)}
        />
      )}
    </Box>
  );
}

function StackTitle({ club }) {
  return (
    <Box>
      <Typography variant="h5" fontWeight={700}>
        {club.name}
        {club.code && (
          <Typography component="span" variant="body2" color="text.secondary" sx={{ ml: 1 }}>
            ({club.code})
          </Typography>
        )}
      </Typography>
      {club.description && (
        <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
          {club.description}
        </Typography>
      )}
      <Chip
        size="small"
        sx={{ mt: 1 }}
        label={CLUB_STATUS_LABELS[club.status] || club.status}
        color={
          club.status === CLUB_STATUSES.ACTIVE
            ? "success"
            : club.status === CLUB_STATUSES.PENDING_SETUP
              ? "warning"
              : club.status === CLUB_STATUSES.PENDING_APPROVAL
                ? "warning"
                : "default"
        }
      />
    </Box>
  );
}

import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Alert,
  Autocomplete,
  Box,
  Button,
  Checkbox,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControlLabel,
  MenuItem,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import { useAuth } from "../../context/AuthContext.jsx";
import { ROLES, normalizeRole } from "../../auth/roles.js";
import GovernanceMemberSelect from "../../components/club/GovernanceMemberSelect.jsx";
import { listClustersForVenue } from "../../features/court-cluster/services/courtClusterService.js";
import {
  cacheRegisterableClusterLocally,
  listRegisterableClusters,
} from "../../features/court-cluster/services/courtClusterDiscoveryService.js";
import { CLUB_STATUSES, listClubGovernanceCandidates, canSelfRegisterClub } from "../../features/club/index.js";
import { createClub, updateClub } from "../../features/club/index.js";

const SEARCH_DEBOUNCE_MS = 300;

const defaultForm = {
  name: "",
  code: "",
  description: "",
  status: CLUB_STATUSES.ACTIVE,
  presidentUserId: "",
  vicePresidentUserId: "",
  registeredClusterId: "",
  assignOwnerToCreator: true,
};

function clusterSearchLabel(cluster) {
  return cluster?.name || cluster?.id || "";
}

function clusterSearchSubtitle(cluster) {
  const venue = cluster?.venueName || cluster?.venueId || "";
  const address = cluster?.address || "";
  return [venue, address].filter(Boolean).join(" · ");
}

export default function ClubFormDialog({
  open,
  club,
  tenantId,
  initialRegisteredClusterId = "",
  lockRegisteredCluster = false,
  onClose,
  onSuccess,
}) {
  const { user } = useAuth();
  const [form, setForm] = useState(defaultForm);
  const [error, setError] = useState(null);
  const [saving, setSaving] = useState(false);
  const [clusterOptions, setClusterOptions] = useState([]);
  const [selectedCluster, setSelectedCluster] = useState(null);
  const [clusterSearchInput, setClusterSearchInput] = useState("");
  const [clusterSearch, setClusterSearch] = useState("");
  const [clusterLoading, setClusterLoading] = useState(false);

  const isEdit = Boolean(club?.id);
  const isCourtOwner = normalizeRole(user?.role) === ROLES.TENANT_OWNER;
  const isSelfRegister = canSelfRegisterClub(user);

  const localVenueClusters = useMemo(
    () => (tenantId ? listClustersForVenue(tenantId) : []),
    [tenantId, open]
  );

  const useCloudClusterPicker = !isEdit && (localVenueClusters.length === 0 || isSelfRegister);

  const governanceCandidates = useMemo(
    () => (isEdit && club?.id ? listClubGovernanceCandidates(club.id, tenantId) : []),
    [isEdit, club?.id, tenantId]
  );

  useEffect(() => {
    const timer = setTimeout(() => {
      setClusterSearch(clusterSearchInput.trim());
    }, SEARCH_DEBOUNCE_MS);
    return () => clearTimeout(timer);
  }, [clusterSearchInput]);

  const loadClusterOptions = useCallback(async () => {
    if (!open || isEdit) {
      return;
    }

    if (!useCloudClusterPicker) {
      setClusterOptions(localVenueClusters);
      return;
    }

    setClusterLoading(true);
    const result = await listRegisterableClusters({ search: clusterSearch });
    setClusterLoading(false);

    if (!result.ok) {
      setClusterOptions(localVenueClusters);
      return;
    }

    let options = result.clusters || [];
    if (tenantId) {
      options = options.filter((cluster) => cluster.venueId === tenantId);
    }
    if (options.length === 0 && localVenueClusters.length > 0) {
      options = localVenueClusters;
    }
    setClusterOptions(options);
  }, [open, isEdit, useCloudClusterPicker, clusterSearch, tenantId, localVenueClusters]);

  useEffect(() => {
    void loadClusterOptions();
  }, [loadClusterOptions]);

  useEffect(() => {
    if (!open) return;
    if (club) {
      setForm({
        name: club.name || "",
        code: club.code || "",
        description: club.description || "",
        status: club.status || CLUB_STATUSES.ACTIVE,
        presidentUserId: club.governance?.presidentUserId || "",
        vicePresidentUserId: club.governance?.vicePresidentUserId || "",
        registeredClusterId: club.governance?.registeredClusterId || "",
        assignOwnerToCreator: true,
      });
      const existing = localVenueClusters.find(
        (item) => item.id === club.governance?.registeredClusterId
      );
      setSelectedCluster(existing || null);
    } else {
      const clusterId = String(initialRegisteredClusterId || "").trim();
      setForm({
        ...defaultForm,
        presidentUserId: isSelfRegister ? user?.id || "" : "",
        registeredClusterId: clusterId,
        assignOwnerToCreator: isCourtOwner,
      });
      setSelectedCluster(null);
    }
    setError(null);
  }, [open, club, user, isSelfRegister, isCourtOwner, initialRegisteredClusterId, localVenueClusters]);

  useEffect(() => {
    if (!open || isEdit || !initialRegisteredClusterId) {
      return;
    }

    const match =
      clusterOptions.find((item) => item.id === initialRegisteredClusterId) ||
      localVenueClusters.find((item) => item.id === initialRegisteredClusterId);

    if (match) {
      setSelectedCluster(match);
      setForm((prev) => ({ ...prev, registeredClusterId: match.id }));
    }
  }, [open, isEdit, initialRegisteredClusterId, clusterOptions, localVenueClusters]);

  const handleClusterChange = (_event, value) => {
    setSelectedCluster(value);
    setForm((prev) => ({
      ...prev,
      registeredClusterId: value?.id || "",
    }));
  };

  const handleSubmit = async () => {
    setSaving(true);
    setError(null);

    const presidentUserId = form.presidentUserId.trim() || (isSelfRegister ? user?.id : "");
    if (!isEdit && !presidentUserId) {
      setSaving(false);
      setError("Chủ tịch CLB bắt buộc — nhập user ID Chủ tịch.");
      return;
    }

    const registeredClusterId = form.registeredClusterId.trim() || null;
    if (registeredClusterId && selectedCluster) {
      const cacheResult = await cacheRegisterableClusterLocally(selectedCluster);
      if (!cacheResult.ok) {
        setSaving(false);
        setError(cacheResult.error || "Không lưu được cụm sân đã chọn.");
        return;
      }
    }

    const governance = {
      presidentUserId: presidentUserId || club?.governance?.presidentUserId,
      ownerUserId: club?.governance?.ownerUserId ?? null,
      vicePresidentUserId: form.vicePresidentUserId.trim() || null,
      registeredClusterId,
    };

    const payload = {
      name: form.name.trim(),
      code: form.code.trim() || null,
      description: form.description.trim(),
      status: form.status,
      tenantId,
      assignOwnerToCreator: form.assignOwnerToCreator,
      governance,
    };

    const result = isEdit
      ? updateClub(club.id, payload, tenantId)
      : await createClub(payload);

    setSaving(false);

    if (!result.ok) {
      setError(result.error || "Không tạo được CLB.");
      return;
    }

    onSuccess?.(result.club, result);
  };

  const clusterPickerOptions = useCloudClusterPicker ? clusterOptions : localVenueClusters;

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>{isEdit ? "Chỉnh sửa CLB" : "Tạo CLB mới"}</DialogTitle>
      <DialogContent>
        <Stack spacing={2} sx={{ mt: 1 }}>
          {error && <Alert severity="error">{error}</Alert>}
          {!isEdit && isSelfRegister && (
            <Alert severity="info">
              Bạn sẽ là <strong>Chủ tịch CLB</strong>. CLB hoạt động ngay sau khi tạo.
            </Alert>
          )}
          <TextField
            label="Tên CLB"
            required
            value={form.name}
            onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
            error={Boolean(error && !form.name.trim())}
          />
          <TextField
            label="Mã CLB"
            value={form.code}
            onChange={(e) => setForm((f) => ({ ...f, code: e.target.value }))}
            helperText="Tùy chọn — không trùng trong cùng tenant"
          />
          <TextField
            label="Mô tả"
            multiline
            minRows={2}
            value={form.description}
            onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))}
          />
          {!isEdit && (
            <TextField
              label="User ID Chủ tịch"
              required
              value={form.presidentUserId}
              onChange={(e) => setForm((f) => ({ ...f, presidentUserId: e.target.value }))}
              helperText={
                isSelfRegister
                  ? "Mặc định là tài khoản của bạn"
                  : "Bắt buộc — auth user id của Chủ tịch CLB"
              }
              disabled={isSelfRegister}
            />
          )}
          {isEdit ? (
            <>
              <GovernanceMemberSelect
                label="Phó chủ tịch"
                value={form.vicePresidentUserId}
                onChange={(value) => setForm((f) => ({ ...f, vicePresidentUserId: value }))}
                candidates={governanceCandidates.filter(
                  (item) =>
                    item.userId !== (form.presidentUserId || club?.governance?.presidentUserId)
                )}
                allowEmpty
                emptyLabel="Không có"
              />
              <Typography variant="caption" color="text.secondary">
                Phó chủ tịch phải là vận động viên trong danh sách CLB.
              </Typography>
            </>
          ) : (
            <TextField
              label="User ID Phó chủ tịch"
              value={form.vicePresidentUserId}
              onChange={(e) => setForm((f) => ({ ...f, vicePresidentUserId: e.target.value }))}
              helperText="Tùy chọn — gán sau khi CLB có vận động viên"
            />
          )}
          {lockRegisteredCluster && selectedCluster ? (
            <TextField
              label="Cụm sân đăng ký"
              value={clusterSearchLabel(selectedCluster)}
              helperText={clusterSearchSubtitle(selectedCluster)}
              disabled
              fullWidth
            />
          ) : (
            <Autocomplete
              options={clusterPickerOptions}
              value={selectedCluster}
              onChange={handleClusterChange}
              inputValue={clusterSearchInput}
              onInputChange={(_event, value) => setClusterSearchInput(value)}
              getOptionLabel={clusterSearchLabel}
              isOptionEqualToValue={(option, value) => option?.id === value?.id}
              loading={clusterLoading}
              disabled={lockRegisteredCluster}
              noOptionsText={
                clusterLoading
                  ? "Đang tải..."
                  : clusterSearch
                    ? "Không tìm thấy cụm sân"
                    : "Gõ tên cụm sân để tìm"
              }
              renderInput={(params) => {
                const autocompleteInputProps = params.InputProps ?? {};

                return (
                  <TextField
                    {...params}
                    label="Cụm sân đăng ký"
                    placeholder="Tùy chọn — tìm theo tên cụm sân"
                    InputProps={{
                      ...autocompleteInputProps,
                      endAdornment: (
                        <>
                          {clusterLoading ? <CircularProgress color="inherit" size={18} /> : null}
                          {autocompleteInputProps.endAdornment}
                        </>
                      ),
                    }}
                  />
                );
              }}
              renderOption={(props, cluster) => (
                <li {...props} key={cluster.id}>
                  <Box>
                    <Typography variant="body2">{clusterSearchLabel(cluster)}</Typography>
                    {clusterSearchSubtitle(cluster) && (
                      <Typography variant="caption" color="text.secondary">
                        {clusterSearchSubtitle(cluster)}
                      </Typography>
                    )}
                  </Box>
                </li>
              )}
            />
          )}
          {!isEdit && isCourtOwner && (
            <FormControlLabel
              control={
                <Checkbox
                  checked={form.assignOwnerToCreator}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, assignOwnerToCreator: e.target.checked }))
                  }
                />
              }
              label="Tôi là Chủ sở hữu CLB"
            />
          )}
          {isEdit && (
            <TextField
              select
              label="Trạng thái"
              value={form.status}
              onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
            >
              <MenuItem value={CLUB_STATUSES.ACTIVE}>Đang hoạt động</MenuItem>
              <MenuItem value={CLUB_STATUSES.PENDING_SETUP}>Chờ thiết lập</MenuItem>
              <MenuItem value={CLUB_STATUSES.PENDING_APPROVAL}>Chờ chủ sân duyệt</MenuItem>
              <MenuItem value={CLUB_STATUSES.INACTIVE}>Vô hiệu hóa</MenuItem>
            </TextField>
          )}
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose} disabled={saving}>
          Hủy
        </Button>
        <Button variant="contained" onClick={() => void handleSubmit()} disabled={saving || !form.name.trim()}>
          {saving ? "Đang lưu..." : isEdit ? "Cập nhật" : "Tạo CLB"}
        </Button>
      </DialogActions>
    </Dialog>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Paper,
  Stack,
  Typography,
} from "@mui/material";
import EditIcon from "@mui/icons-material/Edit";

import { useAuth } from "../../context/AuthContext.jsx";
import GovernanceMemberSelect from "../../components/club/GovernanceMemberSelect.jsx";
import { listClustersForVenue } from "../../features/court-cluster/services/courtClusterService.js";
import {
  FormControl,
  InputLabel,
  ListItemText,
  MenuItem,
  Select,
} from "@mui/material";
import {
  canAssignClubOwner,
  canChangeClubPresident,
  canManageClubGovernance,
  fetchGovernanceNameHints,
  getGovernanceDisplayLabels,
  getRegisteredClusterLabel,
  getVicePresidentUserIds,
  listClubGovernanceCandidates,
  updateClubGovernance,
  assignClubOwner,
  assignClubVicePresident,
  transferClubPresident,
} from "../../features/club/index.js";

export default function ClubGovernancePanel({ club, tenantId, onRefresh }) {
  const { user } = useAuth();
  const [editOpen, setEditOpen] = useState(false);
  const [error, setError] = useState(null);
  const [nameHints, setNameHints] = useState({});
  const [form, setForm] = useState({
    presidentUserId: "",
    vicePresidentUserId: "",
    ownerUserId: "",
    registeredClusterId: "",
  });

  useEffect(() => {
    let cancelled = false;
    const gov = club?.governance || {};
    const ids = [
      gov.presidentUserId,
      gov.ownerUserId,
      ...getVicePresidentUserIds(gov),
    ].filter(Boolean);

    void fetchGovernanceNameHints(ids).then((hints) => {
      if (!cancelled) {
        setNameHints(hints);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [
    club?.id,
    club?.governance?.presidentUserId,
    club?.governance?.ownerUserId,
    club?.governance?.vicePresidentUserId,
    club?.governance?.vicePresidentUserIds,
  ]);

  const labels = useMemo(
    () => getGovernanceDisplayLabels(club, tenantId, nameHints),
    [club, tenantId, nameHints]
  );
  const registeredCluster = useMemo(
    () => getRegisteredClusterLabel(club, tenantId),
    [club, tenantId]
  );

  const venueClusters = useMemo(
    () => listClustersForVenue(tenantId),
    [tenantId]
  );

  const candidates = useMemo(
    () => listClubGovernanceCandidates(club.id, tenantId),
    [club.id, tenantId]
  );

  const canEdit = canManageClubGovernance(user, club);
  const canAssignOwner = canAssignClubOwner(user);
  const canChangePresident = canChangeClubPresident(user, club);

  const openEdit = () => {
    setForm({
      presidentUserId: club.governance?.presidentUserId || "",
      vicePresidentUserId: club.governance?.vicePresidentUserId || "",
      ownerUserId: club.governance?.ownerUserId || "",
      registeredClusterId: club.governance?.registeredClusterId || "",
    });
    setError(null);
    setEditOpen(true);
  };

  const handleSave = async () => {
    setError(null);

    const currentPresident = club.governance?.presidentUserId || "";
    const currentVice = club.governance?.vicePresidentUserId || "";
    const currentCluster = club.governance?.registeredClusterId || "";
    const nextPresident = form.presidentUserId.trim();
    const nextVice = form.vicePresidentUserId.trim();
    const nextCluster = form.registeredClusterId.trim();

    if (canChangePresident && nextPresident !== currentPresident) {
      const presResult = await transferClubPresident(
        club.id,
        nextPresident,
        tenantId
      );
      if (!presResult.ok) {
        setError(presResult.error);
        return;
      }
    }

    if (nextVice !== currentVice) {
      const viceResult = await assignClubVicePresident(
        club.id,
        nextVice || null,
        tenantId
      );
      if (!viceResult.ok) {
        setError(viceResult.error);
        return;
      }
    }

    if (nextCluster !== currentCluster) {
      const govResult = updateClubGovernance(
        club.id,
        { registeredClusterId: nextCluster || null },
        tenantId
      );
      if (!govResult.ok) {
        setError(govResult.error);
        return;
      }
    }

    if (canAssignOwner && form.ownerUserId.trim() !== (club.governance?.ownerUserId || "")) {
      const ownerResult = await assignClubOwner(
        club.id,
        form.ownerUserId.trim() || null,
        tenantId
      );
      if (!ownerResult.ok) {
        setError(ownerResult.error);
        return;
      }
    }

    setEditOpen(false);
    onRefresh?.();
  };

  return (
    <Paper sx={{ p: 2, mb: 3 }}>
      <Stack direction="row" justifyContent="space-between" alignItems="center" mb={1}>
        <Typography variant="subtitle1" fontWeight={600}>
          Quản trị CLB
        </Typography>
        {canEdit && (
          <Button size="small" startIcon={<EditIcon />} onClick={openEdit}>
            Chỉnh sửa
          </Button>
        )}
      </Stack>

      <Stack spacing={0.5}>
        <Typography variant="body2">
          <strong>Chủ sở hữu:</strong> {labels.combinedOwnerPresident ? labels.ownerLabel : labels.ownerLabel}
        </Typography>
        {!labels.combinedOwnerPresident && labels.presidentLabel && (
          <Typography variant="body2">
            <strong>Chủ tịch:</strong> {labels.presidentLabel}
          </Typography>
        )}
        <Typography variant="body2">
          <strong>Phó chủ tịch:</strong> {labels.vicePresidentLabel}
        </Typography>
        <Box sx={{ mt: 1 }}>
          <Typography variant="body2" fontWeight={600} gutterBottom>
            Cụm sân đăng ký hoạt động
          </Typography>
          {!registeredCluster ? (
            <Typography variant="body2" color="text.secondary">
              Chưa đăng ký cụm sân
            </Typography>
          ) : (
            <Chip
              size="small"
              label={registeredCluster.name}
              title={registeredCluster.address || undefined}
            />
          )}
        </Box>
      </Stack>

      <Dialog open={editOpen} onClose={() => setEditOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Chỉnh sửa quản trị CLB</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ mt: 1 }}>
            {error && <Alert severity="error">{error}</Alert>}
            <GovernanceMemberSelect
              label="Chủ tịch"
              value={form.presidentUserId}
              onChange={(value) => setForm((f) => ({ ...f, presidentUserId: value }))}
              candidates={candidates}
              disabled={!canChangePresident}
              required
            />
            {!canChangePresident && (
              <Typography variant="caption" color="text.secondary">
                Chỉ Chủ sở hữu CLB hoặc chủ sân được đổi Chủ tịch
              </Typography>
            )}
            <GovernanceMemberSelect
              label="Phó chủ tịch"
              value={form.vicePresidentUserId}
              onChange={(value) => setForm((f) => ({ ...f, vicePresidentUserId: value }))}
              candidates={candidates.filter(
                (item) => item.userId !== form.presidentUserId
              )}
              allowEmpty
              emptyLabel="Không có"
            />
            <Typography variant="caption" color="text.secondary">
              Chủ tịch / Phó chủ tịch phải là vận động viên trong danh sách CLB.
            </Typography>
            {canAssignOwner && (
              <GovernanceMemberSelect
                label="Chủ sở hữu"
                value={form.ownerUserId}
                onChange={(value) => setForm((f) => ({ ...f, ownerUserId: value }))}
                candidates={candidates}
                allowEmpty
                emptyLabel="Chưa gán"
              />
            )}
            {canAssignOwner && (
              <Typography variant="caption" color="text.secondary">
                Chỉ chủ sân được gán Chủ sở hữu
              </Typography>
            )}
            <FormControl fullWidth>
              <InputLabel>Cụm sân đăng ký</InputLabel>
              <Select
                value={form.registeredClusterId}
                onChange={(e) =>
                  setForm((f) => ({
                    ...f,
                    registeredClusterId: e.target.value,
                  }))
                }
                label="Cụm sân đăng ký"
                displayEmpty
              >
                <MenuItem value="">
                  <em>Chưa chọn</em>
                </MenuItem>
                {venueClusters.length === 0 && (
                  <MenuItem disabled>Chưa có cụm sân trong tổ chức</MenuItem>
                )}
                {venueClusters.map((cluster) => (
                  <MenuItem key={cluster.id} value={cluster.id}>
                    <ListItemText
                      primary={cluster.name || cluster.id}
                      secondary={cluster.address || undefined}
                    />
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setEditOpen(false)}>Hủy</Button>
          <Button variant="contained" onClick={handleSave}>
            Lưu
          </Button>
        </DialogActions>
      </Dialog>
    </Paper>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  IconButton,
  MenuItem,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Tooltip,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import EditIcon from "@mui/icons-material/Edit";
import VisibilityIcon from "@mui/icons-material/Visibility";
import BlockIcon from "@mui/icons-material/Block";
import CloudSyncIcon from "@mui/icons-material/CloudSync";
import CloudDownloadIcon from "@mui/icons-material/CloudDownload";

import { useTenant } from "../../context/TenantContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { isPlatformScopedRole } from "../../auth/roles.js";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  CLUB_STATUSES,
  deactivateClub,
  getClubStats,
  getClubsVisibleToUser,
  canApproveClubRegistration,
  approveClubRegistration,
  rejectClubRegistration,
  isClubStorageV2Enabled,
} from "../../features/club/index.js";
import {
  ClubEmptyState,
  ClubFeedbackAlert,
  ClubPageShell,
  ClubRegistrySkeleton,
  ClubStatusBadge,
  clubRegistryPaperSx,
} from "../../features/club/ui/index.js";
import { CLUB_REGISTRY_SCOPE } from "../../features/club/registry/clubRegistryCache.js";
import { useClubRegistry } from "../../features/club/hooks/useClubRegistry.js";
import { syncClubRegistryForUser } from "../../features/club/services/clubRegistryCloudSync.js";
import { syncClubsForVenueToCloud } from "../../features/club/services/clubRegistryCloudService.js";
import ClubFormDialog from "./ClubFormDialog.jsx";
import ClubDeactivateDialog from "./ClubDeactivateDialog.jsx";

const SORT_OPTIONS = [
  { value: "name", label: "Tên CLB" },
  { value: "members", label: "Số thành viên" },
  { value: "elo", label: "ELO trung bình" },
  { value: "created", label: "Ngày tạo" },
];

export default function ClubListPage() {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const { currentTenantId, currentTenant, revision, refreshTenant, isSuperAdmin } = useTenant();
  const { can, rbacEnabled, isAuthenticated, user } = useAuth();

  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [sortBy, setSortBy] = useState("name");
  const [formOpen, setFormOpen] = useState(false);
  const [editClub, setEditClub] = useState(null);
  const [deactivateTarget, setDeactivateTarget] = useState(null);
  const [error, setError] = useState(null);
  const [message, setMessage] = useState(null);
  const [syncSaving, setSyncSaving] = useState(false);
  const [localRevision, setLocalRevision] = useState(0);

  const storageV2 = isClubStorageV2Enabled();
  const registryFilters = useMemo(
    () => ({
      search,
      status: statusFilter,
      includeInactive: statusFilter === "all",
    }),
    [search, statusFilter]
  );

  const registry = useClubRegistry({
    scope: CLUB_REGISTRY_SCOPE.TENANT,
    tenantId: storageV2 ? currentTenantId : null,
    filters: registryFilters,
    enabled: storageV2 && Boolean(currentTenantId) && isAuthenticated,
  });

  const canSyncCloud = !storageV2 && (isSuperAdmin || isPlatformScopedRole(user?.role));

  useEffect(() => {
    if (storageV2 || !isAuthenticated || !user?.id) {
      return;
    }
    void syncClubRegistryForUser(user).then((result) => {
      if (result.ok) {
        setLocalRevision((value) => value + 1);
      }
    });
  }, [isAuthenticated, storageV2, user, revision]);

  const canCreate =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.CLUB_CREATE, { venueId: currentTenantId, tenantId: currentTenantId });
  const canUpdate =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.CLUB_UPDATE, { venueId: currentTenantId, tenantId: currentTenantId });

  const clubsWithStats = useMemo(() => {
    if (storageV2) {
      return (registry.clubs || []).map((row) => ({
        club: {
          id: row.id,
          name: row.name,
          code: row.code,
          status: row.status,
          createdAt: row.createdAt,
          tenantId: row.tenantId,
          governance: {
            ownerUserId: row._raw?.governance?.ownerUserId || row._raw?.owner_user_id,
            presidentUserId: row._raw?.governance?.presidentUserId || row._raw?.president_user_id,
          },
        },
        stats: {
          memberCount: row.memberCount ?? 0,
          avgElo: 0,
          tournamentCount: 0,
          ownerName: row.ownerName,
          presidentName: row.presidentName,
        },
      }));
    }

    const clubs = getClubsVisibleToUser(currentTenantId, user).filter((c) => !c.isDefault);
    return clubs.map((club) => ({
      club,
      stats: getClubStats(
        club.id,
        club.tenantId || club.venueId || currentTenantId
      ) || {
        memberCount: 0,
        avgElo: 0,
        tournamentCount: 0,
      },
    }));
  }, [currentTenantId, user, revision, localRevision, registry.clubs, storageV2]);

  useEffect(() => {
    if (searchParams.get("create") === "1" && canCreate) {
      setEditClub(null);
      setFormOpen(true);
      setSearchParams({}, { replace: true });
    }
  }, [searchParams, canCreate, setSearchParams]);

  const filtered = useMemo(() => {
    let rows = [...clubsWithStats];

    if (search.trim()) {
      const q = search.trim().toLowerCase();
      rows = rows.filter(
        ({ club }) =>
          club.name.toLowerCase().includes(q) ||
          String(club.code || "").toLowerCase().includes(q)
      );
    }

    if (statusFilter !== "all") {
      rows = rows.filter(({ club }) => club.status === statusFilter);
    }

    rows.sort((a, b) => {
      switch (sortBy) {
        case "members":
          return b.stats.memberCount - a.stats.memberCount;
        case "elo":
          return b.stats.avgElo - a.stats.avgElo;
        case "created":
          return new Date(b.club.createdAt) - new Date(a.club.createdAt);
        default:
          return a.club.name.localeCompare(b.club.name, "vi");
      }
    });

    return rows;
  }, [clubsWithStats, search, statusFilter, sortBy]);

  const bumpList = () => {
    if (storageV2) {
      void registry.invalidate();
    } else {
      setLocalRevision((v) => v + 1);
    }
    refreshTenant();
  };

  const handleFormSuccess = () => {
    setFormOpen(false);
    setEditClub(null);
    bumpList();
  };

  const handleDeactivate = () => {
    if (!deactivateTarget) return;
    const result = deactivateClub(deactivateTarget.id, currentTenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setDeactivateTarget(null);
    bumpList();
  };

  const handleApprove = (club) => {
    const result = approveClubRegistration(club.id, currentTenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    bumpList();
  };

  const handleReject = (club) => {
    const result = rejectClubRegistration(club.id, currentTenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    bumpList();
  };

  const handleSyncToCloud = async () => {
    setError(null);
    setMessage(null);
    setSyncSaving(true);

    const clubs = clubsWithStats.map(({ club }) => club);
    const result = await syncClubsForVenueToCloud({
      clubs,
      venueId: canSyncCloud ? null : currentTenantId,
      actor: user,
    });

    setSyncSaving(false);

    if (!result.ok) {
      setError(result.error || "Đồng bộ CLB lên cloud thất bại.");
      return;
    }

    let successText = `Đã đồng bộ ${result.synced ?? 0} CLB lên Supabase.`;
    if (result.skipped > 0) {
      successText += ` Bỏ qua ${result.skipped} CLB thiếu Chủ tịch UUID hợp lệ.`;
    }
    setMessage(successText);
    setLocalRevision((value) => value + 1);
    refreshTenant();
  };

  const handlePullFromCloud = async () => {
    setError(null);
    setMessage(null);
    setSyncSaving(true);

    const result = await syncClubRegistryForUser(user);
    setSyncSaving(false);

    if (!result.ok) {
      setError(result.error || "Không tải được danh sách CLB từ cloud.");
      return;
    }

    setMessage(
      `Đã tải ${result.pulled ?? 0} CLB từ cloud` +
        (result.pushed ? `, đẩy thêm ${result.pushed} CLB local.` : ".")
    );
    setLocalRevision((value) => value + 1);
    refreshTenant();
  };

  if (!currentTenantId) {
    return (
      <Alert severity="info">
        {isSuperAdmin || isPlatformScopedRole(user?.role)
          ? "Chọn tenant ở header trước khi quản lý sổ đăng ký CLB."
          : "Chưa xác định được tenant. Vui lòng đăng nhập hoặc liên hệ quản trị."}
      </Alert>
    );
  }

  if (storageV2 && registry.loading) {
    return (
      <ClubPageShell
        title="Quản lý CLB"
        subtitle={`Tenant: ${currentTenant?.name || currentTenantId}`}
        breadcrumbs={[
          { label: "Quản lý", href: "/manage/clubs" },
          { label: "Sổ đăng ký CLB" },
        ]}
        maxWidth={1400}
      >
        <ClubRegistrySkeleton />
      </ClubPageShell>
    );
  }

  if (storageV2 && registry.error) {
    return (
      <ClubPageShell
        title="Quản lý CLB"
        subtitle={`Tenant: ${currentTenant?.name || currentTenantId}`}
        breadcrumbs={[
          { label: "Quản lý", href: "/manage/clubs" },
          { label: "Sổ đăng ký CLB" },
        ]}
        maxWidth={1400}
      >
        <Alert
          severity="error"
          action={
            <Button color="inherit" size="small" onClick={() => void registry.reload()}>
              Thử lại
            </Button>
          }
        >
          {registry.error}
        </Alert>
      </ClubPageShell>
    );
  }

  const headerActions = (
    <Stack direction="row" spacing={1} alignItems="center" flexWrap="wrap">
      {canSyncCloud && (
        <>
          <Button
            variant="outlined"
            startIcon={<CloudDownloadIcon />}
            onClick={() => void handlePullFromCloud()}
            disabled={syncSaving}
          >
            {syncSaving ? "Đang tải…" : "Tải từ cloud"}
          </Button>
          <Button
            variant="outlined"
            startIcon={<CloudSyncIcon />}
            onClick={() => void handleSyncToCloud()}
            disabled={syncSaving || filtered.length === 0}
          >
            {syncSaving ? "Đang đồng bộ…" : "Đồng bộ lên cloud"}
          </Button>
        </>
      )}
      <PermissionGate permission={PERMISSIONS.CLUB_CREATE} scope={{ venueId: currentTenantId }}>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => {
            setEditClub(null);
            setFormOpen(true);
          }}
          disabled={!canCreate}
        >
          Tạo CLB mới
        </Button>
      </PermissionGate>
    </Stack>
  );

  return (
    <ClubPageShell
      title="Quản lý CLB"
      subtitle={`Tenant: ${currentTenant?.name || currentTenantId} · ${currentTenantId}`}
      breadcrumbs={[
        { label: "Quản lý", href: "/manage/clubs" },
        { label: "Sổ đăng ký CLB" },
      ]}
      actions={headerActions}
      maxWidth={1400}
    >
      <ClubFeedbackAlert
        message={message ? { type: "success", text: message } : null}
        onClose={() => setMessage(null)}
      />
      <ClubFeedbackAlert message={error ? { type: "error", text: error } : null} onClose={() => setError(null)} />

      <Paper sx={clubRegistryPaperSx}>
        <Stack direction={{ xs: "column", md: "row" }} spacing={2}>
          <TextField
            label="Tìm theo tên / mã CLB"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            size="small"
            fullWidth
          />
          <TextField
            select
            label="Trạng thái"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            size="small"
            sx={{ minWidth: 160 }}
          >
            <MenuItem value="all">Tất cả</MenuItem>
            <MenuItem value={CLUB_STATUSES.ACTIVE}>Đang hoạt động</MenuItem>
            <MenuItem value={CLUB_STATUSES.PENDING_SETUP}>Chờ thiết lập</MenuItem>
            <MenuItem value={CLUB_STATUSES.PENDING_APPROVAL}>Chờ chủ sân duyệt</MenuItem>
            <MenuItem value={CLUB_STATUSES.INACTIVE}>Vô hiệu hóa</MenuItem>
          </TextField>
          <TextField
            select
            label="Sắp xếp"
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            size="small"
            sx={{ minWidth: 180 }}
          >
            {SORT_OPTIONS.map((opt) => (
              <MenuItem key={opt.value} value={opt.value}>
                {opt.label}
              </MenuItem>
            ))}
          </TextField>
        </Stack>
      </Paper>

      {filtered.length === 0 ? (
        <ClubEmptyState
          preset={search || statusFilter !== "all" ? "registryFilter" : "registry"}
          actionLabel={canCreate && !search && statusFilter === "all" ? "Tạo CLB đầu tiên" : undefined}
          onAction={
            canCreate && !search && statusFilter === "all"
              ? () => {
                  setEditClub(null);
                  setFormOpen(true);
                }
              : undefined
          }
        />
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Tên CLB</TableCell>
                <TableCell>Mã</TableCell>
                {storageV2 && <TableCell>Chủ sở hữu</TableCell>}
                {storageV2 && <TableCell>Chủ tịch</TableCell>}
                <TableCell align="right">Thành viên</TableCell>
                {!storageV2 && <TableCell align="right">ELO TB</TableCell>}
                {!storageV2 && <TableCell align="right">Giải nội bộ</TableCell>}
                <TableCell>Trạng thái</TableCell>
                <TableCell>Ngày tạo</TableCell>
                <TableCell align="right">Thao tác</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {filtered.map(({ club, stats }) => (
                <TableRow key={club.id} hover>
                  <TableCell>{club.name}</TableCell>
                  <TableCell>{club.code || "—"}</TableCell>
                  {storageV2 && <TableCell>{stats.ownerName || "—"}</TableCell>}
                  {storageV2 && <TableCell>{stats.presidentName || "—"}</TableCell>}
                  <TableCell align="right">{stats.memberCount}</TableCell>
                  {!storageV2 && <TableCell align="right">{stats.avgElo || "—"}</TableCell>}
                  {!storageV2 && <TableCell align="right">{stats.tournamentCount}</TableCell>}
                  <TableCell>
                    <ClubStatusBadge status={club.status} />
                  </TableCell>
                  <TableCell>
                    {new Date(club.createdAt).toLocaleDateString("vi-VN")}
                  </TableCell>
                  <TableCell align="right">
                    <Tooltip title="Xem chi tiết">
                      <IconButton size="small" onClick={() => navigate(`/manage/clubs/${club.id}`)}>
                        <VisibilityIcon fontSize="small" />
                      </IconButton>
                    </Tooltip>
                    {canApproveClubRegistration(user, club) && (
                      <>
                        <Tooltip title="Duyệt CLB">
                          <Button
                            size="small"
                            variant="outlined"
                            sx={{ ml: 0.5 }}
                            onClick={() => handleApprove(club)}
                          >
                            Duyệt
                          </Button>
                        </Tooltip>
                        <Tooltip title="Từ chối">
                          <Button
                            size="small"
                            color="inherit"
                            sx={{ ml: 0.5 }}
                            onClick={() => handleReject(club)}
                          >
                            Từ chối
                          </Button>
                        </Tooltip>
                      </>
                    )}
                    {canUpdate && (
                      <>
                        <Tooltip title="Chỉnh sửa">
                          <IconButton
                            size="small"
                            onClick={() => {
                              setEditClub(club);
                              setFormOpen(true);
                            }}
                          >
                            <EditIcon fontSize="small" />
                          </IconButton>
                        </Tooltip>
                        {club.status === CLUB_STATUSES.ACTIVE && (
                          <Tooltip title="Vô hiệu hóa">
                            <IconButton
                              size="small"
                              color="warning"
                              onClick={() => setDeactivateTarget(club)}
                            >
                              <BlockIcon fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        )}
                      </>
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <ClubFormDialog
        open={formOpen}
        club={editClub}
        tenantId={currentTenantId}
        onClose={() => {
          setFormOpen(false);
          setEditClub(null);
        }}
        onSuccess={handleFormSuccess}
      />

      <ClubDeactivateDialog
        open={Boolean(deactivateTarget)}
        club={deactivateTarget}
        onClose={() => setDeactivateTarget(null)}
        onConfirm={handleDeactivate}
      />
    </ClubPageShell>
  );
}

import { useMemo, useState } from "react";
import { Link as RouterLink } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Link,
  MenuItem,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";

import { useAuth } from "../../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../../auth/permissions.js";
import {
  createFriendlyClubMatch,
  getClubMatches,
  getClubMembers,
  getTenantPlayers,
} from "../../../features/club/index.js";
import { CLUB_MATCH_TYPES } from "../../../features/club/models/clubMatch.js";
import { CLUB_MEMBER_STATUSES } from "../../../features/club/constants/clubMemberRoles.js";

const TYPE_LABELS = {
  [CLUB_MATCH_TYPES.FRIENDLY]: "Giao hữu",
  [CLUB_MATCH_TYPES.INTERNAL_TOURNAMENT]: "Giải nội bộ",
};

export default function ClubMatchHistoryTab({ club, tenantId, onRefresh }) {
  const { can, rbacEnabled, isAuthenticated } = useAuth();
  const [revision, setRevision] = useState(0);
  const [createOpen, setCreateOpen] = useState(false);
  const [error, setError] = useState(null);
  const [form, setForm] = useState({
    teamAPlayerId: "",
    teamBPlayerId: "",
    teamAScore: "",
    teamBScore: "",
    playedAt: new Date().toISOString().slice(0, 10),
  });

  const canCreate =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.TOURNAMENT_UPDATE, { clubId: club.id, venueId: tenantId });

  const matches = useMemo(
    () => getClubMatches(club.id, tenantId),
    [club.id, tenantId, revision]
  );

  const playersById = useMemo(() => {
    const players = getTenantPlayers(tenantId);
    return new Map(players.map((p) => [p.id, p]));
  }, [tenantId, revision]);

  const activeMemberIds = useMemo(() => {
    return getClubMembers(club.id, tenantId)
      .filter((m) => m.status === CLUB_MEMBER_STATUSES.ACTIVE)
      .map((m) => m.playerId);
  }, [club.id, tenantId, revision]);

  const memberPlayers = useMemo(
    () => activeMemberIds.map((id) => playersById.get(id)).filter(Boolean),
    [activeMemberIds, playersById]
  );

  const formatPlayers = (ids) =>
    ids.map((id) => playersById.get(id)?.name || id).join(" / ");

  const handleCreate = () => {
    setError(null);
    const result = createFriendlyClubMatch(
      club.id,
      {
        teamAPlayerIds: [form.teamAPlayerId],
        teamBPlayerIds: [form.teamBPlayerId],
        teamAScore: Number(form.teamAScore),
        teamBScore: Number(form.teamBScore),
        playedAt: new Date(form.playedAt).toISOString(),
        applyElo: true,
      },
      tenantId
    );

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setCreateOpen(false);
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  return (
    <Box>
      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      <Stack direction="row" justifyContent="space-between" mb={2}>
        <Typography variant="subtitle1" fontWeight={600}>
          {matches.length} trận
        </Typography>
        {canCreate && (
          <Button
            size="small"
            variant="contained"
            startIcon={<AddIcon />}
            onClick={() => setCreateOpen(true)}
          >
            Ghi trận giao hữu
          </Button>
        )}
      </Stack>

      {matches.length === 0 ? (
        <Paper sx={{ p: 3, textAlign: "center" }}>
          <Typography color="text.secondary" gutterBottom>
            Chưa có lịch sử thi đấu.
          </Typography>
          {canCreate && (
            <Button variant="outlined" startIcon={<AddIcon />} onClick={() => setCreateOpen(true)}>
              Ghi trận đầu tiên
            </Button>
          )}
        </Paper>
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Ngày</TableCell>
                <TableCell>Loại</TableCell>
                <TableCell>Đội A</TableCell>
                <TableCell>Đội B</TableCell>
                <TableCell align="center">Tỷ số</TableCell>
                <TableCell>Thắng</TableCell>
                <TableCell>ELO</TableCell>
                <TableCell>Chi tiết</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {matches.map((match) => (
                <TableRow key={match.id} hover>
                  <TableCell>
                    {new Date(match.playedAt).toLocaleDateString("vi-VN")}
                  </TableCell>
                  <TableCell>
                    <Chip size="small" label={TYPE_LABELS[match.type] || match.type} />
                  </TableCell>
                  <TableCell>{formatPlayers(match.teamAPlayerIds)}</TableCell>
                  <TableCell>{formatPlayers(match.teamBPlayerIds)}</TableCell>
                  <TableCell align="center">
                    {match.teamAScore != null && match.teamBScore != null
                      ? `${match.teamAScore} - ${match.teamBScore}`
                      : "—"}
                  </TableCell>
                  <TableCell>
                    {match.winnerTeam === "A"
                      ? "Đội A"
                      : match.winnerTeam === "B"
                        ? "Đội B"
                        : "—"}
                  </TableCell>
                  <TableCell>
                    {match.eloApplied ? (
                      <Chip size="small" color="success" label="Đã cập nhật" />
                    ) : (
                      <Chip size="small" label="Chưa" />
                    )}
                  </TableCell>
                  <TableCell>
                    {match.tournamentId ? (
                      <Link component={RouterLink} to={`/tournament/internal/${match.tournamentId}`}>
                        Xem giải
                      </Link>
                    ) : (
                      "—"
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={createOpen} onClose={() => setCreateOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Ghi trận giao hữu</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ mt: 1 }}>
            <TextField
              type="date"
              label="Ngày thi đấu"
              value={form.playedAt}
              onChange={(e) => setForm((f) => ({ ...f, playedAt: e.target.value }))}
              InputLabelProps={{ shrink: true }}
            />
            <TextField
              select
              label="Đội A"
              value={form.teamAPlayerId}
              onChange={(e) => setForm((f) => ({ ...f, teamAPlayerId: e.target.value }))}
            >
              {memberPlayers.map((p) => (
                <MenuItem key={p.id} value={p.id}>
                  {p.name}
                </MenuItem>
              ))}
            </TextField>
            <TextField
              select
              label="Đội B"
              value={form.teamBPlayerId}
              onChange={(e) => setForm((f) => ({ ...f, teamBPlayerId: e.target.value }))}
            >
              {memberPlayers.map((p) => (
                <MenuItem key={p.id} value={p.id}>
                  {p.name}
                </MenuItem>
              ))}
            </TextField>
            <Stack direction="row" spacing={2}>
              <TextField
                label="Tỷ số A"
                type="number"
                value={form.teamAScore}
                onChange={(e) => setForm((f) => ({ ...f, teamAScore: e.target.value }))}
                fullWidth
              />
              <TextField
                label="Tỷ số B"
                type="number"
                value={form.teamBScore}
                onChange={(e) => setForm((f) => ({ ...f, teamBScore: e.target.value }))}
                fullWidth
              />
            </Stack>
            <Typography variant="caption" color="text.secondary">
              ELO CLB sẽ tự cập nhật sau khi lưu (nếu có tỷ số hợp lệ).
            </Typography>
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setCreateOpen(false)}>Hủy</Button>
          <Button
            variant="contained"
            onClick={handleCreate}
            disabled={
              !form.teamAPlayerId ||
              !form.teamBPlayerId ||
              form.teamAPlayerId === form.teamBPlayerId ||
              form.teamAScore === "" ||
              form.teamBScore === ""
            }
          >
            Lưu & cập nhật ELO
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  IconButton,
  MenuItem,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Tooltip,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import PersonRemoveIcon from "@mui/icons-material/PersonRemove";

import { useAuth } from "../../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../../auth/permissions.js";
import {
  CLUB_MEMBER_ROLE_LABELS,
  CLUB_MEMBER_STATUSES,
  addMemberToClub,
  getClubMembers,
  getClubRatings,
  getTenantPlayers,
  removeMemberFromClub,
  updateClubMemberRole,
  updateClubMemberStatus,
  canViewFullClubMembers,
  canDeleteClubMembers,
  canApproveClubMembershipRequests,
  listPendingMembershipRequests,
  approveClubMembershipRequest,
  rejectClubMembershipRequest,
} from "../../../features/club/index.js";
import { formatPickVnRating } from "../../../features/pick-vn-rating/constants/pickVnRatingScale.js";
import { writeAuditLog, AUDIT_ACTIONS } from "../../../features/identity/services/auditService.js";
import { getCurrentUser } from "../../../auth/authService.js";

export default function ClubMembersTab({ club, tenantId, onRefresh }) {
  const { can, rbacEnabled, isAuthenticated, user } = useAuth();
  const [addOpen, setAddOpen] = useState(false);
  const [selectedPlayerId, setSelectedPlayerId] = useState("");
  const [error, setError] = useState(null);
  const [removeTarget, setRemoveTarget] = useState(null);
  const [revision, setRevision] = useState(0);
  const [reviewNotes, setReviewNotes] = useState({});
  const [requestMessage, setRequestMessage] = useState(null);
  const [pendingMembershipRequests, setPendingMembershipRequests] = useState([]);
  const [loadingPendingRequests, setLoadingPendingRequests] = useState(false);

  const fullAccess = canViewFullClubMembers(user, club);
  const canApproveRequests = canApproveClubMembershipRequests(user, club);

  useEffect(() => {
    let cancelled = false;

    async function loadPending() {
      if (!canApproveRequests) {
        setPendingMembershipRequests([]);
        return;
      }

      setLoadingPendingRequests(true);
      try {
        const rows = await listPendingMembershipRequests(club.id, tenantId, user);
        if (!cancelled) {
          setPendingMembershipRequests(rows);
        }
      } finally {
        if (!cancelled) {
          setLoadingPendingRequests(false);
        }
      }
    }

    loadPending();
    return () => {
      cancelled = true;
    };
  }, [club.id, tenantId, user, revision, canApproveRequests]);

  const canManage =
    fullAccess &&
    (!rbacEnabled ||
      !isAuthenticated ||
      can(PERMISSIONS.PLAYER_UPDATE, { clubId: club.id, venueId: tenantId }));

  const canRemoveMembers = canDeleteClubMembers(user, club) && canManage;

  const members = useMemo(
    () => getClubMembers(club.id, tenantId),
    [club.id, tenantId, revision]
  );

  const ratings = useMemo(
    () => getClubRatings(club.id, tenantId),
    [club.id, tenantId, revision]
  );

  const playersById = useMemo(() => {
    const players = getTenantPlayers(tenantId);
    return new Map(players.map((p) => [p.id, p]));
  }, [tenantId, revision]);

  const ratingByPlayer = useMemo(
    () => new Map(ratings.map((r) => [r.playerId, r])),
    [ratings]
  );

  const existingMemberIds = useMemo(
    () => new Set(members.filter((m) => m.status === CLUB_MEMBER_STATUSES.ACTIVE).map((m) => m.playerId)),
    [members]
  );

  const availablePlayers = useMemo(
    () => getTenantPlayers(tenantId).filter((p) => !existingMemberIds.has(p.id)),
    [tenantId, existingMemberIds, revision]
  );

  const handleAdd = () => {
    const result = addMemberToClub(club.id, selectedPlayerId, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setAddOpen(false);
    setSelectedPlayerId("");
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleRemove = () => {
    if (!removeTarget) return;
    const result = removeMemberFromClub(club.id, removeTarget.playerId, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setRemoveTarget(null);
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleRoleChange = (playerId, role) => {
    const result = updateClubMemberRole(club.id, playerId, role, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleStatusToggle = (member) => {
    const nextStatus =
      member.status === CLUB_MEMBER_STATUSES.ACTIVE
        ? CLUB_MEMBER_STATUSES.INACTIVE
        : CLUB_MEMBER_STATUSES.ACTIVE;
    const result = updateClubMemberStatus(club.id, member.playerId, nextStatus, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleApproveRequest = async (request) => {
    const result = await approveClubMembershipRequest(club.id, request.id, tenantId, {
      user,
      reviewNote: reviewNotes[request.id] || "",
    });

    if (!result.ok) {
      setRequestMessage({ type: "error", text: result.error });
      return;
    }

    await writeAuditLog({
      action: AUDIT_ACTIONS.UPDATE,
      resourceType: "club_membership_request",
      resourceId: request.id,
      clubId: club.id,
      metadata: {
        status: "approved",
        userId: request.userId,
        playerId: result.player?.id,
      },
      actor: getCurrentUser(),
    });

    setRequestMessage({ type: "success", text: "Đã duyệt yêu cầu tham gia CLB." });
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleRejectRequest = async (request) => {
    const result = await rejectClubMembershipRequest(club.id, request.id, tenantId, {
      user,
      reviewNote: reviewNotes[request.id] || "",
    });

    if (!result.ok) {
      setRequestMessage({ type: "error", text: result.error });
      return;
    }

    await writeAuditLog({
      action: AUDIT_ACTIONS.UPDATE,
      resourceType: "club_membership_request",
      resourceId: request.id,
      clubId: club.id,
      metadata: {
        status: "rejected",
        userId: request.userId,
      },
      actor: getCurrentUser(),
    });

    setRequestMessage({ type: "info", text: "Đã từ chối yêu cầu tham gia." });
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  return (
    <Box>
      {!fullAccess && (
        <Alert severity="info" sx={{ mb: 2 }}>
          Bạn không có quyền xem danh sách thành viên CLB này. Chỉ Chủ tịch / Chủ sở hữu CLB mới
          xem được chi tiết.
        </Alert>
      )}

      {fullAccess && error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {fullAccess && (
        <>
      {canApproveRequests && requestMessage && (
        <Alert
          severity={requestMessage.type}
          sx={{ mb: 2 }}
          onClose={() => setRequestMessage(null)}
        >
          {requestMessage.text}
        </Alert>
      )}

      {canApproveRequests && (
        <Box sx={{ mb: 3 }}>
          <Typography variant="subtitle1" fontWeight={600} gutterBottom>
            Yêu cầu tham gia ({pendingMembershipRequests.length})
          </Typography>
          {pendingMembershipRequests.length === 0 ? (
            <Paper sx={{ p: 2 }}>
              <Typography color="text.secondary" variant="body2">
                Không có yêu cầu đang chờ duyệt.
              </Typography>
            </Paper>
          ) : (
            <TableContainer component={Paper}>
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>VĐV</TableCell>
                    <TableCell>Pick_VN</TableCell>
                    <TableCell>Ngày gửi</TableCell>
                    <TableCell>Lời nhắn</TableCell>
                    <TableCell>Ghi chú duyệt</TableCell>
                    <TableCell align="right">Thao tác</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {pendingMembershipRequests.map((request) => (
                    <TableRow key={request.id} hover>
                      <TableCell>{request.displayName || request.userId}</TableCell>
                      <TableCell>
                        {request.pickVnRating != null
                          ? formatPickVnRating(request.pickVnRating)
                          : "—"}
                      </TableCell>
                      <TableCell>
                        {new Date(request.requestedAt).toLocaleDateString("vi-VN")}
                      </TableCell>
                      <TableCell>{request.message || "—"}</TableCell>
                      <TableCell sx={{ minWidth: 180 }}>
                        <TextField
                          size="small"
                          fullWidth
                          placeholder="Ghi chú"
                          value={reviewNotes[request.id] || ""}
                          onChange={(event) =>
                            setReviewNotes((prev) => ({
                              ...prev,
                              [request.id]: event.target.value,
                            }))
                          }
                        />
                      </TableCell>
                      <TableCell align="right">
                        <Stack direction="row" spacing={1} justifyContent="flex-end">
                          <Button
                            size="small"
                            color="success"
                            variant="contained"
                            onClick={() => handleApproveRequest(request)}
                          >
                            Duyệt
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            variant="outlined"
                            onClick={() => handleRejectRequest(request)}
                          >
                            Từ chối
                          </Button>
                        </Stack>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          )}
        </Box>
      )}

      <Stack direction="row" justifyContent="space-between" mb={2}>
        <Typography variant="subtitle1" fontWeight={600}>
          {members.length} thành viên
        </Typography>
        {canManage && (
          <Button startIcon={<AddIcon />} variant="contained" size="small" onClick={() => setAddOpen(true)}>
            Thêm thành viên
          </Button>
        )}
      </Stack>

      {members.length === 0 ? (
        <Paper sx={{ p: 3, textAlign: "center" }}>
          <Typography color="text.secondary">CLB chưa có thành viên.</Typography>
        </Paper>
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Tên</TableCell>
                <TableCell>SĐT</TableCell>
                <TableCell>Giới tính</TableCell>
                <TableCell>Level</TableCell>
                <TableCell align="right">ELO</TableCell>
                <TableCell>Vai trò</TableCell>
                <TableCell>Ngày tham gia</TableCell>
                <TableCell>Trạng thái</TableCell>
                    {canRemoveMembers && (
                      <TableCell align="right">Thao tác</TableCell>
                    )}
              </TableRow>
            </TableHead>
            <TableBody>
              {members.map((member) => {
                const player = playersById.get(member.playerId);
                const rating = ratingByPlayer.get(member.playerId);
                return (
                  <TableRow key={member.id} hover>
                    <TableCell>{player?.name || member.playerId}</TableCell>
                    <TableCell>{player?.phone || "—"}</TableCell>
                    <TableCell>{player?.gender || "—"}</TableCell>
                    <TableCell>{player?.level ?? rating?.level ?? "—"}</TableCell>
                    <TableCell align="right">{rating?.elo ?? "—"}</TableCell>
                    <TableCell>
                      {canManage ? (
                        <TextField
                          select
                          size="small"
                          value={member.role}
                          onChange={(e) => handleRoleChange(member.playerId, e.target.value)}
                          sx={{ minWidth: 120 }}
                        >
                          {Object.entries(CLUB_MEMBER_ROLE_LABELS).map(([value, label]) => (
                            <MenuItem key={value} value={value}>
                              {label}
                            </MenuItem>
                          ))}
                        </TextField>
                      ) : (
                        CLUB_MEMBER_ROLE_LABELS[member.role] || member.role
                      )}
                    </TableCell>
                    <TableCell>
                      {new Date(member.joinedAt).toLocaleDateString("vi-VN")}
                    </TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={member.status === CLUB_MEMBER_STATUSES.ACTIVE ? "Active" : "Inactive"}
                        color={member.status === CLUB_MEMBER_STATUSES.ACTIVE ? "success" : "default"}
                        onClick={canManage ? () => handleStatusToggle(member) : undefined}
                      />
                    </TableCell>
                    {canRemoveMembers && (
                      <TableCell align="right">
                        {member.status === CLUB_MEMBER_STATUSES.ACTIVE && (
                          <Tooltip title="Xóa khỏi CLB">
                            <IconButton size="small" color="error" onClick={() => setRemoveTarget(member)}>
                              <PersonRemoveIcon fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        )}
                      </TableCell>
                    )}
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={addOpen} onClose={() => setAddOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Thêm thành viên</DialogTitle>
        <DialogContent>
          <TextField
            select
            fullWidth
            label="Chọn player"
            value={selectedPlayerId}
            onChange={(e) => setSelectedPlayerId(e.target.value)}
            sx={{ mt: 1 }}
          >
            {availablePlayers.length === 0 && (
              <MenuItem disabled>Không còn player khả dụng trong tenant</MenuItem>
            )}
            {availablePlayers.map((p) => (
              <MenuItem key={p.id} value={p.id}>
                {p.name} {p.phone ? `— ${p.phone}` : ""}
              </MenuItem>
            ))}
          </TextField>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setAddOpen(false)}>Hủy</Button>
          <Button variant="contained" disabled={!selectedPlayerId} onClick={handleAdd}>
            Thêm
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={Boolean(removeTarget)} onClose={() => setRemoveTarget(null)}>
        <DialogTitle>Xóa thành viên</DialogTitle>
        <DialogContent>
          <Typography>
            Xóa{" "}
            <strong>{playersById.get(removeTarget?.playerId)?.name || removeTarget?.playerId}</strong>{" "}
            khỏi CLB?
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRemoveTarget(null)}>Hủy</Button>
          <Button color="error" variant="contained" onClick={handleRemove}>
            Xóa
          </Button>
        </DialogActions>
      </Dialog>
        </>
      )}
    </Box>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  IconButton,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Tooltip,
  Typography,
} from "@mui/material";
import EditIcon from "@mui/icons-material/Edit";

import { useAuth } from "../../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../../auth/permissions.js";
import {
  getClubRatings,
  getTenantPlayers,
  updateClubRating,
} from "../../../features/club/index.js";

export default function ClubRatingsTab({ club, tenantId, onRefresh }) {
  const { can, rbacEnabled, isAuthenticated } = useAuth();
  const [search, setSearch] = useState("");
  const [levelFilter, setLevelFilter] = useState("");
  const [sortBy, setSortBy] = useState("elo");
  const [editTarget, setEditTarget] = useState(null);
  const [newElo, setNewElo] = useState("");
  const [reason, setReason] = useState("");
  const [error, setError] = useState(null);
  const [revision, setRevision] = useState(0);

  const canEditElo =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.PLAYER_UPDATE, { clubId: club.id, venueId: tenantId });

  const playersById = useMemo(() => {
    const players = getTenantPlayers(tenantId);
    return new Map(players.map((p) => [p.id, p]));
  }, [tenantId, revision]);

  const rows = useMemo(() => {
    let ratings = getClubRatings(club.id, tenantId).map((r, index) => {
      const player = playersById.get(r.playerId);
      const winRate =
        r.matchesPlayed > 0 ? Math.round((r.wins / r.matchesPlayed) * 100) : 0;
      return {
        ...r,
        rank: index + 1,
        name: player?.name || r.playerId,
        level: r.level ?? player?.level,
        winRate,
      };
    });

    if (search.trim()) {
      const q = search.trim().toLowerCase();
      ratings = ratings.filter((r) => r.name.toLowerCase().includes(q));
    }

    if (levelFilter) {
      ratings = ratings.filter((r) => String(r.level) === levelFilter);
    }

    ratings.sort((a, b) => {
      switch (sortBy) {
        case "matches":
          return b.matchesPlayed - a.matchesPlayed;
        case "winRate":
          return b.winRate - a.winRate;
        default:
          return b.elo - a.elo;
      }
    });

    return ratings.map((r, i) => ({ ...r, rank: i + 1 }));
  }, [club.id, tenantId, search, levelFilter, sortBy, playersById, revision]);

  const handleSaveElo = () => {
    const result = updateClubRating(
      club.id,
      editTarget.playerId,
      Number(newElo),
      reason,
      tenantId
    );
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setEditTarget(null);
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  return (
    <Box>
      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      <Stack direction={{ xs: "column", sm: "row" }} spacing={2} mb={2}>
        <TextField
          size="small"
          label="Tìm player"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          fullWidth
        />
        <TextField
          size="small"
          label="Lọc level"
          value={levelFilter}
          onChange={(e) => setLevelFilter(e.target.value)}
          sx={{ minWidth: 120 }}
        />
        <TextField
          select
          size="small"
          label="Sắp xếp"
          value={sortBy}
          onChange={(e) => setSortBy(e.target.value)}
          SelectProps={{ native: true }}
          sx={{ minWidth: 140 }}
        >
          <option value="elo">ELO</option>
          <option value="matches">Số trận</option>
          <option value="winRate">Tỷ lệ thắng</option>
        </TextField>
      </Stack>

      {rows.length === 0 ? (
        <Paper sx={{ p: 3, textAlign: "center" }}>
          <Typography color="text.secondary">Chưa có dữ liệu xếp hạng.</Typography>
        </Paper>
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Hạng</TableCell>
                <TableCell>Tên</TableCell>
                <TableCell align="right">ELO</TableCell>
                <TableCell align="right">Level</TableCell>
                <TableCell align="right">Trận</TableCell>
                <TableCell align="right">Thắng</TableCell>
                <TableCell align="right">Thua</TableCell>
                <TableCell align="right">Tỷ lệ thắng</TableCell>
                <TableCell>Cập nhật</TableCell>
                {canEditElo && <TableCell align="right" />}
              </TableRow>
            </TableHead>
            <TableBody>
              {rows.map((row) => (
                <TableRow key={row.playerId} hover>
                  <TableCell>{row.rank}</TableCell>
                  <TableCell>{row.name}</TableCell>
                  <TableCell align="right">{row.elo}</TableCell>
                  <TableCell align="right">{row.level ?? "—"}</TableCell>
                  <TableCell align="right">{row.matchesPlayed}</TableCell>
                  <TableCell align="right">{row.wins}</TableCell>
                  <TableCell align="right">{row.losses}</TableCell>
                  <TableCell align="right">{row.winRate}%</TableCell>
                  <TableCell>
                    {new Date(row.lastUpdatedAt).toLocaleDateString("vi-VN")}
                  </TableCell>
                  {canEditElo && (
                    <TableCell align="right">
                      <Tooltip title="Chỉnh ELO">
                        <IconButton
                          size="small"
                          onClick={() => {
                            setEditTarget(row);
                            setNewElo(String(row.elo));
                            setReason("");
                          }}
                        >
                          <EditIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    </TableCell>
                  )}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={Boolean(editTarget)} onClose={() => setEditTarget(null)} maxWidth="xs" fullWidth>
        <DialogTitle>Chỉnh ELO — {editTarget?.name}</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ mt: 1 }}>
            <TextField
              label="ELO mới"
              type="number"
              value={newElo}
              onChange={(e) => setNewElo(e.target.value)}
            />
            <TextField
              label="Lý do"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Chỉnh thủ công"
            />
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setEditTarget(null)}>Hủy</Button>
          <Button variant="contained" onClick={handleSaveElo}>
            Lưu
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import VisibilityIcon from "@mui/icons-material/Visibility";

import { useAuth } from "../../../context/AuthContext.jsx";
import { useClub } from "../../../context/ClubContext.jsx";
import { PERMISSIONS } from "../../../auth/permissions.js";
import {
  createClubInternalTournament,
  getClubTournaments,
} from "../../../features/club/index.js";

export default function ClubTournamentsTab({ club, tenantId, onNavigateTournament }) {
  const navigate = useNavigate();
  const { switchClub } = useClub();
  const { can, rbacEnabled, isAuthenticated } = useAuth();
  const [createOpen, setCreateOpen] = useState(false);
  const [name, setName] = useState("");
  const [error, setError] = useState(null);
  const [revision, setRevision] = useState(0);

  const canCreate =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.TOURNAMENT_CREATE, { clubId: club.id, venueId: tenantId });

  const tournaments = useMemo(
    () => getClubTournaments(club.id, tenantId),
    [club.id, tenantId, revision]
  );

  const handleCreate = () => {
    const result = createClubInternalTournament(club.id, { name: name.trim() }, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setCreateOpen(false);
    setName("");
    setRevision((v) => v + 1);
    switchClub(club.id);
    onNavigateTournament?.(result.tournament.id);
  };

  return (
    <Box>
      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      <Stack direction="row" justifyContent="space-between" mb={2}>
        <Typography variant="subtitle1" fontWeight={600}>
          {tournaments.length} giải nội bộ
        </Typography>
        {canCreate && (
          <Button
            startIcon={<AddIcon />}
            variant="contained"
            size="small"
            onClick={() => setCreateOpen(true)}
          >
            Tạo giải nội bộ
          </Button>
        )}
      </Stack>

      {tournaments.length === 0 ? (
        <Paper sx={{ p: 3, textAlign: "center" }}>
          <Typography color="text.secondary" gutterBottom>
            CLB chưa tổ chức giải nội bộ nào.
          </Typography>
          {canCreate && (
            <Button variant="outlined" startIcon={<AddIcon />} onClick={() => setCreateOpen(true)}>
              Tạo giải đầu tiên
            </Button>
          )}
        </Paper>
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Tên giải</TableCell>
                <TableCell>Ngày tạo</TableCell>
                <TableCell>Trạng thái</TableCell>
                <TableCell>Thể thức</TableCell>
                <TableCell align="right">Thao tác</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {tournaments.map((t) => (
                <TableRow key={t.id} hover>
                  <TableCell>{t.name}</TableCell>
                  <TableCell>
                    {new Date(t.createdAt).toLocaleDateString("vi-VN")}
                  </TableCell>
                  <TableCell>{t.status}</TableCell>
                  <TableCell>{t.mode || t.type}</TableCell>
                  <TableCell align="right">
                    <Button
                      size="small"
                      startIcon={<VisibilityIcon />}
                      onClick={() => {
                        switchClub(club.id);
                        navigate(`/tournament/internal/${t.id}`);
                      }}
                    >
                      Chi tiết
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={createOpen} onClose={() => setCreateOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Tạo giải nội bộ — {club.name}</DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            fullWidth
            label="Tên giải"
            value={name}
            onChange={(e) => setName(e.target.value)}
            sx={{ mt: 1 }}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setCreateOpen(false)}>Hủy</Button>
          <Button variant="contained" disabled={!name.trim()} onClick={handleCreate}>
            Tạo & mở thiết lập
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  IconButton,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import DeleteIcon from "@mui/icons-material/Delete";
import EditIcon from "@mui/icons-material/Edit";

import { useClub } from "../../context/ClubContext.jsx";

const EMPTY_FORM = {};

export default function CoachingEntityPage({
  title,
  description,
  columns,
  fields,
  listFn,
  saveFn,
  deleteFn,
  emptyLabel = "Chưa có dữ liệu.",
}) {
  const { activeClubId, activeClub } = useClub();
  const [revision, setRevision] = useState(0);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);
  const [error, setError] = useState(null);

  const rows = useMemo(() => {
    if (!activeClubId) return [];
    return listFn(activeClubId);
  }, [activeClubId, listFn, revision]);

  const openCreate = () => {
    setForm(EMPTY_FORM);
    setError(null);
    setDialogOpen(true);
  };

  const openEdit = (row) => {
    setForm({ ...row });
    setError(null);
    setDialogOpen(true);
  };

  const handleSave = () => {
    if (!activeClubId) {
      setError("Chọn CLB trước khi lưu.");
      return;
    }
    const missing = fields.filter((field) => field.required && !String(form[field.key] || "").trim());
    if (missing.length > 0) {
      setError(`Vui lòng nhập: ${missing.map((f) => f.label).join(", ")}`);
      return;
    }
    const result = saveFn(activeClubId, form);
    if (!result.ok) {
      setError(result.error || "Không lưu được.");
      return;
    }
    setDialogOpen(false);
    setRevision((v) => v + 1);
  };

  const handleDelete = (row) => {
    if (!activeClubId) return;
    if (!window.confirm("Xóa mục này?")) return;
    deleteFn(activeClubId, row.id);
    setRevision((v) => v + 1);
  };

  return (
    <Box>
      <Stack direction={{ xs: "column", sm: "row" }} justifyContent="space-between" alignItems={{ xs: "flex-start", sm: "center" }} spacing={2} sx={{ mb: 2 }}>
        <Box>
          <Typography variant="h5" fontWeight={700}>{title}</Typography>
          <Typography color="text.secondary">{description}</Typography>
          {activeClub?.name ? (
            <Typography variant="caption" color="text.secondary" display="block" sx={{ mt: 0.5 }}>
              CLB: {activeClub.name}
            </Typography>
          ) : null}
        </Box>
        <Button startIcon={<AddIcon />} variant="contained" onClick={openCreate} disabled={!activeClubId}>
          Thêm mới
        </Button>
      </Stack>

      {!activeClubId ? (
        <Alert severity="info">Chọn CLB ở header để quản lý huấn luyện.</Alert>
      ) : null}
      {error && !dialogOpen ? <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert> : null}

      <TableContainer component={Paper} variant="outlined">
        <Table size="small">
          <TableHead>
            <TableRow>
              {columns.map((col) => (
                <TableCell key={col.key}>{col.label}</TableCell>
              ))}
              <TableCell align="right">Thao tác</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rows.length === 0 ? (
              <TableRow>
                <TableCell colSpan={columns.length + 1} align="center">
                  {emptyLabel}
                </TableCell>
              </TableRow>
            ) : (
              rows.map((row) => (
                <TableRow key={row.id} hover>
                  {columns.map((col) => (
                    <TableCell key={col.key}>{col.render ? col.render(row) : row[col.key] || "—"}</TableCell>
                  ))}
                  <TableCell align="right">
                    <IconButton size="small" onClick={() => openEdit(row)} aria-label="Sửa">
                      <EditIcon fontSize="small" />
                    </IconButton>
                    <IconButton size="small" color="error" onClick={() => handleDelete(row)} aria-label="Xóa">
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </TableContainer>

      <Dialog open={dialogOpen} onClose={() => setDialogOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>{form.id ? "Chỉnh sửa" : "Thêm mới"}</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ mt: 1 }}>
            {error ? <Alert severity="error">{error}</Alert> : null}
            {fields.map((field) => (
              <TextField
                key={field.key}
                label={field.label}
                value={form[field.key] || ""}
                onChange={(event) => setForm((prev) => ({ ...prev, [field.key]: event.target.value }))}
                required={field.required}
                multiline={field.multiline}
                minRows={field.multiline ? 3 : undefined}
                type={field.type || "text"}
                fullWidth
              />
            ))}
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDialogOpen(false)}>Hủy</Button>
          <Button variant="contained" onClick={handleSave}>Lưu</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useMemo } from "react";
import { useOutletContext } from "react-router-dom";

import { Box, Grid } from "@mui/material";

import LiveCourtsHero from "../../components/courts/LiveCourtsHero.jsx";
import CourtStats from "../../components/courts/CourtStats.jsx";
import DirectorSuggestionPanel from "../../components/courts/DirectorSuggestionPanel.jsx";
import CourtStatusBoard from "./CourtStatusBoard.jsx";
import MyFacilityPanel from "../../features/court-cluster/components/MyFacilityPanel.jsx";
import { isCourtClustersEnabled } from "../../features/court-cluster/config/clusterFlags.js";
import {
  computeCourtDashboardStats,
  generateDirectorSuggestions,
