import { useCallback, useEffect, useMemo, useState } from "react";

import { Link as RouterLink, Outlet, useLocation, useNavigate } from "react-router-dom";



import { Box, Alert, Stack, Tab, Tabs, Typography } from "@mui/material";



import { useClub } from "../../context/ClubContext.jsx";

import { useAuth } from "../../context/AuthContext.jsx";

import { isMenuItemVisible } from "../../auth/menuAccess.js";

import { COURT_MANAGEMENT_TABS } from "../../config/courtManagementTabs.js";

import { loadCourtManagementData, autoCompletePastBookings, autoStartDueBookings } from "../../domain/bookingService.js";

import { getUpcomingReminders, processBookingReminders } from "../../domain/bookingReminderService.js";

import { loadCourtManagementSettings } from "../../domain/courtManagementSettings.js";

import { loadCourts } from "../courts.logic.js";

import CourtManagementSearchBar from "./CourtManagementSearchBar.jsx";



function resolveTabIndex(pathname, visibleTabs) {

  const index = visibleTabs.findIndex(

    (tab) => pathname === tab.path || pathname.startsWith(`${tab.path}/`)

  );

  return index >= 0 ? index : 0;

}



export default function CourtManagementLayout() {

  const { activeClubId, activeClub, revision, refreshClubs } = useClub();

  const auth = useAuth();

  const location = useLocation();

  const navigate = useNavigate();

  const [dataVersion, setDataVersion] = useState(0);

  const [reminderAlerts, setReminderAlerts] = useState([]);



  const scope = useMemo(

    () => ({

      clubId: activeClubId,

      venueId: activeClub?.venueId || auth.user?.venueId || null,

    }),

    [activeClubId, activeClub?.venueId, auth.user?.venueId]

  );



  const visibleTabs = useMemo(

    () =>

      COURT_MANAGEMENT_TABS.filter((tab) =>

        isMenuItemVisible(tab, { ...auth, scope })

      ),

    [auth, scope]

  );



  const courts = useMemo(

    () => loadCourts([], activeClubId),

    [activeClubId, revision, dataVersion]

  );



  const bookings = useMemo(() => {

    return loadCourtManagementData(activeClubId).bookings;

  }, [activeClubId, revision, dataVersion]);



  const handleRefresh = useCallback(() => {

    setDataVersion((value) => value + 1);

    refreshClubs();

  }, [refreshClubs]);



  useEffect(() => {

    setDataVersion((value) => value + 1);

  }, [activeClubId, revision]);



  useEffect(() => {

    if (!auth.rbacEnabled || !auth.isAuthenticated) {

      return;

    }



    const allowed = visibleTabs.some(

      (tab) =>

        location.pathname === tab.path || location.pathname.startsWith(`${tab.path}/`)

    );



    if (!allowed && visibleTabs[0]?.path) {

      navigate(visibleTabs[0].path, { replace: true });

    }

  }, [auth.rbacEnabled, auth.isAuthenticated, location.pathname, navigate, visibleTabs]);



  useEffect(() => {

    const settings = loadCourtManagementSettings(activeClubId);



    if (!settings.automationSettings?.autoCompleteOnOpen) {

      return;

    }



    const result = autoCompletePastBookings(activeClubId);



    if (result.updatedCount > 0) {

      setDataVersion((value) => value + 1);

      refreshClubs();

    }

  }, [activeClubId, refreshClubs]);



  useEffect(() => {

    const settings = loadCourtManagementSettings(activeClubId);



    if (!settings.notificationSettings?.enabled) {

      setReminderAlerts([]);

      return undefined;

    }



    const tick = () => {

      const currentSettings = loadCourtManagementSettings(activeClubId);



      if (!currentSettings.notificationSettings?.enabled) {

        setReminderAlerts([]);

        return;

      }



      const upcoming = getUpcomingReminders(activeClubId);



      if (currentSettings.notificationSettings.inAppNotify && upcoming.length > 0) {

        setReminderAlerts(upcoming);

      }



      processBookingReminders(activeClubId);

    };



    tick();

    const timer = window.setInterval(tick, 60_000);



    return () => window.clearInterval(timer);

  }, [activeClubId, dataVersion, revision]);



  useEffect(() => {

    const tick = () => {

      const settings = loadCourtManagementSettings(activeClubId);



      if (!settings.automationSettings?.autoStartPlaying) {

        return;

      }



      const result = autoStartDueBookings(activeClubId);



      if (result.updatedCount > 0) {

        setDataVersion((value) => value + 1);

        refreshClubs();

      }

    };



    tick();

    const timer = window.setInterval(tick, 60_000);



    return () => window.clearInterval(timer);

  }, [activeClubId, dataVersion, revision, refreshClubs]);



  const tabIndex = resolveTabIndex(location.pathname, visibleTabs);

  const isHomeTab = visibleTabs[tabIndex]?.path === "/court-management";



  return (

    <Box>

      {!isHomeTab && (

        <Stack spacing={1} sx={{ mb: 3 }}>

          <Typography variant="h4" fontWeight="bold">

            Quản lý sân

          </Typography>

          <Typography variant="body2" color="text.secondary">

            Đặt sân, khách hàng, doanh thu và vận hành nâng cao.

          </Typography>

        </Stack>

      )}



      {reminderAlerts.length > 0 && (

        <Stack spacing={1} sx={{ mb: 2 }}>

          {reminderAlerts.map((booking) => (

            <Alert

              key={booking.id}

              severity="info"

              onClose={() =>

                setReminderAlerts((current) => current.filter((item) => item.id !== booking.id))

              }

            >

              Booking sắp tới: {booking.customerName} · {booking.courtName || `Sân ${booking.courtId}`}{" "}

              · {booking.startTime}

            </Alert>

          ))}

        </Stack>

      )}



      <CourtManagementSearchBar clubId={activeClubId} bookings={bookings} />



      <Tabs

        value={tabIndex}

        onChange={(_, index) => navigate(visibleTabs[index]?.path || "/court-management")}

        variant="scrollable"

        scrollButtons="auto"

        sx={{ mb: 3, borderBottom: 1, borderColor: "divider" }}

      >

        {visibleTabs.map((tab) => (

          <Tab

            key={tab.path}

            label={tab.label}

            component={RouterLink}

            to={tab.path}

            sx={{ textTransform: "none", fontWeight: 600 }}

          />

        ))}

      </Tabs>



      <Outlet

        context={{

          clubId: activeClubId,

          courts,

          bookings,

          revision: dataVersion,

          onRefresh: handleRefresh,

        }}

      />

    </Box>

  );

}

import { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";

import {
  Box,
  Button,
  Card,
  CardContent,
  List,
  ListItemButton,
  ListItemText,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import { loadCustomersForClub } from "../../domain/clubStorage.js";
import { searchCourtManagementData } from "../../domain/courtManagementSearch.js";

export default function CourtManagementSearchBar({ clubId, bookings = [] }) {
  const navigate = useNavigate();
  const [query, setQuery] = useState("");

  const customers = useMemo(() => loadCustomersForClub(clubId), [clubId, bookings]);

  const results = useMemo(() => {
    if (!query.trim()) {
      return { bookings: [], customers: [] };
    }

    return searchCourtManagementData(bookings, customers, query);
  }, [bookings, customers, query]);

  const hasResults = results.bookings.length > 0 || results.customers.length > 0;

  const goToBookings = () => {
    navigate(`/court-management/bookings?q=${encodeURIComponent(query.trim())}`);
    setQuery("");
  };

  return (
    <Card variant="outlined" sx={{ mb: 2 }}>
      <CardContent>
        <Stack spacing={1.5}>
          <TextField
            label="Tìm booking / khách / mã / SĐT"
            value={query}
            onChange={(event) => setQuery(event.target.value)}
            fullWidth
            size="small"
          />

          {query.trim() && (
            <Box>
              {!hasResults ? (
                <Typography variant="body2" color="text.secondary">
                  Không tìm thấy kết quả.
                </Typography>
              ) : (
                <List dense disablePadding>
                  {results.bookings.map((booking) => (
                    <ListItemButton key={booking.id} onClick={goToBookings}>
                      <ListItemText
                        primary={`${booking.customerName} · ${booking.courtName}`}
                        secondary={`${booking.date} ${booking.startTime} · ${booking.bookingCode}`}
                      />
                    </ListItemButton>
                  ))}
                  {results.customers.map((customer) => (
                    <ListItemButton
                      key={customer.id}
                      onClick={() => {
                        navigate(
                          `/court-management/customers?q=${encodeURIComponent(customer.name)}`
                        );
                        setQuery("");
                      }}
                    >
                      <ListItemText
                        primary={customer.name}
                        secondary={customer.phone || "Chưa có SĐT"}
                      />
                    </ListItemButton>
                  ))}
                </List>
              )}

              {results.bookings.length > 0 && (
                <Button size="small" onClick={goToBookings} sx={{ mt: 1 }}>
                  Xem tất cả booking khớp
                </Button>
              )}
            </Box>
          )}
        </Stack>
      </CardContent>
    </Card>
  );
}

import { useMemo, useState } from "react";

import { Box, Grid } from "@mui/material";

import { setCourtOperationalStatus, updateBookingStatus } from "../../domain/bookingService.js";
import { buildCourtBoardData } from "../../utils/courtHelpers.js";
import { todayIsoDate } from "./courtManagement.constants.js";
import CourtCard from "../../components/courts/CourtCard.jsx";
import BookingForm from "./BookingForm.jsx";
import BookingDetail from "./BookingDetail.jsx";

export default function CourtStatusBoard({
  clubId,
  courts = [],
  bookings = [],
  onRefresh,
}) {
  const [formDefaults, setFormDefaults] = useState(null);
  const [detailBooking, setDetailBooking] = useState(null);
  const today = todayIsoDate();
  const now = useMemo(() => new Date(), [bookings, courts]);

  const boardData = useMemo(
    () => buildCourtBoardData(courts, bookings, now),
    [courts, bookings, now]
  );

  const handleLockToggle = (court) => {
    const nextStatus = court.status === "locked" ? "active" : "locked";
    setCourtOperationalStatus(court.id, nextStatus, clubId);
    onRefresh?.();
  };

  const handleMaintenanceToggle = (court) => {
    const nextStatus = court.status === "maintenance" ? "active" : "maintenance";
    setCourtOperationalStatus(court.id, nextStatus, clubId);
    onRefresh?.();
  };

  const handleQuickStatus = (booking, status) => {
    const result = updateBookingStatus(booking.id, status, clubId);
    if (result.ok) onRefresh?.();
  };

  return (
    <Box>
      <Grid container spacing={2}>
        {boardData.map((courtData) => (
          <Grid
            key={courtData.court.id}
            size={{ xs: 12, sm: 6, md: 4, xl: 3 }}
          >
            <CourtCard
              courtData={courtData}
              onCreateBooking={(court) => setFormDefaults({ courtId: court.id, date: today })}
              onDetail={setDetailBooking}
              onQuickStatus={handleQuickStatus}
              onLockToggle={handleLockToggle}
              onMaintenanceToggle={handleMaintenanceToggle}
            />
          </Grid>
        ))}
      </Grid>

      <BookingForm
        open={Boolean(formDefaults)}
        onClose={() => setFormDefaults(null)}
        clubId={clubId}
        courts={courts}
        initialValues={formDefaults || {}}
        onSaved={() => {
          setFormDefaults(null);
          onRefresh?.();
        }}
      />

      <BookingDetail
        open={Boolean(detailBooking)}
        booking={detailBooking}
        clubId={clubId}
        courts={courts}
        onClose={() => setDetailBooking(null)}
        onUpdated={() => {
          onRefresh?.();
          setDetailBooking(null);
        }}
      />
    </Box>
  );
}

import { useMemo, useState } from "react";

import {
  Box,
  Button,
  Card,
  CardContent,
  LinearProgress,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import { computeCourtUtilization } from "../../domain/courtBookingEngine.js";
import {
  buildUtilizationCsv,
  downloadTextFile,
  loadCourtManagementSettings,
} from "../../domain/courtManagementSettings.js";
import { todayIsoDate } from "./courtManagement.constants.js";

export default function CourtUtilizationPanel({ clubId, courts = [], bookings = [], revision = 0 }) {
  const [fromDate, setFromDate] = useState(todayIsoDate());
  const [toDate, setToDate] = useState(todayIsoDate());

  const summary = useMemo(() => {
    const settings = loadCourtManagementSettings(clubId);
    return computeCourtUtilization(
      bookings,
      courts,
      fromDate,
      toDate,
      settings.openHour,
      settings.closeHour
    );
  }, [bookings, courts, fromDate, toDate, clubId, revision]);

  return (
    <Card variant="outlined">
      <CardContent>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6">Công suất sân</Typography>
            <Typography variant="body2" color="text.secondary">
              Tỷ lệ giờ đã book so với giờ mở cửa trong khoảng ngày chọn.
            </Typography>
          </Box>

          <Stack direction={{ xs: "column", sm: "row" }} spacing={2}>
            <TextField
              label="Từ ngày"
              type="date"
              value={fromDate}
              onChange={(event) => setFromDate(event.target.value)}
              InputLabelProps={{ shrink: true }}
            />
            <TextField
              label="Đến ngày"
              type="date"
              value={toDate}
              onChange={(event) => setToDate(event.target.value)}
              InputLabelProps={{ shrink: true }}
            />
            <Button
              variant="outlined"
              onClick={() =>
                downloadTextFile(
                  `cong-suat-${fromDate}-${toDate}.csv`,
                  buildUtilizationCsv(summary)
                )
              }
            >
              Xuất CSV
            </Button>
          </Stack>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Công suất tổng
            </Typography>
            <Typography variant="h4" fontWeight="bold">
              {summary.utilizationPercent}%
            </Typography>
            <LinearProgress
              variant="determinate"
              value={Math.min(100, summary.utilizationPercent)}
              sx={{ mt: 1, height: 8, borderRadius: 1 }}
            />
          </Box>

          {summary.byCourt.length === 0 ? (
            <Typography color="text.secondary">Chưa có sân để thống kê.</Typography>
          ) : (
            summary.byCourt.map((row) => (
              <Box key={row.courtId}>
                <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
                  <Typography fontWeight="medium">{row.courtName}</Typography>
                  <Typography variant="body2">
                    {row.utilizationPercent}% · {row.bookingCount} booking
                  </Typography>
                </Stack>
                <LinearProgress
                  variant="determinate"
                  value={Math.min(100, row.utilizationPercent)}
                  sx={{ height: 6, borderRadius: 1 }}
                />
              </Box>
            ))
          )}
        </Stack>
      </CardContent>
    </Card>
  );
}

import { useMemo, useState } from "react";
import { useOutletContext } from "react-router-dom";

import {
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  IconButton,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  TextField,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import DeleteIcon from "@mui/icons-material/Delete";

import {
  createCustomerGroup,
  deleteCustomerGroup,
  listCustomerGroups,
} from "../../features/customer-groups/services/customerGroupService.js";

export default function CustomerGroupsPage() {
  const { clubId, onRefresh } = useOutletContext();
  const [revision, setRevision] = useState(0);
  const [open, setOpen] = useState(false);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");

  const groups = useMemo(() => listCustomerGroups(clubId), [clubId, revision]);

  const handleCreate = () => {
    if (!name.trim()) return;
    createCustomerGroup(clubId, { name, description });
    setName("");
    setDescription("");
    setOpen(false);
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  return (
    <Box>
      <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 2 }}>
        <Typography variant="h6" fontWeight={700}>
          Nhóm khách hàng
        </Typography>
        <Button startIcon={<AddIcon />} variant="contained" onClick={() => setOpen(true)}>
          Tạo nhóm
        </Button>
      </Stack>

      <Paper variant="outlined">
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell>Tên nhóm</TableCell>
              <TableCell>Mô tả</TableCell>
              <TableCell align="right">Thành viên</TableCell>
              <TableCell width={56} />
            </TableRow>
          </TableHead>
          <TableBody>
            {groups.length === 0 ? (
              <TableRow>
                <TableCell colSpan={4}>
                  <Typography color="text.secondary">Chưa có nhóm — tạo nhóm để phân khúc KH.</Typography>
                </TableCell>
              </TableRow>
            ) : (
              groups.map((group) => (
                <TableRow key={group.id}>
                  <TableCell>{group.name}</TableCell>
                  <TableCell>{group.description || "—"}</TableCell>
                  <TableCell align="right">{group.memberIds?.length || 0}</TableCell>
                  <TableCell>
                    <IconButton
                      size="small"
                      onClick={() => {
                        deleteCustomerGroup(clubId, group.id);
                        setRevision((v) => v + 1);
                      }}
                    >
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))
            )}
