  const summary = useMemo(() => {
    const now = new Date();
    const soon = new Date();
    soon.setDate(soon.getDate() + 30);

    let active = 0;
    let expiringSoon = 0;

    for (const member of members) {
      const status = getMembershipStatus(member);
      if (status === "active") {
        active += 1;
        if (member.membershipExpiresAt) {
          const expires = new Date(member.membershipExpiresAt);
          if (!Number.isNaN(expires.getTime()) && expires <= soon && expires >= now) {
            expiringSoon += 1;
          }
        }
      }
    }

    return { total: members.length, active, expiringSoon };
  }, [members]);

  const filteredMembers = useMemo(() => {
    const query = search.trim().toLowerCase();

    return members.filter((member) => {
      const status = getMembershipStatus(member);
      if (statusFilter === "active" && status !== "active") return false;
      if (statusFilter === "expired" && status !== "expired") return false;

      if (!query) return true;

      return (
        member.name.toLowerCase().includes(query) ||
        (member.phone && member.phone.includes(query))
      );
    });
  }, [members, search, statusFilter]);

  const openCreateForm = () => {
    setEditingMember(null);
    setFormOpen(true);
  };

  const openEditForm = (member) => {
    setEditingMember(member);
    setFormOpen(true);
  };

  return (
    <Box>
      <Stack
        direction={{ xs: "column", sm: "row" }}
        spacing={2}
        alignItems={{ xs: "stretch", sm: "center" }}
        justifyContent="space-between"
        sx={{ mb: 2 }}
      >
        <Typography variant="body2" color="text.secondary">
          Quản lý hội viên: gói thành viên, hạn sử dụng và lịch sử sử dụng sân.
        </Typography>
        <PermissionGate permission={PERMISSIONS.CUSTOMER_UPDATE}>
          <Button variant="contained" startIcon={<AddIcon />} onClick={openCreateForm}>
            Thêm hội viên
          </Button>
        </PermissionGate>
      </Stack>

      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid item xs={12} sm={4}>
          <SummaryCard label="Tổng hội viên" value={summary.total} icon={GroupsIcon} />
        </Grid>
        <Grid item xs={12} sm={4}>
          <SummaryCard
            label="Đang hiệu lực"
            value={summary.active}
            icon={EventAvailableIcon}
            color="success.main"
          />
        </Grid>
        <Grid item xs={12} sm={4}>
          <SummaryCard
            label="Sắp hết hạn (30 ngày)"
            value={summary.expiringSoon}
            icon={WarningAmberIcon}
            color="warning.main"
          />
        </Grid>
      </Grid>

      <Stack direction={{ xs: "column", sm: "row" }} spacing={2} sx={{ mb: 2 }}>
        <TextField
          label="Tìm theo tên hoặc SĐT"
          value={search}
          onChange={(event) => setSearch(event.target.value)}
          fullWidth
        />
        <FormControl sx={{ minWidth: 180 }}>
          <InputLabel>Trạng thái</InputLabel>
          <Select
            label="Trạng thái"
            value={statusFilter}
            onChange={(event) => setStatusFilter(event.target.value)}
          >
            <MenuItem value="all">Tất cả</MenuItem>
            <MenuItem value="active">Đang hiệu lực</MenuItem>
            <MenuItem value="expired">Hết hạn</MenuItem>
          </Select>
        </FormControl>
      </Stack>

      {members.length === 0 && (
        <Alert severity="info" sx={{ mb: 2 }}>
          Chưa có hội viên. Bấm &quot;Thêm hội viên&quot; để bắt đầu hoặc chuyển khách hàng sang loại hội viên tại trang Khách hàng.
        </Alert>
      )}

      <TableContainer component={Paper}>
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell>Tên</TableCell>
              <TableCell>Điện thoại</TableCell>
              <TableCell>Gói</TableCell>
              <TableCell>Gia nhập</TableCell>
              <TableCell>Hết hạn</TableCell>
              <TableCell>Trạng thái</TableCell>
              <TableCell>Booking</TableCell>
              <TableCell>Đã chi</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {filteredMembers.length === 0 && (
              <TableRow>
                <TableCell colSpan={8}>
                  <Typography color="text.secondary" sx={{ py: 2, textAlign: "center" }}>
                    {search || statusFilter !== "all"
                      ? "Không tìm thấy hội viên phù hợp."
                      : "Chưa có hội viên."}
                  </Typography>
                </TableCell>
              </TableRow>
            )}

            {filteredMembers.map((member) => {
              const status = getMembershipStatus(member);
              return (
                <TableRow
                  key={member.id}
                  hover
                  sx={{ cursor: "pointer" }}
                  onClick={() => setSelectedMember(member)}
                >
                  <TableCell>{member.name}</TableCell>
                  <TableCell>{member.phone || "—"}</TableCell>
                  <TableCell>{getMembershipPlanLabel(member.membershipPlan)}</TableCell>
                  <TableCell>{formatDate(member.memberSince || member.createdAt)}</TableCell>
                  <TableCell>{formatDate(member.membershipExpiresAt)}</TableCell>
                  <TableCell>
                    <Chip
                      size="small"
                      label={STATUS_LABELS[status] || status}
                      color={STATUS_COLORS[status] || "default"}
                    />
                  </TableCell>
                  <TableCell>{member.totalBookings || 0}</TableCell>
                  <TableCell>{formatCurrency(member.totalSpent || 0)} đ</TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </TableContainer>

      <MemberFormDialog
        open={formOpen}
        onClose={() => setFormOpen(false)}
        clubId={clubId}
        editingMember={editingMember}
        onSaved={() => onRefresh?.()}
      />

      <CustomerDetailDialog
        open={Boolean(selectedMember)}
        customer={selectedMember}
        bookings={bookings}
        clubId={clubId}
        onClose={() => setSelectedMember(null)}
        onEdit={(member) => {
          setSelectedMember(null);
          openEditForm(member);
        }}
        onDeleted={() => {
          setSelectedMember(null);
          onRefresh?.();
        }}
        onOpenBooking={(booking) => {
          setSelectedMember(null);
          setDetailBooking(booking);
        }}
        onBookCourt={(member) => {
          setSelectedMember(null);
          setBookingFormMember(member);
        }}
      />

      <BookingForm
        open={Boolean(bookingFormMember)}
        onClose={() => setBookingFormMember(null)}
        clubId={clubId}
        courts={courts}
        initialValues={{
          date: todayIsoDate(),
          customerName: bookingFormMember?.name || "",
          customerPhone: bookingFormMember?.phone || "",
        }}
        onSaved={() => {
          setBookingFormMember(null);
          onRefresh?.();
        }}
      />

      <BookingDetail
        open={Boolean(detailBooking)}
        booking={detailBooking}
        clubId={clubId}
        courts={courts}
        onClose={() => setDetailBooking(null)}
        onUpdated={() => {
          setDetailBooking(null);
          onRefresh?.();
        }}
      />
    </Box>
  );
}

import { Box, Chip, Stack, Typography } from "@mui/material";

import { CALENDAR_CELL_TONES, CALENDAR_LEGEND_ITEMS } from "./courtCalendarTokens.js";

export default function CourtCalendarLegend() {
  return (
    <Stack direction="row" spacing={1} flexWrap="wrap" sx={{ mt: 2 }}>
      {CALENDAR_LEGEND_ITEMS.map((tone) => {
        const token = CALENDAR_CELL_TONES[tone];
        return (
          <Chip
            key={tone}
            size="small"
            label={token.label}
            sx={{
              bgcolor: token.bg,
              color: token.color,
              border: `1px solid ${token.border}`,
              fontWeight: 600,
            }}
          />
        );
      })}
    </Stack>
  );
}

