import { useMemo, useState } from "react";

import { Alert, Box, Snackbar, Typography } from "@mui/material";

import { loadCourtManagementSettings } from "../../../domain/courtManagementSettings.js";
import {
  getWeekDates,
  shiftIsoDate,
  shiftIsoMonth,
  timeToMinutes,
} from "../../../domain/courtBookingEngine.js";
import { filterCourtsByCluster } from "../../../features/court-cluster/services/courtClusterService.js";
import { isCourtClustersEnabled } from "../../../features/court-cluster/config/clusterFlags.js";
import BookingForm from "../BookingForm.jsx";
import BookingDetail from "../BookingDetail.jsx";
import { formatDisplayDate, todayIsoDate } from "../courtManagement.constants.js";
import CourtCalendarToolbar from "./CourtCalendarToolbar.jsx";
import CourtCalendarDayGrid from "./CourtCalendarDayGrid.jsx";
import CourtCalendarWeekMatrix from "./CourtCalendarWeekMatrix.jsx";
import CourtCalendarMonthBoard from "./CourtCalendarMonthBoard.jsx";

const MONTH_LABELS = [
  "Tháng 1",
  "Tháng 2",
  "Tháng 3",
  "Tháng 4",
  "Tháng 5",
  "Tháng 6",
  "Tháng 7",
  "Tháng 8",
  "Tháng 9",
  "Tháng 10",
  "Tháng 11",
  "Tháng 12",
];

function formatWeekdayDate(isoDate) {
  const date = new Date(`${isoDate}T12:00:00`);
  const weekdays = ["Chủ Nhật", "Thứ Hai", "Thứ Ba", "Thứ Tư", "Thứ Năm", "Thứ Sáu", "Thứ Bảy"];
  return `${weekdays[date.getDay()]}, ${formatDisplayDate(isoDate)}`;
}

export default function CourtCalendarShell({
  clubId,
  courts = [],
  bookings = [],
  revision = 0,
  onRefresh,
  clusters = [],
  previewMode = false,
  initialView = "day",
  initialDate = todayIsoDate(),
}) {
  const [view, setView] = useState(initialView);
  const [anchorDate, setAnchorDate] = useState(initialDate);
  const [activeClusterId, setActiveClusterId] = useState("all");
  const [formOpen, setFormOpen] = useState(false);
  const [formDefaults, setFormDefaults] = useState({});
  const [detailBooking, setDetailBooking] = useState(null);
  const [previewToast, setPreviewToast] = useState("");

  const settings = useMemo(
    () => loadCourtManagementSettings(clubId),
    [clubId, revision]
  );

  const filteredCourts = useMemo(() => {
    if (!isCourtClustersEnabled() || activeClusterId === "all") {
      return courts;
    }
    return filterCourtsByCluster(courts, activeClusterId);
  }, [courts, activeClusterId]);

  const clusterNameById = useMemo(() => {
    const map = {};
    clusters.forEach((cluster) => {
      map[cluster.id] = cluster.name;
    });
    return map;
  }, [clusters]);

  const dateLabel = useMemo(() => {
    if (view === "month") {
      const [year, month] = anchorDate.split("-").map(Number);
      return `${MONTH_LABELS[month - 1]} ${year}`;
    }

    if (view === "week") {
      const weekDates = getWeekDates(anchorDate);
      return `${formatDisplayDate(weekDates[0])} – ${formatDisplayDate(weekDates[6])}`;
    }

    return formatWeekdayDate(anchorDate);
  }, [anchorDate, view]);

  const kpiDate = view === "day" ? anchorDate : todayIsoDate();
  const isToday = anchorDate === todayIsoDate() && view === "day";
  const now = new Date();
  const nowSlotIndex = useMemo(() => {
    if (!isToday) {
      return -1;
    }
    const slots = [];
    for (let hour = settings.openHour; hour < settings.closeHour; hour += 1) {
      slots.push(`${String(hour).padStart(2, "0")}:00`);
    }
    const current = `${String(now.getHours()).padStart(2, "0")}:00`;
    return slots.findIndex((slot) => timeToMinutes(slot) <= timeToMinutes(current));
  }, [isToday, settings.openHour, settings.closeHour, now.getHours()]);

  const openCreateForm = (defaults = {}) => {
    if (previewMode) {
      setPreviewToast("Preview: mở form tạo booking (chưa ghi dữ liệu).");
      return;
    }
    setFormDefaults({
      date: view === "day" ? anchorDate : defaults.date || anchorDate,
      ...defaults,
    });
    setFormOpen(true);
  };

  const handlePrev = () => {
    if (view === "month") {
      setAnchorDate(shiftIsoMonth(anchorDate, -1));
      return;
    }
    if (view === "week") {
      setAnchorDate(shiftIsoDate(anchorDate, -7));
      return;
    }
    setAnchorDate(shiftIsoDate(anchorDate, -1));
  };

  const handleNext = () => {
    if (view === "month") {
      setAnchorDate(shiftIsoMonth(anchorDate, 1));
      return;
    }
    if (view === "week") {
      setAnchorDate(shiftIsoDate(anchorDate, 7));
      return;
    }
    setAnchorDate(shiftIsoDate(anchorDate, 1));
  };

  const handleToday = () => {
    setAnchorDate(todayIsoDate());
  };

  const handleEmptyCell = (court, slotTime) => {
    const endHour = String(Number(slotTime.slice(0, 2)) + 1).padStart(2, "0");
    openCreateForm({
      courtId: court.id,
      startTime: slotTime,
      endTime: `${endHour}:00`,
    });
  };

  const handleBookingClick = (booking) => {
    if (previewMode) {
      setPreviewToast(`Preview: ${booking.customerName} · ${booking.startTime}–${booking.endTime}`);
      return;
    }
    setDetailBooking(booking);
  };

  return (
    <Box>
      {previewMode && (
        <Alert severity="warning" sx={{ mb: 2 }}>
          <Typography variant="body2" fontWeight={700}>
            Bản xem trước thiết kế V5 — chưa áp dụng production
          </Typography>
          <Typography variant="caption">
            Dữ liệu giả trong bộ nhớ. Dùng để duyệt layout, màu sắc và tương tác.
          </Typography>
        </Alert>
      )}

      <CourtCalendarToolbar
        view={view}
        onViewChange={setView}
        anchorDate={anchorDate}
        dateLabel={dateLabel}
        onPrev={handlePrev}
        onToday={handleToday}
        onNext={handleNext}
        courts={filteredCourts}
        bookings={bookings}
        openHour={settings.openHour}
        closeHour={settings.closeHour}
        clusters={clusters}
        activeClusterId={activeClusterId}
        onClusterChange={setActiveClusterId}
        onCreateBooking={() => openCreateForm()}
        kpiDate={kpiDate}
      />

      {view === "month" ? (
        <CourtCalendarMonthBoard
          bookings={bookings}
          anchorDate={anchorDate}
          onEmptyDayClick={(date) => openCreateForm({ date })}
          onBookingClick={handleBookingClick}
        />
      ) : view === "week" ? (
        <CourtCalendarWeekMatrix
          courts={filteredCourts}
          bookings={bookings}
          anchorDate={anchorDate}
          openHour={settings.openHour}
          closeHour={settings.closeHour}
          onOpenDay={(date) => {
            setAnchorDate(date);
            setView("day");
          }}
          onBookingClick={handleBookingClick}
        />
      ) : (
        <CourtCalendarDayGrid
          courts={filteredCourts}
          bookings={bookings}
          selectedDate={anchorDate}
          openHour={settings.openHour}
          closeHour={settings.closeHour}
          slotMinutes={settings.slotMinutes}
          clusterNameById={clusterNameById}
          isToday={isToday}
          nowSlotIndex={nowSlotIndex}
          onEmptyCellClick={handleEmptyCell}
          onBookingClick={handleBookingClick}
        />
      )}

      {!previewMode && (
        <>
          <BookingForm
            open={formOpen}
            onClose={() => setFormOpen(false)}
            clubId={clubId}
            courts={filteredCourts}
            initialValues={formDefaults}
            onSaved={() => onRefresh?.()}
          />

          <BookingDetail
            open={Boolean(detailBooking)}
            booking={detailBooking}
            clubId={clubId}
            courts={filteredCourts}
            onClose={() => setDetailBooking(null)}
            onUpdated={() => {
              onRefresh?.();
              setDetailBooking(null);
            }}
          />
        </>
      )}

      <Snackbar
        open={Boolean(previewToast)}
        autoHideDuration={3000}
        onClose={() => setPreviewToast("")}
        message={previewToast}
        anchorOrigin={{ vertical: "bottom", horizontal: "center" }}
      />
    </Box>
  );
}

import { useMemo, useState } from "react";

import {
  Box,
  Chip,
  Drawer,
  List,
  ListItemButton,
  ListItemText,
  Paper,
  Stack,
  Typography,
} from "@mui/material";

import { getCourtDisplayName } from "../../../models/court.js";
import { getBookingsByDate, getWeekDates } from "../../../domain/courtBookingEngine.js";
import { isActiveBookingStatus } from "../../../models/booking.js";
import { formatDisplayDate } from "../courtManagement.constants.js";
import { CALENDAR_SHELL } from "./courtCalendarTokens.js";

const WEEKDAY_SHORT = ["T2", "T3", "T4", "T5", "T6", "T7", "CN"];

function OccupancyDots({ bookings, openHour = 6, closeHour = 22 }) {
  const peakHours = 8;
  const startHour = Math.max(openHour, 8);
  const dots = [];

  for (let index = 0; index < peakHours; index += 1) {
    const hour = startHour + index;
    const hasBooking = bookings.some((booking) => {
      const start = Number(booking.startTime?.slice(0, 2));
      const end = Number(booking.endTime?.slice(0, 2));
      return hour >= start && hour < end;
    });
    dots.push(hasBooking);
  }

  return (
    <Stack direction="row" spacing={0.4} sx={{ mt: 0.75 }}>
      {dots.map((active, index) => (
        <Box
          key={index}
          sx={{
            width: 8,
            height: 8,
            borderRadius: "50%",
            bgcolor: active ? CALENDAR_SHELL.primary : "action.hover",
          }}
        />
      ))}
    </Stack>
  );
}

export default function CourtCalendarWeekMatrix({
  courts = [],
  bookings = [],
  anchorDate,
  openHour = 6,
  closeHour = 22,
  onOpenDay,
  onBookingClick,
}) {
  const weekDates = useMemo(() => getWeekDates(anchorDate), [anchorDate]);
  const [drawer, setDrawer] = useState(null);

  const cellBookings = useMemo(() => {
    const map = new Map();

    courts.forEach((court) => {
      weekDates.forEach((date) => {
        const key = `${court.id}-${date}`;
        const dayBookings = getBookingsByDate(bookings, date)
          .filter((booking) => booking.courtId === court.id)
          .filter((booking) => isActiveBookingStatus(booking.bookingStatus));
        map.set(key, dayBookings);
      });
    });

    return map;
  }, [bookings, courts, weekDates]);

  return (
    <Box>
      <Paper
        elevation={0}
        sx={{
          border: CALENDAR_SHELL.cardBorder,
          borderRadius: `${CALENDAR_SHELL.cardRadius}px`,
          boxShadow: CALENDAR_SHELL.cardShadow,
          overflow: "auto",
        }}
      >
        <Box
          sx={{
            display: "grid",
            gridTemplateColumns: `160px repeat(7, minmax(120px, 1fr))`,
            minWidth: 900,
          }}
        >
          <Box
            sx={{
              p: 1.25,
              fontWeight: 700,
              borderBottom: 1,
              borderRight: 1,
              borderColor: "divider",
              bgcolor: "background.paper",
              position: "sticky",
              left: 0,
              zIndex: 2,
            }}
          >
            Sân
          </Box>

          {weekDates.map((date, index) => (
            <Box
              key={date}
              sx={{
                p: 1,
                borderBottom: 1,
                borderRight: 1,
                borderColor: "divider",
                bgcolor: "background.paper",
                textAlign: "center",
              }}
            >
              <Typography variant="caption" color="text.secondary" display="block">
                {WEEKDAY_SHORT[index]}
              </Typography>
              <Typography variant="subtitle2" fontWeight={700}>
                {formatDisplayDate(date)}
              </Typography>
            </Box>
          ))}

          {courts.map((court, courtIndex) => (
            <Box key={court.id} sx={{ display: "contents" }}>
              <Box
                sx={{
                  p: 1.25,
                  borderBottom: 1,
                  borderRight: 1,
                  borderColor: "divider",
                  bgcolor: "background.paper",
                  position: "sticky",
                  left: 0,
                  zIndex: 1,
                }}
              >
                <Typography variant="subtitle2" fontWeight={700}>
                  {getCourtDisplayName(court, courtIndex)}
                </Typography>
              </Box>

              {weekDates.map((date) => {
                const key = `${court.id}-${date}`;
                const dayBookings = cellBookings.get(key) || [];
                const visible = dayBookings.slice(0, 2);
                const overflow = dayBookings.length - visible.length;

                return (
                  <Box
                    key={key}
                    onClick={() =>
                      setDrawer({
                        court,
                        date,
                        bookings: dayBookings,
                      })
                    }
                    sx={{
                      p: 1,
                      borderBottom: 1,
                      borderRight: 1,
                      borderColor: "divider",
                      minHeight: 96,
                      cursor: "pointer",
                      transition: "background-color 0.15s",
                      "&:hover": { bgcolor: "rgba(16, 185, 129, 0.06)" },
                    }}
                  >
                    <OccupancyDots bookings={dayBookings} openHour={openHour} closeHour={closeHour} />
                    <Stack spacing={0.5} sx={{ mt: 0.75 }}>
                      {visible.map((booking) => (
                        <Chip
                          key={booking.id}
                          size="small"
                          label={`${booking.startTime} ${booking.customerName}`}
                          onClick={(event) => {
                            event.stopPropagation();
                            onBookingClick?.(booking);
                          }}
                          sx={{
                            justifyContent: "flex-start",
                            height: "auto",
                            py: 0.5,
                            "& .MuiChip-label": { whiteSpace: "normal" },
                          }}
                        />
                      ))}
                      {overflow > 0 && (
                        <Typography variant="caption" color="primary.main" fontWeight={700}>
                          +{overflow} booking
                        </Typography>
                      )}
                      {dayBookings.length === 0 && (
                        <Typography variant="caption" color="text.secondary">
                          Trống
                        </Typography>
                      )}
                    </Stack>
                  </Box>
                );
              })}
            </Box>
          ))}
        </Box>
      </Paper>

      <Drawer
        anchor="right"
        open={Boolean(drawer)}
        onClose={() => setDrawer(null)}
        PaperProps={{ sx: { width: { xs: "100%", sm: 380 } } }}
      >
        {drawer && (
          <Box sx={{ p: 2 }}>
            <Typography variant="h6" fontWeight={800}>
              {getCourtDisplayName(drawer.court)}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              {formatDisplayDate(drawer.date)}
            </Typography>

            <List dense>
              {drawer.bookings.length === 0 ? (
                <Typography color="text.secondary">Không có booking.</Typography>
              ) : (
                drawer.bookings.map((booking) => (
                  <ListItemButton
                    key={booking.id}
                    onClick={() => {
                      onBookingClick?.(booking);
                      setDrawer(null);
                    }}
                  >
                    <ListItemText
                      primary={booking.customerName}
                      secondary={`${booking.startTime} – ${booking.endTime}`}
                    />
                  </ListItemButton>
                ))
              )}
            </List>

            <Chip
              label="Xem theo ngày"
              color="primary"
              onClick={() => {
                onOpenDay?.(drawer.date);
                setDrawer(null);
              }}
              sx={{ mt: 2, fontWeight: 700 }}
            />
          </Box>
        )}
      </Drawer>
    </Box>
  );
}

import { useMemo, useState, useEffect } from "react";
import {
  Alert,
  Box,
  Button,
  Card,
  CardActions,
  CardContent,
  Chip,
  Grid,
  Typography,
} from "@mui/material";
import { Link as RouterLink, useNavigate } from "react-router-dom";

import { useTenant } from "../../context/TenantContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  listProducts,
  seedDefaultProducts,
  createOrder,
} from "../../features/marketplace/index.js";
import { isMarketplaceEnabled } from "../../features/integrations/config/integrationFlags.js";
import { simulateMockPayment } from "../../features/payments/index.js";
import { usePlatformRuntime } from "../../core/platform/app/usePlatformRuntime.js";

export default function MarketplacePage() {
  const { currentTenantId } = useTenant();
  const { user } = useAuth();
  const runtime = usePlatformRuntime();
  const navigate = useNavigate();
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);
  const [accessAllowed, setAccessAllowed] = useState(true);

  useEffect(() => {
    try {
      const decision = runtime.accessService.authorize(
        {
          user_id: user?.id || "demo-user",
          tenant_id: currentTenantId || "marketplace-preview",
          role: user?.role || "USER",
        },
        { tenant_id: currentTenantId || "marketplace-preview" },
        "marketplace.purchase"
      );
      setAccessAllowed(Boolean(decision.allowed));
    } catch {
      setAccessAllowed(false);
    }
  }, [currentTenantId, runtime, user?.id, user?.role]);

  const products = useMemo(() => {
    seedDefaultProducts();
    return listProducts({ tenantId: currentTenantId, activeOnly: true });
  }, [currentTenantId, refreshKey]);

  const handleBuy = async (productId) => {
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác mua gói.");
      return;
    }
    setError(null);
    const result = await createOrder({
      tenantId: currentTenantId,
      buyerUserId: user?.id,
      productId,
      provider: "mock",
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    const pay = await simulateMockPayment(result.payment.id, "success");
    if (!pay.ok) {
      setError(pay.error);
      return;
    }
    setMessage("Mua gói thành công (mock payment).");
    setRefreshKey((v) => v + 1);
  };

  if (!isMarketplaceEnabled()) {
    return (
      <Alert severity="info">
        Marketplace chưa bật. Set <code>VITE_MARKETPLACE_ENABLED=true</code> trong .env.
      </Alert>
    );
  }

  return (
    <PermissionGate permissions={[PERMISSIONS.MARKETPLACE_VIEW]}>
      <Box>
        <StackHeader navigate={navigate} />
        <Chip
          size="small"
          label={`Runtime access: ${accessAllowed ? "allowed" : "denied"}`}
          color={accessAllowed ? "success" : "warning"}
          sx={{ mb: 2 }}
        />
        {message && <Alert severity="success" sx={{ mb: 2 }}>{message}</Alert>}
        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Grid container spacing={2}>
          {products.map((product) => (
            <Grid key={product.id} size={{ xs: 12, sm: 6, md: 4 }}>
              <Card>
                <CardContent>
                  <Typography variant="h6">{product.name}</Typography>
                  <Chip size="small" label={product.category} sx={{ my: 1 }} />
                  <Typography variant="body2" color="text.secondary">
                    {product.description || "Gói dịch vụ mở rộng"}
                  </Typography>
                  <Typography variant="h6" sx={{ mt: 1 }}>
                    {product.price.toLocaleString("vi-VN")} {product.currency}
                  </Typography>
                  <Typography variant="caption">{product.billingType}</Typography>
                </CardContent>
                <CardActions>
                  <Button size="small" component={RouterLink} to={`/marketplace/${product.id}`}>
                    Chi tiết
                  </Button>
                  <Button size="small" variant="contained" onClick={() => handleBuy(product.id)}>
                    Mua ngay
                  </Button>
                </CardActions>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Box>
    </PermissionGate>
  );
}

function StackHeader({ navigate }) {
  return (
    <Box sx={{ display: "flex", justifyContent: "space-between", mb: 2 }}>
      <Typography variant="h5">Marketplace</Typography>
      <Button onClick={() => navigate("/marketplace/orders")}>Đơn hàng của tôi</Button>
    </Box>
  );
}

