import { useEffect, useMemo, useState } from "react";
import { Link as RouterLink } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  FormControl,
  FormControlLabel,
  FormLabel,
  Grid,
  Paper,
  Radio,
  RadioGroup,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import GroupsIcon from "@mui/icons-material/Groups";
import ChevronRightIcon from "@mui/icons-material/ChevronRight";

import { useAuth } from "../../context/AuthContext.jsx";
import { useTenant } from "../../context/TenantContext.jsx";
import { ROLE_LABELS } from "../../auth/roles.js";
import { resolveSelfProfileRoleLabel } from "../../features/identity/utils/selfProfileVariant.js";
import {
  fetchSelfProfile,
  updateSelfProfile,
  updateSelfDemographics,
} from "../../features/identity/services/selfProfileService.js";
import { changePassword } from "../../features/identity/services/passwordService.js";
import AvatarPicker from "../../features/identity/components/AvatarPicker.jsx";
import AthleteRatingSummary from "../../features/pick-vn-rating/components/AthleteRatingSummary.jsx";
import PickVnRatingBadge from "../../features/pick-vn-rating/components/PickVnRatingBadge.jsx";
import { getPickVnRatingByAuthUserId } from "../../features/pick-vn-rating/services/pickVnRatingService.js";
import { RATING_STATUS } from "../../features/pick-vn-rating/constants/ratingStatus.js";
import { getMyClubSummary } from "../../features/club/services/clubMembershipRequestService.js";
import { CLUB_STATUS_LABELS } from "../../features/club/constants/clubStatus.js";

const GENDER_OPTIONS = [
  { value: "Nam", label: "Nam" },
  { value: "Nữ", label: "Nữ" },
  { value: "Khác", label: "Khác" },
];

const CURRENT_YEAR = new Date().getFullYear();

export default function AthleteSelfProfilePage() {
  const { user, refresh } = useAuth();
  const { currentTenantId } = useTenant();

  const [displayName, setDisplayName] = useState("");
  const [phone, setPhone] = useState("");
  const [gender, setGender] = useState("");
  const [birthYear, setBirthYear] = useState("");
  const [avatarUrl, setAvatarUrl] = useState("");
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState(null);
  const [loading, setLoading] = useState(false);
  const [ratingTick, setRatingTick] = useState(0);

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      const result = await fetchSelfProfile();
      if (cancelled || !result.ok) {
        return;
      }
      setDisplayName(result.user.displayName || "");
      setPhone(result.user.phone || "");
      setGender(result.user.gender || "");
      setBirthYear(result.user.birthYear ? String(result.user.birthYear) : "");
      setAvatarUrl(result.user.avatarUrl || "");
    };

    load();
    return () => {
      cancelled = true;
    };
  }, [user?.id]);

  const ratingRecord = useMemo(() => {
    void ratingTick;
    return user?.id ? getPickVnRatingByAuthUserId(user.id) : null;
  }, [ratingTick, user?.id]);

  const clubSummary = useMemo(() => {
    if (!user?.clubId) {
      return null;
    }
    return getMyClubSummary(user.clubId, currentTenantId);
  }, [currentTenantId, user?.clubId]);

  const handleSaveProfile = async () => {
    setLoading(true);
    setMessage(null);

    const profileResult = await updateSelfProfile({ displayName, phone, avatarUrl });
    if (!profileResult.ok) {
      setLoading(false);
      setMessage({ type: "error", text: profileResult.error });
      return;
    }

    const demoResult = await updateSelfDemographics({
      gender,
      birthYear: birthYear ? Number(birthYear) : null,
    });

    setLoading(false);

    if (!demoResult.ok) {
      setMessage({ type: "error", text: demoResult.error });
      return;
    }

    refresh();
    setRatingTick((value) => value + 1);
    setMessage({ type: "success", text: "Đã cập nhật hồ sơ." });
  };

  const handleChangePassword = async () => {
    if (newPassword !== confirmPassword) {
      setMessage({ type: "error", text: "Mật khẩu xác nhận không khớp." });
      return;
    }

    setLoading(true);
    setMessage(null);
    const result = await changePassword({ currentPassword, newPassword });
    setLoading(false);

    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    setCurrentPassword("");
    setNewPassword("");
    setConfirmPassword("");
    setMessage({ type: "success", text: result.message });
  };

  if (!user) {
    return <Alert severity="warning">Vui lòng đăng nhập để xem hồ sơ.</Alert>;
  }

  const hasRating =
    ratingRecord &&
    ratingRecord.ratingStatus !== RATING_STATUS.UNRATED &&
    ratingRecord.currentRating != null;

  const roleLabel =
    resolveSelfProfileRoleLabel(user) || ROLE_LABELS[user.role] || "Vận động viên";

  return (
    <Box>
      <Typography variant="h4" fontWeight={800} gutterBottom>
        Hồ sơ của tôi
      </Typography>

      {message && (
        <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      )}

      <Grid container spacing={2}>
        <Grid item xs={12} md={4}>
          <Paper variant="outlined" sx={{ p: 2, position: { md: "sticky" }, top: 88 }}>
            <Stack spacing={2} alignItems="center">
              <AvatarPicker
                user={user}
                avatarUrl={avatarUrl}
                onAvatarUrlChange={setAvatarUrl}
                onAvatarUpdated={() => {
                  refresh();
                  setMessage({ type: "success", text: "Đã cập nhật hình đại diện." });
                }}
                disabled={loading}
              />
              <Box sx={{ textAlign: "center", width: "100%" }}>
                <Typography variant="h6" fontWeight={700}>
                  {displayName || user.displayName || "Vận động viên"}
                </Typography>
                <Chip
                  size="small"
                  color="primary"
                  label={roleLabel}
                  sx={{ mt: 0.5 }}
                />
                {clubSummary?.name && (
                  <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                    {clubSummary.name}
                  </Typography>
                )}
              </Box>
              {hasRating && (
                <PickVnRatingBadge
                  rating={ratingRecord.currentRating}
                  status={ratingRecord.ratingStatus}
                  confidence={ratingRecord.ratingConfidence}
                  size="medium"
                />
              )}
            </Stack>
          </Paper>
        </Grid>

        <Grid item xs={12} md={8}>
          <Stack spacing={2}>
            <Card>
              <CardContent>
                <Typography variant="h6" fontWeight={700} gutterBottom>
                  Thông tin cá nhân
                </Typography>
                <Stack spacing={2}>
                  <TextField
                    label="Họ tên"
                    value={displayName}
                    onChange={(e) => setDisplayName(e.target.value)}
                    fullWidth
                  />
                  <TextField
                    label="Số điện thoại"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    fullWidth
                  />
                  <FormControl>
                    <FormLabel>Giới tính</FormLabel>
                    <RadioGroup
                      row
                      value={gender}
                      onChange={(e) => setGender(e.target.value)}
                    >
                      {GENDER_OPTIONS.map((option) => (
                        <FormControlLabel
                          key={option.value}
                          value={option.value}
                          control={<Radio size="small" />}
                          label={option.label}
                        />
                      ))}
                    </RadioGroup>
                  </FormControl>
                  <TextField
                    label="Năm sinh"
                    type="number"
                    value={birthYear}
                    onChange={(e) => setBirthYear(e.target.value)}
                    inputProps={{ min: CURRENT_YEAR - 90, max: CURRENT_YEAR - 8 }}
                    fullWidth
                  />
                  <TextField label="Email" value={user.email || ""} disabled fullWidth />
                  <Button variant="contained" onClick={handleSaveProfile} disabled={loading}>
                    Lưu hồ sơ
                  </Button>
                </Stack>
              </CardContent>
            </Card>

            <AthleteRatingSummary authUserId={user.id} />

            <Card>
              <CardContent>
                <Stack
                  direction="row"
                  justifyContent="space-between"
                  alignItems="center"
                  spacing={1}
                >
                  <Stack direction="row" spacing={1} alignItems="center">
                    <GroupsIcon color="action" />
                    <Box>
                      <Typography variant="h6" fontWeight={700}>
                        CLB của tôi
                      </Typography>
                      {clubSummary ? (
                        <Typography variant="body2" color="text.secondary">
                          {clubSummary.name} · {clubSummary.memberCount} thành viên ·{" "}
                          {CLUB_STATUS_LABELS[clubSummary.status] || clubSummary.status}
                        </Typography>
                      ) : (
                        <Typography variant="body2" color="text.secondary">
                          Chưa gia nhập CLB
                        </Typography>
                      )}
                    </Box>
                  </Stack>
                  <Button
                    component={RouterLink}
                    to="/my-club"
                    endIcon={<ChevronRightIcon />}
                    size="small"
                  >
                    Xem CLB
                  </Button>
                </Stack>
              </CardContent>
            </Card>

            <Card>
              <CardContent>
                <Typography variant="h6" fontWeight={700} gutterBottom>
                  Bảo mật
                </Typography>
                <Stack spacing={2}>
                  <TextField
                    label="Mật khẩu hiện tại"
                    type="password"
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    fullWidth
                    autoComplete="current-password"
                  />
                  <TextField
                    label="Mật khẩu mới"
                    type="password"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    fullWidth
                    autoComplete="new-password"
                  />
                  <TextField
                    label="Xác nhận mật khẩu mới"
                    type="password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    fullWidth
                    autoComplete="new-password"
                  />
                  <Button
                    variant="outlined"
                    onClick={handleChangePassword}
                    disabled={loading || !currentPassword || !newPassword}
                  >
                    Đổi mật khẩu
                  </Button>
                </Stack>
              </CardContent>
            </Card>
          </Stack>
        </Grid>
      </Grid>
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Alert, Box, Button } from "@mui/material";
import { useNavigate, useSearchParams } from "react-router-dom";

import { useAuth } from "../../context/AuthContext.jsx";
import { useTenant } from "../../context/TenantContext.jsx";
import {
  canApproveClubMembershipRequests,
  canDeleteClub,
  canManageClubGovernance,
  canViewFullClubMembers,
  fetchGovernanceNameHints,
  getClubById,
  getClubStats,
  getGovernanceDisplayLabels,
  getMyClubSummary,
  getRegisteredClusterLabel,
  getVicePresidentUserIds,
  leaveMyClub,
} from "../../features/club/index.js";
import { useRequiredMyClubMembership } from "../../features/club/hooks/MyClubMembershipContext.jsx";
import { buildMyClubSummaryFromClub } from "../../features/club/services/clubActiveMembershipService.js";
import { isClubStorageV2Enabled } from "../../features/club/config/clubRegistryFlags.js";
import { CLUB_ROUTE_PATHS } from "../../features/club/routing/clubMembershipRouteLogic.js";
import {
  ClubConfirmDialog,
  ClubFeedbackAlert,
  ClubPageShell,
  MyClubHomeInsights,
} from "../../features/club/ui/index.js";
import ClubActiveMembershipGuard from "./guards/ClubActiveMembershipGuard.jsx";
import MyClubSummaryCard from "./myClub/MyClubSummaryCard.jsx";
import MyClubGovernancePanel from "./myClub/MyClubGovernancePanel.jsx";
import MyClubActionBar from "./myClub/MyClubActionBar.jsx";
import MyClubSchedulePanel from "./myClub/MyClubSchedulePanel.jsx";
import MyClubMembersPanel from "./myClub/MyClubMembersPanel.jsx";
import { resolveInitialView } from "./myClub/myClubViewLogic.js";

function MyClubPageContent() {
  const { user, refresh } = useAuth();
  const { currentTenantId } = useTenant();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const tenantId = currentTenantId || user?.tenantId || user?.venueId || "";
  const membership = useRequiredMyClubMembership();
  const { revision, bumpRevision } = membership;
  const clubId = membership.clubId;
  const hasClub = Boolean(membership.hasActiveMembership && clubId);

  const [message, setMessage] = useState(null);
  const [leaveLoading, setLeaveLoading] = useState(false);
  const [leaveConfirmOpen, setLeaveConfirmOpen] = useState(false);
  const [nameHints, setNameHints] = useState({});

  const [view, setView] = useState(() => resolveInitialView(true, searchParams));

  const handleViewChange = (nextView) => {
    setView(nextView);
    const nextParams = new URLSearchParams(searchParams);
    if (nextView === "home") {
      nextParams.delete("view");
    } else {
      nextParams.set("view", nextView);
    }
    setSearchParams(nextParams, { replace: true });
  };

  useEffect(() => {
    setView(resolveInitialView(hasClub, searchParams));
  }, [hasClub, searchParams]);

  const clubRecord = useMemo(() => {
    void revision;
    if (!clubId) {
      return null;
    }
    if (membership.club?.id === clubId) {
      return membership.club;
    }
    return getClubById(clubId, tenantId);
  }, [clubId, tenantId, revision, membership.club]);

  const clubSummary = useMemo(() => {
    void revision;
    if (!clubId) {
      return null;
    }
    if (isClubStorageV2Enabled() && membership.club?.id === clubId) {
      const fromRpc = buildMyClubSummaryFromClub(membership.club);
      if (fromRpc) {
        return fromRpc;
      }
    }
    return getMyClubSummary(clubId, tenantId);
  }, [clubId, tenantId, revision, membership.club]);

  const clubStats = useMemo(() => {
    if (!clubId) {
      return null;
    }
    return getClubStats(clubId, tenantId);
  }, [clubId, tenantId, revision]);

  useEffect(() => {
    let cancelled = false;
    const gov = clubSummary?.governance || clubRecord?.governance || {};
    const ids = [
      gov.presidentUserId,
      gov.ownerUserId,
      ...getVicePresidentUserIds(gov),
    ].filter(Boolean);

    if (ids.length === 0) {
      setNameHints({});
      return undefined;
    }

    void fetchGovernanceNameHints(ids).then((hints) => {
      if (!cancelled) {
        setNameHints(hints);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [
    clubId,
    clubSummary?.governance?.presidentUserId,
    clubSummary?.governance?.ownerUserId,
    clubSummary?.governance?.vicePresidentUserId,
    clubSummary?.governance?.vicePresidentUserIds,
    clubRecord?.governance?.presidentUserId,
    clubRecord?.governance?.ownerUserId,
    revision,
  ]);

  const governanceLabels = clubSummary
    ? getGovernanceDisplayLabels(
        { id: clubId, governance: clubSummary.governance },
        tenantId,
        nameHints
      )
    : clubRecord
      ? getGovernanceDisplayLabels(clubRecord, tenantId, nameHints)
      : null;

  const registeredCluster = clubSummary
    ? getRegisteredClusterLabel({ governance: clubSummary.governance }, tenantId)
    : clubRecord
      ? getRegisteredClusterLabel(clubRecord, tenantId)
      : null;

  const showGovernance =
    clubRecord &&
    user &&
    (canManageClubGovernance(user, clubRecord) || canDeleteClub(user, clubRecord));

  const manageHref =
    clubId && user && canViewFullClubMembers(user, clubRecord)
      ? `/manage/clubs/${clubId}`
      : null;

  const showRequestsLink =
    Boolean(clubRecord && user && canApproveClubMembershipRequests(user, clubRecord));

  const handleLeaveClub = async () => {
    setLeaveLoading(true);
    try {
      const result = await leaveMyClub({ user, tenantId, clubId });
      if (!result.ok) {
        setMessage({ type: "error", text: result.error });
        return;
      }
      setMessage({ type: "success", text: "Đã rời CLB." });
      setLeaveConfirmOpen(false);
      await refresh();
      bumpRevision();
      navigate(CLUB_ROUTE_PATHS.DISCOVER, { replace: true });
    } finally {
      setLeaveLoading(false);
    }
  };

  return (
    <ClubPageShell
      title="CLB của tôi"
      subtitle="Trang chủ CLB — lịch sinh hoạt, thành viên và hoạt động."
      breadcrumbs={[{ label: "CLB", href: CLUB_ROUTE_PATHS.MY_CLUB }]}
    >
      <MyClubActionBar
        activeView={view}
        onViewChange={handleViewChange}
        onLeaveClick={() => setLeaveConfirmOpen(true)}
        leaveLoading={leaveLoading}
        showLeave={hasClub}
        showRequestsLink={showRequestsLink}
      />

      <ClubFeedbackAlert message={message} onClose={() => setMessage(null)} />

      {view === "schedule" ? (
        <MyClubSchedulePanel
          clubId={clubId}
          tenantId={tenantId}
          user={user}
          clubRecord={clubRecord}
          revision={revision}
          onRevision={bumpRevision}
          onMessage={setMessage}
        />
      ) : view === "members" ? (
        <MyClubMembersPanel
          clubId={clubId}
          tenantId={tenantId}
          clubRecord={clubRecord}
          user={user}
          manageHref={manageHref}
          revision={revision}
        />
      ) : clubSummary ? (
        <>
          <MyClubSummaryCard
            clubSummary={clubSummary}
            clubStats={clubStats}
            governanceLabels={governanceLabels}
            registeredCluster={registeredCluster}
            user={user}
            manageHref={manageHref}
            clubId={clubId}
            tenantId={tenantId}
            clubRecord={clubRecord}
            onRefresh={bumpRevision}
            onMessage={setMessage}
          />

          <MyClubHomeInsights
            clubId={clubId}
            tenantId={tenantId}
            clubRecord={clubRecord}
            user={user}
            revision={revision}
            showRequestsLink={showRequestsLink}
            onViewSchedule={() => handleViewChange("schedule")}
          />

          {showGovernance && (
            <Box sx={{ mt: 3 }}>
              <MyClubGovernancePanel
                clubId={clubId}
                tenantId={tenantId}
                revision={revision}
                onRefresh={bumpRevision}
              />
            </Box>
          )}
        </>
      ) : (
        <Alert
          severity="warning"
          action={
            <Button color="inherit" size="small" onClick={() => bumpRevision()}>
              Thử lại
            </Button>
          }
        >
          Không tải được tóm tắt CLB. Vui lòng thử lại.
        </Alert>
      )}

      <ClubConfirmDialog
        open={leaveConfirmOpen}
        title="Rời câu lạc bộ"
        description="Bạn sẽ mất quyền truy cập lịch và giải nội bộ. Bạn sẽ cần gửi yêu cầu mới để tham gia lại. Tiếp tục?"
        confirmLabel="Rời CLB"
        confirmColor="error"
        loading={leaveLoading}
        onConfirm={() => void handleLeaveClub()}
        onClose={() => setLeaveConfirmOpen(false)}
      />
    </ClubPageShell>
  );
}

export default function MyClubPage() {
  return (
    <ClubActiveMembershipGuard>
      <MyClubPageContent />
    </ClubActiveMembershipGuard>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Box,
  Grid,
  InputAdornment,
  TextField,
  Typography,
} from "@mui/material";
import SearchIcon from "@mui/icons-material/Search";

import {
  CLUB_MEMBERSHIP_REQUEST_STATUSES,
  cancelClubMembershipRequest,
  fetchGovernanceNameHints,
  getClubDiscoverySummary,
  getGovernanceDisplayLabels,
  isClubStorageV2Enabled,
  listDiscoverableClubs,
  listMyMembershipRequestsAll,
  rpcV2ClubListDiscoverable,
  rpcV2ClubListMyRequests,
} from "../../../features/club/index.js";
import { syncClubRegistryForUser } from "../../../features/club/services/clubRegistryCloudSync.js";
import JoinClubDialog from "./JoinClubDialog.jsx";
import { resolvePresidentDisplayLabel } from "./myClubViewLogic.js";
import {
  ClubCard,
  ClubDiscoverSkeleton,
  ClubEmptyState,
} from "../../../features/club/ui/index.js";

export default function MyClubDiscoverPanel({
  user,
  revision = 0,
  onRevision,
  onMessage,
  showHeader = true,
  showSearch = true,
  hasClub: hasClubProp = null,
  activeClubId = null,
}) {
  const [joinClub, setJoinClub] = useState(null);
  const [search, setSearch] = useState("");
  const [nameHints, setNameHints] = useState({});
  const [v2Clubs, setV2Clubs] = useState([]);
  const [v2Requests, setV2Requests] = useState([]);
  const [loading, setLoading] = useState(false);
  const storageV2 = isClubStorageV2Enabled();

  useEffect(() => {
    if (!user?.id) {
      return;
    }

    if (!storageV2) {
      void syncClubRegistryForUser(user).then((result) => {
        if (result.ok) {
          onRevision?.();
        }
      });
      return;
    }

    let cancelled = false;
    setLoading(true);
    void Promise.all([
      rpcV2ClubListDiscoverable({ search, limit: 200 }),
      rpcV2ClubListMyRequests(),
    ]).then(([clubsResult, requestsResult]) => {
      if (cancelled) {
        return;
      }
      setLoading(false);
      if (clubsResult.ok) {
        setV2Clubs(clubsResult.clubs || []);
      } else {
        onMessage?.({ type: "error", text: clubsResult.error || "Không tải được danh sách CLB." });
      }
      if (requestsResult.ok) {
        setV2Requests(requestsResult.requests || []);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [user?.id, onRevision, storageV2, search, revision, onMessage]);

  const myRequests = useMemo(() => {
    if (storageV2) {
      return (v2Requests || []).map((request) => ({
        id: request.id,
        clubId: request.club_id,
        userId: request.user_id,
        status: request.status,
        message: request.message,
        version: request.version,
        requestedAt: request.created_at,
      }));
    }
    void revision;
    if (!user?.id) {
      return [];
    }
    return listMyMembershipRequestsAll(user.id);
  }, [revision, user?.id, storageV2, v2Requests]);

  const requestByClubId = useMemo(
    () => new Map(myRequests.map((request) => [request.clubId, request])),
    [myRequests]
  );

  const discoverableClubs = useMemo(() => {
    if (storageV2) {
      return v2Clubs;
    }
    void revision;
    const query = search.trim().toLowerCase();
    const clubs = listDiscoverableClubs();
    if (!query) {
      return clubs;
    }
    return clubs.filter((club) => String(club.name || "").toLowerCase().includes(query));
  }, [revision, search, storageV2, v2Clubs]);

  useEffect(() => {
    if (storageV2) {
      return undefined;
    }
    let cancelled = false;
    const ids = discoverableClubs
      .flatMap((club) => [
        club?.governance?.presidentUserId,
        club?.governance?.ownerUserId,
      ])
      .filter(Boolean);

    void fetchGovernanceNameHints(ids).then((hints) => {
      if (!cancelled) {
        setNameHints(hints);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [discoverableClubs, storageV2]);

  const bumpRevision = () => {
    onRevision?.();
  };

  const handleCancelRequest = async (request) => {
    const result = await cancelClubMembershipRequest(request.clubId, request.id, user.id, {
      expectedVersion: request.version,
    });
    if (!result.ok) {
      onMessage?.({ type: "error", text: result.error });
      return;
    }
    onMessage?.({ type: "info", text: "Đã hủy yêu cầu tham gia." });
    bumpRevision();
  };

  const hasClub =
    hasClubProp != null
      ? Boolean(hasClubProp)
      : Boolean(activeClubId);

  const resolvedActiveClubId = activeClubId || null;

  return (
    <Box>
      {showHeader && (
        <>
          <Typography variant="subtitle1" fontWeight={600} gutterBottom>
            Danh sách câu lạc bộ
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Xem tất cả CLB trên hệ thống. Chưa gia nhập chỉ hiển thị tên CLB, chủ tịch, số thành
            viên và cụm sân đăng ký. Bạn có thể xin gia nhập bất kỳ CLB nào.
          </Typography>
        </>
      )}

      {showSearch && (
        <TextField
          size="small"
          fullWidth
          placeholder="Tìm theo tên CLB"
          value={search}
          onChange={(event) => setSearch(event.target.value)}
          sx={{ mb: 2, maxWidth: 520 }}
          InputProps={{
            startAdornment: (
              <InputAdornment position="start">
                <SearchIcon fontSize="small" />
              </InputAdornment>
            ),
          }}
        />
      )}

      {loading && storageV2 ? (
        <ClubDiscoverSkeleton count={3} />
      ) : discoverableClubs.length === 0 ? (
        <ClubEmptyState
          preset={search.trim() ? "discoverSearch" : "discover"}
          actionLabel={search.trim() ? "Xóa tìm kiếm" : undefined}
          onAction={search.trim() ? () => setSearch("") : undefined}
        />
      ) : (
        <Grid container spacing={2}>
          {discoverableClubs.map((club) => {
            const summary = storageV2
              ? {
                  name: club.name,
                  activeMemberCount: club.activeMemberCount ?? 0,
                  presidentLabel: club.presidentLabel,
                  clusterLabel: null,
                }
              : getClubDiscoverySummary(club.id);
            const labels = storageV2
              ? null
              : getGovernanceDisplayLabels(club, club.tenantId || club.venueId, nameHints);
            const presidentLabel = storageV2
              ? club.presidentLabel
              : resolvePresidentDisplayLabel(labels) !== "Chưa gán"
                ? resolvePresidentDisplayLabel(labels)
                : summary?.presidentLabel;
            const request = requestByClubId.get(club.id);
            const isMyClub = resolvedActiveClubId === club.id;

            const clubName = summary?.name || club.name;
            let variant = "joinable";
            if (isMyClub) {
              variant = "your-club";
            } else if (request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.PENDING) {
              variant = "pending";
            } else if (request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED) {
              variant = "rejected";
            }

            return (
              <Grid item xs={12} md={6} lg={4} key={club.id}>
                <ClubCard
                  clubName={clubName}
                  memberCount={summary?.activeMemberCount ?? 0}
                  presidentLabel={presidentLabel}
                  clusterLabel={summary?.clusterLabel}
                  variant={variant}
                  requestStatus={!isMyClub ? request?.status : null}
                  reviewNote={request?.reviewNote}
                  disabled={hasClub}
                  onJoin={() => setJoinClub(club)}
                  onCancel={() => void handleCancelRequest(request)}
                />
              </Grid>
            );
          })}
        </Grid>
      )}

      <JoinClubDialog
        open={Boolean(joinClub)}
        onClose={() => setJoinClub(null)}
        user={user}
        clubs={discoverableClubs}
        preselectedClub={joinClub}
        onSuccess={(text) => {
          onMessage?.({ type: "success", text });
          bumpRevision();
        }}
        onError={(text) => onMessage?.({ type: "error", text })}
      />
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogContentText,
  DialogTitle,
  FormControl,
  InputLabel,
  ListItemText,
  MenuItem,
  Paper,
  Select,
  Stack,
  Typography,
} from "@mui/material";
import DeleteIcon from "@mui/icons-material/Delete";
import SwapHorizIcon from "@mui/icons-material/SwapHoriz";

import { useAuth } from "../../../context/AuthContext.jsx";
import GovernanceMemberSelect from "../../../components/club/GovernanceMemberSelect.jsx";
import {
  canAssignClubOwner,
  canChangeClubPresident,
  canDeleteClub,
  canManageClubGovernance,
  canTransferClubOwnership,
  deleteClubAsOwner,
  fetchGovernanceNameHints,
  getClubById,
  getGovernanceDisplayLabels,
  getRegisteredClusterLabel,
  getVicePresidentUserIds,
  listClubGovernanceCandidates,
  setClubVicePresidents,
  transferClubOwnership,
  transferClubPresident,
  updateClubGovernance,
} from "../../../features/club/index.js";
import { listClustersForVenue } from "../../../features/court-cluster/services/courtClusterService.js";

export default function MyClubGovernancePanel({ clubId, tenantId, revision = 0, onRefresh }) {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [error, setError] = useState(null);
  const [message, setMessage] = useState(null);
  const [busy, setBusy] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [nameHints, setNameHints] = useState({});
  const [nextPresidentId, setNextPresidentId] = useState("");
  const [nextOwnerId, setNextOwnerId] = useState("");
  const [vicePresidentIds, setVicePresidentIds] = useState(["", ""]);
  const [registeredClusterId, setRegisteredClusterId] = useState("");

  const club = useMemo(
    () => getClubById(clubId, tenantId),
    [clubId, tenantId, revision]
  );

  useEffect(() => {
    let cancelled = false;
    const gov = club?.governance || {};
    const ids = [
      gov.presidentUserId,
      gov.ownerUserId,
      ...getVicePresidentUserIds(gov),
    ].filter(Boolean);

    void fetchGovernanceNameHints(ids).then((hints) => {
      if (!cancelled) {
        setNameHints(hints);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [
    club?.id,
    club?.governance?.presidentUserId,
    club?.governance?.ownerUserId,
    club?.governance?.vicePresidentUserId,
    club?.governance?.vicePresidentUserIds,
    revision,
  ]);

  const candidates = useMemo(
    () => listClubGovernanceCandidates(clubId, tenantId),
    [clubId, tenantId, revision]
  );

  const labels = useMemo(
    () => (club ? getGovernanceDisplayLabels(club, tenantId, nameHints) : null),
    [club, tenantId, nameHints]
  );
  const registeredCluster = useMemo(
    () => (club ? getRegisteredClusterLabel(club, tenantId) : null),
    [club, tenantId]
  );
  const venueClusters = useMemo(
    () => listClustersForVenue(tenantId),
    [tenantId]
  );

  if (!club) {
    return null;
  }

  const canManage = canManageClubGovernance(user, club);
  const canAssignOwner = canAssignClubOwner(user);
  const canChangePresident = canChangeClubPresident(user, club);
  const canTransferOwner = canTransferClubOwnership(user, club);
  const canDelete = canDeleteClub(user, club);

  if (!canManage && !canDelete) {
    return null;
  }

  const handleTransferPresident = async () => {
    setBusy(true);
    setError(null);
    const result = await transferClubPresident(clubId, nextPresidentId, tenantId);
    setBusy(false);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage({ type: "success", text: "Đã chuyển Chủ tịch CLB." });
    setNextPresidentId("");
    onRefresh?.();
  };

  const handleTransferOwner = () => {
    setBusy(true);
    setError(null);
    const result = transferClubOwnership(clubId, nextOwnerId, tenantId);
    setBusy(false);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage({ type: "success", text: "Đã chuyển quyền sở hữu CLB." });
    setNextOwnerId("");
    onRefresh?.();
  };

  const handleSaveGovernance = async () => {
    setBusy(true);
    setError(null);

    const currentViceIds = getVicePresidentUserIds(club.governance);
    const nextViceIds = vicePresidentIds.map((id) => String(id || "").trim()).filter(Boolean);
    const currentCluster = club.governance?.registeredClusterId || "";
    const nextCluster = registeredClusterId.trim();

    const viceChanged =
      currentViceIds.length !== nextViceIds.length ||
      currentViceIds.some((id, index) => String(id) !== String(nextViceIds[index] || ""));

    if (viceChanged) {
      const viceResult = await setClubVicePresidents(clubId, nextViceIds, tenantId);
      if (!viceResult.ok) {
        setBusy(false);
        setError(viceResult.error);
        return;
      }
    }

    if (nextCluster !== currentCluster) {
      const clusterResult = updateClubGovernance(
        clubId,
        { registeredClusterId: nextCluster || null },
        tenantId
      );
      if (!clusterResult.ok) {
        setBusy(false);
        setError(clusterResult.error);
        return;
      }
    }

    setBusy(false);
    setMessage({ type: "success", text: "Đã cập nhật quản trị CLB." });
    onRefresh?.();
  };

  const handleDeleteClub = () => {
    setBusy(true);
    setError(null);
    const result = deleteClubAsOwner(clubId, tenantId);
    setBusy(false);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setDeleteOpen(false);
    navigate("/my-club", { replace: true });
  };

  return (
    <Paper sx={{ p: 2, mb: 2 }}>
      <Typography variant="subtitle1" fontWeight={600} gutterBottom>
        Quản trị CLB
      </Typography>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}
      {message && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      )}

      <Stack spacing={0.5} sx={{ mb: 2 }}>
        <Typography variant="body2">
          <strong>Chủ sở hữu:</strong> {labels?.ownerLabel}
        </Typography>
        {!labels?.combinedOwnerPresident && labels?.presidentLabel && (
          <Typography variant="body2">
            <strong>Chủ tịch:</strong> {labels.presidentLabel}
          </Typography>
        )}
        <Typography variant="body2">
          <strong>Phó chủ tịch:</strong>{" "}
          {(labels?.vicePresidentLabels || []).filter(Boolean).join(", ") || "—"}
        </Typography>
        {registeredCluster && (
          <Typography variant="body2" color="text.secondary">
            Cụm sân: {registeredCluster.name}
          </Typography>
        )}
      </Stack>

      {canManage && (
        <Stack spacing={2}>
          {[0, 1].map((index) => (
            <GovernanceMemberSelect
              key={index}
              label={`Phó chủ tịch ${index + 1}`}
              value={vicePresidentIds[index] || getVicePresidentUserIds(club.governance)[index] || ""}
              onChange={(value) =>
                setVicePresidentIds((prev) => {
                  const next = [...prev];
                  next[index] = value;
                  return next;
                })
              }
              candidates={candidates.filter(
                (item) =>
                  item.userId !== club.governance?.presidentUserId &&
                  !vicePresidentIds.some(
                    (selectedId, selectedIndex) =>
                      selectedIndex !== index &&
                      selectedId &&
                      selectedId === item.userId
                  )
              )}
              allowEmpty
              emptyLabel="Không có"
            />
          ))}
          <Typography variant="caption" color="text.secondary">
            Tối đa 2 Phó chủ tịch; phải là vận động viên trong danh sách CLB.
          </Typography>

          <FormControl fullWidth>
            <InputLabel>Cụm sân đăng ký</InputLabel>
            <Select
              value={registeredClusterId || club.governance?.registeredClusterId || ""}
              onChange={(event) => setRegisteredClusterId(event.target.value)}
              label="Cụm sân đăng ký"
              displayEmpty
            >
              <MenuItem value="">
                <em>Chưa chọn</em>
              </MenuItem>
              {venueClusters.map((cluster) => (
                <MenuItem key={cluster.id} value={cluster.id}>
                  <ListItemText
                    primary={cluster.name || cluster.id}
                    secondary={cluster.address || undefined}
                  />
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <Button variant="outlined" onClick={handleSaveGovernance} disabled={busy}>
            Lưu thông tin quản trị
          </Button>

          {canChangePresident && (
            <Stack direction={{ xs: "column", sm: "row" }} spacing={1} alignItems="stretch">
              <Box sx={{ flex: 1 }}>
                <GovernanceMemberSelect
                  label="Chuyển Chủ tịch cho"
                  value={nextPresidentId}
                  onChange={setNextPresidentId}
                  candidates={candidates.filter(
                    (item) => item.userId !== club.governance?.presidentUserId
                  )}
                  allowEmpty
                />
              </Box>
              <Button
                variant="contained"
                startIcon={<SwapHorizIcon />}
                onClick={handleTransferPresident}
                disabled={busy || !nextPresidentId}
                sx={{ alignSelf: { sm: "flex-end" }, minWidth: 160 }}
              >
                Chuyển Chủ tịch
              </Button>
            </Stack>
          )}

          {canTransferOwner && (
            <Stack direction={{ xs: "column", sm: "row" }} spacing={1} alignItems="stretch">
              <Box sx={{ flex: 1 }}>
                <GovernanceMemberSelect
                  label="Chuyển quyền sở hữu cho"
                  value={nextOwnerId}
                  onChange={setNextOwnerId}
                  candidates={candidates.filter(
                    (item) => item.userId !== club.governance?.ownerUserId
                  )}
                  allowEmpty
                />
              </Box>
              <Button
                variant="contained"
                color="secondary"
                startIcon={<SwapHorizIcon />}
                onClick={handleTransferOwner}
                disabled={busy || !nextOwnerId}
                sx={{ alignSelf: { sm: "flex-end" }, minWidth: 180 }}
              >
                Chuyển sở hữu
              </Button>
            </Stack>
          )}

          {canAssignOwner && (
            <Alert severity="info">
              Chủ sân có thể gán Chủ sở hữu qua trang Danh sách CLB.
            </Alert>
          )}
        </Stack>
      )}

      {canDelete && (
        <Box sx={{ mt: 2 }}>
          <Button
            color="error"
            variant="outlined"
            startIcon={<DeleteIcon />}
            onClick={() => setDeleteOpen(true)}
            disabled={busy}
          >
            Xóa CLB
          </Button>
        </Box>
      )}

      <Dialog open={deleteOpen} onClose={() => setDeleteOpen(false)}>
        <DialogTitle>Xóa CLB {club.name}?</DialogTitle>
        <DialogContent>
          <DialogContentText>
            Thao tác này xóa CLB và dữ liệu liên quan trên thiết bị này. Không thể hoàn tác.
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteOpen(false)}>Hủy</Button>
          <Button color="error" variant="contained" onClick={handleDeleteClub} disabled={busy}>
            Xóa CLB
          </Button>
        </DialogActions>
      </Dialog>
    </Paper>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Grid,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import {
  CLUB_MEMBERSHIP_REQUEST_STATUS_LABELS,
  CLUB_MEMBERSHIP_REQUEST_STATUSES,
  cancelClubMembershipRequest,
  getClubDiscoverySummary,
  listDiscoverableClubs,
  listMyMembershipRequestsAll,
  submitClubMembershipRequest,
} from "../../../features/club/index.js";
import { resolveTenantIdForClub } from "../../../features/tenant/guards/tenantGuard.js";
import { Link } from "react-router-dom";

function requestStatusChip(status) {
  const label = CLUB_MEMBERSHIP_REQUEST_STATUS_LABELS[status] || status;
  const color =
    status === CLUB_MEMBERSHIP_REQUEST_STATUSES.PENDING
      ? "warning"
      : status === CLUB_MEMBERSHIP_REQUEST_STATUSES.APPROVED
        ? "success"
        : status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED
          ? "error"
          : "default";
  return <Chip size="small" label={label} color={color} />;
}

export default function MyClubJoinPanel({ tenantId, user, onRevision }) {
  const [revision, setRevision] = useState(0);
  const [message, setMessage] = useState(null);
  const [joinClub, setJoinClub] = useState(null);
  const [joinMessage, setJoinMessage] = useState("");

  const myRequests = useMemo(() => {
    void revision;
    if (!user?.id) {
      return [];
    }
    return listMyMembershipRequestsAll(user.id);
  }, [revision, user?.id]);

  const requestByClubId = useMemo(
    () => new Map(myRequests.map((request) => [request.clubId, request])),
    [myRequests]
  );

  const joinableClubs = useMemo(() => {
    void revision;
    return listDiscoverableClubs();
  }, [revision]);

  const bumpRevision = () => {
    setRevision((value) => value + 1);
    onRevision?.();
  };

  const handleSubmitJoin = () => {
    if (!joinClub) {
      return;
    }

    const clubTenantId = resolveTenantIdForClub(joinClub.id);
    const result = submitClubMembershipRequest(joinClub.id, clubTenantId, user, {
      message: joinMessage,
    });

    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    setMessage({ type: "success", text: "Đã gửi yêu cầu tham gia CLB." });
    setJoinClub(null);
    setJoinMessage("");
    bumpRevision();
  };

  const handleCancelRequest = (request) => {
    const result = cancelClubMembershipRequest(request.clubId, request.id, user.id);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setMessage({ type: "info", text: "Đã hủy yêu cầu tham gia." });
    bumpRevision();
  };

  return (
    <Box>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
        Duyệt danh sách CLB trong hệ thống và gửi yêu cầu tham gia. Chủ tịch hoặc Phó chủ tịch
        CLB sẽ duyệt yêu cầu của bạn.{" "}
        <Typography component={Link} to="/discover-clubs" variant="body2" sx={{ fontWeight: 600 }}>
          Xem tất cả CLB →
        </Typography>
      </Typography>

      {message && (
        <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      )}

      {joinableClubs.length === 0 ? (
        <Alert severity="info">Chưa có CLB đang hoạt động trên hệ thống.</Alert>
      ) : (
        <Grid container spacing={2}>
          {joinableClubs.slice(0, 4).map((club) => {
            const summary = getClubDiscoverySummary(club.id);
            const request = requestByClubId.get(club.id);

            return (
              <Grid item xs={12} md={6} key={club.id}>
                <Card sx={{ height: "100%" }}>
                  <CardContent>
                    <Stack spacing={1.5}>
                      <Stack direction="row" justifyContent="space-between" alignItems="flex-start">
                        <Typography variant="h6" fontWeight={700}>
                          {club.name}
                        </Typography>
                        {request && requestStatusChip(request.status)}
                      </Stack>

                      <Typography variant="body2" color="text.secondary">
                        {summary?.activeMemberCount ?? 0} thành viên
                        {summary?.presidentLabel ? ` · Chủ tịch: ${summary.presidentLabel}` : ""}
                      </Typography>

                      {summary?.clusterLabel && (
                        <Typography variant="body2" color="text.secondary">
                          Cụm sân: {summary.clusterLabel}
                        </Typography>
                      )}

                      {request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED &&
                        request.reviewNote && (
                          <Typography variant="caption" color="error">
                            Lý do: {request.reviewNote}
                          </Typography>
                        )}

                      <Stack direction="row" spacing={1}>
                        {!request && (
                          <Button
                            variant="contained"
                            size="small"
                            onClick={() => {
                              setJoinClub(club);
                              setJoinMessage("");
                            }}
                          >
                            Xin tham gia
                          </Button>
                        )}
                        {request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.PENDING && (
                          <Button
                            variant="outlined"
                            size="small"
                            color="inherit"
                            onClick={() => handleCancelRequest(request)}
                          >
                            Hủy yêu cầu
                          </Button>
                        )}
                        {request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED && (
                          <Button
                            variant="outlined"
                            size="small"
                            onClick={() => {
                              setJoinClub(club);
                              setJoinMessage("");
                            }}
                          >
                            Gửi lại
                          </Button>
                        )}
                      </Stack>
                    </Stack>
                  </CardContent>
                </Card>
              </Grid>
            );
          })}
        </Grid>
      )}

      <Dialog open={Boolean(joinClub)} onClose={() => setJoinClub(null)} maxWidth="sm" fullWidth>
        <DialogTitle>Xin tham gia {joinClub?.name}</DialogTitle>
        <DialogContent>
          <TextField
            fullWidth
            multiline
            minRows={3}
            label="Lời nhắn (tùy chọn)"
            value={joinMessage}
            onChange={(event) => setJoinMessage(event.target.value)}
            sx={{ mt: 1 }}
            placeholder="Giới thiệu ngắn hoặc lý do muốn tham gia CLB..."
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setJoinClub(null)}>Hủy</Button>
          <Button variant="contained" onClick={handleSubmitJoin}>
            Gửi yêu cầu
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useMemo } from "react";
import { Link as RouterLink } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  Chip,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
  useMediaQuery,
  useTheme,
} from "@mui/material";

import { useAuth } from "../../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../../auth/permissions.js";
import {
  CLUB_MEMBER_ROLE_LABELS,
  CLUB_MEMBER_STATUSES,
  canViewFullClubMembers,
  getClubMembers,
  getTenantPlayers,
  getVicePresidentUserIds,
} from "../../../features/club/index.js";
import { ClubEmptyState, GovernanceRoleChip } from "../../../features/club/ui/index.js";
import { loadPlayersForClub } from "../../../domain/clubStorage.js";
import { findUserIdByPlayerId } from "../../../features/club/storage/athleteClubLinkStore.js";
import { resolveMemberGovernanceRole } from "./myClubViewLogic.js";

function mapGovernanceChip(governanceRole) {
  if (!governanceRole) {
    return null;
  }
  if (governanceRole.includes("Phó")) {
    return { role: "vice", label: governanceRole };
  }
  if (governanceRole.includes("Chủ tịch") && governanceRole.includes("Chủ sở hữu")) {
    return { role: "president", label: governanceRole };
  }
  if (governanceRole === "Chủ tịch") {
    return { role: "president" };
  }
  if (governanceRole === "Chủ sở hữu") {
    return { role: "owner" };
  }
  return { role: "member", label: governanceRole };
}

function MemberRowContent({ row }) {
  const gov = mapGovernanceChip(row.governanceRole);
  return (
    <>
      <Typography fontWeight={600}>{row.name}</Typography>
      <Stack direction="row" spacing={0.5} flexWrap="wrap" useFlexGap sx={{ mt: 0.5 }}>
        {gov && <GovernanceRoleChip role={gov.role} label={gov.label} />}
        <GovernanceRoleChip role="member" label={row.memberRole} />
        <Chip
          size="small"
          label={row.isActive ? "Đang hoạt động" : "Không hoạt động"}
          color={row.isActive ? "success" : "default"}
          aria-label={row.isActive ? "Đang hoạt động" : "Không hoạt động"}
        />
      </Stack>
    </>
  );
}

export default function MyClubMembersPanel({
  clubId,
  tenantId,
  clubRecord,
  user,
  manageHref = null,
  revision = 0,
}) {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down("md"));
  const { can, rbacEnabled, isAuthenticated } = useAuth();

  const fullAccess = clubRecord && user && canViewFullClubMembers(user, clubRecord);

  const canManage =
    fullAccess &&
    manageHref &&
    (!rbacEnabled ||
      !isAuthenticated ||
      can(PERMISSIONS.PLAYER_UPDATE, { clubId, venueId: tenantId }));

  const members = useMemo(() => {
    void revision;
    if (!fullAccess || !clubId) {
      return [];
    }
    return getClubMembers(clubId, tenantId);
  }, [clubId, tenantId, revision, fullAccess]);

  const playersById = useMemo(() => {
    const players = getTenantPlayers(tenantId);
    return new Map(players.map((player) => [player.id, player]));
  }, [tenantId, revision]);

  const rows = useMemo(() => {
    if (!clubRecord) {
      return [];
    }

    const clubPlayers = clubId ? loadPlayersForClub(clubId) : [];
    const clubPlayerById = new Map(clubPlayers.map((player) => [player.id, player]));

    return members
      .map((member) => {
        const player = clubPlayerById.get(member.playerId) || playersById.get(member.playerId);
        const linkedUserId =
          findUserIdByPlayerId(member.playerId) ||
          String(player?.authUserId || "").trim() ||
          null;
        const governanceRole = resolveMemberGovernanceRole(
          linkedUserId,
          clubRecord.governance,
          getVicePresidentUserIds
        );

        return {
          id: member.id,
          name: player?.name || member.playerId,
          governanceRole,
          memberRole: CLUB_MEMBER_ROLE_LABELS[member.role] || member.role,
          status: member.status,
          isActive: member.status === CLUB_MEMBER_STATUSES.ACTIVE,
        };
      })
      .sort((a, b) => a.name.localeCompare(b.name, "vi"));
  }, [members, playersById, clubRecord, clubId]);

  const activeCount = rows.filter((row) => row.isActive).length;

  return (
    <Box>
      <Stack
        direction={{ xs: "column", sm: "row" }}
        justifyContent="space-between"
        alignItems={{ xs: "flex-start", sm: "center" }}
        spacing={1}
        sx={{ mb: 2 }}
      >
        <Box>
          <Typography variant="subtitle1" fontWeight={700} component="h3">
            Thành viên CLB
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {fullAccess
              ? `${activeCount} thành viên đang hoạt động`
              : "Bạn không có quyền xem danh sách chi tiết thành viên CLB này."}
          </Typography>
        </Box>
        {canManage && (
          <Button component={RouterLink} to={manageHref} variant="outlined" size="small">
            Quản lý thành viên
          </Button>
        )}
      </Stack>

      {!fullAccess && (
        <Alert severity="info">
          Theo quy tắc quyền riêng tư CLB, chỉ thành viên CLB và ban quản trị mới xem được danh sách
          đầy đủ. Chủ sân không tự động xem danh sách trừ khi là Chủ sở hữu CLB.
        </Alert>
      )}

      {fullAccess && rows.length === 0 && <ClubEmptyState preset="members" />}

      {fullAccess && rows.length > 0 && isMobile ? (
        <Stack spacing={1.5}>
          {rows.map((row) => (
            <Paper key={row.id} variant="outlined" sx={{ p: 2, borderRadius: 2 }}>
              <MemberRowContent row={row} />
            </Paper>
          ))}
        </Stack>
      ) : null}

      {fullAccess && rows.length > 0 && !isMobile ? (
        <TableContainer component={Paper} variant="outlined" sx={{ borderRadius: 2 }}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Tên</TableCell>
                <TableCell>Vai trò CLB</TableCell>
                <TableCell>Trạng thái</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {rows.map((row) => {
                const gov = mapGovernanceChip(row.governanceRole);
                return (
                  <TableRow key={row.id} hover>
                    <TableCell>
                      <Typography fontWeight={600}>{row.name}</Typography>
                    </TableCell>
                    <TableCell>
                      <Stack direction="row" spacing={0.5} flexWrap="wrap" useFlexGap>
                        {gov && <GovernanceRoleChip role={gov.role} label={gov.label} />}
                        <GovernanceRoleChip role="member" label={row.memberRole} />
                      </Stack>
                    </TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={row.isActive ? "Đang hoạt động" : "Không hoạt động"}
                        color={row.isActive ? "success" : "default"}
                      />
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </TableContainer>
      ) : null}
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Box,
  Button,
  Card,
  CardContent,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Stack,
  Typography,
} from "@mui/material";
import GroupsIcon from "@mui/icons-material/Groups";
import StarIcon from "@mui/icons-material/Star";
import WorkspacePremiumIcon from "@mui/icons-material/WorkspacePremium";
import SwapHorizIcon from "@mui/icons-material/SwapHoriz";

import GovernanceMemberSelect from "../../../components/club/GovernanceMemberSelect.jsx";
import {
  canRelinquishClubPresident,
  canManageClubGovernance,
  fetchGovernanceNameHints,
  getClubById,
  getClubStats,
  getGovernanceDisplayLabels,
  getVicePresidentUserIds,
  listClubGovernanceCandidates,
  transferClubPresident,
} from "../../../features/club/index.js";
import { miniGovernanceCardSx } from "./myClubUiStyles.js";
import { resolvePresidentDisplayLabel } from "./myClubViewLogic.js";

function GovernanceMiniCard({ accent, icon, title, value, action = null }) {
  return (
    <Box sx={miniGovernanceCardSx(accent)}>
      <Stack direction="row" justifyContent="space-between" alignItems="flex-start" spacing={1}>
