export default function MyClubOrgChart({
  clubId,
  tenantId,
  user,
  revision = 0,
  onRefresh,
  onMessage,
}) {
  const [nextPresidentId, setNextPresidentId] = useState("");
  const [transferOpen, setTransferOpen] = useState(false);
  const [busy, setBusy] = useState(false);
  const [nameHints, setNameHints] = useState({});

  const club = useMemo(() => getClubById(clubId, tenantId), [clubId, tenantId, revision]);

  useEffect(() => {
    let cancelled = false;
    const gov = club?.governance || {};
    const ids = [
      gov.presidentUserId,
      gov.ownerUserId,
      ...getVicePresidentUserIds(gov),
    ].filter(Boolean);

    void fetchGovernanceNameHints(ids).then((hints) => {
      if (!cancelled) {
        setNameHints(hints);
      }
    });

    return () => {
      cancelled = true;
    };
  }, [
    club?.id,
    club?.governance?.presidentUserId,
    club?.governance?.ownerUserId,
    club?.governance?.vicePresidentUserId,
    club?.governance?.vicePresidentUserIds,
    revision,
  ]);

  const labels = useMemo(
    () => (club ? getGovernanceDisplayLabels(club, tenantId, nameHints) : null),
    [club, tenantId, nameHints, revision]
  );
  const stats = useMemo(() => getClubStats(clubId, tenantId), [clubId, tenantId, revision]);
  const candidates = useMemo(
    () => listClubGovernanceCandidates(clubId, tenantId),
    [clubId, tenantId, revision]
  );

  if (!club || !labels) {
    return null;
  }

  const viceLabels = labels.vicePresidentLabels || [];
  const canTransfer = canRelinquishClubPresident(user, club);
  const canManage = canManageClubGovernance(user, club);
  const viceIds = getVicePresidentUserIds(club.governance || {});
  const presidentLabel = resolvePresidentDisplayLabel(labels);

  const handleTransferPresident = async () => {
    if (!nextPresidentId) {
      return;
    }
    setBusy(true);
    const result = await transferClubPresident(clubId, nextPresidentId, tenantId);
    setBusy(false);
    if (!result.ok) {
      onMessage?.({ type: "error", text: result.error });
      return;
    }
    onMessage?.({ type: "success", text: "Đã chuyển Chủ tịch CLB." });
    setNextPresidentId("");
    setTransferOpen(false);
    onRefresh?.();
  };

  return (
    <Card variant="outlined" sx={{ borderRadius: 2, height: "100%" }}>
      <CardContent>
        <Typography variant="subtitle1" fontWeight={700} gutterBottom>
          Cấu trúc CLB
        </Typography>

        <Stack spacing={1.5}>
          <GovernanceMiniCard
            accent="president"
            icon={<WorkspacePremiumIcon color="warning" fontSize="small" />}
            title="Chủ tịch"
            value={presidentLabel}
            action={
              canTransfer ? (
                <Button
                  size="small"
                  variant="outlined"
                  startIcon={<SwapHorizIcon />}
                  onClick={() => setTransferOpen(true)}
                >
                  Nhường chức
                </Button>
              ) : null
            }
          />

          {[0, 1].map((index) => (
            <GovernanceMiniCard
              key={index}
              accent="vice"
              icon={<StarIcon color="primary" fontSize="small" />}
              title={`Phó CT ${index + 1}`}
              value={viceLabels[index] || "(trống)"}
            />
          ))}

          <GovernanceMiniCard
            accent="members"
            icon={<GroupsIcon color="action" fontSize="small" />}
            title="Thành viên"
            value={`${stats?.activeMemberCount ?? 0} thành viên`}
          />

          {canManage && viceIds.length < 2 && (
            <Typography variant="caption" color="text.secondary">
              Gán Phó chủ tịch trong mục Quản trị CLB (tối đa 2 người).
            </Typography>
          )}
        </Stack>
      </CardContent>

      <Dialog open={transferOpen} onClose={() => setTransferOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Nhường chức Chủ tịch</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Chọn thành viên trong CLB để nhường vai trò Chủ tịch. Bạn sẽ trở thành thành viên
            thường sau khi chuyển.
          </Typography>
          <GovernanceMemberSelect
            label="Chủ tịch mới"
            value={nextPresidentId}
            onChange={setNextPresidentId}
            candidates={candidates.filter(
              (item) => item.userId !== club.governance?.presidentUserId
            )}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setTransferOpen(false)}>Hủy</Button>
          <Button
            variant="contained"
            onClick={handleTransferPresident}
            disabled={busy || !nextPresidentId}
          >
            Xác nhận chuyển
          </Button>
        </DialogActions>
      </Dialog>
    </Card>
  );
}

import { useMemo, useState } from "react";
import { Link as RouterLink } from "react-router-dom";
import {
  Box,
  Button,
  Card,
  Stack,
  Typography,
} from "@mui/material";
import GroupsIcon from "@mui/icons-material/Groups";
import PersonIcon from "@mui/icons-material/Person";
import PlaceIcon from "@mui/icons-material/Place";
import SportsTennisIcon from "@mui/icons-material/SportsTennis";
import WorkspacePremiumIcon from "@mui/icons-material/WorkspacePremium";

import {
  canAssignClubOwner,
  listClubGovernanceCandidates,
} from "../../../features/club/index.js";
import { ClubAvatar, ClubStatusBadge } from "../../../features/club/ui/index.js";
import AssignClubOwnerDialog from "./AssignClubOwnerDialog.jsx";
import {
  heroGradientSx,
  statBoxSx,
} from "./myClubUiStyles.js";
import {
  resolveOwnerStatContent,
  resolvePresidentDisplayLabel,
} from "./myClubViewLogic.js";

export default function MyClubSummaryCard({
  clubSummary,
  clubStats,
  governanceLabels,
  registeredCluster,
  user,
  manageHref = null,
  clubId,
  tenantId,
  clubRecord,
  onRefresh,
  onMessage,
}) {
  const [assignOpen, setAssignOpen] = useState(false);

  const canAssign = canAssignClubOwner(user);
  const ownerStat = resolveOwnerStatContent({
    club: clubRecord,
    governanceLabels,
    canAssign,
  });
  const presidentLabel = resolvePresidentDisplayLabel(governanceLabels);

  const candidates = useMemo(
    () => (clubId ? listClubGovernanceCandidates(clubId, tenantId) : []),
    [clubId, tenantId, clubRecord?.governance?.ownerUserId]
  );

  return (
    <>
      <Card sx={{ mb: 2, overflow: "hidden", borderRadius: 2, border: 1, borderColor: "divider" }}>
        <Box sx={{ ...heroGradientSx, p: { xs: 2, md: 2.5 } }}>
          <Stack direction="row" spacing={2} alignItems="center" flexWrap="wrap">
            <ClubAvatar name={clubSummary.name} size={64} />
            <Box sx={{ flex: 1, minWidth: 200 }}>
              <Stack direction="row" spacing={1} alignItems="center" flexWrap="wrap">
                <Typography variant="h5" fontWeight={700} component="h2">
                  {clubSummary.name}
                </Typography>
                <ClubStatusBadge status={clubSummary.status} />
              </Stack>
              {registeredCluster && (
                <Stack direction="row" spacing={0.75} alignItems="center" sx={{ mt: 0.5 }}>
                  <PlaceIcon fontSize="small" color="action" aria-hidden />
                  <Typography variant="body2" color="text.secondary">
                    Cụm sân: {registeredCluster.name}
                  </Typography>
                </Stack>
              )}
            </Box>
          </Stack>
        </Box>

        <Box sx={{ p: { xs: 2, md: 2.5 } }}>
          <Stack direction={{ xs: "column", sm: "row" }} spacing={1.5} sx={{ mb: 2 }}>
            <Box sx={statBoxSx}>
              <Stack direction="row" spacing={0.75} alignItems="center">
                <GroupsIcon fontSize="small" color="primary" />
                <Box>
                  <Typography variant="caption" color="text.secondary">
                    Thành viên
                  </Typography>
                  <Typography variant="body1" fontWeight={600}>
                    {clubStats?.activeMemberCount ?? clubSummary.memberCount}
                  </Typography>
                </Box>
              </Stack>
            </Box>

            <Box sx={statBoxSx}>
              <Stack direction="row" spacing={0.75} alignItems="center">
                <PersonIcon fontSize="small" color="primary" />
                <Box>
                  <Typography variant="caption" color="text.secondary">
                    Chủ tịch
                  </Typography>
                  <Typography variant="body1" fontWeight={600}>
                    {presidentLabel}
                  </Typography>
                </Box>
              </Stack>
            </Box>

            <Box sx={statBoxSx}>
              <Stack direction="row" spacing={0.75} alignItems="center">
                <WorkspacePremiumIcon fontSize="small" color="action" />
                <Box sx={{ flex: 1 }}>
                  <Typography variant="caption" color="text.secondary">
                    Chủ sở hữu
                  </Typography>
                  {ownerStat.mode === "assigned" && (
                    <Typography variant="body1" fontWeight={600}>
                      {ownerStat.label}
                    </Typography>
                  )}
                  {ownerStat.mode === "assign" && (
                    <Button
                      size="small"
                      variant="outlined"
                      onClick={() => setAssignOpen(true)}
                      sx={{ mt: 0.25, px: 1.5 }}
                    >
                      Gắn chủ sở hữu
                    </Button>
                  )}
                  {ownerStat.mode === "unassigned" && (
                    <Typography variant="body1" color="text.secondary">
                      Chưa gán
                    </Typography>
                  )}
                </Box>
              </Stack>
            </Box>
          </Stack>

          <Stack direction={{ xs: "column", sm: "row" }} spacing={1} alignItems={{ sm: "center" }}>
            <Button
              component={RouterLink}
              to="/tournament"
              variant="contained"
              startIcon={<SportsTennisIcon />}
            >
              Giải đấu CLB
            </Button>
            {user?.playerId && (
              <Button
                component={RouterLink}
                to={`/players/profile/${user.playerId}`}
                variant="outlined"
                startIcon={<PersonIcon />}
              >
                Hồ sơ thi đấu
              </Button>
            )}
            {manageHref && (
              <Button component={RouterLink} to={manageHref} variant="text">
                Chi tiết CLB
              </Button>
            )}
          </Stack>
        </Box>
      </Card>

      <AssignClubOwnerDialog
        open={assignOpen}
        onClose={() => setAssignOpen(false)}
        clubId={clubId}
        tenantId={tenantId}
        candidates={candidates}
        onSuccess={() => {
          onMessage?.({ type: "success", text: "Đã gắn Chủ sở hữu CLB." });
          onRefresh?.();
        }}
        onError={(text) => onMessage?.({ type: "error", text })}
      />
    </>
  );
}

