export { MembershipRequestBadge };

import { useMemo, useState, useEffect } from "react";
import {
  Alert,
  Box,
  Button,
  FormControlLabel,
  Chip,
  Paper,
  Stack,
  Switch,
  TextField,
  Typography,
} from "@mui/material";
import { Link as RouterLink } from "react-router-dom";

import { useTenant } from "../../context/TenantContext.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  getIntegrationOverview,
  updateIntegrationSettings,
} from "../../features/integrations/index.js";
import { usePlatformRuntime } from "../../core/platform/app/usePlatformRuntime.js";

export default function IntegrationPaymentsPage() {
  const { currentTenantId } = useTenant();
  const runtime = usePlatformRuntime();
  const [refreshKey, setRefreshKey] = useState(0);
  const [message, setMessage] = useState(null);
  const [accessAllowed, setAccessAllowed] = useState(true);

  const overview = useMemo(
    () => getIntegrationOverview(currentTenantId),
    [currentTenantId, refreshKey]
  );

  useEffect(() => {
    try {
      const decision = runtime.accessService.authorize(
        {
          user_id: "demo-admin",
          tenant_id: currentTenantId || "payments-preview",
          role: "SUPER_ADMIN",
        },
        { tenant_id: currentTenantId || "payments-preview" },
        "payment.manage"
      );
      setAccessAllowed(Boolean(decision.allowed));
    } catch {
      setAccessAllowed(false);
    }
  }, [currentTenantId, runtime]);

  const [form, setForm] = useState({
    defaultPaymentProvider: overview?.settings?.defaultPaymentProvider || "mock",
    vnpayEnabled: overview?.settings?.vnpayEnabled || false,
    momoEnabled: overview?.settings?.momoEnabled || false,
    stripeEnabled: overview?.settings?.stripeEnabled || false,
    mockPaymentEnabled: overview?.settings?.mockPaymentEnabled !== false,
  });

  const handleSave = () => {
    if (!accessAllowed) {
      setMessage("Runtime platform chặn thao tác cấu hình thanh toán.");
      return;
    }

    const result = updateIntegrationSettings(currentTenantId, form);
    if (!result.ok) {
      setMessage(result.error);
      return;
    }
    setMessage("Đã lưu cấu hình thanh toán.");
    setRefreshKey((v) => v + 1);
  };

  return (
    <PermissionGate permissions={[PERMISSIONS.INTEGRATION_MANAGE]}>
      <Box>
        <Button component={RouterLink} to="/settings/integrations" sx={{ mb: 2 }}>
          ← Quay lại Tích hợp
        </Button>
        <Typography variant="h5" gutterBottom>
          Cấu hình thanh toán
        </Typography>

        <Chip
          size="small"
          label={`Runtime access: ${accessAllowed ? "allowed" : "denied"}`}
          color={accessAllowed ? "success" : "warning"}
          sx={{ mb: 2 }}
        />

        {message && (
          <Alert severity="info" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
            {message}
          </Alert>
        )}

        <Paper sx={{ p: 2 }}>
          <Stack spacing={2}>
            <TextField
              select
              SelectProps={{ native: true }}
              label="Provider mặc định"
              value={form.defaultPaymentProvider}
              onChange={(e) => setForm({ ...form, defaultPaymentProvider: e.target.value })}
            >
              <option value="mock">Mock</option>
              <option value="vnpay">VNPay</option>
              <option value="momo">MoMo</option>
              <option value="stripe">Stripe</option>
            </TextField>

            <FormControlLabel
              control={
                <Switch
                  checked={form.mockPaymentEnabled}
                  onChange={(e) => setForm({ ...form, mockPaymentEnabled: e.target.checked })}
                />
              }
              label="Bật Mock Payment"
            />
            <FormControlLabel
              control={
                <Switch
                  checked={form.vnpayEnabled}
                  onChange={(e) => setForm({ ...form, vnpayEnabled: e.target.checked })}
                />
              }
              label="Bật VNPay"
            />
            <FormControlLabel
              control={
                <Switch
                  checked={form.momoEnabled}
                  onChange={(e) => setForm({ ...form, momoEnabled: e.target.checked })}
                />
              }
              label="Bật MoMo"
            />
            <FormControlLabel
              control={
                <Switch
                  checked={form.stripeEnabled}
                  onChange={(e) => setForm({ ...form, stripeEnabled: e.target.checked })}
                />
              }
              label="Bật Stripe"
            />

            <Typography variant="subtitle2">Callback URLs (copy vào cổng thanh toán)</Typography>
            <TextField
              label="VNPay callback"
              value={overview?.callbackUrls?.vnpay || ""}
              InputProps={{ readOnly: true }}
              fullWidth
            />
            <TextField
              label="MoMo callback"
              value={overview?.callbackUrls?.momo || ""}
              InputProps={{ readOnly: true }}
              fullWidth
            />
            <TextField
              label="Stripe webhook"
              value={overview?.callbackUrls?.stripe || ""}
              InputProps={{ readOnly: true }}
              fullWidth
            />

            <Button variant="contained" onClick={handleSave}>
              Lưu
            </Button>
          </Stack>
        </Paper>
      </Box>
    </PermissionGate>
  );
}

import { useMemo, useState, useEffect } from "react";
import {
  Alert,
  Box,
  Button,
  Chip,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
} from "@mui/material";
import { Link as RouterLink } from "react-router-dom";

import { useTenant } from "../../context/TenantContext.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  buildIntegrationProviderRows,
  canManageIntegrations,
  getIntegrationOverview,
  hydrateIntegrationSettings,
  isIntegrationOperational,
  isIntegrationsFeatureEnabled,
  toggleIntegrationProvider,
} from "../../features/integrations/index.js";
import { sendTestNotification } from "../../features/notifications/index.js";

const STATUS_COLOR = {
  disabled: "default",
  configured: "success",
  mock_only: "info",
  error: "error",
  active: "success",
  not_configured: "default",
  inactive: "warning",
};

export default function IntegrationSettingsPage() {
  const { currentTenantId } = useTenant();
  const tenantId = currentTenantId;
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);

  const overview = useMemo(
    () => (tenantId ? getIntegrationOverview(tenantId) : null),
    [tenantId, refreshKey]
  );

  const rows = useMemo(() => buildIntegrationProviderRows(overview), [overview]);

  useEffect(() => {
    if (!tenantId) return;
    let cancelled = false;
    void hydrateIntegrationSettings(tenantId).then((result) => {
      if (!cancelled && result?.ok) {
        setRefreshKey((v) => v + 1);
      }
    });
    return () => {
      cancelled = true;
    };
  }, [tenantId]);

  const access = canManageIntegrations();
  const permissionScope = useMemo(
    () => ({ venueId: tenantId, tenantId }),
    [tenantId]
  );

  const handleToggle = (provider, enabled) => {
    if (!tenantId) {
      setError("Chưa xác định tenant.");
      return;
    }
    setError(null);
    const result = toggleIntegrationProvider(tenantId, provider, enabled);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage(`Đã ${enabled ? "bật" : "tắt"} ${provider}.`);
    setRefreshKey((v) => v + 1);
  };

  const handleTest = async (channel) => {
    if (!tenantId) {
      setError("Chưa xác định tenant.");
      return;
    }

    setError(null);
    const result = await sendTestNotification(tenantId, channel);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage(`Gửi test ${channel} thành công (mock).`);
  };

  if (!tenantId) {
    return (
      <Alert severity="warning">
        Chưa xác định tenant. Kiểm tra profile <code>venue_id</code> hoặc chọn tenant.
      </Alert>
    );
  }

  return (
    <PermissionGate
      permissions={[PERMISSIONS.INTEGRATION_VIEW, PERMISSIONS.SETTINGS_VIEW]}
      scope={permissionScope}
      fallback={
        <Alert severity="warning">
          Bạn không có quyền xem cấu hình tích hợp cho tenant này.
        </Alert>
      }
    >
      <Box>
        <Typography variant="h5" gutterBottom>
          Tích hợp bên ngoài
        </Typography>
        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
          Cấu hình Zalo, thanh toán, email, SMS theo tenant. Mặc định chạy mock/sandbox.
        </Typography>

        {!isIntegrationsFeatureEnabled() && (
          <Alert severity="info" sx={{ mb: 2 }}>
            Feature flag tích hợp chưa bật trên env. Danh sách vẫn hiển thị ở chế độ disabled.
            Set <code>VITE_MARKETPLACE_ENABLED=true</code> hoặc <code>VITE_API_ENABLED=true</code> để
            bật đầy đủ.
          </Alert>
        )}

        {message && (
          <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
            {message}
          </Alert>
        )}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
            {error}
          </Alert>
        )}

        {rows.length === 0 ? (
          <Alert severity="warning">Không có provider tích hợp để hiển thị.</Alert>
        ) : (
          <TableContainer component={Paper}>
            <Table size="small">
              <TableHead>
                <TableRow>
                  <TableCell>Tích hợp</TableCell>
                  <TableCell>Trạng thái</TableCell>
                  <TableCell align="right">Thao tác</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {rows.map((row) => (
                  <TableRow key={row.key}>
                    <TableCell>{row.label}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={row.status}
                        color={STATUS_COLOR[row.status] || "default"}
                      />
                    </TableCell>
                    <TableCell align="right">
                      <Stack direction="row" spacing={1} justifyContent="flex-end">
                        {row.link && (
                          <Button size="small" component={RouterLink} to={row.link}>
                            Cấu hình
                          </Button>
                        )}
                        {access.ok &&
                          ["zalo", "email", "sms", "vnpay", "momo", "stripe", "mock"].includes(
                            row.key
                          ) && (
                            <Button
                              size="small"
                              onClick={() =>
                                handleToggle(
                                  row.key === "mockPayment" ? "mock" : row.key,
                                  !isIntegrationOperational(row.status)
                                )
                              }
                            >
                              {isIntegrationOperational(row.status) ? "Tắt" : "Bật"}
                            </Button>
                          )}
                        {row.key === "email" && access.ok && (
                          <Button size="small" onClick={() => handleTest("email")}>
                            Test
                          </Button>
                        )}
                        {row.key === "sms" && access.ok && (
                          <Button size="small" onClick={() => handleTest("sms")}>
                            Test
                          </Button>
                        )}
                        {row.key === "zalo" && access.ok && (
                          <Button size="small" onClick={() => handleTest("zalo")}>
                            Test
                          </Button>
                        )}
                      </Stack>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </Box>
    </PermissionGate>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  FormControlLabel,
  Paper,
  Stack,
  Switch,
  TextField,
  Typography,
} from "@mui/material";
import { Link as RouterLink } from "react-router-dom";

import { useTenant } from "../../context/TenantContext.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  getTenantIntegrationSettings,
  updateIntegrationSettings,
} from "../../features/integrations/index.js";
import { sendTestNotification, listNotificationLogs } from "../../features/notifications/index.js";

export default function ZaloIntegrationPage() {
  const { currentTenantId } = useTenant();
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [refreshKey, setRefreshKey] = useState(0);

  const settings = useMemo(
    () => getTenantIntegrationSettings(currentTenantId),
    [currentTenantId, refreshKey]
  );

  const logs = useMemo(
    () =>
      listNotificationLogs({ tenantId: currentTenantId }).filter((l) => l.channel === "zalo"),
    [currentTenantId, refreshKey]
  );

  const [form, setForm] = useState({
    zaloEnabled: settings.zaloEnabled || false,
    oaId: settings.zaloConfig?.oaId || "",
    appId: settings.zaloConfig?.appId || "",
  });

  const handleSave = () => {
    const result = updateIntegrationSettings(currentTenantId, {
      zaloEnabled: form.zaloEnabled,
      zaloConfig: {
        ...settings.zaloConfig,
        oaId: form.oaId,
        appId: form.appId,
        status: form.zaloEnabled ? "active" : "inactive",
        lastConnectedAt: form.zaloEnabled ? new Date().toISOString() : settings.zaloConfig?.lastConnectedAt,
      },
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage("Đã lưu cấu hình Zalo OA.");
    setRefreshKey((v) => v + 1);
  };

  const handleTest = async () => {
    setError(null);
    const result = await sendTestNotification(currentTenantId, "zalo");
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setMessage("Đã gửi tin test Zalo (mock).");
    setRefreshKey((v) => v + 1);
  };

  return (
    <PermissionGate permissions={[PERMISSIONS.INTEGRATION_MANAGE]}>
      <Box>
        <Button component={RouterLink} to="/settings/integrations" sx={{ mb: 2 }}>
          ← Quay lại Tích hợp
        </Button>
        <Typography variant="h5" gutterBottom>
          Zalo OA
        </Typography>

        {message && <Alert severity="success" sx={{ mb: 2 }}>{message}</Alert>}
        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Paper sx={{ p: 2, mb: 2 }}>
          <Stack spacing={2}>
            <FormControlLabel
              control={
                <Switch
                  checked={form.zaloEnabled}
                  onChange={(e) => setForm({ ...form, zaloEnabled: e.target.checked })}
                />
              }
              label="Bật gửi Zalo"
            />
            <TextField
              label="OA ID"
              value={form.oaId}
              onChange={(e) => setForm({ ...form, oaId: e.target.value })}
            />
            <TextField
              label="App ID (sandbox)"
              value={form.appId}
              onChange={(e) => setForm({ ...form, appId: e.target.value })}
            />
            <Stack direction="row" spacing={1}>
              <Button variant="contained" onClick={handleSave}>
                Lưu
              </Button>
              <Button variant="outlined" onClick={handleTest}>
                Gửi test
              </Button>
            </Stack>
          </Stack>
        </Paper>

        <Typography variant="subtitle1" gutterBottom>
          Log gửi tin gần đây
        </Typography>
        {logs.length === 0 ? (
          <Typography variant="body2" color="text.secondary">
            Chưa có log.
          </Typography>
        ) : (
          logs.slice(0, 10).map((log) => (
            <Typography key={log.id} variant="body2">
              {log.createdAt} — {log.status} — {log.templateKey}
            </Typography>
          ))
        )}
      </Box>
    </PermissionGate>
  );
}

import { useMemo, useState } from "react";
import { Link as RouterLink, useNavigate, useParams } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControl,
  Grid,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";
import LockIcon from "@mui/icons-material/Lock";
import LockOpenIcon from "@mui/icons-material/LockOpen";

import { getDirectorState, lockCourt, unlockCourt } from "../../ai/director.js";
import { useClub } from "../../context/ClubContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { canViewPlayerSkillLevel } from "../../auth/rbac.js";
import { loadCourtsForClub, loadPlayersForClub } from "../../domain/clubStorage.js";
import {
  getTournament,
  setTournamentStatus,
  updateTournament,
} from "../../domain/tournamentService.js";
import { getCourtDisplayName } from "../../models/court.js";
import TournamentCourtSchedulePanel from "../../components/tournament/TournamentCourtSchedulePanel.jsx";
import { formatOrganizerPlayerMeta } from "../../utils/skillLevelVisibility.js";
import {
  assignDailyMatchToCourt,
  createFairDailyMatches,
  DAILY_GENDER_FILTER,
  DAILY_MATCH_TYPE,
  getDefaultDailyPlaySettings,
  normalizeDailyPlaySettings,
  partitionDailyMatches,
  submitDailyPlayMatchScore,
  toggleDailyCheckIn,
  buildDailyPlayTournamentPatch,
} from "../../tournament/engines/dailyPlayEngine.js";
import TournamentManageGate from "../../components/tournament/TournamentManageGate.jsx";
import TournamentSetupShell from "../../components/tournament/TournamentSetupShell.jsx";
import { buildCourtRuntimeStates } from "../../tournament/engines/courtEngine.js";
import MatchListPanel from "../../components/tournament/MatchListPanel.jsx";
import RefereeRosterPanel from "../../components/tournament/RefereeRosterPanel.jsx";
import { buildDailyMatchCardProps } from "../../components/tournament/matchCardProps.js";
import TournamentAnimationDialog from "../../components/tournament/animation/TournamentAnimationDialog.jsx";
import {
  ANIMATION_MODES,
} from "../../components/tournament/animation/animationUtils.js";
import { buildDailyFairMatchAnimationPayload } from "../../components/tournament/animation/daily/dailyFairMatchUtils.js";
import { FAIR_MATCH_CONTROL_MODES } from "../../components/tournament/animation/daily/useFairMatchSequence.js";
import { useTournamentAnimation } from "../../components/tournament/animation/useTournamentAnimation.js";
import { buildRefereeSettingsPatch, getRefereeSettings } from "../../tournament/engines/refereeEngine.js";

const MATCH_TYPE_OPTIONS = [
  { value: DAILY_MATCH_TYPE.MEN_DOUBLE, label: "Đôi nam" },
  { value: DAILY_MATCH_TYPE.WOMEN_DOUBLE, label: "Đôi nữ" },
  { value: DAILY_MATCH_TYPE.MIXED_DOUBLE, label: "Đôi nam nữ" },
  { value: DAILY_MATCH_TYPE.AUTO, label: "Tự động nhiều loại" },
];

const GENDER_FILTER_OPTIONS = [
  { value: DAILY_GENDER_FILTER.ALL, label: "Tất cả" },
  { value: DAILY_GENDER_FILTER.MALE, label: "Nam" },
  { value: DAILY_GENDER_FILTER.FEMALE, label: "Nữ" },
];

export default function DailyPlaySetup() {
  const { tournamentId } = useParams();
  const navigate = useNavigate();
  const { activeClubId, activeClub, refreshClubs } = useClub();
  const { user, rbacEnabled } = useAuth();
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [scoreDialog, setScoreDialog] = useState(null);
  const [scoreA, setScoreA] = useState("");
  const [scoreB, setScoreB] = useState("");
  const [localRevision, setLocalRevision] = useState(0);
  const anim = useTournamentAnimation();

  const canViewSkillInSetup = useMemo(
    () =>
      canViewPlayerSkillLevel(
        user,
        { clubId: activeClubId, tournamentId, tournamentContext: true },
        { rbacEnabled }
      ),
    [user, activeClubId, tournamentId, rbacEnabled]
  );

  const tournament = useMemo(
    () => getTournament(activeClubId, tournamentId),
    [activeClubId, tournamentId, localRevision]
  );

  const players = useMemo(
    () => loadPlayersForClub(activeClubId),
    [activeClubId, localRevision]
  );

  const courts = useMemo(
    () => loadCourtsForClub(activeClubId),
    [activeClubId, localRevision]
  );

  const dailySettings = useMemo(
    () =>
      normalizeDailyPlaySettings(
        tournament?.settings?.dailyPlay || getDefaultDailyPlaySettings()
      ),
    [tournament, localRevision]
  );

  const refereeRoster = useMemo(
    () => getRefereeSettings(tournament).roster,
    [tournament, localRevision]
  );

  const lockedCourtIds = useMemo(
    () => getDirectorState(activeClubId).lockedCourts || [],
    [activeClubId, localRevision]
  );

  const enabledCourts = useMemo(() => {
    const activeCourts = courts.filter((court) => court.active !== false);
    if (!dailySettings.enabledCourtIds.length) {
      return activeCourts;
    }
    return activeCourts.filter((court) =>
      dailySettings.enabledCourtIds.includes(String(court.id))
    );
  }, [courts, dailySettings.enabledCourtIds]);

  const courtStates = useMemo(
    () =>
      buildCourtRuntimeStates(enabledCourts, dailySettings.matches, {
        lockedCourtIds,
      }),
    [enabledCourts, dailySettings.matches, lockedCourtIds]
  );

  const { waiting, playing, completed } = useMemo(
    () => partitionDailyMatches(dailySettings.matches),
    [dailySettings.matches]
  );

  const checkedInSet = useMemo(
    () => new Set(dailySettings.checkedInPlayerIds),
    [dailySettings.checkedInPlayerIds]
  );

  const saveSettings = (nextSettings, options = {}) => {
    const result = updateTournament(
      activeClubId,
      tournamentId,
      buildDailyPlayTournamentPatch(nextSettings),
      {
        processMatchId: options.processMatchId || null,
      }
    );

    if (!result.ok) {
      setError(result.error || "Khong luu duoc trang thai Daily Play.");
      return false;
    }

    if (tournament?.status === TOURNAMENT_STATUS.DRAFT) {
      setTournamentStatus(activeClubId, tournamentId, TOURNAMENT_STATUS.ACTIVE);
    }

    setLocalRevision((value) => value + 1);
    refreshClubs();
    return true;
  };

  const handleToggleCheckIn = (playerId) => {
    saveSettings(toggleDailyCheckIn(dailySettings, playerId));
  };

  const handleSelectAllCheckIn = () => {
    saveSettings({
      ...dailySettings,
      checkedInPlayerIds: players.map((player) => String(player.id)),
    });
  };

  const handleClearAllCheckIn = () => {
    saveSettings({
      ...dailySettings,
      checkedInPlayerIds: [],
    });
  };

  const handleRefereeRosterChange = (nextRoster) => {
    const result = updateTournament(
      activeClubId,
      tournamentId,
      buildRefereeSettingsPatch(tournament, { roster: nextRoster })
    );

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setLocalRevision((value) => value + 1);
    refreshClubs();
    setMessage("Đã cập nhật danh sách trọng tài.");
  };

  const handleCreateMatches = () => {
    setError(null);
    const availableCourts = courtStates.filter(
      (court) => court.status === "available" && !court.locked
    ).length;

    const result = createFairDailyMatches({
      players,
      settings: dailySettings,
      tournamentId,
      matchCount: Math.max(1, availableCourts || 1),
      skipScore: dailySettings.skipScore,
    });

    if (!result.ok) {
      setError(result.error || result.errors?.join(" ") || "Khong tao duoc tran.");
      return;
    }

    const animationPayload = buildDailyFairMatchAnimationPayload({
      result,
      players,
      courts: enabledCourts,
      clubName: activeClub?.name || "CLB",
      playDate: new Date(),
    });

    const poolPlayerIds = new Set(
      animationPayload.players.map((player) => String(player.id))
    );
    const animationPlayers = players.filter((player) =>
      poolPlayerIds.has(String(player.id))
    );

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.DAILY_FAIR_MATCH,
        ...animationPayload,
        players: animationPlayers,
        controlMode: FAIR_MATCH_CONTROL_MODES.AUTO,
        autoStart: true,
        speed: "normal",
      },
      () => {
        if (saveSettings(result.settings)) {
          const waitingNote =
            result.waitingPlayers?.length > 0
              ? ` • ${result.waitingPlayers.length} VĐV chờ lượt tiếp theo`
              : "";
          setMessage(`Đã tạo ${result.matches.length} trận công bằng${waitingNote}.`);
        }
      }
    );
  };

  const handleAssignCourt = (match) => {
    const result = assignDailyMatchToCourt({
      settings: dailySettings,
      courts: enabledCourts,
      matchId: match.id,
      lockedCourtIds,
    });

    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (saveSettings(result.settings)) {
      setMessage("Da xep tran vao san trong.");
    }
  };

  const handleToggleCourt = (courtId, locked) => {
    if (locked) {
      unlockCourt(courtId, activeClubId);
    } else {
      lockCourt(courtId, activeClubId);
    }
    setLocalRevision((value) => value + 1);
  };

  const handleOpenScore = (match) => {
    setScoreDialog(match);
    setScoreA(match.scoreA != null ? String(match.scoreA) : "");
    setScoreB(match.scoreB != null ? String(match.scoreB) : "");
  };

  const handleSubmitScore = () => {
    if (!scoreDialog) {
      return;
    }

    const result = submitDailyPlayMatchScore(
      dailySettings,
      scoreDialog.id,
      { scoreA, scoreB },
      { allowDraw: false }
    );

    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (result.releasedCourtId) {
      unlockCourt(result.releasedCourtId, activeClubId);
    }

    if (saveSettings(result.settings, { processMatchId: scoreDialog.id })) {
      setScoreDialog(null);
      setMessage("Da luu ket qua va giai phong san.");
    }
  };

  const updateDailyField = (patch) => {
    saveSettings({ ...dailySettings, ...patch });
  };

  if (!tournament) {
    return (
      <Box>
        <Alert severity="error">Khong tim thay giai Daily Play.</Alert>
        <Button component={RouterLink} to="/tournament" sx={{ mt: 2 }}>
          Quay lai
        </Button>
      </Box>
    );
  }

  if (tournament.mode !== TOURNAMENT_MODE.DAILY_PLAY) {
    return (
      <Box>
        <Alert severity="warning">Giai nay khong phai che do Daily Play.</Alert>
        <Button component={RouterLink} to="/tournament" sx={{ mt: 2 }}>
          Quay lai
        </Button>
      </Box>
    );
  }

  return (
    <TournamentManageGate tournamentId={tournamentId}>
    <TournamentSetupShell
      tournament={tournament}
      description="Daily Play — check-in, ghép trận công bằng, xếp sân"
      onBack={() => navigate("/tournament")}
      headerActions={
        <Button
          variant="outlined"
          onClick={() => navigate(`/tournament/director/${tournamentId}`)}
        >
          Mở Director Mode
        </Button>
      }
      alerts={
        <>
          {message && (
            <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
              {message}
            </Alert>
          )}
          {error && (
            <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
              {error}
            </Alert>
          )}
        </>
      }
    >
      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12 }}>
          <RefereeRosterPanel roster={refereeRoster} onChange={handleRefereeRosterChange} />
        </Grid>
      </Grid>

      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12, md: 4 }}>
          <FormControl fullWidth size="small">
            <InputLabel>Loại trận</InputLabel>
            <Select
              label="Loại trận"
              value={dailySettings.matchType}
              onChange={(event) => updateDailyField({ matchType: event.target.value })}
            >
              {MATCH_TYPE_OPTIONS.map((option) => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid size={{ xs: 12, md: 4 }}>
          <FormControl fullWidth size="small">
            <InputLabel>Lọc VĐV</InputLabel>
            <Select
              label="Lọc VĐV"
              value={dailySettings.genderFilter}
              onChange={(event) => updateDailyField({ genderFilter: event.target.value })}
            >
              {GENDER_FILTER_OPTIONS.map((option) => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid size={{ xs: 12, md: 4 }}>
          <Stack direction="row" spacing={1} sx={{ height: "100%" }}>
            <Button
              fullWidth
              variant="contained"
              size="large"
              onClick={handleCreateMatches}
              sx={{ minHeight: 48 }}
            >
              Tạo trận công bằng
            </Button>
          </Stack>
        </Grid>
      </Grid>

      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12, lg: 5 }}>
          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Check-in hôm nay ({dailySettings.checkedInPlayerIds.length})
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mb: 1 }}>
              <Button size="small" variant="contained" onClick={handleSelectAllCheckIn}>
                Chọn tất cả
              </Button>
              <Button
                size="small"
                variant="outlined"
                onClick={handleClearAllCheckIn}
                disabled={dailySettings.checkedInPlayerIds.length === 0}
              >
                Bỏ chọn tất cả
              </Button>
            </Stack>
            <Stack spacing={1} sx={{ maxHeight: 320, overflow: "auto" }}>
              {players.map((player) => {
                const checked = checkedInSet.has(String(player.id));
                return (
                  <Button
                    key={player.id}
                    fullWidth
                    variant={checked ? "contained" : "outlined"}
                    onClick={() => handleToggleCheckIn(player.id)}
                    sx={{ justifyContent: "space-between", minHeight: 44 }}
                  >
                    <span>{player.name}</span>
                    <span>{formatOrganizerPlayerMeta(player, canViewSkillInSetup)}</span>
                  </Button>
                );
              })}
            </Stack>
          </Paper>
        </Grid>

        <Grid size={{ xs: 12, lg: 7 }}>
          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Sân đang dùng
            </Typography>
            <Stack spacing={1}>
              {courtStates.map((court, index) => {
                const locked = court.locked || lockedCourtIds.includes(court.id);
                return (
                  <Paper key={court.id} variant="outlined" sx={{ p: 1.25 }}>
                    <Stack
                      direction={{ xs: "column", sm: "row" }}
                      justifyContent="space-between"
                      spacing={1}
                    >
                      <Box>
                        <Typography fontWeight="bold">
                          {getCourtDisplayName(
                            enabledCourts.find((item) => String(item.id) === String(court.id)),
                            index
                          )}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {court.status}
                          {court.currentMatchId ? ` • Trận ${court.currentMatchId}` : ""}
                        </Typography>
                      </Box>
                      <Button
                        size="small"
                        startIcon={locked ? <LockOpenIcon /> : <LockIcon />}
                        onClick={() => handleToggleCourt(court.id, locked)}
                        disabled={Boolean(court.currentMatchId) && !locked}
                      >
                        {locked ? "Mở sân" : "Khóa sân"}
                      </Button>
                    </Stack>
                  </Paper>
                );
              })}
            </Stack>
          </Paper>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, md: 4 }}>
          <MatchListPanel
            title="Trận chờ"
            matches={waiting}
            emptyText="Chưa có trận chờ."
            getCardProps={(match) =>
              buildDailyMatchCardProps(match, {
                actionLabel: "Xếp vào sân trống",
                onAction: handleAssignCourt,
              })
            }
          />
        </Grid>
        <Grid size={{ xs: 12, md: 4 }}>
          <MatchListPanel
            title="Đang đánh"
            matches={playing}
            emptyText="Chưa có trận trên sân."
            chipColor="success"
            getCardProps={(match) =>
              buildDailyMatchCardProps(match, {
                actionLabel: "Nhập điểm",
                onAction: handleOpenScore,
              })
            }
          />
        </Grid>
        <Grid size={{ xs: 12, md: 4 }}>
          <MatchListPanel
            title="Đã xong"
            matches={completed}
            emptyText="Chưa có trận hoàn thành."
            getCardProps={(match) => buildDailyMatchCardProps(match)}
          />
        </Grid>
      </Grid>

      <Dialog open={Boolean(scoreDialog)} onClose={() => setScoreDialog(null)} fullWidth>
        <DialogTitle>Nhập điểm</DialogTitle>
        <DialogContent>
          <Typography sx={{ mb: 2 }}>
            {scoreDialog?.teamALabel} vs {scoreDialog?.teamBLabel}
          </Typography>
          <Stack direction="row" spacing={2}>
            <TextField
              label="Điểm A"
              type="number"
              value={scoreA}
              onChange={(event) => setScoreA(event.target.value)}
              fullWidth
            />
            <TextField
              label="Điểm B"
              type="number"
              value={scoreB}
              onChange={(event) => setScoreB(event.target.value)}
              fullWidth
            />
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setScoreDialog(null)}>Bỏ qua</Button>
          <Button variant="contained" onClick={handleSubmitScore}>
            Lưu điểm
          </Button>
        </DialogActions>
      </Dialog>

      <TournamentAnimationDialog {...anim.dialogProps} />

      {tournament && (
        <Box sx={{ mt: 3 }}>
          <TournamentCourtSchedulePanel
            clubId={activeClubId}
            tournament={tournament}
            courts={courts}
            onSaved={() => {
              refreshClubs();
              setLocalRevision((value) => value + 1);
            }}
          />
        </Box>
      )}
    </TournamentSetupShell>
    </TournamentManageGate>
  );
}

