import { useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Chip,
  Paper,
  Stack,
  Typography,
} from "@mui/material";
import AccountTreeIcon from "@mui/icons-material/AccountTree";
import ChevronRightIcon from "@mui/icons-material/ChevronRight";

import { useClub } from "../../context/ClubContext.jsx";
import { useSeasonLeague } from "../../context/SeasonContext.jsx";
import { listTournaments } from "../../domain/tournamentService.js";
import { TOURNAMENT_MODE, TOURNAMENT_STATUS } from "../../models/tournament/index.js";
import { getTournamentBracketPath,
  getTournamentSetupPath,
  isBracketTournament,
  rankTournamentsForBracket,
} from "../../utils/tournamentNavigation.js";
import TournamentPageHeader from "../../components/tournament/TournamentPageHeader.jsx";
import { tournamentCardHoverSx, tournamentCardSx } from "../../components/tournament/tournamentLayout.js";

const MODE_LABELS = {
  [TOURNAMENT_MODE.INTERNAL_TOURNAMENT]: "Nội bộ",
  [TOURNAMENT_MODE.OFFICIAL_TOURNAMENT]: "Chính thức",
};

const STATUS_LABELS = {
  [TOURNAMENT_STATUS.ACTIVE]: "Đang diễn ra",
  [TOURNAMENT_STATUS.READY]: "Sẵn sàng",
  [TOURNAMENT_STATUS.REGISTRATION]: "Đăng ký",
  [TOURNAMENT_STATUS.COMPLETED]: "Hoàn thành",
  [TOURNAMENT_STATUS.DRAFT]: "Nháp",
};

export default function TournamentBracketHub() {
  const navigate = useNavigate();
  const { activeClubId, revision } = useClub();
  const { activeSeason, activeLeague } = useSeasonLeague();

  const tournaments = useMemo(
    () => listTournaments(activeClubId),
    [activeClubId, revision]
  );

  const bracketTournaments = useMemo(
    () =>
      rankTournamentsForBracket(tournaments, {
        seasonId: activeSeason?.id,
        leagueId: activeLeague?.id,
      }),
    [tournaments, activeSeason?.id, activeLeague?.id]
  );

  const pendingSetup = useMemo(
    () =>
      tournaments.filter(
        (tournament) =>
          isBracketTournament(tournament) &&
          tournament.status !== TOURNAMENT_STATUS.CANCELLED &&
          tournament.status !== TOURNAMENT_STATUS.DRAFT
      ),
    [tournaments]
  );

  useEffect(() => {
    if (bracketTournaments.length === 1) {
      const path = getTournamentBracketPath(bracketTournaments[0]);
      if (path) {
        navigate(path, { replace: true });
      }
    }
  }, [bracketTournaments, navigate]);

  if (bracketTournaments.length === 1) {
    return null;
  }

  return (
    <Box>
      <TournamentPageHeader
        title="Sơ đồ thi đấu"
        description={`Chọn giải để xem bracket knock-out của ${activeLeague?.name || "giải hiện tại"}.`}
      />

      {bracketTournaments.length > 0 ? (
        <Stack spacing={1.5}>
          {bracketTournaments.map((tournament) => (
            <Paper
              key={tournament.id}
              variant="outlined"
              elevation={0}
              sx={{
                ...tournamentCardSx,
                ...tournamentCardHoverSx,
                p: 2,
                cursor: "pointer",
                "&:hover": {
                  ...tournamentCardHoverSx["&:hover"],
                  transform: "translateY(-1px)",
                },
              }}
              onClick={() => {
                const path = getTournamentBracketPath(tournament);
                if (path) navigate(path);
              }}
            >
              <Stack
                direction={{ xs: "column", sm: "row" }}
                spacing={1}
                alignItems={{ xs: "flex-start", sm: "center" }}
                justifyContent="space-between"
              >
                <Box>
                  <Typography variant="subtitle1" fontWeight={800}>
                    {tournament.name}
                  </Typography>
                  <Stack direction="row" spacing={0.75} sx={{ mt: 0.75 }} flexWrap="wrap">
                    <Chip
                      size="small"
                      label={MODE_LABELS[tournament.mode] || "Giải"}
                      color="primary"
                      variant="outlined"
                    />
                    <Chip
                      size="small"
                      label={STATUS_LABELS[tournament.status] || tournament.status}
                    />
                  </Stack>
                </Box>
                <Button endIcon={<ChevronRightIcon />} variant="contained" size="small">
                  Mở sơ đồ
                </Button>
              </Stack>
            </Paper>
          ))}
        </Stack>
      ) : (
        <Alert severity="info" sx={{ mb: 2 }}>
          {pendingSetup.length > 0
            ? "Các giải đã tạo nhưng chưa có sơ đồ knock-out. Nhập đủ điểm vòng bảng — bracket sẽ được tạo tự động."
            : "Chưa có giải nội bộ/chính thức nào có sơ đồ thi đấu."}
        </Alert>
      )}

      {pendingSetup.length > 0 && bracketTournaments.length === 0 && (
        <Stack spacing={1}>
          {pendingSetup.map((tournament) => (
            <Button
              key={tournament.id}
              variant="outlined"
              onClick={() => navigate(getTournamentSetupPath(tournament))}
              sx={{ justifyContent: "flex-start" }}
            >
              Thiết lập giải: {tournament.name}
            </Button>
          ))}
        </Stack>
      )}

      <Button sx={{ mt: 3 }} onClick={() => navigate("/tournament")}>
        Về danh sách giải
      </Button>
    </Box>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import { Alert, Box, Typography } from "@mui/material";

import { useClub } from "../../context/ClubContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { useTenant } from "../../context/TenantContext.jsx";
import { loadCourtsForClub } from "../../domain/clubStorage.js";
import { assertTournamentAccess, getTournament } from "../../domain/tournamentService.js";
import { resolveBracketProgress } from "../../tournament/engines/index.js";
import TournamentBracketScreen from "../../components/tournament/bracket/TournamentBracketScreen.jsx";

const MODE_LABELS = {
  internal: "Giải nội bộ",
  official: "Giải mở",
};

const LIVE_REFRESH_MS = 2500;

export default function TournamentBracketPage() {
  const { tournamentId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const mode = location.pathname.includes("/official/") ? "official" : "internal";
  const { activeClubId, revision } = useClub();
  const { rbacEnabled, isAuthenticated } = useAuth();
  const { currentTenantId } = useTenant();
  const [liveTick, setLiveTick] = useState(0);

  useEffect(() => {
    const timer = window.setInterval(() => {
      setLiveTick((value) => value + 1);
    }, LIVE_REFRESH_MS);

    return () => window.clearInterval(timer);
  }, []);

  const tournamentAccess = useMemo(() => {
    if (!rbacEnabled || !isAuthenticated) {
      return { ok: true };
    }

    return assertTournamentAccess(activeClubId, tournamentId, {
      tenantId: currentTenantId,
    });
  }, [activeClubId, currentTenantId, isAuthenticated, rbacEnabled, tournamentId]);

  const tournament = useMemo(
    () => getTournament(activeClubId, tournamentId),
    [activeClubId, tournamentId, revision, liveTick]
  );

  const courts = useMemo(() => loadCourtsForClub(activeClubId), [activeClubId, revision]);
  const event = tournament?.events?.[0] || null;

  const progress = useMemo(
    () => (event ? resolveBracketProgress(event) : null),
    [event]
  );

  const knockoutMatchesByBracketId = useMemo(() => {
    const map = {};
    (event?.matches || []).forEach((match) => {
      if (match.bracketMatchId) {
        map[match.bracketMatchId] = match;
      }
    });
    return map;
  }, [event]);

  const backPath =
    mode === "official"
      ? `/tournament/official/${tournamentId}`
      : `/tournament/internal/${tournamentId}`;

  if (tournamentId && !tournamentAccess.ok) {
    return (
      <Box sx={{ p: 2 }}>
        <Alert severity="error">
          {tournamentAccess.error || "Không có quyền xem giải đấu này."}
        </Alert>
      </Box>
    );
  }

  if (!tournament) {
    return (
      <Box sx={{ p: 2 }}>
        <Alert severity="warning">Không tìm thấy giải đấu.</Alert>
      </Box>
    );
  }

  if (!progress?.rounds?.length) {
    return (
      <Box sx={{ p: 2 }}>
        <Alert severity="info" sx={{ mb: 2 }}>
          Chưa có sơ đồ thi đấu. Nhập đủ điểm vòng bảng — bracket sẽ được tạo tự động từ BXH.
        </Alert>
        <Typography
          variant="body2"
          color="primary"
          sx={{ cursor: "pointer", textDecoration: "underline" }}
          onClick={() => navigate(backPath)}
        >
          Quay lại thiết lập giải
        </Typography>
      </Box>
    );
  }

  return (
    <TournamentBracketScreen
      tournament={tournament}
      event={event}
      progress={progress}
      knockoutMatchesByBracketId={knockoutMatchesByBracketId}
      courts={courts}
      categoryLabel={MODE_LABELS[mode] || ""}
      onBack={() => navigate(backPath)}
      onOpenResults={() => navigate(backPath)}
      onOpenDetails={() => navigate(backPath)}
      autoPlayReveal={false}
    />
  );
}

import { useMemo, useEffect, useState } from "react";
import { useNavigate, useParams, useLocation } from "react-router-dom";

import {
  Alert,
  Badge,
  Box,
  Breadcrumbs,
  Button,
  Chip,
  CircularProgress,
  Snackbar,
  LinearProgress,
  Link,
  List,
  ListItem,
  ListItemText,
  Paper,
  Tab,
  Tabs,
  Typography,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";
import ArrowForwardIcon from "@mui/icons-material/ArrowForward";
import AutoAwesomeIcon from "@mui/icons-material/AutoAwesome";
import NotificationsIcon from "@mui/icons-material/Notifications";
import ExpandLessIcon from "@mui/icons-material/ExpandLess";
import ExpandMoreIcon from "@mui/icons-material/ExpandMore";

import { useTournamentEngineState } from "../../features/tournament-engine/hooks/useTournamentEngine.js";
import { groupWorkflowHistoryByDate } from "../../features/tournament-engine/hooks/workflowHistory.js";
import EngineSetupTab from "./engine/tabs/EngineSetupTab.jsx";
import EngineSeedTab from "./engine/tabs/EngineSeedTab.jsx";
import EngineDrawTab from "./engine/tabs/EngineDrawTab.jsx";
import EngineScheduleTab from "./engine/tabs/EngineScheduleTab.jsx";
import EngineCourtsTab from "./engine/tabs/EngineCourtsTab.jsx";
import EngineRankingTab from "./engine/tabs/EngineRankingTab.jsx";
import EngineLogsTab from "./engine/tabs/EngineLogsTab.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import TournamentPageHeader from "../../components/tournament/TournamentPageHeader.jsx";
import { tournamentCardSx } from "../../components/tournament/tournamentLayout.js";
import { PERMISSIONS } from "../../auth/permissions.js";
import { runPlatformEngineWorkflow } from "../../core/platform/engines/orchestrator.js";
import {
  getPlatformEventSummary,
  getPlatformNotificationSummary,
  getUnreadNotificationCount,
  getWorkflowNotificationMessage,
  getWorkflowStageConfig,
  getWorkflowStatusLabel,
} from "./engine/workflowPreviewUtils.js";

const TAB_CONFIG = [
  { key: "setup", label: "Thiết lập" },
  { key: "seed", label: "Hạt giống" },
  { key: "draw", label: "Bốc thăm" },
  { key: "schedule", label: "Lịch đấu" },
  { key: "courts", label: "Sân" },
  { key: "ranking", label: "Xếp hạng" },
  { key: "logs", label: "Nhật ký AI" },
];

function resolveTabFromPath(pathname) {
  if (pathname.endsWith("/seed")) return "seed";
  if (pathname.endsWith("/draw")) return "draw";
  if (pathname.endsWith("/schedule")) return "schedule";
  if (pathname.endsWith("/courts")) return "courts";
  if (pathname.endsWith("/ranking")) return "ranking";
  if (pathname.endsWith("/logs")) return "logs";
  return "setup";
}

function tabPath(tournamentId, tabKey) {
  if (tabKey === "setup") {
    return `/tournaments/${tournamentId}/engine`;
  }
  return `/tournaments/${tournamentId}/${tabKey}`;
}

export default function TournamentEnginePage() {
  const { tournamentId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const activeTab = resolveTabFromPath(location.pathname);
  const [historyExpanded, setHistoryExpanded] = useState(true);
  const [confirmClearHistory, setConfirmClearHistory] = useState(false);
  const [toastMessage, setToastMessage] = useState("");
  const [notificationFilter, setNotificationFilter] = useState("all");

  const engine = useTournamentEngineState(tournamentId);
  const platformSummary = useMemo(
    () =>
      runPlatformEngineWorkflow({
        tournament: engine.tournament,
        players: engine.players || [],
        courts: engine.courts || [],
        matches: engine.matches || [],
      }),
    [engine.tournament, engine.players, engine.courts, engine.matches]
  );

  const workflowHistoryGroups = useMemo(() => groupWorkflowHistoryByDate(engine.workflowHistory || []), [engine.workflowHistory]);

  const workflowStages = useMemo(() => getWorkflowStageConfig(engine.engineState, engine.matches), [engine.engineState, engine.matches]);

  const completedStageCount = useMemo(() => workflowStages.filter((stage) => stage.done).length, [workflowStages]);

  const workflowStatusLabel = useMemo(() => getWorkflowStatusLabel(completedStageCount), [completedStageCount]);

  const latestHistoryEntry = useMemo(() => {
    return (engine.workflowHistory || [])[0] || null;
  }, [engine.workflowHistory]);

  const platformEventSummaries = useMemo(() => {
    return (engine.platformEvents || []).slice(0, 5).map((event) => getPlatformEventSummary(event));
  }, [engine.platformEvents]);

  const platformNotificationSummaries = useMemo(() => {
    const notifications = (engine.platformNotifications || []).slice(0, 10).map((notification) => getPlatformNotificationSummary(notification));
    if (notificationFilter === "unread") {
      return notifications.filter((notification) => notification?.read !== true && notification?.status !== "read");
    }
    return notifications;
  }, [engine.platformNotifications, notificationFilter]);

  const unreadNotificationCount = useMemo(() => {
    return getUnreadNotificationCount(engine.platformNotifications || []);
  }, [engine.platformNotifications]);

  const nextWorkflowAction = useMemo(() => {
    if (!engine.engineState?.participants?.length) {
      return {
        label: "Next: generate seed and build the initial player pool.",
        tab: "seed",
      };
    }
    if (!engine.engineState?.groups?.length) {
      return {
        label: "Next: create the draw so the bracket structure is ready.",
        tab: "draw",
      };
    }
    if (!engine.matches?.length) {
      return {
        label: "Next: schedule matches and assign court slots.",
        tab: "schedule",
      };
    }
    if (!engine.engineState?.rankingResult) {
      return {
        label: "Next: publish the ranking snapshot for the current workflow.",
        tab: "ranking",
      };
    }
    return {
      label: "Next: review the latest workflow summary and export the plan.",
      tab: "setup",
    };
  }, [engine.engineState, engine.matches]);

  const handleTabChange = (_, tabKey) => {
    navigate(tabPath(tournamentId, tabKey));
  };

  useEffect(() => {
    if (!confirmClearHistory) return undefined;

    const timer = window.setTimeout(() => setConfirmClearHistory(false), 2500);
    return () => window.clearTimeout(timer);
  }, [confirmClearHistory]);

  useEffect(() => {
    if (!engine.platformNotifications?.length) {
      return undefined;
    }

    const latestNotification = engine.platformNotifications[engine.platformNotifications.length - 1];
    const message = getWorkflowNotificationMessage(latestNotification);
    setToastMessage(message);
    return undefined;
  }, [engine.platformNotifications]);

  const handleClearHistory = () => {
    if (confirmClearHistory) {
      engine.clearWorkflowHistory?.();
      setConfirmClearHistory(false);
      return;
    }

    setConfirmClearHistory(true);
  };

  const handleNotificationClick = (notification) => {
    if (notification?.read || notification?.status === "read") {
      return;
    }
    engine.markNotificationAsRead?.(notification.id);
  };

  if (!engine.tournament) {
    return (
      <Box sx={{ p: 3 }}>
        <Alert severity="error">Không tìm thấy giải đấu.</Alert>
        <Button startIcon={<ArrowBackIcon />} sx={{ mt: 2 }} onClick={() => navigate("/tournament")}>
          Quay lại
        </Button>
      </Box>
    );
  }

  const tabContent = (() => {
    switch (activeTab) {
      case "seed":
        return <EngineSeedTab engine={engine} />;
      case "draw":
        return <EngineDrawTab engine={engine} />;
      case "schedule":
        return <EngineScheduleTab engine={engine} />;
      case "courts":
        return <EngineCourtsTab engine={engine} />;
      case "ranking":
        return <EngineRankingTab engine={engine} />;
      case "logs":
        return <EngineLogsTab tournamentId={tournamentId} />;
      default:
        return <EngineSetupTab engine={engine} tournamentId={tournamentId} />;
    }
  })();

  return (
    <PermissionGate
      permission={PERMISSIONS.TOURNAMENT_UPDATE}
      fallback={<Alert severity="warning">Bạn không có quyền cấu hình giải.</Alert>}
    >
      <Box sx={{ p: { xs: 1, md: 2 } }}>
        <Snackbar
          open={Boolean(toastMessage)}
          autoHideDuration={4000}
          onClose={() => setToastMessage("")}
          message={toastMessage}
        />
        <Breadcrumbs sx={{ mb: 1 }}>
          <Link component="button" underline="hover" color="inherit" onClick={() => navigate("/tournament")}>
            Giải đấu
          </Link>
          <Typography color="text.primary">{engine.tournament.name}</Typography>
          <Typography color="text.secondary">Engine 4.0</Typography>
        </Breadcrumbs>

        <TournamentPageHeader
          title="Tournament Engine 4.0"
          description={engine.tournament.name}
          action={<AutoAwesomeIcon color="primary" />}
        />

        <Box sx={{ mb: 2, p: 1.25, border: 1, borderColor: "divider", borderRadius: 1, bgcolor: "background.paper" }}>
          <Box sx={{ display: "flex", flexWrap: "wrap", alignItems: "flex-start", justifyContent: "space-between", gap: 1.25 }}>
            <Box>
              <Box sx={{ display: "flex", alignItems: "center", gap: 1, mb: 0.25 }}>
                <Typography variant="subtitle2" color="primary">
                  Platform v5 Engine Preview
                </Typography>
                <Chip
                  size="small"
                  label={workflowStatusLabel}
                  color={completedStageCount === 4 ? "success" : completedStageCount > 0 ? "info" : "default"}
                  variant="outlined"
                />
              </Box>
              <Typography variant="body2" color="text.secondary" sx={{ fontSize: "0.85rem" }}>
                {platformSummary.data.recommendation.recommendation} · {platformSummary.data.recommendation.reason}
              </Typography>
            </Box>
            <Button
              size="small"
              variant="contained"
              color="primary"
              endIcon={<ArrowForwardIcon />}
              sx={{ py: 0.2, px: 1, fontSize: "0.8rem", fontWeight: 600 }}
              onClick={() => navigate(tabPath(tournamentId, nextWorkflowAction.tab))}
            >
              {nextWorkflowAction.label}
            </Button>
          </Box>
          <Box sx={{ display: "flex", justifyContent: "space-between", alignItems: "center", mt: 0.75, mb: 0.5 }}>
            <Typography variant="caption" color="text.secondary">
              Tiến độ workflow
            </Typography>
            <Typography variant="caption" color="primary">
              {completedStageCount}/4 stages
            </Typography>
          </Box>
          <LinearProgress
            variant="determinate"
            value={(completedStageCount / 4) * 100}
            sx={{ height: 6, borderRadius: 999 }}
          />
          <Typography variant="caption" color="text.secondary" sx={{ display: "block", mt: 0.5 }}>
            {completedStageCount === 4
              ? "Tất cả các bước workflow đã hoàn tất."
              : completedStageCount > 0
                ? `Workflow đang ở ${completedStageCount}/4 bước. Hãy tiếp tục với bước tiếp theo.`
                : "Workflow chưa bắt đầu. Hãy bắt đầu từ bước đầu tiên."}
          </Typography>
          <Box sx={{ display: "flex", flexWrap: "wrap", gap: 0.75, mt: 0.75 }}>
            {workflowStages.map((stage, index) => {
              const isNextStage = !stage.done && workflowStages.findIndex((item) => !item.done) === index;
              return (
                <Box
                  key={stage.key}
                  component="button"
                  title={`Go to ${stage.label.toLowerCase()} workflow`}
                  onClick={() => navigate(tabPath(tournamentId, stage.tab))}
                  sx={{
                    display: "flex",
                    alignItems: "center",
                    gap: 0.5,
                    px: 0.75,
                    py: 0.25,
                    borderRadius: 999,
                    border: "1px solid",
                    borderColor: stage.done ? "success.main" : isNextStage ? "primary.main" : "divider",
                    bgcolor: stage.done ? "success.main" : isNextStage ? "primary.light" : "grey.100",
                    color: stage.done ? "common.white" : isNextStage ? "primary.contrastText" : "text.secondary",
                    cursor: "pointer",
                    fontSize: "0.75rem",
                    transition: "all 120ms ease-in-out",
                    "&:hover": {
                      transform: "translateY(-1px)",
                      boxShadow: 1,
                    },
                    "&:focus-visible": {
                      outline: "2px solid",
                      outlineColor: "primary.main",
                      outlineOffset: 1,
                    },
                  }}
                >
                  <Typography variant="caption" sx={{ color: "inherit" }}>
                    {stage.done ? "●" : isNextStage ? "▶" : "○"}
                  </Typography>
                  <Typography variant="caption" sx={{ color: "inherit" }}>
                    {stage.label}
                  </Typography>
                </Box>
              );
            })}
          </Box>
        </Box>

        <Paper sx={{ p: 1.5, mb: 1.5, bgcolor: "grey.50" }}>
          <Box sx={{ display: "flex", flexWrap: "wrap", justifyContent: "space-between", alignItems: "center", gap: 1, mb: 1 }}>
            <Typography variant="subtitle2" color="text.secondary">
              Platform event feed
            </Typography>
            <Chip size="small" label={`${platformEventSummaries.length} events`} variant="outlined" />
          </Box>
          {platformEventSummaries.length > 0 ? (
            <List dense disablePadding sx={{ mb: 1 }}>
              {platformEventSummaries.map((event, index) => (
                <ListItem key={`${event.title}-${index}`} disablePadding sx={{ py: 0.2 }}>
                  <ListItemText
                    primary={
                      <Box sx={{ display: "flex", alignItems: "center", gap: 1, flexWrap: "wrap" }}>
                        <Typography variant="body2" sx={{ fontWeight: 600 }}>
                          {event.title}
                        </Typography>
                        <Chip size="small" label={event.status} variant="outlined" />
                      </Box>
                    }
                    secondary={
                      <Typography variant="caption" color="text.secondary">
                        {`${event.detail} · ${new Date(event.timestamp).toLocaleString("vi-VN")}`}
                      </Typography>
                    }
                  />
                </ListItem>
              ))}
            </List>
          ) : (
            <Typography variant="body2" color="text.secondary">
              Chưa có event nào được ghi nhận cho workflow này.
            </Typography>
          )}

          <Box sx={{ mt: 1.5 }}>
            <Box sx={{ display: "flex", alignItems: "center", gap: 1, mb: 0.75, flexWrap: "wrap" }}>
              <Typography variant="subtitle2" color="text.secondary">
                Recent notifications
              </Typography>
              <Badge badgeContent={unreadNotificationCount} color="primary" max={99}>
                <NotificationsIcon color="action" fontSize="small" />
              </Badge>
              {unreadNotificationCount > 0 && (
                <Button size="small" variant="text" onClick={() => engine.markAllNotificationsAsRead?.()}>
                  Đánh dấu tất cả đã đọc
                </Button>
              )}
              <Button size="small" variant="text" color={notificationFilter === "all" ? "primary" : "inherit"} onClick={() => setNotificationFilter("all")}>
                Tất cả
              </Button>
              <Button size="small" variant="text" color={notificationFilter === "unread" ? "primary" : "inherit"} onClick={() => setNotificationFilter("unread")}>
                Chưa đọc
              </Button>
            </Box>
            {platformNotificationSummaries.length > 0 ? (
              <List dense disablePadding>
                {platformNotificationSummaries.map((notification, index) => (
                  <ListItem
                    key={`${notification.title}-${index}`}
                    disablePadding
                    sx={{
                      py: 0.2,
                      cursor: notification?.read || notification?.status === "read" ? "default" : "pointer",
                      bgcolor: notification?.read || notification?.status === "read" ? "transparent" : "primary.50",
                      borderRadius: 1,
                      border: notification?.read || notification?.status === "read" ? "1px solid transparent" : "1px solid",
                      borderColor: notification?.read || notification?.status === "read" ? "transparent" : "primary.100",
                    }}
                    onClick={() => handleNotificationClick(notification)}
                  >
                    <ListItemText
                      primary={
                        <Box sx={{ display: "flex", alignItems: "center", gap: 1, flexWrap: "wrap" }}>
                          <Typography variant="body2" sx={{ fontWeight: 600 }}>
                            {notification.title}
                          </Typography>
                          {!notification?.read && notification?.status !== "read" && (
                            <Chip size="small" label="NEW" color="primary" variant="filled" />
                          )}
                          <Chip size="small" label={notification.channel} variant="outlined" />
                        </Box>
                      }
                      secondary={
                        <Typography variant="caption" color="text.secondary">
                          {`${notification.detail} · ${new Date(notification.timestamp).toLocaleString("vi-VN")}`}
                        </Typography>
                      }
                    />
                  </ListItem>
                ))}
              </List>
            ) : (
              <Typography variant="body2" color="text.secondary">
                Chưa có notification nào được tạo cho workflow này.
              </Typography>
            )}
          </Box>
        </Paper>

        {engine.workflowHistory?.length > 0 && (
          <Paper sx={{ p: 1.5, mb: 1.5, bgcolor: "grey.50" }}>
            {latestHistoryEntry && !historyExpanded && (
              <Box sx={{ mb: 0.75, p: 0.75, borderRadius: 1, bgcolor: "background.paper", border: "1px solid", borderColor: "divider" }}>
                <Typography variant="caption" color="text.secondary">
                  Latest action
                </Typography>
                <Typography variant="body2" sx={{ textTransform: "capitalize", fontWeight: 600 }}>
                  {latestHistoryEntry.action}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  {`${latestHistoryEntry.detail} · ${new Date(latestHistoryEntry.timestamp).toLocaleString("vi-VN")}`}
                </Typography>
              </Box>
            )}
            <Box sx={{ display: "flex", flexWrap: "wrap", justifyContent: "space-between", alignItems: "center", gap: 1, mb: 0.75 }}>
              <Typography variant="subtitle2" color="text.secondary">
                Workflow history
              </Typography>
              <Box sx={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: 0.75 }}>
                <Chip size="small" label={`${engine.workflowHistory?.length || 0} entries`} variant="outlined" />
                <Button
                  size="small"
                  variant="text"
                  color={historyExpanded ? "primary" : "inherit"}
                  startIcon={historyExpanded ? <ExpandLessIcon /> : <ExpandMoreIcon />}
                  onClick={() => setHistoryExpanded((value) => !value)}
                >
                  {historyExpanded ? "Thu gọn" : "Mở rộng"}
                </Button>
                <Button size="small" variant="text" color={confirmClearHistory ? "warning" : "inherit"} onClick={handleClearHistory}>
                  {confirmClearHistory ? "Xác nhận" : "Xóa"}
                </Button>
              </Box>
            </Box>
            {historyExpanded && (
              <List dense disablePadding>
                {workflowHistoryGroups.slice(0, 3).map((group) => (
                  <Box key={group.label} sx={{ mb: 1 }}>
                    <Typography variant="caption" color="text.secondary" sx={{ display: "block", mb: 0.5 }}>
                      {group.label}
                    </Typography>
                    {group.entries.slice(0, 3).map((entry) => {
                      const statusColor = entry.status === "success" ? "success" : entry.status === "error" ? "error" : "default";
                      return (
                        <ListItem key={entry.id} disablePadding sx={{ py: 0.1 }}>
                          <ListItemText
                            primary={
                              <Box sx={{ display: "flex", alignItems: "center", gap: 1, flexWrap: "wrap" }}>
                                <Typography variant="body2" sx={{ textTransform: "capitalize", fontWeight: 600 }}>
                                  {entry.action}
                                </Typography>
                                <Chip size="small" label={entry.status} color={statusColor} variant="outlined" />
                              </Box>
                            }
                            secondary={
                              <Typography variant="caption" color="text.secondary">
                                {`${entry.detail} · ${new Date(entry.timestamp).toLocaleString("vi-VN")}`}
                              </Typography>
                            }
                          />
                        </ListItem>
                      );
                    })}
                  </Box>
                ))}
              </List>
            )}
          </Paper>
        )}

        {engine.error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {engine.error}
          </Alert>
        )}

        <Tabs
          value={activeTab}
          onChange={handleTabChange}
          variant="scrollable"
          scrollButtons="auto"
          sx={{ mb: 2, borderBottom: 1, borderColor: "divider" }}
        >
          {TAB_CONFIG.map((tab) => (
            <Tab key={tab.key} label={tab.label} value={tab.key} />
          ))}
        </Tabs>

        {engine.loading && (
          <Box sx={{ display: "flex", alignItems: "center", gap: 1, mb: 2 }}>
            <CircularProgress size={20} />
            <Typography variant="body2">Đang xử lý…</Typography>
          </Box>
        )}

        {tabContent}
      </Box>
    </PermissionGate>
  );
}

import { useEffect, useMemo, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Grid,
  Typography,
} from "@mui/material";

import GroupsIcon from "@mui/icons-material/Groups";
import EmojiEventsIcon from "@mui/icons-material/EmojiEvents";
import Diversity3Icon from "@mui/icons-material/Diversity3";

import { useAuth } from "../../context/AuthContext.jsx";
import { useClub } from "../../context/ClubContext.jsx";
import { useSeasonLeague } from "../../context/SeasonContext.jsx";
import ActiveTournamentsPanel from "../../components/tournament/ActiveTournamentsPanel.jsx";
import TournamentListTable from "../../components/tournament/TournamentListTable.jsx";
import TournamentPageHeader from "../../components/tournament/TournamentPageHeader.jsx";
import {
  createTournament,
  deleteTournament,
  listTournaments,
} from "../../domain/tournamentService.js";
import { TOURNAMENT_MODE, TOURNAMENT_STATUS, OFFICIAL_MODE } from "../../models/tournament/index.js";
import ModeCard from "../../components/tournament/ModeCard.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import ClubAssignmentBanner from "../../components/auth/ClubAssignmentBanner.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import { usePageRuntimeAccess } from "../../core/platform/app/usePageRuntimeAccess.js";
import { createTeamTournament } from "../../features/team-tournament/services/teamTournamentService.js";
import { getTeamData } from "../../features/team-tournament/engines/teamTournamentEngine.js";
import { findTeamForCaptain } from "../../features/team-tournament/engines/teamPermissionEngine.js";
import { TOURNAMENT_LAYOUT } from "../../components/tournament/tournamentLayout.js";

const SECTION_META = {
  overview: {
    title: "Tổng quan",
    description: "Tạo giải mới, theo dõi giải đang mở và quản lý danh sách giải.",
  },
  create: {
    title: "Tạo giải",
    description: "Chọn loại giải để tạo giải nháp mới.",
  },
  list: {
    title: "Danh sách giải",
    description: "Xem và quản lý tất cả giải trong CLB hiện tại.",
  },
};

const CREATE_TOURNAMENT_MODE_OPTIONS = [
  {
    mode: TOURNAMENT_MODE.INTERNAL_TOURNAMENT,
    title: "Giải nội bộ CLB",
    description:
      "Chia bảng theo hạt giống, vòng bảng, bán kết/chung kết và bracket cho giải nội bộ CLB.",
    icon: <GroupsIcon sx={{ fontSize: 18 }} />,
    badge: "Internal",
  },
  {
    mode: TOURNAMENT_MODE.OFFICIAL_TOURNAMENT,
    title: "Giải chính thức / mở rộng",
    description:
      "Giải nhiều CLB, nhiều nội dung thi đấu, Open Mode hoặc AI Balance Mode.",
    icon: <EmojiEventsIcon sx={{ fontSize: 18 }} />,
    badge: "Official",
  },
  {
    mode: TOURNAMENT_MODE.TEAM_TOURNAMENT,
    title: "Giải đồng đội MLP",
    description:
      "MLP 4 người (2M+2F): đôi nữ → đôi nam → mixed×2, Dreambreaker khi 2-2, Rally 21 điểm.",
    icon: <Diversity3Icon sx={{ fontSize: 18 }} />,
    badge: "MLP",
  },
];

function buildDefaultName(modeLabel) {
  const date = new Date().toLocaleDateString("vi-VN");
  return `${modeLabel} ${date}`;
}

function canDeleteTournament(tournament) {
  return (
    tournament.status === TOURNAMENT_STATUS.DRAFT ||
    tournament.status === TOURNAMENT_STATUS.CANCELLED
  );
}

export default function TournamentHome({ section = "overview" }) {
  const navigate = useNavigate();
  const createRef = useRef(null);
  const listRef = useRef(null);
  const { user } = useAuth();
  const { activeClub, activeClubId, revision, refreshClubs } = useClub();
  const { activeSeason, activeLeague } = useSeasonLeague();
  const { accessAllowed } = usePageRuntimeAccess("tournament.manage", activeClub?.tenantId || activeClubId, {
    source: "tournament.home",
  });
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [selectedIds, setSelectedIds] = useState([]);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);

  const tournaments = useMemo(
    () => listTournaments(activeClubId),
    [activeClubId, revision]
  );

  const showCreateSection = section === "overview" || section === "create";
  const showActiveSection = section === "overview";
  const showListSection = section === "overview" || section === "list";
  const sectionMeta = SECTION_META[section] || SECTION_META.overview;

  const contextLine = [
    activeClub?.name ? `CLB ${activeClub.name}` : null,
    activeSeason?.name || null,
    activeLeague?.name || null,
  ]
    .filter(Boolean)
    .join(" • ");

  useEffect(() => {
    const target = section === "create" ? createRef : section === "list" ? listRef : null;
    if (target?.current) {
      target.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, [section]);

  const deletableSelectedCount = useMemo(
    () =>
      tournaments.filter(
        (tournament) =>
          selectedIds.includes(tournament.id) && canDeleteTournament(tournament)
      ).length,
    [tournaments, selectedIds]
  );

  const handleToggleSelection = (tournamentId, checked) => {
    setSelectedIds((prev) =>
      checked ? [...prev, tournamentId] : prev.filter((id) => id !== tournamentId)
    );
  };

  const handleSelectAll = () => {
    setSelectedIds(tournaments.map((tournament) => tournament.id));
  };

  const handleClearSelection = () => {
    setSelectedIds([]);
  };

  const handleConfirmDelete = () => {
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác quản lý giải đấu.");
      return;
    }

    setError(null);
    setMessage(null);

    let deletedCount = 0;
    const blocked = [];

    selectedIds.forEach((tournamentId) => {
      const tournament = tournaments.find((item) => item.id === tournamentId);
      if (!tournament) return;

      const result = deleteTournament(activeClubId, tournamentId);
      if (result.ok) {
        deletedCount += 1;
        return;
      }
      blocked.push(tournament.name);
    });

    refreshClubs();
    setSelectedIds([]);
    setDeleteDialogOpen(false);

    if (deletedCount > 0) {
      setMessage(`Đã xóa ${deletedCount} giải.`);
    }

    if (blocked.length > 0) {
      setError(
        `Không thể xóa ${blocked.length} giải (chỉ xóa được giải Nháp hoặc Đã hủy): ${blocked.slice(0, 3).join(", ")}${
          blocked.length > 3 ? "..." : ""
        }`
      );
    }
  };

  const handleStartMode = (option) => {
    if (!accessAllowed) {
      setError("Runtime platform chặn thao tác quản lý giải đấu.");
      return;
    }

    setError(null);
    setMessage(null);

    const result =
      option.mode === TOURNAMENT_MODE.TEAM_TOURNAMENT
        ? createTeamTournament(activeClubId, {
            name: buildDefaultName(option.title),
            seasonId: activeSeason?.id,
            leagueId: activeLeague?.id,
            formatPreset: "mlp_4",
          })
        : createTournament(activeClubId, {
            name: buildDefaultName(option.title),
            mode: option.mode,
            officialMode:
              option.mode === TOURNAMENT_MODE.OFFICIAL_TOURNAMENT
                ? OFFICIAL_MODE.OPEN
                : undefined,
            hostClubName:
              option.mode === TOURNAMENT_MODE.OFFICIAL_TOURNAMENT
                ? activeClub?.name || ""
                : undefined,
            seasonId: activeSeason?.id,
            leagueId: activeLeague?.id,
          });

    if (!result.ok) {
      setError(result.error || "Không thể tạo giải.");
      return;
    }

    refreshClubs();

    if (option.mode === TOURNAMENT_MODE.DAILY_PLAY) {
      navigate(`/tournament/daily/${result.tournament.id}`);
      return;
    }
    if (option.mode === TOURNAMENT_MODE.INTERNAL_TOURNAMENT) {
      navigate(`/tournament/internal/${result.tournament.id}`);
      return;
    }
    if (option.mode === TOURNAMENT_MODE.OFFICIAL_TOURNAMENT) {
      navigate(`/tournament/official/${result.tournament.id}`);
      return;
    }
    if (option.mode === TOURNAMENT_MODE.TEAM_TOURNAMENT) {
      navigate(`/tournament/team/${result.tournament.id}`);
      return;
    }

    setMessage(
      `Đã tạo giải nháp "${result.tournament.name}". Màn hình setup sẽ có ở bước tiếp theo.`
    );
  };

  const isCaptainForTeamTournament = (tournament) => {
    const playerId = user?.playerId;
    if (!playerId || tournament?.mode !== TOURNAMENT_MODE.TEAM_TOURNAMENT) {
      return false;
    }
    const teamData = getTeamData(tournament);
    return Boolean(findTeamForCaptain(teamData, playerId));
  };

  return (
    <Box>
      <TournamentPageHeader
        title={sectionMeta.title}
        description={sectionMeta.description}
        contextLine={contextLine || undefined}
      />

      <ClubAssignmentBanner />

      {message && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message}
        </Alert>
      )}

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {showCreateSection ? (
        <Box ref={createRef} sx={{ mb: TOURNAMENT_LAYOUT.sectionGap }}>
          <Typography variant="subtitle1" fontWeight={700} sx={{ mb: 1.5 }}>
            Tạo giải mới
          </Typography>
          <PermissionGate permission={PERMISSIONS.TOURNAMENT_UPDATE}>
            <Grid container spacing={TOURNAMENT_LAYOUT.gridSpacing}>
              {CREATE_TOURNAMENT_MODE_OPTIONS.map((option) => (
                <Grid key={option.mode} size={{ xs: 12, sm: 6, lg: 4 }}>
                  <ModeCard
                    title={option.title}
                    description={option.description}
                    icon={option.icon}
                    mode={option.mode}
                    badge={option.badge}
                    onStart={() => handleStartMode(option)}
                  />
                </Grid>
              ))}
            </Grid>
          </PermissionGate>
        </Box>
      ) : null}

      {showActiveSection ? (
        <Box sx={{ mb: TOURNAMENT_LAYOUT.sectionGap }}>
          <ActiveTournamentsPanel tournaments={tournaments} title="Giải đang mở" />
        </Box>
      ) : null}

      {showListSection ? (
        <Box ref={listRef}>
          <TournamentListTable
            tournaments={tournaments}
            selectedIds={selectedIds}
            onToggleSelection={handleToggleSelection}
            onSelectAll={handleSelectAll}
            onClearSelection={handleClearSelection}
            onDeleteSelected={() => setDeleteDialogOpen(true)}
            canDeleteTournament={canDeleteTournament}
            showCaptainPortal={isCaptainForTeamTournament}
            onCaptainPortal={(tournament) => navigate(`/team-portal/${tournament.id}`)}
          />
        </Box>
      ) : null}

      <Dialog open={deleteDialogOpen} onClose={() => setDeleteDialogOpen(false)}>
        <DialogTitle>Xác nhận xóa giải</DialogTitle>
        <DialogContent>
          <Typography>
            Bạn đã chọn <strong>{selectedIds.length}</strong> giải.
          </Typography>
          <Typography sx={{ mt: 1 }} color="text.secondary">
            Chỉ giải ở trạng thái <strong>Nháp</strong> hoặc <strong>Đã hủy</strong> mới
            được xóa. Trong số đã chọn, <strong>{deletableSelectedCount}</strong> giải có
            thể xóa.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteDialogOpen(false)}>Hủy</Button>
          <Button
            color="error"
            variant="contained"
            disabled={deletableSelectedCount === 0}
            onClick={handleConfirmDelete}
          >
            Xóa {deletableSelectedCount > 0 ? deletableSelectedCount : ""} giải
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useState } from "react";

import {
  Alert,
  Box,
  Button,
  Chip,
  Stack,
  Typography,
} from "@mui/material";

import {
  addTeamToTournament,
  buildRoundRobinMatchups,
  initializeTeamTournamentData,
} from "../../features/team-tournament/engines/teamTournamentEngine.js";
import {
  canPublishSchedule,
  getSchedulePublishStatus,
  lockPublishedSchedule,
  publishSchedule,
  SCHEDULE_PUBLISH_STATUS,
} from "../../features/team-tournament/engines/publishScheduleEngine.js";
import TournamentConfigPageShell from "../../components/tournament/TournamentConfigPageShell.jsx";

const STATUS_LABEL = {
  [SCHEDULE_PUBLISH_STATUS.DRAFT]: "Nháp",
  [SCHEDULE_PUBLISH_STATUS.PUBLISHED]: "Đã công bố",
  [SCHEDULE_PUBLISH_STATUS.LOCKED]: "Đã khóa",
};

function buildDemoTeamData() {
  let teamData = initializeTeamTournamentData();
  teamData = addTeamToTournament(teamData, { id: "team-a", name: "Team A", playerIds: [] });
  teamData = addTeamToTournament(teamData, { id: "team-b", name: "Team B", playerIds: [] });
  return buildRoundRobinMatchups(teamData, {
    scheduledAt: "2026-07-10T08:00:00.000Z",
  });
}

export default function TournamentPublishSchedulePage() {
  const [teamData, setTeamData] = useState(() => buildDemoTeamData());
  const [message, setMessage] = useState(null);
  const publish = getSchedulePublishStatus(teamData);

  const handlePublish = () => {
    const result = publishSchedule(teamData, { userId: "btc" });
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setTeamData(result.teamData);
    setMessage({ type: "success", text: "Đã công bố lịch thi đấu." });
  };

  const handleLock = () => {
    const result = lockPublishedSchedule(teamData, { userId: "btc" });
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setTeamData(result.teamData);
    setMessage({ type: "success", text: "Đã khóa lịch sau công bố." });
  };

  const readiness = canPublishSchedule(teamData);

  return (
    <TournamentConfigPageShell
      title="Công bố lịch"
      description="Công bố và khóa lịch thi đấu cho BTC."
    >
      {message ? (
        <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      ) : null}

      <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 2 }}>
        <Typography>Trạng thái:</Typography>
        <Chip label={STATUS_LABEL[publish.status] || publish.status} color="primary" />
      </Stack>

      {!readiness.ok ? (
        <Alert severity="info" sx={{ mb: 2 }}>
          {readiness.error}
        </Alert>
      ) : null}

      <Stack direction="row" spacing={1}>
        <Button
          variant="contained"
          onClick={handlePublish}
          disabled={publish.status === SCHEDULE_PUBLISH_STATUS.LOCKED}
        >
          Công bố lịch
        </Button>
        <Button
          variant="outlined"
          onClick={handleLock}
          disabled={publish.status !== SCHEDULE_PUBLISH_STATUS.PUBLISHED}
        >
          Khóa lịch
        </Button>
      </Stack>
    </TournamentConfigPageShell>
  );
}

