    const deleted = await deleteClubActivitySession(
      CLUB_ID,
      created.session.id,
      TENANT,
      { user: president }
    );
    assert.equal(deleted.ok, true);
    assert.equal(listClubActivitySessions(CLUB_ID, TENANT).length, 0);
  });
});

