    const visible = listAccessibleClustersForUser(CLUSTER_OWNER, VENUE_A);
    assert.equal(visible.length, 1);
    assert.equal(visible[0].id, c1.cluster.id);
  });

  it("blocks cross-venue cluster access", () => {
