    phase: active ? MEMBERSHIP_PHASE.ACTIVE : MEMBERSHIP_PHASE.NONE,
    hasActiveMembership: active,
    clubId: active ? CLUB_ID : null,
    loading: false,
    ok: true,
  };
}

function menuAuth(user) {
